window.HADITH_CACHE = window.HADITH_CACHE || {};
window.HADITH_CACHE["darimi_4"] = {"2001":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مُوسَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فُكُّوا الْعَانِيَ وَأَطْعِمُوا الْجَائِعَ","id":"Telah `mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Manshur] dari [Abu Wa`il] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Bebaskanlah para tawanan, dan berilah makan orang yang lapar.\""},"2002":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَادَى رَجُلًا بِرَجُلَيْنِ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Abu Al Muhallab] dari ['Imran bin Hushain] bahwa Rasulullah shallallahu 'alaihi wasallam pernah menebus satu orang dengan dua orang."},"2003":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَمَّادٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سُلَيْمَانَ عَنْ مُجَاهِدٍ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ أَبِي ذَرٍّ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُعْطِيتُ خَمْسًا لَمْ يُعْطَهُنَّ نَبِيٌّ قَبْلِي بُعِثْتُ إِلَى الْأَحْمَرِ وَالْأَسْوَدِ وَجُعِلَتْ لِيَ الْأَرْضُ مَسْجِدًا وَطَهُورًا وَأُحِلَّتْ لِيَ الْغَنَائِمُ وَلَمْ تَحِلَّ لِأَحَدٍ قَبْلِي وَنُصِرْتُ بِالرُّعْبِ شَهْرًا يُرْعَبُ مِنِّي الْعَدُوُّ مَسِيرَةَ شَهْرٍ وَقِيلَ لِي سَلْ تُعْطَهْ فَاخْتَبَأْتُ دَعْوَتِي شَفَاعَةً لِأُمَّتِي وَهِيَ نَائِلَةٌ مِنْكُمْ إِنْ شَاءَ اللَّهُ تَعَالَى مَنْ لَمْ يُشْرِكْ بِاللَّهِ شَيْئًا","id":"Telah mengabarkan kepada kami [Yahya bin Hammad] telah menceritakan kepada kami [Abu 'Awanah] dari [Sulaiman] dari [Mujahid] dari ['Ubaid bin 'Umair] dari [Abu Dzar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Aku diberi lima hal yang tidak diberikan kepada seorang nabipun sebelumku. Aku diutus kepada manusia dan jin, dan dijadikan bagiku tanah sebagai masjid serta pensuci, dihalalkan rampasan perang yang tidak dihalalkan bagi seorangpun sebelumku, dan aku diberi kemenangan dengan rasa takut musuh sejauh perjalanan satu bulan. Dikatakan kepadaku; mintalah maka engkau akan diberi. Kemudian aku menyimpan permohonanku sebagai syafa'at bagi umatku, dan syafa'at tersebut akan didapatkan insya Allah Ta'ala bagi orang yang tidak mensekutukan Allah dengan sesuatupun.\""},"2004":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَاصِمٍ عَنْ أَبِي وَائِلٍ قَالَ قَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَنَائِمَ حُنَيْنٍ بِالْجِعْرَانَةِ قَالَ عَبْد اللَّهِ عَبْدُ اللَّهِ بْنُ مَسْعُودٍ فِي الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Ashim] dari [Abu Wa'il] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam membagi-bagikan harta rampasan perang Hunain di Ja'ranah.\" Hammad berkata; (nama) Abdullah yang tercantum dalam sanad tersebut adalah Abdullah bin Mas'ud."},"2005":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الرَّقِّيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ زَيْدٍ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِيهِ قَالَ شَهِدْتُ فَتْحَ خَيْبَرَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْهَزَمَ الْمُشْرِكُونَ فَوَقَعْنَا فِي رِحَالِهِمْ فَابْتَدَرَ النَّاسُ مَا وَجَدُوا مِنْ جَزُورٍ قَالَ فَلَمْ يَكُنْ ذَلِكَ بِأَسْرَعَ مِنْ أَنْ فَارَتْ الْقُدُورُ فَأَمَرَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُكْفِئَتْ قَالَ ثُمَّ قَسَمَ بَيْنَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ لِكُلِّ عَشْرَةٍ شَاةً قَالَ وَكَانَ بَنُو فُلَانٍ مَعَهُ تِسْعَةً وَكُنْتُ وَحْدِي فَالْتَفَتُّ إِلَيْهِمْ فَكُنَّا عَشْرَةً بَيْنَنَا شَاةٌ قَالَ عَبْد اللَّهِ بَلَغَنِي أَنَّ صَاحِبَكُمْ يَقُولُ عَنْ قَيْسِ بْنِ مُسْلِمٍ كَأَنَّهُ يَقُولُ إِنَّهُ لَمْ يَحْفَظْهُ أَخْبَرَنَا زَكَرِيَّا بْنُ عَدِيٍّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَمْرٍو عَنْ زَيْدٍ هُوَ ابْنُ أَبِي أُنَيْسَةَ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ فَأُلِّفْتُ إِلَيْهِمْ قَالَ أَبُو مُحَمَّد الصَّوَابُ عِنْدِي مَا قَالَ زَكَرِيَّا فِي الْإِسْنَادِ","id":"Telah mengabarkan kepada kami [Abdullah bin Ja'far Ar Raqqi] telah menceritakan kepada kami ['Ubaidullah bin 'Amr] dari [Zaid] dari [Al Hakam dari [Abdurrahman bin Abu Laila] dari [ayahnya] ia berkata; \"Aku pernah ikut serta dalam penaklukan Khaibar bersama Rasulullah shallallahu 'alaihi wasallam. Ketika kaum Musyrikin mengalami kekalahan dan terpukul mundur, kami bermukim di tempat tinggal mereka, lantas orang-orang bersegera mengambil binatang ternak yang mereka dapatkan. Hal itu tidaklah lebih cepat daripada mendidihnya kuali yang diletakkan (diatas tungku api). Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan agar kuali tersebut ditumpahkan. Setelah itu beliau membagi-bagikan (harta rampasan) diantara mereka, beliau membagi untuk sepuluh orang satu kambing.\" Abu Laila berkata; \"Bani Fulan baru berjumlah sembilan orang, sementara aku sendirian, maka aku ikut bergabung dengan mereka, hingga kami berjumlah sepuluh, lantas seekor kambing dibagi diantara kami.\" Abdullah berkata; telah sampai kepadaku bahwa sahabat kalian berkata dari Qais bin Muslim, seolah-olah ia berkata; sesungguhnya ia tidak menghafal hadits tersebut.\" Telah mengabarkan kepada kami [Zakariya bin 'Adi] dari ['Ubaidullah bin 'Amr] dari [Zaid yaitu Ibnu Abu Unaisah] dari [Qais bin Muslim] dari [Abdurrahman bin Abu Laila] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas. Perawi berkata; dan aku menjelaskan redaksi periwayatan jalur lain sebagai pembanding redaksi aslinya. Abu Muhammad berkata; yang benar menurutku adalah apa yang dikatakan Zakariya dalam sanadnya."},"2006":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنِي قَيْسُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ هُرْمُزَ قَالَ كَتَبَ نَجْدَةُ بَنُ عَامِرٍ إِلَى ابْنِ عَبَّاسٍ يَسْأَلُهُ عَنْ أَشْيَاءَ فَكَتَبَ إِلَيْهِ إِنَّكَ سَأَلْتَ عَنْ سَهْمِ ذِي الْقُرْبَى الَّذِي ذَكَرَ اللَّهُ وَإِنَّا كُنَّا نَرَى أَنَّ قَرَابَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُمْ فَأَبَى ذَلِكَ عَلَيْنَا قَوْمُنَ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Jarir bin Hazim] telah menceritakan kepadaku [Qais bin Sa'd] dari [Yazid bin Hurmuz] ia berkata; Najdah bin 'Amir telah menulis surat kepada [Ibnu Abbas], ia bertanya mengenai beberapa hal, Ibnu Abbaspun membalas suratnya; \"Sesungguhnya engkau bertanya mengenai bagian kerabat yang telah Allah sebutkan, sesungguhnya kami melihat bahwa kerabat Rasulullah shallallahu 'alaihi wasallam termasuk dari mereka, namun kaum kami menolak hal itu.\""},"2007":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ عِيسَى حَدَّثَنَا مُحَمَّدُ بْنُ خَازِمٍ أَبُو مُعَاوِيَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْهَمَ يَوْمَ خَيْبَرَ لِلْفَارِسِ ثَلَاثَةَ أَسْهُمٍ وَلِلرَّاجِلِ سَهْمًا حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Isa] telah menceritakan kepada kami [Muhammad bin Hazim Abu Mu'awiyah] dari ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] bahwa pada waktu (penaklukan) Khaibar, Rasulullah shallallahu 'alaihi wasallam membagikan (harta rampasan) kepada para sahabatnya, untuk yang berkuda tiga bagian, dan untuk yang pejalan kaki satu bagian.\" Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] seperti hadits di atas."},"2008":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ عَمَّارِ بْنِ أَبِي عَمَّارٍ عَنْ أَبِي هُرَيْرَةَ قَالَ مَا شَهِدْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَغْنَمًا إِلَّا قَسَمَ لِي إِلَّا يَوْمَ خَيْبَرَ فَإِنَّهَا كَانَتْ لِأَهْلِ الْحُدَيْبِيَةِ خَاصَّةً وَكَانَ أَبُو مُوسَى وَأَبُو هُرَيْرَةَ جَاءَا بَيْنَ الْحُدَيْبِيَةِ وَخَيْبَرَ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ali bin Zaid] dari ['Ammar bin Abu 'Ammar] dari [Abu Hurairah], ia berkata; \"Tidaklah aku ikut serta bersama Rasulullah shallallahu 'alaihi wasallam waktu membagikan rampasan perang, malainkan beliau membagiku, kecuali pada saat perang Khaibar, sebab ia khusus untuk orang-oarng yang ikut dalam perjanjian Hudaibiyah.\" Sementara Abu Musa dan Abu Hurairah datang (masuk Islam -pent) antara Hudaibiyah dan Khaibar.\""},"2009":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ خَلِيلٍ أَخْبَرَنَا حَفْصٌ حَدَّثَنَا مُحَمَّدُ بْنُ زَيْدٍ عَنْ عُمَيْرٍ مَوْلَى آبِي اللَّحْمِ قَالَ شَهِدْتُ خَيْبَرَ وَأَنَا عَبْدٌ مَمْلُوكٌ فَأَعْطَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خُرْثِيِّ الْمَتَاعِ وَأَعْطَانِي سَيْفًا فَقَالَ تَقَلَّدْ بِهَذَا","id":"Telah mengabarkan kepada kami [Isma'il bin Khalil] telah mengabarkan kepada kami [Hafsh] telah menceritakan kepada kami [Muhammad bin Zaid] dari ['Umair] mantan budak Abu Al Lahm, ia berkata; aku ikut dalam perang Khaibar, sementara aku adalah seorang budak, kemudian Rasulullah shallallahu 'alaihi wasallam memberiku perkakas rumah tangga dan beliau juga memberiku sebilah pedang, beliau bersabda: \"(Belajar) berperanglah dengan pedang ini.\""},"2010":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ حُمْيَدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ عَنْ الْقَاسِمِ وَمَكْحُولٍ عَنْ أَبِي أُمَامَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى أَنْ تُبَاعَ السِّهَامُ حَتَّى تُقْسَمَ","id":"Telah mengabarkan kepada kami [Ahmad bin Humaid] telah menceritakan kepada kami [Abu Usamah] dari [Abdurrahman bin Yazid bin Jabir] dari [Al Qasim] dan [Makhul] dari [Abu Umamah] dari Nabi shallallahu 'alaihi wasallam bahwa beliau melarang menjual bagian (ghanimah) kecuali setelah dibagikan."},"2011":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي مَرْزُوقٍ مَوْلًى لِتُجِيبَ قَالَ حَدَّثَنِي حَنَشٌ الصَّنْعَانِيُّ قَالَ غَزَوْنَا الْمَغْرِبَ وَعَلَيْنَا رُوَيْفِعُ بْنُ ثَابِتٍ الْأَنْصَارِيُّ فَافْتَتَحْنَا قَرْيَةً يُقَالُ لَهَا جَرْبَةُ فَقَامَ فِينَا رُوَيْفِعُ بْنُ ثَابِتٍ الْأَنْصَارِيُّ خَطِيبًا فَقَالَ إِنِّي لَا أَقُومُ فِيكُمْ إِلَّا مَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فِينَا يَوْمَ خَيْبَرَ حِينَ افْتَتَحْنَاهَا فَقَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا يَأْتِيَنَّ شَيْئًا مِنْ السَّبْيِ حَتَّى يَسْتَبْرِئَهَا","id":"Telah mengabarkkan kepada kami [Ahmad bin Khalid] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari [Abu Marzuq] mantan budak Tujib, ia berkata; telah menceritakan kepada kami [Hanasy Ash Shan'ani] ia berkata; \"Kami pernah melakukan penyerangan di daerah Maghrib, dan pemimpin kami waktu itu adalah [Ruwaifi' bin Tsabit Al Anshari], setelah kami berhasil menaklukkan suatu perkampungan yang disebut Jarbah, Ruwaifi' berdiri di hadapan kami sambil berkhutbah. Ia berkata; \"Sesungguhnya aku berdiri dihadapan kalian tidak lain karena sesuatu yang telah aku dengar dari Rasulullah shallallahu 'alaihi wasallam. Beliau berdiri di hadapan kami ketika kami selesai menaklukkan Khaibar, beliau bersabda: \"Barangsiapa beriman kepada Allah dan hari Akhir, janganlah ia mendatangi tawanan wanita hingga ia mengalami haid.\""},"2012":{"ar":" أَخْبَرَنَا أَسَدُ بْنُ مُوسَى حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ بْنِ خُمَيْرٍ أَبِي عُمَرَ الشَّامِيِّ الْهَمْدَانِيِّ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ أَبِي الدَّرْدَاءِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى امْرَأَةً مُجِحَّةً يَعْنِي حُبْلَى عَلَى بَابِ فُسْطَاطٍ فَقَالَ لَعَلَّهُ قَدْ أَلَمَّ بِهَا قَالُوا نَعَمْ قَالَ لَقَدْ هَمَمْتُ أَنْ أَلْعَنَهُ لَعْنَةً تَدْخُلُ مَعَهُ قَبْرَهُ كَيْفَ يُوَرِّثُهُ وَهُوَ لَا يَحِلُّ لَهُ وَكَيْفَ يَسْتَخْدِمُهُ وَهُوَ لَا يَحِلُّ لَهُ","id":"Telah mengabarkan kepada kami [Asad bin Musa] telah menceritakan kepada kami [Syu'bah] dari [Yazid bin Humair Abu Umar Asy Syami Al Hamdani], ia berkata; aku mendengar [Abdurrahman bin Jubair bin Nufair] dari [Ayahnya] dari [Abu Ad Darda`] bahwa Nabi shallallahu 'alaihi wasallam pernah melihat seorang wanita hamil berada di depan pintu tenda besar. Kemudian beliau bersabda: \"Kemungkinan (tuannya) telah menggauli wanita tersebut.\" Para sahabat berkata; \"Ya.\" Beliau bersabda: \"Sungguh aku ingin melaknat laki-laki itu dengan laknat yang masuk bersamanya dalam kuburnya, bagaimana mungkin ia menjadikan anak yang ada dalam kandungan tersebut sebagai pewarisnya, sementara hal itu tidak halal baginya, dan bagaimana ia mempergunakannya sebagai budak, sementara hal itu tidak halal baginya?\""},"2013":{"ar":" أَخْبَرَنَا الْقَاسِمُ بْنُ كَثِيرٍ عَنْ اللَّيْثِ بْنِ سَعْدٍ قِرَاءَةً عَنْ عَبْدِ اللَّهِ بْنِ جُنَادَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِىِّ أَنَّ أَبَا أَيُّوبَ كَانَ فِي جَيْشٍ فَفُرِّقَ بَيْنَ الصِّبْيَانِ وَبَيْنَ أُمَّهَاتِهِمْ فَرَآهُمْ يَبْكُونَ فَجَعَلَ يَرُدُّ الصَّبِيَّ إِلَى أُمِّهِ وَيَقُولُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ فَرَّقَ بَيْنَ الْوَالِدَةِ وَوَلَدِهَا فَرَّقَ اللَّهُ بَيْنَهُ وَبَيْنَ الْأَحِبَّاءِ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Al Qasim bin Katsir] dari [Al Laits bin Sa'd] dengan membacakan riwayat, dari [Abdullah bin Junadah] dari [Abu Abdurrahman Al Hubuli] bahwa [Abu Ayyub] berada dalam pasukan, ternyata diantara anak-anak dipisahkan dengan ibu mereka. Ketika Abu Ayyub melihat mereka menangis, ia langsung mengembalikan anak tersebut kepada ibunya sambil berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memisahkan antara seorang ibu dan anaknya, maka Allah akan memisahkan antara dirinya dengan orang-orang yang dicintainya pada Hari Kiamat.\""},"2014":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا أَبَانُ بْنُ عَبْدِ اللَّهِ الْبَجَلِيُّ عَنْ عُثْمَانَ بْنِ أَبِي حَازِمٍ عَنْ صَخْرِ بْنِ الْعَيْلَةِ قَالَ أَبُو مُحَمَّد وَمِنْهُمْ مَنْ يَقُولُ الْعِيلَةِ قَالَ أَخَذْتُ عَمَّةَ الْمُغِيرَةِ بْنِ شُعْبَةَ فَقَدِمْتُ بِهَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَمَّتَهُ فَقَالَ يَا صَخْرُ إِنَّ الْقَوْمَ إِذَا أَسْلَمُوا أَحْرَزُوا أَمْوَالَهُمْ وَدِمَاءَهُمْ فَادْفَعْهَا إِلَيْهِ وَكَانَ مَاءٌ لِبَنِي سُلَيْمٍ فَأَسْلَمُوا فَأَتَوْهُ فَسَأَلُوهُ ذَلِكَ فَدَعَانِي فَقَالَ يَا صَخْرُ إِنَّ الْقَوْمَ إِذَا أَسْلَمُوا أَحْرَزُوا أَمْوَالَهُمْ وَدِمَاءَهُمْ فَادْفَعْهُ إِلَيْهِمْ فَدَفَعْتُهُ","id":"Telah mengabarkan kepada [Abu Nu'aim] telah menceritakan kepada kami [Aban bin Abdullah Al Bajali] dari [Utsman bin Abu Hazim] dari [Shakhr bin Al 'Ailah], -Abu Muhammad berkata; Diantara mereka (hali hadits) ada yang mengatakan; Al 'Ilah- Ia berkata; \"Aku membawa bibi Al Mughirah bin Syu'bah mengahdap Rasulullah shallallahu 'alaihi wasallam, setelah itu Nabi shallallahu 'alaihi wasallam bertanya kepada bibinya, lalu beliau bersabda: \"Wahai Shakhr, sesungguhnya apabila suatu kaum telah masuk Islam, maka harta dan darah mereka telah terjaga, oleh karena itu serahkanlah ia kepada Mughirah.\" Dahulu Bani Sulaim memiliki mata air, kemudian mereka masuk Islam dan memintanya kembali kepada beliau. Beliau pun bersabda: \"Wahai Shakhr, sesungguhnya jika suatu kaum telah masuk Islam, maka harta dan darah mereka telah terjaga, oleh karena itu serahkanlah (mata air tyersebut) kepada mereka.\""},"2015":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابِنِ عُمَرَ قَالَ بَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً فِيهَا ابْنُ عُمَرَ فَغَنِمُوا إِبِلًا كَثِيرَةً فَكَانَتْ سِهَامُهُمْ اثْنَيْ عَشَرَ بَعِيرًا أَوْ أَحَدَ عَشَرَ بَعِيرًا وَنُفِّلُوا بَعِيرًا بَعِيرًا","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah mengutus satuan pasukan, dalam pasukan tersebut terdapat Ibnu Umar, kemudian mereka memperoleh harta rampasan berupa beberapa ekor unta. Maka setiap pasukan memperoleh bagian dua belas unta atau sebelas unta, ditambah lagi satu unta, satu unta.\""},"2016":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ حَدَّثَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَيَّاشٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ أَبِي سَلَّامٍ عَنْ أَبِي أُمَامَةَ الْبَاهِلِيِّ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَغَارَ فِي أَرْضِ الْعَدُوِّ نَفَّلَ الرُّبُعَ وَإِذَا أَقْبَلَ رَاجِعًا وَكَلَّ النَّاسُ نَفَّلَ الثُّلُثَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Uyainah] telah menceritakan kepada kami [Abu Ishaq Al Fazari] dari [Abdurrahman bin 'Ayyasy] dari [Sulaiman bin Musa] dari [Abu Sallam] dari [Abu Umamah Al Bahili] dari ['Ubadah bin Ash Shamit] ia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam menyerang di negeri musuh, maka beliau akan memberikan tambahan (ghanimah) seperempat bagian, apabila kembali, beliau memberikan tambahan (ghanimah) kepada setiap pasukan sepertiga bagian.\""},"2017":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ سُفْيَانَ عَنْ يَزِيدَ بْنِ يَزِيدَ بْنِ جَابِرٍ عَنْ مَكْحُولٍ عَنْ زِيَادِ بْنِ جَارِيَةَ عَنْ حَبِيبِ بْنِ مَسْلَمَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفَّلَ الثُّلُثَ بَعْدَ الْخُمُسِ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Sufyan] dari [Yazid bin Jabir] dari [Makhul] dari [Ziyad bin Jariyah] dari [Habib bin Maslamah] bahwa Nabi shallallahu 'alaihi wasallam memberikan tambahan (ghanimah) sepertiga bagian (kepada setiap pasukan) setelah bagian seperlima dibagikan."},"2018":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا إِسْحَقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَتَلَ كَافِرًا فَلَهُ سَلَبُهُ فَقَتَلَ أَبُو طَلْحَةَ يَوْمَئِذٍ عِشْرِينَ وَأَخَذَ أَسْلَابَهُمْ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membunuh orang kafir, maka baginya (boleh mengambil) apa yang melekat pada orang tersebut.\" Pada saat itu Abu Thalhah sempat membunuh dua puluh orang, lalu ia mengambil barang yang melekat pada dua orang tersebut."},"2019":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ ابْنِ كَثِيرِ بْنِ أَفْلَحَ هُوَ عُمَرُ بْنُ كَثِيرٍ عَنْ أَبِي مُحَمَّدٍ مَوْلَى أَبِي قَتَادَةَ عَنْ أَبِي قَتَادَةَ قَالَ بَارَزْتُ رَجُلًا فَقَتَلْتُهُ فَنَفَّلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلَبَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan bin 'Uyainah] dari [Yahya bin Sa'id] dari [Ibnu Katsir bin Aflah yaitu 'Umar bin Katsir] dari [Abu Muhammad] mantan budak Abu Qatadah, dari [Abu Qatadah] ia berkata; \"Aku pernah perang tanding dengan seorang laki-laki, lalu aku berhasil membunuhnya. Kemudian Rasulullah shallallahu 'alaihi wasallam memberikan barang yang melekat pada orang tersebut kepadaku.\""},"2020":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ حَدَّثَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَيَّاشٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ أَبِي سَلَّامٍ عَنْ أَبِي أُمَامَةَ الْبَاهِلِيِّ عَنْ عُبَادَةَ بْنِ الصَّامِتِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَكْرَهُ الْأَنْفَالَ وَيَقُولُ لِيَرُدَّ قَوِيُّ الْمُسْلِمِينَ عَلَى ضَعِيفِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin 'Uyainah] telah menceritakan kepada kami [Abu Ishaq Al Fazari] dari [Abdurrahman bin 'Ayyasy] dari [Sulaiman bin Musa] dari [Abu Sallam] dari [Abu Umamah Al Bahili] dari ['Ubadah bin Ash Shamit] bahwa Nabi shallallahu 'alaihi wasallam tidak menyukai nafal dan beliau bersabda: \"Hendaknya orang yang kuat memberikan kepada orang yang lemah dari kaum Muslimin.\" "},"2021":{"ar":" وَبِهَذَا الْإِسْنَادِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ أَدُّوا الْخِيَاطَ وَالْمَخِيطَ وَإِيَّاكُمْ وَالْغُلُولَ فَإِنَّهُ عَارٌ عَلَى أَهْلِهِ يَوْمَ الْقِيَامَةِ","id":"Dan dengan sanad ini, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Serahkanlah (walau hanya) benang dan jarum, dan berhati-hatilah kalian dengan ghulul, karena hal itu merupakan aib atas pelakunya pada Hari Kiamat.\" "},"2022":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ إِسْحَقَ عَنْ يَزِيدَ هُوَ ابْنُ أَبِي حَبِيبٍ عَنْ أَبِي مَرْزُوقٍ مَوْلًى لِتُجِيبَ قَالَ حَدَّثَنِي حَنَشٌ الصَّنْعَانِيُّ قَالَ غَزَوْنَا الْمَغْرِبَ وَعَلَيْنَا رُوَيْفِعُ بْنُ ثَابِتٍ الْأَنْصَارِيُّ فَافْتَتَحْنَا قَرْيَةً يُقَالُ لَهَا جَرْبَةُ فَقَامَ فِينَا رُوَيْفِعُ بْنُ ثَابِتٍ الْأَنْصَارِيُّ خَطِيبًا فَقَالَ إِنِّي لَا أَقُومُ فِيكُمْ إِلَّا مَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فِينَا يَوْمَ خَيْبَرَ حِينَ افْتَتَحْنَاهَا مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا يَرْكَبَنَّ دَابَّةً مِنْ فَيْءِ الْمُسْلِمِينَ حَتَّى إِذَا أَجْحَفَهَا أَوْ قَالَ أَعْجَفَهَا قَالَ أَبُو مُحَمَّد أَنَا أَشُكُّ فِيهِ رَدَّهَا وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا يَلْبَسْ ثَوْبًا مِنْ فَيْءِ الْمُسْلِمِينَ حَتَّى إِذَا أَخْلَقَهُ رَدَّهُ فِيهِ","id":"Telah mengabarkkan kepada kami [Ahmad bin Khalid] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari [Abu Marzuq] mantan budak Tujib, ia berkata; telah menceritakan kepada kami [Hanasy Ash Shan'ani], ia berkata; \"Kami pernah melakukan penyerangan di daerah Maghrib, ketika itu pemimpin kami adalah [Ruwaifi' bin Tsabit Al Anshari], kemudian kami berhasil menaklukkan suatu perkampungan yang bernama Jarbah, lalu Ruwaifi' bin Tsabit Al Anshari berdiri dihadapan kami sambil berkhutbah. Ia berkata; \"Sesungguhnya aku berdiri diantara kalian tidak lain karena sesuatu yang pernah aku dengar dari Rasulullah shallallahu 'alaihi wasallam. Ketika negeri Khaibar berhasil kami taklukkan, beliau berdiri dihadapan kami, beliau bersabda: \"Barangsiapa beriman kepada Allah dan hari Akhir, janganlah ia menunggangi kendaraan dari harta rampasan perang kaum Muslimin, setelah ia membuatnya tidak berdaya atau membuatnya lemah…-Abu Muhammad berkata; aku tidak ragu beliau mengatakan- lalu ia mengembalikannya ke dalam rampasan perang. Dan barangsiapa beriman keapda Allah dan hari Akhir, janganlah ia memakai pakaian dari harta rampasan perang kaum Muslimin, setelah pakaian itu usang, ia mengembalikannya ke dalam rampasan perang.\""},"2023":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنِي أَبُو زُمَيْلٍ حَدَّثَنِي ابْنُ عَبَّاسٍ حَدَّثَنِي عُمَرُ بْنُ الْخَطَّابِ قَالَ قُتِلَ نَفَرٌ يَوْمَ خَيْبَرَ فَقَالُوا فُلَانٌ شَهِيدٌ حَتَّى ذَكَرُوا رَجُلًا فَقَالُوا فُلَانٌ شَهِيدٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلَّا إِنِّي رَأَيْتُهُ فِي النَّارِ فِي عَبَاءَةٍ أَوْ فِي بُرْدَةٍ غَلَّهَا قَالَ لِي يَا ابْنَ الْخَطَّابِ قُمْ فَنَادِ فِي النَّاسِ أَنَّهُ لَا يَدْخُلُ الْجَنَّةَ إِلَّا الْمُؤْمِنُونَ فَقُمْتُ فَنَادَيْتُ فِي النَّاسِ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami ['Ikrimah bin 'Ammar] telah menceritakan kepadaku [Abu Zumail] telah menceritakan kepadaku [Ibnu Abbas] telah menceritakan kepadaku [Umar bin Al Khathab], ia berkata; \"Beberapa orang terbunuh pada saat terjadi perang Khaibar. Kemudian orang-orang mengatakan; \"Fulan syahid...\" hinggga ketika mereka sampai kepada seseorang, mereka berkata; \"Fulan telah syahid, \" mendengar itu, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak, sungguh aku telah melihatnya di Neraka sambil memakai 'mantel dan burdah yang ia curi dari rampasan perang.\" Beliau mengatakan kepadaku: \"Wahai Ibnu Al Khathab, berdiri dan umumkanlah kepada manusia, bahwa tidak masuk Surga kecuali orang-orang yang beriman.\" Kemudian aku mengumumkannya dihadapan orang-orang.\""},"2024":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ مُحَمَّدٍ عَنْ صَالِحِ بْنِ مُحَمَّدِ بْنِ زَائِدَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ وَجَدْتُمُوهُ غَلَّ فَاضْرِبُوهُ وَأَحْرِقُوا مَتَاعَهُ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] dari [Abdul 'Aziz bin Muhammad] dari [Shalih bin Muhammad bin Zaidah] dari [Salim bin Abdullah] dari [Ayahnya] dari [Kakeknya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian mendapati seseorang melakukan ghulul dalam rampasan perang, maka bunuhlah dia dan bakarlah hartanya.\" "},"2025":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ الْمُكْتِبُ حَدَّثَنَا الْقَاسِمُ بْنُ مَالِكٍ حَدَّثَنِي كَثِيرُ بْنُ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عَوْفٍ الْمُزَنِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَهْبَ وَلَا إِغْلَالَ وَلَا إِسْلَالَ { وَمَنْ يَغْلُلْ يَأْتِ بِمَا غَلَّ يَوْمَ الْقِيَامَةِ } قَالَ أَبُو مُحَمَّد الْإِسْلَالُ السَّرِقَةُ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim Al Muktib] telah menceritakan kepada kami [Al Qasim bin Malik] telah menceritakan kepadaku [Katsir bin Abdullah bin 'Amr bin 'Auf Al Muzani] dari [Ayahnya] dari [kakeknya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh merampas, tidak boleh ghulul dalam rampasan perang dan tidak boleh mencuri, barang siapa yang berkhianat dalam rampasan perang, maka ia akan datang pada Hari Kiamat membawa apa yang ia curi.\" Abu Muhammad berkata; \"(artinya) Al Islal adalah mencuri.\" "},"2026":{"ar":" حَدَّثَنَا بِشْرُ بْنُ عُمَرَ الزَّهْرَانِيُّ حَدَّثَنَا عَبْدُ اللَّهِ هُوَ ابْنُ لَهِيعَةَ حَدَّثَنَا عَيَّاشُ بْنُ عَبَّاسٍ عَنْ شِيَيْمِ بْنِ بَيْتَانَ عَنْ جُنَادَةَ بْنِ أَبِي أُمَيَّةَ قَالَ لَوْلَا أَنِّي سَمِعْتُ ابْنَ أَرْطَاةَ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُقْطَعُ الْأَيْدِي فِي الْغَزْوِ لَقَطَعْتُهَا","id":"Telah menceritakan kepada kami [Bisyr bin Umar Az Zahrani] telah menceritakan kepadaku [Abdullah yaitu Ibnu Luhai'ah] telah menceritakan kepada kami [Ayyasy bin Abbas] dari [Syiyaim bin Baitan] dari [Junadah bin Abu Umayyah], ia berkata; \"Seandainya aku tidak mendengar [Ibnu Artha`ah] berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu memotong tangan dalam peperangan.\" Niscaya aku telah memotongnya.\""},"2027":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ أَنَّهُ أَخْبَرَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعْمَلَ عَامِلًا عَلَى الصَّدَقَةِ فَجَاءَهُ الْعَامِلُ حِينَ فَرَغَ مِنْ عَمَلِهِ فَقَالَ يَا رَسُولَ اللَّهِ هَذَا الَّذِي لَكُمْ وَهَذَا أُهْدِيَ لِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلَّا قَعَدْتَ فِي بَيْتِ أَبِيكَ وَأَمِّكَ فَنَظَرْتَ أَيُهْدَى لَكَ أَمْ لَا ثُمَّ قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشِيَّةً بَعْدَ الصَّلَاةِ عَلَى الْمِنْبَرِ فَتَشَهَّدَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ فَمَا بَالُ الْعَامِلِ نَسْتَعْمِلُهُ فَيَأْتِينَا فَيَقُولُ هَذَا مِنْ عَمَلِكُمْ وَهَذَا أُهْدِيَ لِي فَهَلَّا قَعَدَ فِي بَيْتِ أَبِيهِ وَأُمِّهِ فَيَنْظُرَ أَيُهْدَى لَهُ أَمْ لَا وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَا يَغُلُّ أَحَدٌ مِنْكُمْ مِنْهَا شَيْئًا إِلَّا جَاءَ بِهِ يَوْمَ الْقِيَامَةِ يَحْمِلُهُ عَلَى عُنُقِهِ إِنْ كَانَ بَعِيرًا جَاءَ بِهِ لَهُ رُغَاءٌ وَإِنْ كَانَتْ بَقَرَةً جَاءَ بِهَا لَهَا خُوَارٌ وَإِنْ كَانَتْ شَاةً جَاءَ بِهَا تَيْعِرُ فَقَدْ بَلَّغْتُ قَالَ أَبُو حُمَيْدٍ ثُمَّ رَفَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ حَتَّى إِنَّا لَنَنْظُرُ إِلَى عُفْرَةِ إِبِطَيْهِ قَالَ أَبُو حُمَيْدٍ وَقَدْ سَمِعَ ذَلِكَ مَعِي مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدُ بْنُ ثَابِتٍ فَسَلُوهُ","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] telah menceritakan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku ['Urwah bin Az Zubair] dari [Abu Humaid As Sa'idi] bahwa ia telah mengabarkan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam pernah mengangkat seorang sebagai amil zakat untuk mengambil harta sedekah, ketika amil zakat tersebut selesai mengambil harta sedekah, ia dating kepada beliau seraya berkata; \"Wahai Rasulullah, ini bagian anda dan ini dihadiahkan kepadaku.\" Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Tidakkah kamu duduk-duduk saja di rumah ayah dan ibumu, kemudian kamu lihat, apakah kamu akan diberi hadiah ataukah tidak?\" Ketika sore hari, yaitu setelah shalat (Ashar) Nabi shallallahu 'alaihi wasallam berdiri di atas mimbar, setelah mengucapkan syahadat dan memuji Allah dengan pujian milikNya, beliau bersabda: \"Bagaimana dengan seorang amil zakat yang kami pekerjakan, kemudian datang kepada kami sambil berkata; \"ini adalah bagian anda dan ini dihadiahkan kepadaku.\" Tidakkah ia duduk-duduk di rumah ayah dan ibunya saja, kemudian melihat apakah ia akan diberi hadiah ataukah tidak? Demi Dzat yang jiwa Muhammad ada di tanganNya, tidaklah seseorang diantara kalian mengambil sesuatupun yang bukan haknya, kecuali pada hari Kiamat ia akan datang dengan memikulnya dilehernya, apabila sesuatu itu adalah unta, maka ia datang memikulnya sambil melenguh, apabila sesuatu itu adalah sapi maka ia memikulnya sambil mengemoh, dan apabila sesuatu itu adalah kambing, maka ia datang memikulnya sambil mengembek, sungguh aku telah menyampaikannya.\" Abu Humaid berkata; \"Setelah itu Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya hingga kami melihat putih ketiaknya. Abu Humaid berkata; \"Dan sungguh Zaid bin Tsabit telah mendengar hal itu bersamaku dari Nabi shallallahu 'alaihi wasallam, (jika tidak percaya) tanyalah kepadanya."},"2028":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا عُمَارَةُ بْنُ زَاذَانَ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ مَلِكَ ذِي يَزَنٍ أَهْدَى إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُلَّةً أَخَذَهَا بِثَلَاثَةٍ وَثَلَاثِينَ بَعِيرًا أَوْ ثَلَاثٍ وَثَلَاثِينَ نَاقَةً فَقَبِلَهَا","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah mengabarkan kepada kami ['Umarah bin Zadan] dari [Tsabit] dari [Anas bin Malik] bahwa raja Dzi Yazan pernah menghadiahkan perhiasan kepada Nabi shallallahu 'alaihi wasallam dengan di sertai tiga puluh tiga unta jantan atau tiga puluh tiga unta betina, beliaupun menerimanya.\""},"2029":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ عَبَّاسِ بْنِ سَهْلٍ السَّاعِدِيِّ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ قَالَ بَعَثَ صَاحِبُ أَيْلَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكِتَابٍ وَأَهْدَى لَهُ بَغْلَةً بَيْضَاءَ فَكَتَبَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْدَى لَهُ بُرْدًا","id":"Telah mengabarkan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Sulaiman bin Bilal] dari ['Amr bin Yahya] dari [Abbas bin Sahl As Sa'idi] dari [Abu Humaid As Sa'idi] ia berkata; para raja Ailah mengirim utusan kepada Rasulullah shallallahu 'alaihi wasallam dengan membawa sepucuk surat dan menghadiahkan seekor bighal putih kepada beliau. Kemudian Rasulullah shallallahu 'alaihi wasallam menulis surat balasan kepadanya dan menghadiahkan pakaian bergaris-garis kepada raja tersebut."},"2030":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وَكِيعٌ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ نِيَارٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّا لَا نَسْتَعِينُ بِمُشْرِكٍ أَخْبَرَنَا إِسْحَقُ عَنْ رَوْحٍ عَنْ مَالِكٍ عَنْ فُضَيْلٍ هُوَ ابْنُ أَبِي عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ نِيَارٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَطْوَلُ مِنْهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Waki'] dari [Malik bin Anas] dari [Abdullah bin Niyar] dari ['Urwah] dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kami tidak meminta bantuan terhadap orang-orang musyrik.\" Telah mengabarkan kepada kami [Ishaq] dari [Rauh] dari [Malik] dari [Fudhail yaitu Ibnu Abu Abdullah] dari [Abdullah bin Niyar] dari ['Urwah] dari ['Aisyah] yang lebih panjang dari hadits diatas."},"2031":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ حَدَّثَنَا إِبْرَاهِيمُ بْنُ مَيْمُونٍ رَجُلٌ مِنْ أَهْلِ الْكُوفَةِ حَدَّثَنِي سَعْدُ بْنُ سَمُرَةَ بْنِ جُنْدُبٍ عَنْ أَبِيهِ سَمُرَةَ عَنْ أَبِي عُبَيْدَةَ بْنِ الْجَرَّاحِ قَالَ كَانَ فِي آخِرِ مَا تَكَلَّمَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَخْرِجُوا يَهُودَ الْحِجَازِ وَأَهْلَ نَجْرَانَ مِنْ جَزِيرَةِ الْعَرَبِ","id":"Telah mengabarkan kepada kami ['Affan] telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] telah menceritakan kepada kami [Ibraihim bin Maimun] seorang laki-laki dari penduduk Kufah, telah menceritakan kepadaku [Sa'd bin Samurah bin Jundub] dari ayahnya yaitu [Samurah] dari [Abu 'Ubaidah bin Al Jarrah] ia berkata; \"Diantara perkataan terakhir yang diucapkan Rasulullah shallallahu 'alaihi wasallam adalah, beliau bersabda: \"Keluarkanlah orang-orang Yahudi Hijaz dan penduduk Najran dari Jazirah Arab.\""},"2032":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ حَدَّثَنِي رَبِيعَةُ بْنُ يَزِيدَ حَدَّثَنِي أَبُو إِدْرِيسَ حَدَّثَنِي أَبُو ثَعْلَبَةَ قَالَ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا بِأَرْضِ أَهْلِ الْكِتَابِ فَنَأْكُلُ فِي آنِيَتِهِمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كُنْتَ بِأَرْضٍ كَمَا ذَكَرْتَ فَلَا تَأْكُلُوا فِي آنِيَتِهِمْ إِلَّا أَنْ لَا تَجِدُوا مِنْهَا بُدًّا فَإِنْ لَمْ تَجِدُوا مِنْهَا بُدًّا فَاغْسِلُوهَا ثُمَّ كُلُوا فِيهَا","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Haiwah bin Syuraih] telah menceritakan kepadaku [Rabi'ah bin Yazid] telah menceritakan kepadaku [Abu Idris] telah menceritakan kepadaku [Abu Tsa'labah] ia berkata; aku datang menemui Rasulullah shallallahu 'alaihi wasallam sambil berkata; \"Wahai Rasulullah, sesungguhnya kami berada di negeri orang-orang ahli kitab, kami makan dengan bejana mereka.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila engkau berada di suatu negeri sebagaimana yang telah engkau sebutkan, maka janganlah engkau makan dengan bejana mereka, kecuali jika tidak ada tempat lain untuk kalian pergunakan. Jika kalian tidak mendapatkan tempat lain, maka cucilah bejana tersebut kemudian makanlan dengannya.\""},"2033":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا سُلَيْمَانُ هُوَ ابْنُ الْمُغِيرَةِ عَنْ حُمَيْدٍ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَ دُلِّيَ جِرَابٌ مِنْ شَحْمٍ يَوْمَ خَيْبَرَ قَالَ فَأَتَيْتُهُ فَالْتَزَمْتُهُ قَالَ ثُمَّ قُلْتُ لَا أُعْطِي مِنْ هَذَا أَحَدًا الْيَوْمَ شَيْئًا فَالْتَفَتُّ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْتَسِمُ إِلَيَّ قَالَ عَبْد اللَّهِ أَرْجُو أَنْ يَكُونَ حُمَيْدٌ سَمِعَ مِنْ عَبْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepadaku [Sulaiman yaitu Ibnu Al Mughirah] dari [Humaid] dari [Abdullah bin Mughaffal] ia berkata; \"Ketika perang Khaibar, terdapat sekantong lemak yang menggantung (dalam wadah), lalu akupun mendatanginya serta menungguinya sambil mengatakan; \"Tidak akan aku berikan sedikitpun kepada orang lain.\" Ketika aku menoleh, ternyata Rasulullah shallallahu 'alaihi wasallam tersenyum kepadaku.\" Abdullah mengatakan; \"Aku berharap Humaid telah mendengar dari Abdullah."},"2034":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ بَجَالَةَ قَالَ سَمِعْتُهُ يَقُولُ لَمْ يَكُنْ عُمَرُ أَخَذَ الْجِزْيَةَ مِنْ الْمَجُوسِ حَتَّى شَهِدَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَهَا مِنْ مَجُوسِ هَجَرَ","id":"Telah mengabarkan kepada kepada [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] dari ['Amr] dari [Bajalah] ia berkata; aku mendengarnya berkata; \"Umar tidak pernah mengambil Jizyah (pajak) dari orang-orang Majusi hingga [Abdurrahman bin 'Auf] bersaksi bahwa Rasulullah shallallahu 'alaihi wasallam mengambilnya dari orang-orang Majusi Hajar.\""},"2035":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا مَالِكٌ عَنْ أَبِي النَّضْرِ أَنَّ أَبَا مُرَّةَ مَوْلَى عَقِيلِ بْنِ أَبِي طَالِبٍ أَخْبَرَهُ أَنَّهُ سَمِعَ أُمَّ هَانِئٍ بِنْتَ أَبِي طَالِبٍ تُحَدِّثُ أَنَّهَا ذَهَبَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ فَقَالَتْ يَا رَسُولَ اللَّهِ زَعَمَ ابْنُ أُمِّي أَنَّهُ قَاتِلٌ رَجُلًا أَجَرْتُهُ فُلَانُ بْنُ هُبَيْرَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَجَرْنَا مَنْ أَجَرْتِ يَا أُمَّ هَانِئٍ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepadaku [Malik] dari [An Nadhr] bahwa [Abu Murrah] mantan budak 'Uqail bin Abu Thalib telah mengabarkan kepadanya, bahwa ia mendengar [Ummu Hani`] menceritakan bahwa dirinya pergi menemui Rasulullah shallallahu 'alaihi wasallam ketika tahun penaklukan kota Makkah, ia berkata; \"Wahai Rasulullah, saudaraku yaitu Fulan bin Hubairah mengaku bahwa ia akan membunuh seseorang yang telah aku lindungi.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku telah melindungi orang yang engkau lindungi wahai Ummu Hani`.\""},"2036":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَاصِمٍ عَنْ أَبِي وَائِلٍ عَنْ ابْنِ مُعَيْزٍ السَّعْدِيِّ قَالَ خَرَجْتُ أُسْفِرُ فَرَسًا لِي مِنْ السَّحَرِ فَمَرَرْتُ عَلَى مَسْجِدٍ مِنْ مَسَاجِدِ بَنِي حَنِيفَةَ فَسَمِعْتُهُمْ يَشْهَدُونَ أَنَّ مُسَيْلَمَةَ رَسُولُ اللَّهِ فَرَجَعْتُ إِلَى عَبْدِ اللَّهِ بْنِ مَسْعُودٍ فَأَخْبَرْتُهُ فَبَعَثَ إِلَيْهِمْ الشُّرَطَ فَأَخَذُوهُمْ فَجِيءَ بِهِمْ إِلَيْهِ فَتَابَ الْقَوْمُ وَرَجَعُوا عَنْ قَوْلِهِمْ فَخَلَّى سَبِيلَهُمْ وَقَدَّمَ رَجُلًا مِنْهُمْ يُقَالُ لَهُ عَبْدُ اللَّهِ بْنُ نُوَاحَةَ فَضَرَبَ عُنُقَهُ فَقَالُوا لَهُ تَرَكْتَ الْقَوْمَ وَقَتَلْتَ هَذَا فَقَالَ إِنِّي كُنْتُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسًا إِذْ دَخَلَ هَذَا وَرَجُلٌ وَافِدَيْنِ مِنْ عِنْدِ مُسَيْلَمَةَ فَقَالَ لَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَشْهَدَانِ أَنِّي رَسُولُ اللَّهِ فَقَالَا لَهُ تَشْهَدُ أَنْتَ أَنَّ مُسَيْلَمَةَ رَسُولُ اللَّهِ فَقَالَ آمَنْتُ بِاللَّهِ وَرُسُلِهِ لَوْ كُنْتُ قَاتِلًا وَفْدًا لَقَتَلْتُكُمَا فَلِذَلِكَ قَتَلْتُهُ وَأَمَرَ بِمَسْجِدِهِمْ فَهُدِمَ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Bakr bin 'Ayyasy] dari ['Ashim] dari [Abu Wa`il] dari [Ibnu Mu'aiz As Sa'di], ia berkata; Pada waktu sahur, aku keluar mencari kudaku, lalu aku melewati suatu masjid diantara masjid-masjid Bani Hanifah. Aku mendengar mereka bersaksi bahwa Musailamah adalah Rasulullah. Aku bergegas kembali menemui [Abdullah bin Mas'ud] dan mengabarkan kepadanya. Lalu ia mengirimkan beberapa polisi untuk menangkap mereka, Orang-orang itu lalu dihadapkan kepadanya, akhirnya mereka bertaubat dan mencabut perkataan mereka. Setelah Abdullah bin Mas'ud membebaskan mereka, ia mendatangi seseorang yang bernama Abdullah bin Nuwahah dan memenggal kepalanya. Orang-orang berkata kepadanya; \"(Kenapa) anda membiarkan orang-orang itu dan membunuh orang ini?\" Abdullah menjawab; \"Sungguh dahulu aku pernah duduk-duduk bersama Rasulullah shallallahu 'alaihi wasallam, tiba-tiba orang ini dan yang lain masuk sebagai kurir dari Musailamah, beliau lalu berkata kepada mereka berdua: \"Apakah kalian bersaksi bahwa aku adalah Rasulullah?\" Mereka berkata kepada beliau; \"Apakah engkau bersaksi bahwa Musailamah adalah Rasulullah?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku beriman kepada Allah dan para rasulNya, seandainya aku boleh membunuh utusan, niscaya aku bunuh kalian berdua.\" Oleh karena itulah aku membunuhnya. Ibnu Mas'ud memerintahkan supaya masjid mereka juga dihancurkan."},"2037":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا عُيَيْنَةُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ جَوْشَنٍ الْغَطَفَانِيُّ عَنْ أَبِيهِ عَنْ أَبِي بَكْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَتَلَ مُعَاهَدًا فِي غَيْرِ كُنْهِهِ حَرَّمَ اللَّهُ عَلَيْهِ الْجَنَّةَ","id":"Telah mengabarkan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami ['Uyainah bin Abdurrahman bin Jausyan Al Ghathafani] dari [Ayahnya] dari [Abu Bakrah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membunuh orang kafir Mu'ahhad (yang memiliki perjanjian dengan orang muslim) sebelum waktunya, maka Allah mengharamkan Surga baginya.\""},"2038":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَ كَانَتْ الْعَضْبَاءُ لِرَجُلٍ مِنْ بَنِي عُقَيْلٍ فَأُسِرَ وَأُخِذَتْ الْعَضْبَاءُ فَمَرَّ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي وَثَاقٍ فَقَالَ يَا مُحَمَّدُ عَلَى مَا تَأْخُذُونِي وَتَأْخُذُونَ سَابِقَةَ الْحَاجِّ وَقَدْ أَسْلَمْتُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ قُلْتَهَا وَأَنْتَ تَمْلِكُ أَمْرَكَ أَفْلَحْتَ كُلَّ الْفَلَاحِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَأْخُذُكَ بِجَرِيرَةِ حُلَفَائِكَ وَكَانَتْ ثَقِيفٌ قَدْ أَسَرُوا رَجُلَيْنِ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى حِمَارٍ عَلَيْهِ قَطِيفَةٌ فَقَالَ يَا مُحَمَّدُ إِنِّي جَائِعٌ فَأَطْعِمْنِي وَظَمْآنُ فَاسْقِنِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ حَاجَتُكَ ثُمَّ إِنَّ الرَّجُلَ فُدِيَ بِرَجُلَيْنِ فَحَبَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَضْبَاءَ لِرَحْلِهِ وَكَانَتْ مِنْ سَوَابِقِ الْحَاجِّ ثُمَّ إِنَّ الْمُشْرِكِينَ أَغَارُوا عَلَى سَرْحِ الْمَدِينَةِ فَذَهَبُوا بِهِ فِيهَا الْعَضْبَاءُ وَأَسَرُوا امْرَأَةً مِنْ الْمُسْلِمِينَ وَكَانُوا إِذَا نَزَلُوا قَالَ أَبُو مُحَمَّد ثُمَّ ذَكَرَ كَلِمَةً إِبِلُهُمْ فِي أَفْنِيَتِهِمْ فَلَمَّا كَانَ ذَاتَ لَيْلَةٍ قَامَتْ الْمَرْأَةُ وَقَدْ نُوِّمُوا فَجَعَلَتْ لَا تَضَعُ يَدَيْهَا عَلَى بَعِيرٍ إِلَّا رَغَا حَتَّى أَتَتْ الْعَضْبَاءَ فَأَتَتْ عَلَى نَاقَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلُولٍ مُجَرَّسَةٍ فَرَكِبَتْهَا ثُمَّ تَوَجَّهَتْ قِبَلَ الْمَدِينَةِ وَنَذَرَتْ لَئِنْ اللَّهُ نَجَّاهَا لَتَنْحَرَنَّهَا قَالَ فَلَمَّا قَدِمَتْ عُرِفَتْ النَّاقَةُ فَقِيلَ نَاقَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَوْا بِهَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَخْبَرَتْ الْمَرْأَةُ بِنَذْرِهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِئْسَمَا جَزَيْتِهَا أَوْ بِئْسَمَا جَزَتْهَا إِنْ اللَّهُ نَجَّاهَا لَتَنْحَرَنَّهَا لَا وَفَاءَ لِنَذْرٍ فِي مَعْصِيَةِ اللَّهِ وَلَا فِيمَا لَا يَمْلِكُ ابْنُ آدَمَ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Abu Al Muhallab] dari [Imran bin Hushain] ia berkata; Dahulu 'Adhba` (nama unta rasul) adalah milik seorang laki-laki Bani 'Uqail, kemudian ia ditawan, dan 'Adhba`pun diambil. Kemudian Rasulullah shallallahu 'alaihi wasallam melewatinya, sementara orang itu dalam keadaan terikat. Laki-laki itu berkata; \"Wahai Muhammad, kenapa engkau menawanku dan mengambil unta pacuanku yang larinya cepat? Sungguh aku telah masuk Islam.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika yang kamu katakan benar, dan kamu dapat mengendalikan urusanmuy, maka kamu akan mendapatkan keberuntungan.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami menangkapmu karena kejahatan para sekutumu (yaitu Tsaqif).\" -Bani Tsaqif telah menawan dua sahabat Rasulullah shallallahu 'alaihi wasallam- Rasulullah shallallahu 'alaihi wasallam lalu datang sambil naik keledai dengan memakai mantel. Tawanan itu berkata; \"Wahai Muhammad, aku lapar, berilah aku makan, dan aku juga haus, berilah aku minum.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ini kebutuhanmu!.\" Lalu tawanan itu ditebus dengan dua orang sahabat, sementara Rasulullah shallallahu 'alaihi wasallam menahan Al 'Adhba` untuk kendaraan beliau. Unta tersebut termasuk diantara unta-unta yang gerak lajunya sangat cepat. Suatu ketika orang-orang musyrik menyerang Madinah dengan tiba-tiba, dan berhasil membawa beberapa ekor ternak, diantaranya pula terdapat Al Adhba`, mereka juga berhasil menawan seorang wanita, apabila mereka singgah…\" -Abu Muhammad berkata; kemudian (Imran bin Hushain) menyebutkan redaksi hadits; \"Mereka menderumkan unta-unta mereka di halaman persinggahan mereka. Pada suatu malam wanita yang tertawan berdiri ketika mereka terlelap tertidur. Setiap kali wanita itu meletakkan tangannya di atas unta, unta tersebut bersuara hingga ia sampai kepada Al 'Adhba`, lalu ia mendatangi unta Rasulullah shallallahu 'alaihi wasallam yang penurut dan berpengalaman, wanita itu langsung menungganginya menuju arah Madinah, ia bernadzar seandainya Allah menyelamatkannya, niscaya ia akan menyembelih unta tersebut. Imran berkata; \"Setibanya di Madinah, unta tersebut dikenali dan dikatakan; \"Itu adalah unta Rasulullah shallallahu 'alaihi wasallam.\" orang-orangpun menemui Nabi shallallahu 'alaihi wasallam dengan membawa untanya, wanita itu memberitahukan nadzarnya. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh buruk balasan yang engkau berikan.\" Atau \"Sungguh buruk balasan yang diberikan wanita itu, sesungguhnya Allah telah menyelamatkannya, justeru ia hendak menyembelihnya. Tidak boleh menunaikan nadzar dalam kemaksiatan kepada Allah, dan dalam perkara yang tidak dimiliki anak Adam.\""},"2039":{"ar":" أَخْبَرَنَا بِشْر�� بْنُ ثَابِتٍ حَدَّثَنَا شُعْبَةُ عَنْ الْمُغِيرَةِ عَنْ الشَّعْبِيِّ عَنْ مُحَرَّرِ بْنِ أَبِي هُرَيْرَةَ عَنْ أَبِيهِ قَالَ كُنْتُ مَعَ عَلِيِّ بْنِ أَبِي طَالِبٍ لَمَّا بَعَثَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَادَى بِأَرْبَعٍ حَتَّى صَهَلَ صَوْتُهُ أَلَا لَا يَدْخُلُ الْجَنَّةَ إِلَّا نَفْسٌ مُسْلِمَةٌ وَلَا يَحُجَّنَّ بَعْدَ الْعَامِ مُشْرِكٌ وَلَا يَطُوفُ بِالْبَيْتِ عُرْيَانٌ وَمَنْ كَانَ بَيْنَهُ وَبَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهْدٌ فَإِنَّ أَجَلَهُ إِلَى أَرْبَعَةِ أَشْهُرٍ فَإِذَا مَضَتْ الْأَرْبَعَةُ فَإِنَّ اللَّهَ بَرِيءٌ مِنْ الْمُشْرِكِينَ وَرَسُولُهُ","id":"Telah mengabarkan kepada kami [Bisyr bin Tsabit] telah menceritakan kepada kami [Syu'bah] dari [Al Mughirah] dari [Asy Sya'bi] dari [Muharrar bin Abu Hurairah] dari [Ayahnya], ia berkata; aku pernah bersama Ali bin Abu Thalib ketika Rasulullah shallallahu 'alaihi wasallam mengutusnya. Kemudian ia mengumumkan empat perkara hingga suaranya menjadi serak, katanya; \"Ketahuilah, bahwa tidak akan masuk Surga kecuali jiwa mukmin, dan orang-orang musyrik tidak boleh berthawaf di Ka'bah dalam keadaan telanjang, barangsiapa antara dia dan Rasulullah shallallahu 'alaihi wasallam terdapat perjanjian, maka temponya hingga empat bulan, apabila telah berlalu empat bulan, sesungguhnya Allah dan rasulNYa berlepas diri dari orang-orang musyrik.\""},"2040":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ إِسْرَائِيلَ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَ اعْتَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذِي الْقَعْدَةِ فَأَبَى أَهْلُ مَكَّةَ أَنْ يَدَعُوهُ أَنْ يَدْخُلَ مَكَّةَ حَتَّى قَاضَاهُمْ عَلَى أَنْ يُقِيمَ ثَلَاثَةَ أَيَّامٍ فَلَمَّا كَتَبُوا هَذَا مَا قَاضَى عَلَيْهِ مُحَمَّدٌ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا لَا نُقِرُّ بِهَذَا لَوْ نَعْلَمُ أَنَّكَ رَسُولُ اللَّهِ مَا مَنَعْنَاكَ شَيْئًا وَلَكِنْ أَنْتَ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ فَقَالَ أَنَا رَسُولُ اللَّهِ وَأَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ فَقَالَ لِعَلِيٍّ امْحُ مُحَمَّدٌ رَسُولُ اللَّهِ فَقَالَ لَا وَاللَّهِ لَا أَمْحُوهُ أَبَدًا فَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكِتَابَ وَلَيْسَ يُحْسِنُ يَكْتُبُ فَكَتَبَ مَكَانَ رَسُولِ اللَّهِ هَذَا مَا قَاضَى عَلَيْهِ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ أَنْ لَا يَدْخُلَ مَكَّةَ بِسِلَاحٍ إِلَّا السَّيْفَ فِي الْقِرَابِ وَأَنْ لَا يُخْرِجَ مِنْ أَهْلِهَا أَحَدًا أَرَادَ أَنْ يَتْبَعَهُ وَلَا يَمْنَعَ أَحَدًا مِنْ أَصْحَابِهِ أَرَادَ أَنْ يُقِيمَ بِهَا فَلَمَّا دَخَلَهَا وَمَضَى الْأَجَلُ أَتَوْا عَلِيًّا فَقَالُوا قُلْ لِصَاحِبِكَ فَلْيَخْرُجْ عَنَّا فَقَدْ مَضَى الْأَجَلُ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Isma'il] telah menceritakan kepada kami [Abu Ishaq] dari [Al Bara` bin 'Azib], ia berkata; Rasulullah shallallahu 'alaihi wasallam melakukan umrah pada bulan Dzul Qa'dah, namun penduduk Makkah enggan membiarkan beliau memasuki Makkah, hingga beliau membuat perjanjian dengan mereka untuk tinggal selama tiga hari. Tatkala mereka menulis; \"Ini adalah perjanjian yang dibuat Muhammad Rasulullah shallallahu 'alaihi wasallam shallallahu 'alaihi wasallam.\" Mengetahui hal itu, orang-orang musyrik berkata; \"Kami tidak mengakui hal ini, seandainya kami mengetahui bahwa engkau adalah utusan Allah, maka kami tidak akan menghalangimu sedikitpun, akan tetapi engkau adalah Muhammad bin Abdullah.\" Kemudian beliau bersabda: \"Aku adalah Rasulullah dan aku adalah Muhammad bin Abdullah.\" Kemudian beliau bersabda kepada Ali: \"Hapuslah Muhammad Rasulullah.\" Kemudian Ali berkata; \"Tidak, demi Allah aku tidak akan menghapusnya selamanya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam mengambil tulisan tersebut, sementara beliau tidak pandai menulis, beliau menulis pada tempat Rasulullah, dengan kata; \"Ini adalah perjanjian yang dibuat Muhammad bin Abdullah, yaitu untuk tidak masuk Makkah dengan membawa senjata kecuali pedang dalang sarungnya, dan seorangpun dari penduduk Makkah tidak boleh keluar mengikutinya, dan tidak melarang seorangpun dari sahabatnya yang ingin tinggal di Makkah.\" Setelah beliau memasuki Makkah, dan telah jatuh tempo, orang-orang musyrik berkata kepada Ali; \"Katakan kepada sahabatmu, hendaknya ia keluar dari (wilayah) kami, sebab temponya telah berlalu.\""},"2041":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو خَالِدٍ عَنْ الْحَجَّاجِ عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ قَالَ خَرَجَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدَانِ مِنْ الطَّائِفِ فَأَعْتَقَهُمَا أَحَدُهُمَا أَبُو بَكْرَةَ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Khalid] dari [Al Hajjaj] dari [Al Hakam] dari [Miqsam] dari [Ibnu Abbas], ia berkata; \"Dua orang budak dari Tha`if keluar hendak menemui Nabi shallallahu 'alaihi wasallam, kemudian beliau membebaskan keduanya, salah satunya dari budak tersebut bernama Abu Bakrah."},"2042":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّهُ قَالَ رُمِيَ يَوْمَ الْأَحْزَابِ سَعْدُ بْنُ مُعَاذٍ فَقَطَعُوا أَبْجَلَهُ فَحَسَمَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّارِ فَانْتَفَخَتْ يَدُهُ فَنَزَفَهُ فَحَسَمَهُ أُخْرَى فَانْتَفَخَتْ يَدُهُ فَلَمَّا رَأَى ذَلِكَ قَالَ اللَّهُمَّ لَا تُخْرِجْ نَفْسِي حَتَّى تُقِرَّ عَيْنِي مِنْ بَنِي قُرَيْظَةَ فَاسْتَمْسَكَ عِرْقُهُ فَمَا قَطَرَ قَطْرَةً حَتَّى نَزَلُوا عَلَى حُكْمِ سَعْدٍ فَأَرْسَلَ إِلَيْهِ فَحَكَمَ أَنْ تُقْتَلَ رِجَالُهُمْ وَتُسْتَحْيَى نِسَاؤُهُمْ وَذَرَارِيُّهُمْ يَسْتَعِينُ بِهِمْ الْمُسْلِمُونَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَبْتَ حُكْمَ اللَّهِ فِيهِمْ وَكَانُوا أَرْبَعَ مِائَةٍ فَلَمَّا فُرِغَ مِنْ قَتْلِهِمْ انْفَتَقَ عِرْقُهُ فَمَاتَ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Laits bin Sa'd] dari [Abu Az Zubair] dari [Jabir bin Abdullah] bahwa ia berkata; Pada saat perang Khandaq, Sa'd bin Mu'adz terkena panah, kemudian mereka memotong urat nadinya, Rasulullah shallallahu 'alaihi wasallam lalu menghentikan darahnya dengan kay. Tenyata tangannya membengkak, maka beliau mengeluarkan darahnya dan menghentikannya dengan kay, namun tangannya tetap membengkak, setelah mengetahui hal itu, ia berkata; \"Ya Allah, janganlah engkau mengeluarkan nyawaku hingga mataku terasa sejuk karena kebinasaan Bani Quraizhah.\" Setelah itu uratnya terhenti, dan tidak ada tetesan darah yang keluar setetespun, hingga Bani Quraizhah mendapatkan keputusan dari hukum Sa'd. Suatu ketika beliau mengirim utusan kepadanya, lalu Sa'd memutuskan agar orang laki-laki mereka dibunuh dan para wanita serta keturunan mereka dibiarkan hidup sebagai pembantu kaum Muslimin. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Engkau telah meutusi dengan hukum Allah terhadap mereka.\" Waktu itu mereka berjumlahh empat ratus orang, seusai membunuh mereka, uratnya pecah hingga ia meninggal dunia.\""},"2043":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ عَبْدَ اللَّهِ بْنَ عَدِيِّ بْنِ حَمْرَاءَ الزُّهْرِيَّ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى رَاحِلَتِهِ وَاقِفًا بِالْحَزْوَرَةِ يَقُولُ وَاللَّهِ إِنَّكِ لَخَيْرُ أَرْضِ اللَّهِ وَأَحَبُّ أَرْضِ اللَّهِ إِلَى اللَّهِ وَلَوْلَا أَنِّي أُخْرِجْتُ مِنْكِ مَا خَرَجْتُ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] bahwa [Abdullah bin 'Adi bin Hamra` Az Zuhri] berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam berada di atas kendaraannya sambil berdiri di Hazwarah, beliau bersabda: \"Demi Allah, sesungguhnya engkau adalah tanah Allah yang terbaik dan yang paling Allah cintai. Seandainya aku tidak dikeluarkan darimu, niscaya aku tidak akan keluar.\""},"2044":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ الرَّبِيعِ أَخْبَرَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ مُجَاهِدٍ قَالَ قَالَتْ عَائِشَةُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسُبُّوا الْأَمْوَاتَ فَإِنَّهُمْ قَدْ أَفْضَوْا إِلَى مَا قَدَّمُوا","id":"Telah menceritakan kepada kami [Sa'id bin Ar Rabi'] telah mengabarkan kepada kami [Syu'bah] dari [Sulaiman] dari [Mujahid], ia berkata; ['Aisyah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mencaci orang yang telah meninggal, sesungguhnya mereka telah sampai kepada apa yang telah mereka lakukan (pembalasan amal).\""},"2045":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَ لَمَّا كَانَ يَوْمُ فَتْحِ مَكَّةَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا هِجْرَةَ بَعْدَ الْفَتْحِ وَلَكِنْ جِهَادٌ وَنِيَّةٌ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Isra`il] dari [Manshur] dari [Mujahid] dari [Thawus] dari [Ibnu Abbas], ia berkata; Pada saat penaklukan kota Makkah, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada hijrah setelah penaklukan kota Makkah, yang ada hanyalah jihad dan niat.\""},"2046":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ عَنْ حَرِيزِ بْنِ عُثْمَانَ عَنْ ابْنِ أَبِي عَوْفٍ وَهُوَ عَبْدُ الرَّحْمَنِ عَنْ أَبِي هِنْدٍ الْبَجَلِيِّ وَكَانَ مِنْ السَّلَفِ قَالَ تَذَاكَرُوا الْهِجْرَةَ عِنْدَ مُعَاوِيَةَ وَهُوَ عَلَى سَرِيرِهِ فَقَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَنْقَطِعُ الْهِجْرَةُ حَتَّى تَنْقَطِعَ التَّوْبَةُ ثَلَاثًا وَلَا تَنْقَطِعُ التَّوْبَةُ حَتَّى تَطْلُعَ الشَّمْسُ مِنْ مَغْرِبِهَا","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] dari [Hariz bin Utsman] dari [Ibnu Abu 'Auf yaitu Abdurrahman] dari [Abu Hindun Al Bajali] -dan dia termasuk dari ulama salaf- Ia berkata; \"Orang-orang saling menyebutkan mengenai hijrah di hadapan [Mu'awiyah], ketika itu Mu'awiyah tengah berada di atas dipannya. Kemudian ia berkata; \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Hijrah tidak terputus hingga terputusnya taubat. -Beliau mengucapkannya hingga tiga kali- dan taubat tidak akan terputus hingga matahari terbit dari baratnya.\""},"2047":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا الْهِجْرَةُ لَكُنْتُ امْرَأً مِنْ الْأَنْصَارِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin 'Amr] dari [Abu Salamah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya tidak ada hijrah, niscaya aku termnasuk dari orang Anshar.\""},"2048":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ سَعِيدِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ أَمِيرِ عَشَرَةٍ إِلَّا يُؤْتَى بِهِ يَوْمَ الْقِيَامَةِ مَغْلُولَةٌ يَدَاهُ إِلَى عُنُقِهِ أَطْلَقَهُ الْحَقُّ أَوْ أَوْبَقَهُ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Yahya bin Sa'id] dari [Sa'id bin Yasar] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorang pemimpinpun yang memimpin sepuluh orang, kecuali ia akan didatangkan pada hari kiamat dalam keadaan tangannya terbelenggu ke lehernya, tidak ada yang bisa melepasnya kecuali keadilan atau dia akan celaka karena kezhaliman.\""},"2049":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي عَمْرٌو قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ الْحَارِثِ يُحَدِّثُ عَنْ أَبِي كَثِيرٍ قَالَ سَمِع��تُ عَبْدَ اللَّهِ بْنَ عَمْرٍو يُحَدِّثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِيَّاكُمْ وَالظُّلْمَ فَإِنَّ الظُّلْمَ ظُلُمَاتٌ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah], telah mengabarkan kepadaku ['Amr], ia berkata; Aku mendengar [Abdullah bin Al Harits] menceritakan dari [Abu Katsir], ia berkata; aku mendengar [Abdullah bin 'Amr] menceritakan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jauhilah kezhaliman, sesungguhnya kezhaliman adalah kegelapan pada hari Kiamat.\""},"2050":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ قَالَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ يُؤَيِّدُ هَذَا الدِّينَ بِالرَّجُلِ الْفَاجِرِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] telah mengabarkan kepad kami [Syu'aib] dari [Az Zuhri], telah mengabarkan kepadaku [Sa'id bin Al Musayyab] bahwa [Abu Hurairah] berkata; sesungguhnya Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah menguatkan agama ini dengan laki-laki fajir.\""},"2051":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا صَفْوَانُ حَدَّثَنِي أَزْهَرُ بْنُ عَبْدِ اللَّهِ الْحَرَازِيُّ عَنْ أَبِي عَامِرٍ هُوَ عَبْدُ اللَّهِ بْنُ لُحَيٍّ الْهَوْزَنِيِّ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فِينَا فَقَالَ أَلَا إِنَّ مَنْ كَانَ قَبْلَكُمْ مِنْ أَهْلِ الْكِتَابِ افْتَرَقُوا عَلَى ثِنْتَيْنِ وَسَبْعِينَ مِلَّةً وَإِنَّ هَذِهِ الْأُمَّةَ سَتَفْتَرِقُ عَلَى ثَلَاثٍ وَسَبْعِينَ اثْنَتَانِ وَسَبْعُونَ فِي النَّارِ وَوَاحِدَةٌ فِي الْجَنَّةِ قَالَ عَبْد اللَّهِ الْحَرَازُ قَبِيلَةٌ مِنْ أَهْلِ الْيَمَنِ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Shafwan] telah menceritakan kepadaku [Azhar bin Abdullah Al Harazi] dari [Abu Amir yaitu Abdullah bin Luhai Al Hauzani] dari [Mu'awiyah bin Abu Sufyan] bahwa Rasulullah shallallahu 'alaihi wasallam berdiri diantara kami seraya bersabda: \"Ketahuilah, bahwa orang-orang sebelum kalian dari kalangan ahli kitab terpecah menjadi tujuh dua agama, sedangkan umat ini akan terpecah menjadi tujuh puluh tiga golongan. Tujuh puluh dua di Neraka dan satu di Surga.\" Abdullah bekata; \"Al Haraz adalah suatu kabilah dari penduduk Yaman.\""},"2052":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ الْجَعْدِ أَبِي عُثْمَانَ حَدَّثَنَا أَبُو رَجَاءٍ الْعُطَارِدِيُّ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَرْوِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ رَأَى مِنْ أَمِيرِهِ شَيْئًا يَكْرَهُهُ فَلْيَصْبِرْ فَإِنَّهُ لَيْسَ مِنْ أَحَدٍ يُفَارِقُ الْجَمَاعَةَ شِبْرًا فَيَمُوتُ إِلَّا مَاتَ مِيتَةً جَاهِلِيَّةً","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Zaid] dari [Al Ja'd Abu Utsman] telah menceritakan kepada kami [Abu Raja` Al 'Utharidi], ia berkata; aku mendengar [Ibnu Abbas] meriwayatkan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa melihat pada diri pemimpinnya sesuatu yang tidak ia sukai, hendaknya ia bersabar, sesungguhnya tidak seorangpun yang memisahkan diri dari Jam'ah walau sejengkal, kemudian mati, maka matinya seperti mati jahiliyah.\""},"2053":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنَا إِيَاسُ بْنُ سَلَمَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ سَلَّ عَلَيْنَا السِّلَاحَ فَلَيْسَ مِنَّا","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Ikrimah bin 'Ammar] telah menceritakan kepada kami [Iyas bin Salamah] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa menodongkan sejata kepada kami, maka bukan termasuk golongan kami.\""},"2054":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ عَنْ شُعَيْبِ بْنِ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ قَالَ كَانَ مُحَمَّدُ بْنُ جُبَيْرِ بْنِ مُطْعِمٍ يُحَدِّثُ عَنْ مُعَاوِيَةَ أَنَّهُ قَالَ وَهُوَ عِنْدَهُ فِي وَفْدٍ مِنْ قُرَيْشٍ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ هَذَا الْأَمْرَ فِي قُرَيْشٍ لَا يُعَادِيهِمْ أَحَدٌ إِلَّا كَبَّهُ اللَّهُ عَلَى وَجْهِهِ مَا أَقَامُوا الدِّينَ","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] dari [Syu'aib bin Abu Hamzah] dari [Az Zuhri], ia berkata; [Muhammad bin Jubair bin Muth'im] menceritakan dari [Mu'awiyah] bahwa ia berkata; -sedangkan dirinya berada di antara para delegasi orang-orang Quraisy- \"Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya perkara kekhilafahan ini ada pada orang-orang Quraisy, tidak ada seorangpun yang menentang mereka kecuali Allah akan menghinakannya selama mereka menegakkan agama ini.\""},"2055":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هُرْمُزَ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُرَيْشٌ وَالْأَنْصَارُ وَمُزَيْنَةُ وَجُهَيْنَةُ وَأَسْلَمُ وَغِفَارٌ وَأَشْجَعُ لَيْسَ لَهُمْ مَوْلًى دُونَ اللَّهِ وَرَسُولِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Sa'd bin Ibrahim] dari [Abdurrahman bin Hurmuz Al A'raj] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Quraisy, Anshar, Muzainah, Juhainah, Aslam, Ghifar, serta Asyja', mereka tidak memiliki penolong selain Allah dan rasul-Nya.\""},"2056":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرَأَيْتُمْ إِنْ كَانَ أَسْلَمُ وَغِفَارٌ خَيْرًا مِنْ الْحَلِيفَيْنِ أَسَدٍ وَغَطَفَانَ أَتُرَوْنَهُمْ خَسِرُوا قَالُوا نَعَمْ قَالَ فَإِنَّهُمْ خَيْرٌ مِنْهُمْ قَالَ أَفَرَأَيْتُمْ إِنْ كَانَتْ مُزَيْنَةُ وَجُهَيْنَةُ خَيْرًا مِنْ تَمِيمٍ وَعَامِرِ بْنِ صَعْصَعَةَ وَمَدَّ بِهَا صَوْتَهُ أَتُرَوْنَهُمْ خَسِرُوا قَالُوا نَعَمْ قَالَ فَإِنَّهُمْ خَيْرٌ مِنْهُمْ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ali bin Zaid] dari [Abdurrahman bin Abu Bakrah] dari [Ayahnya] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Bagaimana pendapat kalian apabila Aslam, dan Ghifar lebih baik daripada kedua sekutunya yaitu Asad dan Ghathafan, apakah kalian melihat mereka akan merugi?\" Para sahabat menjawab; \"Ya.\" Beliau bersabda: \"Sesungguhnya mereka (Aslam dan Ghifar) lebih baik daripada mereka (Asad dan Ghathafan).\" Beliau bersabda lagi: \"Bagaimana pendapat kalian apabila Muzainah dan Juhainah lebih baik daripada Tamim dan 'Amir bin Sha'sha'ah -beliau memanjangkan suaranya- apakah kalian melihat mereka akan merugi?\" Para sahabat menjawab; \"Ya.\" Beliau bersabda; \"Sesungguhnya mereka (Bani Muzainah dan Juhainah) lebih baik daripada mereka (Tamim dan 'Amr bin Sha'sha'ah).\""},"2057":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا سُلَيْمَانُ هُوَ ابْنُ الْمُغِيرَةِ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غِفَارٌ غَفَرَ اللَّهُ لَهَا وَأَسْلَمُ سَالَمَهَا اللَّهُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Sulaiman yaitu Ibnu Al Mughirah] dari [Humaid bin Hilal] dari [Abdullah bin Ash Shamit] dari [Abu Dzar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ghifar, semoga Allah mengampuni mereka dan Aslam, semoga Allah menyelamatkan mereka.\""},"2058":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ غِفَارٌ غَفَرَ اللَّهُ لَهَا وَأَسْلَمُ سَالَمَهَا اللَّهُ وَعُصَيَّةُ عَصَتْ اللَّهَ وَرَسُولَهُ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Abdul Aziz] dari [Musa bin 'Uqbah] dari [Abdullah bin Dinar] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ghifar, semoga Allah mengampuni mereka dan Aslam, semoga Allah menyelamatkan mereka dan 'Ushayyah telah berdurhaka kepada Allah dan rasulNya.\""},"2059":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَرِيكٌ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قِيلَ لِشَرِيكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ لَا حِلْفَ فِي الْإِسْلَامِ وَفِي الْجَاهِلِيَّةِ لَمْ يَزِدْهُ الْإِسْلَامُ إِلَّا شِدَّةً وَجِدَّةً","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syarik] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas], Syarik ditanya; \"Apakah dari Nabi shallallahu 'alaihi wasallam?\" Ia menjawab; \"Ya. Tidak ada perjanjian dalam Islam, dan Jahiliyah, melainkan tidak menambah Islam kecuali menjadi semakin kuat dan erat.\""},"2060":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شُعْبَةُ قَالَ قُلْتُ لِمُعَاوِيَةَ بْنِ قُرَّةَ أَكَانَ أَنَسٌ يَذْكُرُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلنُّعْمَانِ بْنِ مُقَرِّنٍ ابْنُ أُخْتِ الْقَوْمِ مِنْهُمْ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syu'bah], ia berkata; aku berkata kepada [Mu'awiyah bin Qurrah]; \"Apakah [Anas] menyebutkan bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada An Nu'man bin Muqarrin: \"Anak saudara wanita suatu kaum adalah bagian dari mereka.?\" Ia berkata; \"Ya.\""},"2061":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ الْمُغِيرَةِ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ كَثِيرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَوْلَى الْقَوْمِ مِنْهُمْ وَحَلِيفُ الْقَوْمِ مِنْهُمْ وَابْنُ أُخْتِ الْقَوْمِ مِنْهُمْ","id":"Telah menceritakan kepada kami [Sa'id bin Al Mughirah] telah menceritakan kepada kami [Isa bin Yunus] dari [Katsir bin Abdullah] dari [Ayahnya] dari [Kakeknya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mantan budak suatu kaum adalah bagian dari mereka, sekutu suatu kaum adalah bagian dari mereka, dan anak seorang saudara wanita suatu kaum adalah bagian dari mereka.\""},"2062":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ الدَّسْتَوَائِيُّ حَدَّثَنَا قَتَادَةُ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ عَنْ عَمْرِو بْنِ خَارِجَةَ قَالَ كُنْتُ تَحْتَ نَاقَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعْتُهُ يَقُولُ مَنْ ادَّعَى إِلَى غَيْرِ أَبِيهِ أَوْ انْتَمَى إِلَى غَيْرِ مَوَالِيهِ رَغْبَةً عَنْهُمْ فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يُقْبَلُ مِنْهُ صَرْفٌ وَلَا عَدْلٌ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam Ad Dastawa`i] telah menceritakan kepada kami [Qatadah] dari [Syahr bin Hausyab] dari [Abdurrahman bin Ghanm] dari ['Amr bin Kharijah], ia berkata; aku pernah berada di bawah unta Nabi shallallahu 'alaihi wasallam dan mendengar beliau bersabda: \"Barangsiapa mengaku memiliki nasab selain (nasab) bapaknya atau menisbatkan kepada selain tuannya karena kebencian kepada mereka, maka baginya laknat Allah dan para Malaikat serta seluruh manusia, tidak diterima taubat serta ibadahnya.\""},"2063":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ عَاصِمٍ عَنْ أَبِي عُثْمَانَ عَنْ سَعْدٍ وَأَبِي بَكْرَةَ أَنَّهُمَا حَدَّثَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ادَّعَى إِلَى غَيْرِ أَبِيهِ وَهُوَ يَعْلَمُ أَنَّهُ غَيْرُ أَبِيهِ فَالْجَنَّةُ عَلَيْهِ حَرَامٌ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari ['Ashim] dari [Abu Utsman] dari [Sa'd] serta [Abu Bakrah] bahwa keduanya menceritakan, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengaku memiliki nasab kepada selain ayahnya, padahal ia mengetahui bahwa ia bukanlah ayahnya, maka haram baginya Surga.\""},"2064":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَكَرِيَّا عَنْ الشَّعْبِيِّ قَالَ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْحَلَالُ بَيِّنٌ وَالْحَرَامُ بَيِّنٌ وَبَيْنَهُمَا مُتَشَابِهَاتٌ لَا يَعْلَمُهَا كَثِيرٌ مِنْ النَّاسِ فَمَنْ اتَّقَى الشُّبُهَاتِ اسْتَبْرَأَ لِعِرْضِهِ وَدِينِهِ وَمَنْ وَقَعَ فِي الشُّبُهَاتِ وَقَعَ فِي الْحَرَامِ كَالرَّاعِي يَرْعَى حَوْلَ الْحِمَى فَيُوشِكُ أَنْ يُوَاقِعَهُ وَإِنَّ لِكُلِّ مَلِكٍ حِمًى أَلَا وَإِنَّ حِمَى اللَّهِ مَحَارِمُهُ أَلَا وَإِنَّ فِي الْجَسَدِ مُضْغَةً إِذَا صَلَحَتْ صَلَحَ الْجَسَدُ كُلُّهُ وَإِذَا فَسَدَتْ فَسَدَ الْجَسَدُ كُلُّهُ أَلَا وَهِيَ الْقَلْبُ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zakariya] dari [Asy Sya'bi], ia berkata; aku mendengar [An Nu'man bin Basyir] berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesuatu yang halal telah nyata (jelas) dan yang haram telah nyata. Dan diantara keduanya ada perkara yang tidak jelas, yang tidak diketahui kebanyakan orang, barangsiapa menjaga dirinya dari perkara yang tidak jelas, maka selamatlah agama dan harga dirinya, tetapi siapa yang terjatuh dalam perkara yang syubhat (tidak jelas), berarti dia terjatuh kepada keharaman. Tak ubahnya seperti gembala yang menggembala ditepi pekarangan, dikhawatirkan ternaknya akan terjatuh kedalamnya. Ketahuilah setiap raja itu memiliki larangan, dan larangan Allah adalah sesuatu yang diharamkannya. Ketahuilah bahwa dalam setiap tubuh terdapat segumpal daging, jika segumpal daging itu baik, maka baik pula seluruh badannya, namun jika segumpal daging itu rusak, maka rusaklah seluruh tubuhnya, ketahuilah gumpalan darah itu adalah hati.\""},"2065":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ حَدَّثَنَا شُعْبَةُ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ أَبِي الْحَوْرَاءِ السَّعْدِيِّ قَالَ قُلْتُ لِلْحَسَنِ بْنِ عَلِيٍّ مَا تَحْفَظُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَأَلَهُ رَجُلٌ عَنْ مَسْأَلَةٍ لَا أَدْرِي مَا هِيَ فَقَالَ دَعْ مَا يَرِيبُكَ إِلَى مَا لَا يَرِيبُكَ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] telah menceritakan kepada kami [Syu'bah] dari [Buraid bin Abu Maryam] dari [Abu Al Haura` As Sa'di], ia berkata; aku berkata kepada [Al Hasan bin Ali]; \"Apa yang engkau hafal dari Rasulullah?, \" Ia menjawab; \"Seorang laki-laki bertanya kepada beliau mengenai suatu permasalahan, namun aku tidak tahu permasalahan apa itu, kemudian beliau bersabda: \"Tinggalkanlah sesuatu yang meragukanmu kepada sesuatu yang tidak meragukanmu.\""},"2066":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ الزُّبَيْرِ أَبِي عَبْدِ السَّلَامِ عَنْ أَيُّوبَ بْنِ عَبْدِ اللَّهِ بْنِ مِكْرَزٍ الْفِهْرِيِّ عَنْ وَابِصَةَ بْنِ مَعْبَدٍ الْأَسَدِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِوَابِصَةَ جِئْتَ تَسْأَلُ عَنْ الْبِرِّ وَالْإِثْمِ قَالَ قُلْتُ نَعَمْ قَالَ فَجَمَعَ أَصَابِعَهُ فَضَرَبَ بِهَا صَدْرَهُ وَقَالَ اسْتَفْتِ نَفْسَكَ اسْتَفْتِ قَلْبَكَ يَا وَابِصَةُ ثَلَاثًا الْبِرُّ مَا اطْمَأَنَّتْ إِلَيْهِ النَّفْسُ وَاطْمَأَنَّ إِلَيْهِ الْقَلْبُ وَالْإِثْمُ مَا حَاكَ فِي النَّفْسِ وَتَرَدَّدَ فِي الصَّدْرِ وَإِنْ أَفْتَاكَ النَّاسُ وَأَفْتَوْكَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Az Zubair Abu Abdussalam] dari [Ayyub bin Abdullah bin Mikraz Al Fihri] dari [Wabishah bin Ma'bad Al Asadi] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada Wabishah: \"Engkau datang bertanya mengenai kebaikan dan dosa?\" Wabishah berkata; Aku menjawab; \"Ya.\" Ayyub mengatakan; Kemudian beliau menggenggam jari-jarinya dan memukulkannya ke dada Wabishah sambil bersabda: \"Tanyakan kepada dirimu, tanyakan kepada hatimu wahai Wabishah. -Beliau mengatakannya hingga tiga kali- Kebaikan adalah apa yang membuat jiwa tenang dan membuat hati tenang, sedangkan dosa adalah sesuatu yang membekas dalam jiwa dan membuat hati ragu, walaupun orang-orang memberikan fatwa kepadamu.\""},"2067":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ أَبِي حُرَّةَ الرَّقَاشِيِّ عَنْ عَمِّهِ قَالَ كُنْتُ آخِذًا بِزِمَامِ نَاقَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَوْسَطِ أَيَّامِ التَّشْرِيقِ أَذُودُ النَّاسَ عَنْهُ فَقَالَ أَلَا إِنَّ كُلَّ رِبًا فِي الْجَاهِلِيَّةِ مَوْضُوعٌ أَلَا وَإِنَّ اللَّهَ قَدْ قَضَى أَنَّ أَوَّلَ رِبًا يُوضَعُ رِبَا عَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ لَكُمْ رُءُوسُ أَمْوَالِكُمْ لَا تَظْلِمُونَ وَلَا تُظْلَمُونَ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kmai [Ali bin Zaid] dari [Abu Hurrah Ar Raqasyi] dari [pamannya], ia berkata; \"Aku memegang tali kekang unta Rasulullah shallallahu 'alaihi wasallam pada pertengahan hari-hari Tasyriq, aku memerintahkan orang-orang supaya menjauh darinya. Kemudian beliau bersabda: \"Sesungguhnya seluruh riba pada masa jahiliyah telah dibatalkan, ketahuilah sesungguhnya Allah telah memutuskan bahwa riba pertama yang dibatalkan adalah riba Abbas bin Abdul Muththalib, yaitu bagi kalian modal harta kalian, kalian tidak menzhalimi dan tidak dizhalimi.\""},"2068":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي قَيْسٍ عَنْ هُزَيْلٍ عَنْ عَبْدِ اللَّهِ قَالَ لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آكِلَ الرِّبَا وَمُؤْكِلَهُ","id":"Telah mengabarkan kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Abu Qais] dari [Huzail] dari [Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam melaknat pemakan riba dan orang yang memberi makan dari hasil riba."},"2069":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيَأْتِيَنَّ زَمَانٌ لَا يُبَالِي الْمَرْءُ بِمَا أَخَذَ الْمَالَ بِحَلَالٍ أَمْ بِحَرَامٍ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah bin Yunus] telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Sa'id Al Maqburi] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh akan datang suatu zaman dimana seseorang tidak peduli apakah ia mengambil hartanya dengan cara halal atau haram.\""},"2070":{"ar":" أَخْبَرَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ عَمَّتِهِ عَنْ عَائِشَةَ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَحَقَّ مَا يَأْكُلُ الرَّجُلُ مِنْ أَطْيَبِ كَسْبِهِ وَإِنَّ وَلَدَهُ مِنْ أَطْيَبِ كَسْبِهِ","id":"Telah mengabarkan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari ['Umarah bin 'Umair] dari [bibinya] dari ['Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sesuatu yang paling baik dimakan oleh seseorang yang berasal dari usahanya sendiri dan sesungguhnya anaknya termasuk dari usahanya yang paling baik.\""},"2071":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ هُوَ ابْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ إِسْمَعِيلَ بْنِ رِفَاعَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْبَقِيعِ فَقَالَ يَا مَعْشَرَ التُّجَّارِ حَتَّى إِذَا اشْرَأَبُّوا قَالَ التُّجَّارُ يُحْشَرُونَ يَوْمَ الْقِيَامَةِ فُجَّارًا إِلَّا مَنْ اتَّقَى وَبَرَّ وَصَدَقَ قَالَ أَبُو مُحَمَّد كَانَ أَبُو نُعَيْمٍ يَقُولُ عُبَيْدُ اللَّهِ بْنُ رِفَاعَةَ وَإِنَّمَا هُوَ إِسْمَعِيلُ بْنُ عُبَيْدِ بْنِ رِفَاعَةَ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Abdullah yaitu Ibnu Utsman bin Khutsaim] dari [Isma'il bin Rifa'ah] dari [Ayahnya] dari [Kakeknya], ia berkata; Rasulullah shallallahu 'alaihi wasallam keluar menuju Baqi', kemudian bersabda: \"Wahai para pedagang!.\" Hingga ketika mereka mengangkat kepala, beliau bersabda: \"Para pedagang akan dikumpulkan pada Hari Kiamat sebagai orang yang berbuat dosa, kecuali orang yang bertakwa, berbuat kebaikan dan berkata jujur.\" Abu Muhammad berkata; Abu Nu'aim berkata; 'Ubaidullah bin Rifa'ah adalah Isma'il bin Ubaid bin Rifa'ah."},"2072":{"ar":" أَخْبَرَنَا قَبِيصَةُ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْحَسَنِ عَنْ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ التَّاجِرُ الصَّدُوقُ الْأَمِينُ مَعَ النَّبِيِّينَ وَالصِّدِّيقِينَ وَالشُّهَدَاءِ قَالَ عَبْد اللَّهِ لَا عِلْمَ لِي بِهِ إِنَّ الْحَسَنَ سَمِعَ مِنْ أَبِي سَعِيدٍ وَقَالَ أَبُو حَمْزَةَ هَذَا هُوَ صَاحِبُ إِبْرَاهِيمَ وَهُوَ مَيْمُونٌ الْأَعْوَرُ","id":"Telah mengabarkan kepada kami [Qabishah] telah mengabarkan kepada kami [Sufyan] dari [Abu Hamzah] dari [Al Hasan] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Pedagang yang jujur dan dapat dipercaya akan bersama para nabi, para shiddiqin, dan para syuhada'.\" [Abdullah] berkata; aku tidak mengetahui mengenai hal itu. Sesungguhnya Al Hasan telah mendengar dari Abu Sa'id. Abu Hamzah berkata; \"Orang ini adalah sahabat Ibrahim, yaitu Maimun Al A'war.\""},"2073":{"ar":" حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا إِسْمَعِيلُ عَنْ قَيْسٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَ بَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى إِقَامِ الصَّلَاةِ وَإِيتَاءِ الزَّكَاةِ وَالنُّصْحِ لِكُلِّ مُسْلِمٍ","id":"Telah menceritakan kepada kami [Ya'la bin 'Ubaid] telah menceritakan kepada kami [Isma'il] dari [Qais] dari [Jarir bin Abdullah], ia berkata; \"Aku berbai'at kepada Rasulullah shallallahu 'alaihi wasallam untuk menegakkan shalat dan menunaikan zakat, serta menasehati setiap orang muslim.\""},"2074":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ حَدَّثَنَا أَبُو عَقِيلٍ يَحْيَى بْنُ الْمُتَوَكِّلِ قَالَ أَخْبَرَنِي الْقَاسِمُ بْنُ عُبَيْدِ اللَّهِ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِطَعَامٍ بِسُوقِ الْمَدِينَةِ فَأَعْجَبَهُ حُسْنُهُ فَأَدْخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ فِي جَوْفِهِ فَأَخْرَجَ شَيْئًا لَيْسَ كَالظَّاهِرِ فَأَفَّفَ بِصَاحِبِ الطَّعَامِ ثُمَّ قَالَ لَا غِشَّ بَيْنَ الْمُسْلِمِينَ مَنْ غَشَّنَا فَلَيْسَ مِنَّا","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shalt] telah menceritakan kepada kami [Abu 'Aqil Yahya bin Al Mutawakkil], ia berkata; telah mengabarkan kepadaku [Al Qasim bin 'Ubaidullah] dari [Salim] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam pernah melewati makanan di pasar Madinah, kemudian beliau terkagum-kagum terhadap bagusnya makanan tersebut. Kemudian Rasulullah shallallahu 'alaihi wasallam memasukkan tangannya ke dalam makanan itu, ternyata beliau menemukan sesuatu yang tidak sama seperti yang nampak. Beliaupun merasa kesal terhadap pemilik makanan, beliau lalu bersabda; \"Tidak boleh ada penipuan diantara orang muslim. Barangsiapa menipu kami, maka bukan termasuk dari golongan kami.\""},"2075":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ قَالَ سَمِعْتُ أَبَا وَائِلٍ عَنْ عَبْدِ اللَّهِ عَنْ النَّب��يِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِكُلِّ غَادِرٍ لِوَاءٌ يَوْمَ الْقِيَامَةِ يُقَالُ هَذِهِ غَدْرَةُ فُلَانٍ","id":"Telah menceritakan kepada kami [Sa'id bin Ar Rabi'] telah menceritakan kepada kami [Syu'bah] dari [Sulaiman], ia berkata; aku mendengar [Abu Wa`il] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap pengkhianat akan mengibarkan bendera pada Hari Kiamat, dikatakan; ini adalah (bendera) pengkhianatan Fulan.\""},"2076":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ مَعْمَرِ بْنِ عَبْدِ اللَّهِ بْنِ نَافِعِ بْنِ نَضْلَةَ الْعَدَوِيِّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحْتَكِرُ إِلَّا خَاطِئٌ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Ahmad bin Khalid] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim] dari [Sa'id bin Al Musayyab] dari [Ma'mar bin Abdullah bin Nafi' bin Nadhlah Al 'Adawi], ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak menimbun kecuali ia akan berdosa.\" Beliau mengucapkan hingga dua kali."},"2077":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ إِسْرَائِيلَ عَنْ عَلِيِّ بْنِ سَالِمٍ عَنْ عَلِيِّ بْنِ زَيْدِ بْنِ جُدْعَانَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْجَالِبُ مَرْزُوقٌ وَالْمُحْتَكِرُ مَلْعُونٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Israil] dari [Ali bin Salim] dari [Ali bin Zaid bin Jud'an] dari [Sa'id bin Al Musayyab] dari [Umar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Semoga seorang Importir akan mendapatkan rizqi dan orang yang menimbun semoga dilaknat.\""},"2078":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حُمَيْدٍ وَثَابِتٍ وَقَتَادَةَ عَنْ أَنَسٍ قَالَ غَلَا السِّعْرُ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّاسُ يَا رَسُولَ اللَّهِ غَلَا السِّعْرُ فَسَعِّرْ لَنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ هُوَ الْخَالِقُ الْقَابِضُ الْبَاسِطُ الرَّازِقُ الْمُسَعِّرُ وَإِنِّي أَرْجُو أَنْ أَلْقَى رَبِّي وَلَيْسَ أَحَدٌ مِنْكُمْ يَطْلُبُنِي بِمَظْلَمَةٍ ظَلَمْتُهَا إِيَّاهُ بِدَمٍ وَلَا مَالٍ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah mengabarkan kepada kami [Hammad bin Salamah] dari [Humaid] serta [Tsabit] dan [Qatadah] dari [Anas], ia berkata; Pernah terjadi krisis pada masa Nabi shallallahu 'alaihi wasallam, lalu orang-orang berkata; \"Wahai Rasulullah, harga barang-barang telah melonjak, oleh karena itu tetapkanlah harga untuk kami! \" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah adalah Pencipta, Dzat yang membentangkan rizqi serta Pemberi rizqi dan yang menentukan harga. Sesungguhnya aku berharap dapat bertemu dengan Rabbku, sementara tidak ada salah seorang dari kalian yang menuntut kezhaliman yang pernah aku lakukan terhadapnya, baik yang berkaitan dengan darah maupun harta.\""},"2079":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا مَنْصُورُ بْنُ الْمُعْتَمِرِ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ أَنَّ حُذَيْفَةَ حَدَّثَهُمْ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَلَقَّتْ الْمَلَائِكَةُ رُوحَ رَجُلٍ مِمَّنْ قَبْلَكُمْ فَقَالُوا عَمِلْتَ مِنْ الْخَيْرِ شَيْئًا فَقَالَ لَا قَالُوا تَذَكَّرْ قَالَ كُنْتُ أُدَايِنُ النَّاسَ فَآمُرُ فِتْيَانِي أَنْ يُنْظِرُوا الْمُعْسِرَ وَيَتَجَاوَزُوا عَنْ الْمُوسِرِ قَالَ قَالَ اللَّهُ تَجَاوَزُوا عَنْهُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Manshur bin Al Mu'tamir] dari [Rib'i bin Hirasy] bahwa [Hudzaifah] telah menceritakan kepada mereka, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Para Malaikat mengambil ruh seorang laki-laki dari kaum sebelum kalian. Para Malaikat berkata; \"apakah engkau telah melakukan suatu kebaikan?\" laki-laki itu menjawab; \"Tidak.\" Para malaikat berkata; \"Ingat-ingatlah!.\" Laki-laki itu berkata; \"Dahulu aku pernah memberikan hutang kepada orang-orang, lalu aku memerintahkan kepada para pembantuku agar memberikan tangguh kepada mereka yang kesulitan, serta memberi kelapangan dalam pembayaran hutang kepada orang-orang yang kaya.\" Allah berfirman: \"Berilah kelapangan kepadanya.\""},"2080":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ صَالِحٍ أَبِي الْخَلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ حَكِيمِ بْنِ حِزَامٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَتَفَرَّقَا فَإِنْ صَدَقَا وَبَيَّنَا بُورِكَ لَهُمَا فِي بَيْعِهِمَا وَإِنْ كَذَبَا وَكَتَمَا مُحِقَ بَرَكَةُ بَيْعِهِمَا أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ بِإِسْنَادِهِ مِثْلَهُ","id":"Telah mengbarkan kepada kami [Sa'id bin 'Amir] dari [Sa'id] dari [Qatadah] dari [Shalih Abu Al Khalid] dari [Abdullah bin Al Harts] dari [Hakim bin Hizam] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua orang yang berjual beli, memiliki hak memilih selama mereka belum berpisah, dan apabila mereka jujur dan memberikan penjelasan, maka mereka akan diberkahi dalam jual beli tersebut, namun apabila ia berdusta dan menyembunyikan aib, maka berkah jual beli akan terhapus darinya.\" Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dengan sanad seperti itu."},"2081":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا ابْنُ أَبِي لَيْلَى عَنْ الْقَاسِمِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْبَيِّعَانِ إِذَا اخْتَلَفَا وَالْبَيْعُ قَائِمٌ بِعَيْنِهِ وَلَيْسَ بَيْنَهُمَا بَيِّنَةٌ فَالْقَوْلُ مَا قَالَ الْبَائِعُ أَوْ يَتَرَادَّانِ الْبَيْعَ","id":"Telah mengabarkan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Husyaim] telah menceritakan kepada kami [Ibnu Abu Laila] dari [Al Qasim bin Abdurrahman] dari [Ayahnya] dari [Abdullah], ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila dua orang yang berjual beli berselisih, sementara jual beli telah dilakukan dan keduanya tidak memiliki bukti, maka perkataan yang didengar adalah apa yang dikatakan oleh penjual atau mereka membatalkan jual beli.\""},"2082":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِمَاسَةَ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ لِامْرِئٍ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ يَبِيعَ عَلَى بَيْعِ أَخِيهِ حَتَّى يَتْرُكَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Ar Raqasyi] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Muhammad yaitu Ibnu Ishaq] dari [Yazid bin Abu Habib] dari [Abdurrahman bin Syimasah] dari ['Uqbah bin 'Amir], ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi orang yang beriman kepada Allah dan hari Akhir membeli barang yang telah dibeli (dipesan) saudaranya, hingga ia meninggalkannya.\""},"2083":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ حَدَّثَنَا قَتَادَةُ عَنْ الْحَسَنِ عَنْ عُقْبَةَ بْنِ عَامِرٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عُهْدَةُ الرَّقِيقِ ثَلَاثَةُ أَيَّامٍ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Aban bin Yazid] telah menceritakan kepada kami [Qatadah] dari [Al Hasan] dari ['Uqbah bin 'Amir] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jaminan seorang budak selama tiga hari.\""},"2084":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ هَمَّامٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُهْدَةُ الرَّقِيقِ ثَلَاثٌ فَفَسَّرَهُ قَتَادَةُ إِنْ وَجَدَ فِي الثَّلَاثِ عَيْبًا رَدَّهُ بِغَيْرِ بَيِّنَةٍ وَإِنْ وَجَدَهُ بَعْدَ ثَلَاثٍ لَمْ يَرُدَّهُ إِلَّا بِبَيِّنَةٍ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Hammam] dari [Qatadah] dari [Al Hasan] dari ['Uqbah bin 'Amir], ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Jaminan seorang budak selama tiga hari.\" Kemudian Qatadah menjelaskannya; \"Apabila ia mendapatkan aib dalam tiga hari, maka ia boleh mengembalikannya tanpa adanya bukti, namun jika ia mendapatkan cacatnya setelah berlalu tiga hari, maka ia tidak boleh mengembalikan budak tersebut kecuali dengan bukti yang nyata.\""},"2085":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْمِنْهَالِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا هِشَامٌ هُوَ ابْنُ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اشْتَرَى شَاةً مُصَرَّاةً أَوْ لَقْحَةً مُصَرَّاةً فَهُوَ بِالْخِيَارِ ثَلَاثَةَ أَيَّامٍ فَإِنْ رَدَّهَا رَدَّ مَعَهَا صَاعًا مِنْ طَعَامٍ لَا سَمْرَاءَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Minhal] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Hisyam yaitu Ibnu Hassan] dari [Muhammad bin Sirin] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membeli seekor kambing musharrah atau unta bunting yang hampir melahirkan dan air susunya ditahan, maka ia memiliki hak memilih selama tiga hari, apabila ia berkehendak, maka ia boleh mengembalikan disertai dengan satu sha' makanan, tidak harus gandum.\" "},"2086":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا يَحْيَى الْقَطَّانُ عَنْ عُبَيْدِ اللَّهِ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْغَرَرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Yahya Al Qaththan] dari ['Ubaidullah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang jual beli gharar. "},"2087":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الثِّمَارِ حَتَّى يَبْدُوَ صَلَاحُهَا نَهَى الْبَائِعَ وَالْمُشْتَرِيَ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang menjual buah hingga nampak kelayakannya. Beliau melarang baik kepada penjual ataupun pembeli.\""},"2088":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ابْتَاعَ ثَمَرَةً فَأَصَابَتْهُ جَائِحَةٌ فَلَا يَأْخُذَنَّ مِنْهُ شَيْئًا بِمَ تَأْخُذُ مَالَ أَخِيكَ بِغَيْرِ حَقٍّ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membeli buah kemudian buah tersebut terserang hama, janganlah ia mengambil sesuatupun darinya, dengan alasan apa ia mengambil harta saudaranya dengan tanpa hak.\""},"2089":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ مُحَمَّدِ بْنِ عَمْرٍو ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُحَاقَلَةِ وَالْمُزَابَنَةِ قَالَ عَبْد اللَّهِ الْمُحَاقَلَةُ بَيْعُ الزَّرْعِ بِالْبُرِّ وَقَالُوا كَذَلِكَ يَقُولُ ابْنُ الْمُسَيَّبِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah mengabarkan kepada kami [Khalid bin Abdullah] dari [Muhammad bin 'Amr], (dan diriwayatkan dari jalur yang lain) telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Muhammad bin 'Amr] dari [Abu Salamah] dari [Abu Sa'id], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang muhaqalah dan muzabanah.\" Abdullah berkata; muhaqalah adalah menjual tanaman dengan gandum. Dan para perawi berkata; \"Demikianlah yang dikatakan Ibnu Al Musayyab.\" "},"2090":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ الْأَوْزَاعِيِّ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَ رَخَّصَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْعِ الْعَرَايَا بِالتَّمْرِ وَالرُّطَبِ وَلَمْ يُرَخِّصْ فِي غَيْرِ ذَلِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Al Auza'i] dari [Ibnu Syihab] dari [Salim] dari [Ibnu Umar] dari [Zaid bin Tsabit], ia berkata; Rasulullah shallallahu 'alaihi wasallam memberikan keringanan dalam jual beli 'araya.\" "},"2091":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ابْتَاعَ طَعَامًا فَلَا يَبِعْهُ حَتَّى يَقْبِضَهُ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa membeli makanan maka janganlah ia menjualnya hingga ia menakarnya lebih dulu.\""},"2092":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ سَلَفٍ وَبَيْعٍ وَعَنْ شَرْطَيْنِ فِي بَيْعٍ وَعَنْ رِبْحِ مَا لَمْ يُضْمَنْ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Husain Al Mu'allim] dari ['Amr bin Syu'aib] dari [Ayahnya] dari [Kakeknya], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang jual beli dengan syarat diberi hutang, serta dua syarat dalam jual beli dan menjual barang yang tidak ada terjamin."},"2093":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اشْتَرَى عَبْدًا وَلَمْ يَشْتَرِطْ مَالَهُ فَلَا شَيْءَ لَهُ","id":"Telah mengabarkan kepada kami [Abdullah bin Maslamah] dari [Ibnu Abu Dzi`b] dari [Ibnu Syihab] dari [Salim] dari [Ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membeli seorang budak dan tidak mensyaratkan hartanya, maka ia tidak ada bagian untuknya.\""},"2094":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعَتَيْنِ وَعَنْ لِبْسَتَيْنِ عَنْ بَيْعِ الْمُنَابَذَةِ وَالْمُلَامَسَةِ قَالَ عَبْد اللَّهِ الْمُنَابَذَةُ يَرْمِي هَذَا إِلَى ذَاكَ وَيَرْمِي ذَاكَ إِلَى ذَا قَالَ كَانَ هَذَا فِي الْجَاهِلِيَّةِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Atha` bin Yazid] dari [Abu Sa'id Al Khudri], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dua macam transaksi jual beli dan dua pakaian yaitu jual beli dengan system munabadzah dan mulamasah.\" Abdullah mengatakan; munabadzah yaitu seseorang melempar barang kepada orang lain, begitu sebaliknya, orang tersebut ganti melempar barang kepada orang pertama.\" Abdullah berkata; \"Hal ini biasa di lakukan pada zaman jahiliyah.\" "},"2095":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْغَرَرِ وَعَنْ بَيْعِ الْحَصَاةِ قَالَ عَبْد اللَّهِ إِذَا رَمَى بِحَصًا وَجَبَ الْبَيْعُ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami ['Uqbah bin Khalid] telah menceritakan kepada kami ['Ubaidullah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang jual beli Hasha.\" Abdullah mengatakan; yaitu seseorang melempar dengan kerikil, maka jual beli harus dilaksanakan."},"2096":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ وَجَعْفَرُ بْنُ عَوْنٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْحَيَوَانِ بِالْحَيَوَانِ نَسِيئَةً ثُمَّ إِنَّ الْحَسَنَ نَسِيَ هَذَا الْحَدِيثَ وَلَمْ يَقُلْ جَعْفَرٌ ثُمَّ إِنَّ الْحَسَنَ نَسِيَ هَذَا الْحَدِيثَ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] serta [Ja'far bin 'Aun] dari [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundub], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang jual beli hewan dengan hewan dengan system pembayarannya ditangguhkan.\" Al Hasan lupa hadits ini, sedangkan Ja'far tidak mengatakan bahwa Al Hasan lupa hadits ini."},"2097":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ عَنْ مَالِكٍ قِرَاءَةً عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي رَافِعٍ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اسْتَسْلَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَكْرًا فَجَاءَتْ إِبِلٌ مِنْ إِبِلِ الصَّدَقَةِ قَالَ أَبُو رَافِعٍ فَأَمَرَنِي أَنْ أَقْضِيَ الرَّجُلَ بَكْرَهُ فَقُلْتُ لَمْ أَجِدْ فِي الْإِبِلِ إِلَّا جَمَلًا خِيَارًا رَبَاعِيًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطِهِ إِيَّاهُ فَإِنَّ خَيْرَ النَّاسِ أَحْسَنُهُمْ قَضَاءً قَالَ عَبْد اللَّهِ هَذَا يُقَوِّي قَوْلَ مَنْ يَقُولُ الْحَيَوَانُ بِالْحَيَوَانِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] dari [Malik] dengan membacakan riwayat, dari [Zaid bin Aslam] dari ['Atha` bin Yasar] dari [Abu Rafi'] mantan budak Rasulullah shallallahu 'alaihi wasallam, dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah berhutang seekor unta muda. Lalu unta sedekah datang kepada balaiu. Abu Rafi' berkata; kemudian beliau memerintah aku (mengambil unta tersebut) untuk kubayarkan kepada orang tersebut. aku berkata; \"Aku tidak mendapatkan kecuali unta pilihan yang berumur tujuh tahun.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berikan kepadanya, sesungguhnya sebaik-baik orang adalah orang yang paling baik dalam membayar (hutang).\" Abdullah berkata; \"Hal ini menguatkan pendapat orang yang mengatakan bolehnya (hutang) hewan dibayar dengan hewan.\""},"2098":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْمِنْهَالِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَلَقَّوْا الْجَلَبَ مَنْ تَلَقَّاهُ فَاشْتَرَى مِنْهُ شَيْئًا فَهُوَ بِالْخِيَارِ إِذَا دَخَلَ السُّوقَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Minhal] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Hisyam bin Hassan] dari [Muhammad] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mencegat para pedagang dari luar kota, barangsiapa mencegat kemudian membeli sesuatu darinya, maka pedagang tersebut berhak memilih apabila ia telah memasuki pasar.\""},"2099":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَبِيعُ بَعْضُكُمْ عَلَى بَيْعِ بَعْضٍ وَلَا تَلَقَّوْا السِّلَعَ حَتَّى يُهْبَطَ بِهَا الْأَسْوَاقَ وَلَا تَنَاجَشُوا","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah sebagian dari kalian menjual di atas penjualan orang lain, dan janganlah kalian mencegat barang yang datang dari luar (kota) hingga sampai di pasar, dan janganlan melakukan najasy.\" "},"2100":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي مَسْعُودٍ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَمَنِ الْكَلْبِ وَمَهْرِ الْبَغِيِّ وَحُلْوَانِ الْكَاهِنِ قَالَ عَبْد اللَّهِ حُلْوَانُ الْكَاهِنِ مَا يُعْطَى عَلَى كَهَانَتِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] telah menceritakan kepadaku [Az Zuhri] dari [Abu Bakr bin Abdurrahman] dari [Abu Mas'ud], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang (hasil) penjualan anjing dan pelacur serta dukun.\" Abdullah berkata; \"Hulwan Al Kahin adalah sesuatu yang diberikan lantaran perdukunan yang ia lakukan.\""},"2101":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا الْأَعْمَشُ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْ لَمَّا نَزَلَتْ الْآيَةُ فِي آخِرِ سُورَةِ الْبَقَرَةِ فِي الرِّبَا خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَلَاهُنَّ عَلَى النَّاسِ ثُمَّ حَرَّمَ التِّجَارَةَ فِي الْخَمْرِ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Al A'masy] dari [Muslim] dari [Masruq] dari ['Aisyah], ia berkata; \"Ketika turun ayat akhir Surat Al Baqarah tentang riba, Rasulullah shallallahu 'alaihi wasallam keluar dan membacakannya kepada para sahabat, setelah itu beliau mengharamkan bisnis khamer."},"2102":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْ لَمَّا نَزَلَتْ الْآيَاتُ مِنْ أَوَاخِرِ سُورَةِ الْبَقَرَةِ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاقْتَرَأَهُنَّ عَلَى النَّاسِ ثُمَّ نَهَى عَنْ التِّجَارَةِ فِي الْخَمْرِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Adh Dhuha] dari [Masruq] dari ['Aisyah], ia berkata; \"Ketika turun ayat akhir dari Surat Al Baqarah, Rasulullah shallallahu 'alaihi wasallam keluar dan membacakannya kepada para sahabat, kemudian beliau melarang dari bisnis khamer.\""},"2103":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي يَزِيدَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ وَعْلَةَ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ عَنْ جُلُودِ الْمَيْتَةِ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِبَاغُهَا طَهُورُهَا وَسَأَلْتُهُ عَنْ بَيْعِ الْخَمْرِ مِنْ أَهْلِ الذِّمَّةِ فَقُلْتُ لَهُ إِنَّ لَنَا أَعْنَابًا وَإِنَّا نَتَّخِذُ مِنْهَا هَذِهِ الْخُمُورَ فَنَبِيعُهَا مِنْ أَهْلِ الذِّمَّةِ قَالَ ابْنُ عَبَّاسٍ أَهْدَى رَجُلٌ مِنْ ثَقِيفٍ أَوْ دَوْسٍ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَاوِيَةً مِنْ خَمْرٍ فِي حَجَّةِ الْوَدَاعِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا عَلِمْتَ يَا أَبَا فُلَانٍ أَنَّ اللَّهَ قَدْ حَرَّمَهَا قَالَ لَا وَاللَّهِ قَالَ فَإِنَّ اللَّهَ قَدْ حَرَّمَهَا فَالْتَفَتَ إِلَى غُلَامِهِ فَقَالَ اخْرُجْ بِهَا إِلَى الْحَزْوَرَةِ فَبِعْهَا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَ مَا عَلِمْتَ يَا أَبَا فُلَانٍ أَنَّ الَّذِي حَرَّمَ شُرْبَهَا حَرَّمَ بَيْعَهَا قَالَ فَأَمَرَ بِهَا فَأُفْرِغَتْ فِي الْبَطْحَاءِ","id":"Telah mengabarkan kepada kami [Ahmad bin Khalid] telah menceritakan kepada kami [Muhammad yaitu Ishaq] dari [Abdurrahman bin Abu Yazid] dari [Al Qa'qa' bin Hakim] dari [Abdurrahman bin Wa'lah], ia berkata; \"Aku bertanya kepada [Ibnu Abbas] mengenai kulit binatang yang telah mati. Ibnu Abbas menjawab; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Menyamaknya telah menjadikan ia suci.\" Dan aku juga bertanya mengenai penjualan khamer kepada orang kafir dzimmi, aku katakan kepadanya; \"Sesungguhnya kami memiliki anggur yang kami jadikan khamer, kemudian kami menjualnya kepada orang kafir dzimmi.\" Ibnu Abbas berkata; \"Seorang laki-laki dari Tsaqif atau Daus pernah meberikan hadiah kepada Rasulullah shallallahu 'alaihi wasallam sekantong khamer pada saat haji wada', kemudian Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Tidakkah engkau tahu wahai Abu Fulan, bahwa Allah telah mengharamkannya.\" Laki-laki itu berujar; \"Tidak, demi Allah.\" Beliau bersabda: \"Sesungguhnya Allah telah mengharamkannya.\" Kemudian orang itu menoleh kepada budaknya sambil berkata; \"Bawalah ini keluar ke Jazwarah (sebuah tempat di Mekkah) dan juallah.\" Mendengar itu, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidakkah engkau mengetahui wahai Abu Fulan, bahwa sesuatu yang haram untuk meminumnya, maka haram pula menjualnya.\" Ibnu Abbas berkata; \"Kemudian beliau memerintahkan agar khamer tersebut ditumpahkan di Bathha`.\" "},"2104":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْوَلَاءِ وَعَنْ هِبَتِهِ قَالَ عَبْد اللَّهِ الْأَمْرُ عَلَى هَذَا لَا يُبَاعُ وَلَا يُوهَبُ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang menjual perwalian, dan menghibahkannya.\" [Abdullah] berkata; \"Perintah ini adalah tidak dijual dan tidak pula dihibahkan.\""},"2105":{"ar":" أَخْبَرَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ الْأَنْصَارِيَّ قَالَ أَعْتَقَ رَجُلٌ مِنَّا عَبْدًا لَهُ عَنْ دُبُرٍ قَالَ فَدَعَا بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَاعَهُ قَالَ جَابِرٌ وَإِنَّمَا مَاتَ عَامَ أَوَّلَ","id":"Telah mengabarkan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari ['Amr bin Dinar], ia berkata; aku mendengar [Jabir bin Abdullah Al Anshari] berkata; \"Seorang laki-laki dari kami hendak membebaskan seorang budaknya jika dirinya telah meninggal.\" Jabir berkata; \"Kemudian Rasulullah shallallahu 'alaihi wasallam memanggil budak tersebut dan menjualnya.\" [Jabir] berkata; \"Laki-laki tiu meninggal pada tahun pertama.\""},"2106":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَرِيكٌ عَنْ حُسَيْنِ بْنِ عَبْدِ اللَّهِ بْنِ عُبَيْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وَلَدَتْ أَمَةُ الرَّجُلِ مِنْهُ فَهِيَ مُعْتَقَةٌ عَنْ دُبُرٍ مِنْهُ أَوْ بَعْدَهُ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syarik] dari [Husain bin Abdullah bin 'Ubaidullah bin Abbas] dari [Ikrimah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Apabila budak wanita milik seorang laki-laki telah melahirkan (anak) darinya, maka budak tersebut merdeka setelah meninggalnya laki-laki tersebut.\""},"2107":{"ar":" أَخْبَرَنَا أَبُو مُحَمَّدٍ الْحَنَفِيُّ الْمَدَنِيُّ حَدَّثَنَا مَالِكٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ بَارِكْ لَهُمْ فِي مِكْيَالِهِمْ وَبَارِكْ لَهُمْ فِي صَاعِهِمْ وَمُدِّهِمْ يَعْنِي الْمَدِينَةَ","id":"Telah mengabarkan kepada kami [Abu Muhammad Al Hanafi Al Madani] telah menceritakan kepada kami [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, berkahilah mereka di dalam takaran mereka, dan berkahilah mereka dalam sha' mereka serta mud mereka.\" yaitu ketika beliau berada di Madinah."},"2108":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ مَسْرُوقٍ عَنْ بِلَالٍ قَالَ كَانَ عِنْدِي مُدُّ تَمْرٍ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدْتُ أَطْيَبَ مِنْهُ صَاعًا بِصَاعَيْنِ فَاشْتَرَيْتُ مِنْهُ فَأَتَيْتُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مِنْ أَيْنَ لَكَ هَذَا يَا بِلَالُ قُلْتُ اشْتَرَيْتُ صَاعًا بِصَاعَيْنِ قَالَ رُدَّهُ وَرُدَّ عَلَيْنَا تَمْرَنَا","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Isra`il] dari [Abu Ishaq] dari [Masruq] dari [Bilal], ia berkata; \"Aku pernah memiliki satu mud kurma yang hendak kuberikan kepada Nabi shallallahu 'alaihi wasallam, ternyata aku mendapatkan sesuatu yang lebih baik dari kurma itu, maka aku membeli satu sha' dengan dua sha'. Kemudian aku membawanya kepada Nabi shallallahu 'alaihi wasallam. Beliau lalu bertanya: \"Dari manakah engkau mendapatkan ini wahai BIlal?\" Aku katakan; \"Aku membeli satu sha' dengan dua sha'.\" Beliau bersabda: \"Kembalikan dan berikan kepada kami kurmamu!.\""},"2109":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا سُلَيْمَانُ هُوَ ابْنُ بِلَالٍ عَنْ عَبْدِ الْمَجِيدِ بْنِ سُهَيْلِ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُ سَمِعَ سَعِيدَ بْنَ الْمُسَيَّبِ يُحَدِّثُ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ وَأَبَا هُرَيْرَةَ حَدَّثَاهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ أَخَا بَنِي عَدِيٍّ الْأَنْصَارِيَّ فَاسْتَعْمَلَهُ عَلَى خَيْبَرَ فَقَدِمَ بِتَمْرٍ جَنِيبٍ قَالَ ابْنُ مَسْلَمَةَ يَعْنِي جَيِّدًا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكُلُّ تَمْرِ خَيْبَرَ هَكَذَا قَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ إِنَّا لَنَشْتَرِي الصَّاعَ بِالصَّاعَيْنِ مِنْ الْجَمْعِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَفْعَلُوا وَلَكِنْ مِثْلًا بِمِثْلٍ أَوْ بِيعُوا هَذَا وَاشْتَرُوا بِثَمَنِهِ مِنْ هَذَا وَكَذَلِكَ الْمِيزَانُ","id":"Telah mengabarkan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Sulaiman yaitu Ibnu Bilal] dari [Abdul Majid bin Suhail bin Abdurrahman] bahwa ia mendengar [Sa'id bin Al Musayyab] bercerita bahwa [Abu Sa'id Al Khudri] serta [Abu Hurairah] telah menceritakan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengutus saudara Bani 'Adi Al Anshari dan mengangkatnya sebagai pegawai untuk mengurusi Khaibar. Kemudian ia datang membawa kurma jenis Janib, -Ibnu Maslamah berkata; yaitu jenis kurma yang bagus kwalitasnya- Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Apakah semua kurma Khaibar seperti ini?\" Ia berkata; \"Tidak, demi Allah wahai Rasulullah. Sesungguhnya kami membeli satu sha' dengan dua sha' dari kurma jam'.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah engkau melakukan itu, namun belilah yang semisalnya dengan (harga) yang semisalnya, atau juallah ini dan belilah yang ini dengan uang hasil penjualannya. Demikianlah timbangannya.\""},"2110":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ مَالِكِ بْنِ أَوْسِ بْنِ الْحَدَثَانِ النَّصْرِيِّ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الذَّهَبُ بِالذَّهَبِ هَاءَ وَهَاءَ وَالْفِضَّةُ بِالْفِضَّةِ هَاءَ وَهَاءَ وَالتَّمْرُ بِالتَّمْرِ هَاءَ وَهَاءَ وَالْبُرُّ بِالْبُرِّ هَاءَ وَهَاءَ وَالشَّعِيرُ بِالشَّعِيرِ هَاءَ وَهَاءَ وَلَا فَضْلَ بَيْنَهُمَا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Az Zuhri] dari [Malik bin Aus bin Al Hadatsan An Nashri] dari [Umar bin Al Khathab], ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Emas dengan emas secara kontan, perak dengan perak secara kontan dan tidak boleh ada lebih diantara keduanya.\""},"2111":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا خَالِدٌ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ قَالَ قَامَ نَاسٌ فِي إِمَارَةِ مُعَاوِيَةَ يَبِيعُونَ آنِيَةَ الذَّهَبِ وَالْفِضَّةِ إِلَى الْعَطَاءِ فَقَامَ عُبَادَةُ بْنُ الصَّامِتِ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الذَّهَبِ بِالذَّهَبِ وَالْفِضَّةِ بِالْفِضَّةِ وَالْبُرِّ بِالْبُرِّ وَالتَّمْرِ بِالتَّمْرِ وَالشَّعِيرِ بِالشَّعِيرِ وَالْمِلْحِ بِالْمِلْحِ إِلَّا مِثْلًا بِمِثْلٍ سَوَاءً بِسَوَاءٍ فَمَنْ زَادَ أَوْ ازْدَادَ فَقَدْ أَرْبَى","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah mengabarkan kepada kami [Khalid] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Abu Al Asy'ats Ash Shan'ani], ia berkata; \"Pada waktu Mu'awiyah memimpin, orang-orang biasa menjual bejana emas dan perak kepada 'Atha`. Kemudian ['Ubadah bin Ash Shamit] berdiri dan berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarang menjual emas dengan perak, gandum dengan gandum, kurma dengan kurma serta jewawut dengan jewawut, garam dengan garam, kecuali semisal dengan yang semisal, secara sama (kontan), barangsiapa menambah atau minta tambahan, maka sungguh ia telah melakukan riba.\""},"2112":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ عَنْ ابْنِ عَبَّاسٍ قَالَ أَخْبَرَنِي أُسَامَةُ بْنُ زَيْدٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا الرِّبَا فِي الدَّيْنِ قَالَ عَبْد اللَّهِ مَعْنَاهُ دِرْهَمٌ بِدِرْهَمَيْنِ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari ['Ubaidullah bin Abu Yazid] dari [Ibnu Abbas], ia berkata; telah mengabarkan kepadaku [Usamah bin Zaid] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya riba bisa terjadi dalam hutang piutang.\" [Abdullah] berkata; \"Maksudnya adalah satu dirham dengan dua dirham.\""},"2113":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَ قَالَ كُنْتُ أَبِيعُ الْإِبِلَ بِالْبَقِيعِ فَأَبِيعُ بِالدَّنَانِيرِ وَآخُذُ الدَّرَاهِمَ وَأَبِيعُ بِالدَّرَاهِمِ وَآخُذُ الدَّنَانِيرَ وَرُبَّمَا قَالَ أَقْبِضُ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ رُوَيْدَكَ أَسْأَلُكَ إِنِّي أَبِيعُ الْإِبِلَ بِالْبَقِيعِ فَأَبِيعُ بِالدَّنَانِيرِ وَآخُذُ الدَّرَاهِمَ وَأَبِيعُ بِالدَّرَاهِمِ وَآخُذُ الدَّنَانِيرَ قَالَ لَا بَأْسَ أَنْ تَأْخُذَ بِسِعْرِ يَوْمِكَ مَا لَمْ تَفْتَرِقَا وَبَيْنَكُمَا شَيْءٌ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Hammad bin Salamah] dari [Simak bin Harb] dari [Sa'id bin Jubair] dari [Ibnu Umar], ia berkata; \"Aku pernah menjual unta di Baqi', aku menjualnya dengan beberapa dinar dan mengambil beberapa dirham, menjual dengan beberapa dirham dan mengambil beberapa dinar. Kemudian aku mendatangi Rasulullah shallallahu 'alaihi wasallam dan berkata; \"Wahai Rasulullah, pelan-pelanlah, aku hendak bertanya kepada anda. Sesungguhnya aku telah menjual unta di Baqi', kau menjual dengan beberapa dinar dan mengambil beberapa dirham dan menjual dengan beberapa dirham dan mengambil beberapa dinar. Beliau bersabda: \"Tidak mengapa engkau mengambil dengan harga hari itu, selama kalian belum berpisah, sementara diantara kalian ada sesuatu.\""},"2114":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا هِشَامٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّ دِرْعَهُ لَمَرْهُونَةٌ عِنْدَ رَجُلٍ مِنْ الْيَهُودِ بِثَلَاثِينَ صَاعًا مِنْ شَعِيرٍ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Hisyam] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah wafat, sementara baju perang beliau masih digadaikan pada seorang laki-laki Yahudi dengan tiga puluh sha' gandum.\""},"2115":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَبْدِ اللَّهِ بْنِ كَثِيرٍ عَنْ أَبِي الْمِنْهَالِ عَنْ ابْنِ عَبَّاسٍ قَالَ قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَهُمْ يُسْلِفُونَ فِي الثِّمَارِ فِي سَنَتَيْنِ وَثَلَاثٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلِّفُوا فِي الثِّمَارِ فِي كَيْلٍ مَعْلُومٍ وَوَزْنٍ مَعْلُومٍ وَقَدْ كَانَ سُفْيَانُ يَذْكُرُهُ زَمَانًا إِلَى أَجَلٍ مَعْلُومٍ ثُمَّ شَكَّكَهُ عَبَّادُ بْنُ كَثِيرٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Abdullah bin Katsir] dari [Abu Al Minhal] dari [Ibnu Abbas], ia berkata; \"Ketika Nabi shallallahu 'alaihi wasallam tiba di Madinah, penduduk Madinah menjual buah-buahan dengan pembayaran di muka, sedangkan buah-buahan yang dijualnya dijanjikan mereka dalam tempo setahun atau dua tahun kemudian. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang menjual kurma dengan berjanji, hendaklah dengan takaran tertentu, timbangan tertentu dan jangka waktu tertentu.\""},"2116":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ مُحَارِبٍ قَالَ سَمِعْتُ جَابِرًا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَزَنَ لَهُمْ دَرَاهِمَ فَأَرْجَحَهَا","id":"Telah menceritakan kepada kami [Sa'id bin Ar Rabi'] telah menceritakan kepada kami [Syu'bah] dari [Muharib], ia berkata; aku mendengar [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam menimbang untuk mereka beberapa dirham, kemudian melebihkannya."},"2117":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ سُوَيْدِ بْنِ قَيْسٍ قَالَ جَلَبْتُ أَنَا وَمَخْرَمَةُ الْعَبْدِيُّ بَزًّا مِنْ الْبَحْرَيْنِ إِلَى مَكَّةَ فَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْشِي فَسَاوَمَنَا بِسَرَاوِيلَ أَوْ اشْتَرَى مِنَّا سَرَاوِيلَ وَثَمَّ وَزَّانٌ يَزِنُ بِالْأَجْرِ فَقَالَ لِلْوَزَّانِ زِنْ وَأَرْجِحْ فَلَمَّا ذَهَبَ يَمْشِي قَالُوا هَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Simak bin Harb] dari [Suwaid bin Qais], ia berkata; aku dan Makhramah mendapatkan beberapa pakaian yang dating dari Bahrain menuju Makkah, kemudian Rasulullah shallallahu 'alaihi wasallam mendatangi kami dengan berjalan kami, beliau lalu menawar kami dengan beberapa celana panjang atau membeli beberapa celana dari kami, dan disana terdapat tukang penimbang yang melakukan penimbangan dengan diupah. Kemudian beliau berkata kepada tukang penimbang tersebut: \"Timbanglah dan penuhilah dalam timbangan.\" Setelah beliau pergi, mereka berkata; \"Ini adalah Rasulullah shallallahu 'alaihi wasallam.\""},"2118":{"ar":" حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَطْلُ الْغَنِيِّ ظُلْمٌ وَإِذَا أُتْبِعَ أَحَدُكُمْ عَلَى مَلِيءٍ فَلْيَتْبَعْ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mengulur-ulur waktu pembayaran hutang bagi yang mampu adalah kedzaliman, tapi jika piutangmu dialihkan kepada orang yang kaya, maka terimalah.\""},"2119":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبٍ عَنْ أَبِيهِ أَنَّهُ تَقَاضَى ابْنَ أَبِي حَدْرَدٍ دَيْنًا كَانَ لَهُ عَلَيْهِ فِي الْمَسْجِدِ فَارْتَفَعَتْ أَصْوَاتُهُمَا حَتَّى سَمِعَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي بَيْتِهِ فَخَرَجَ إِلَيْهِمَا فَنَادَى يَا كَعْبُ قَالَ لَبَّيْكَ يَا رَسُولَ اللَّهِ فَقَالَ ضَعْ مِنْ دَيْنِكَ فَأَوْمَأَ إِلَيْهِ أَيْ الشَّطْرَ قَالَ قَدْ فَعَلْتُ قَالَ قُمْ فَاقْضِهِ","id":"Telah menceritakan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] dari [Abdullah bin Ka'b] dari [Ayahnya] bahwa ia meminta Ibnu Abu Hadrad untuk membayar hutang yang menjadi tanggungannya di masjid, ternyata suara mereka meninggi hingga terdengar oleh Nabi shallallahu 'alaihi wasallam, ketika itu beliau tengah berada di rumahnya. Kemudian beliau keluar menemui mereka berdua seraya memanggil: \"Wahai Ka'b! \" Ka'b menjawab; \"Aku menyambut seruanmu wahai Rasulullah!.\" Beliau bersabda: \"Gugurkan sebagian hutangmu.\" Kemudian beliau memberi isyarat kepadanya, maksudnya (supaya digugurkan) setengah!.\" Ka'b berkata; \"Aku telah melakukannya.\" Beliau bersabda: \"Berdiri dan bayarlah hutang itu! \""},"2120":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا زَائِدَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ رِبْعِيٍّ عَنْ أَبِي الْيَسَرِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَنْظَرَ مُعْسِرًا أَوْ وَضَعَ عَنْهُ أَظَلَّهُ اللَّهُ فِي ظِلِّهِ يَوْمَ لَا ظِلَّ إِلَّا ظِلُّهُ قَالَ فَبَزَقَ فِي صَحِيفَتِهِ فَقَالَ اذْهَبْ فَهِيَ لَكَ لِغَرِيمِهِ وَذَكَرَ أَنَّهُ كَانَ مُعْسِرًا","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Zaidah] dari [Abdul Malik bin 'Umair] dari [Rib'i] dari [Abu Al Yasar], ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memberikan tangguh kepada orang yang mengalami kesulitan atau menggugurkan sebagian (hutang) darinya, maka Allah akan menaunginya pada hari yang tidak ada naungan kecuali naunganNya.\" Kemudian Abu Yasar meludah di kertasnya dan berkata kepada orang yang berhutang kepadanya; \"Pergilah, itu untukmu.\" Dan Abdul Malik menyebutkan bahwa orang tersebut tengah mengalami kesulitan."},"2121":{"ar":" حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا أَبُو جَعْفَرٍ الْخَطْمِيُّ عَنْ مُحَمَّدِ بْنِ كَعْبٍ الْقُرَظِيِّ عَنْ أَبِي قَتَادَةَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ نَفَّسَ عَنْ غَرِيمِهِ أَوْ مَحَا عَنْهُ كَانَ فِي ظِلِّ الْعَرْشِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami ['Affan bin Muslim] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Abu Ja'far Al Khathmi] dari [Muhammad bin Ka'b Al Qurazhi] dari [Abu Qatadah], ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membebaskan tanggungan orang yang berhutang kepadanya atau menghapus darinya, maka ia akan berada di bawah naungan 'Arsy pada hari Kiamat.\""},"2122":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا يَحْيَى أَنَّ أَبَا بَكْرِ بْنَ مُحَمَّدٍ أَخْبَرَهُ أَنَّهُ سَمِعَ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ يُحَدِّثُ أَنَّهُ سَمِعَ أَبَا بَكْرِ بْنَ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَدْرَكَ مَالَهُ بِعَيْنِهِ عِنْدَ إِنْسَانٍ قَدْ أَفْلَسَ أَوْ عِنْدَ رَجُلٍ قَدْ أَفْلَسَ فَهُوَ أَحَقُّ بِهِ مِنْ غَيْرِهِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Yahya] bahwa [Abu Bakr bin Muhammad] telah mengabarkan kepadanya, bahwa ia mendengar [Umar bin Abdul 'Aziz] menceritakan, bahwa ia mendengar [Abu Bakr bin Abdurrahman bin Al Harits bin Hisyam] bahwa ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendapati hartanya pada seorang yang bangkrut atau pada seorang laki-laki yang mengalami kebangkrutan, maka ia lebih berhak terhadap hartanya daripada orang lain.\""},"2123":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفْسُ الْمُؤْمِنِ مُعَلَّقَةٌ مَا كَانَ عَلَيْهِ دَيْنٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Sa'd bin Ibrahim] dari [Umar bin Abu Salamah] dari [Ayahnya] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jiwa seorang mukmin akan senantiasa tertahan selama ia memiliki hutang.\""},"2124":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ عَنْ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ فَارَقَ الرُّوحُ الْجَسَدَ وَهُوَ بَرِيءٌ مِنْ ثَلَاثٍ دَخَلَ الْجَنَّةَ مِنْ الْكِبْرِ وَالْغُلُولِ وَالدَّيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Ar Raqasyi] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Salim bin Abu Al Ja'd] dari [Ma'dan bin Abu Thalhah] dari [Tsauban] mantan budak Rasulullah shallallahu 'alaihi wasallam bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa nyawanya berpisah dengan jasad, sementara ia terbebas dari tiga perkara, maka ia akan masuk Surga; yaitu; kesombongan, pengkhianatan, dan hutang.\""},"2125":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ وَأَبُو الْوَلِيدِ عَنْ شُعْبَةَ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِرَجُلٍ لِيُصَلِّيَ عَلَيْهِ فَقَالَ صَلُّوا عَلَى صَاحِبِكُمْ فَإِنَّ عَلَيْهِ دَيْنًا قَالَ أَبُو قَتَادَةَ هُوَ عَلَيَّ يَا رَسُولَ اللَّهِ قَالَ بِالْوَفَاءِ قَالَ بِالْوَفَاءِ قَالَ فَصَلَّى عَلَيْهِ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] serta [Abu Al Walid] dari [Syu'bah] dari [Utsman bin Abdullah bin Mauhib] dari [Abdullah bin Abu Qatadah] dari [Ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam dihadapkan kepada (jenazah) seseorang agar beliau menshalatinya. Lalu beliau bersabda: \"Shalatilah sahabat kalian ini, sesungguhnya ia masih memiliki hutang.\" Abu Qatadah lalu berkata; \"Hutangnya menjadi tanggunganku wahai Rasulullah!.\" Beliau bersabda: \"Apakah dengan membayarnya?\" ia berkata; \"Dengan membayarnya.\" Abdullah berkata; \"Kemudian beliau menshalatinya.\""},"2126":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ مَا عَلَى الْأَرْضِ مُؤْمِنٌ إِلَّا أَنَا أَوْلَى النَّاسِ بِهِ فَمَنْ تَرَكَ دَيْنًا أَوْ ضَيَاعًا فَلْأُدْعَ لَهُ فَأَنَا مَوْلَاهُ وَمَنْ تَرَكَ مَالًا فَلِعَصَبَتِهِ مَنْ كَانَ قَالَ عَبْد اللَّهِ ضَيَاعًا يَعْنِي عِيَالًا وَقَالَ فَلْأُدْعَ لَهُ يَعْنِي ادْعُونِي لَهُ أَقْضِ عَنْهُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Sufyan] dari [Abu Az Zinad] dari Al A'raj] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku ada di tanganNya, tidak ada seorang mukmin yang berada diatas bumi, kecuali aku orang yang paling berhak terhadap dirinya. Barangsiapa meninggalkan hutang atau keluarga yang membutuhkan, maka hendaknya aku diundang untuknya, aku adalah walinya, yaitu undanglah aku, maka aku akan membayarkan untuknya.\""},"2127":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ أَبِي فُدَيْكٍ حَدَّثَنَا سَعِيدُ بْنُ سُفْيَانَ مَوْلَى الْأَسْلَمِيِّينَ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ مَعَ الدَّائِنِ حَتَّى يُقْضَى دَيْنُهُ مَا لَمْ يَكُنْ فِيمَا يَكْرَهُ اللَّهُ قَالَ وَكَانَ عَبْدُ اللَّهِ بْنُ جَعْفَرٍ يَقُولُ لِخَازِنِهِ اذْهَبْ فَخُذْ لِي بِدَيْنٍ فَإِنِّي أَكْرَهُ أَنْ أَبِيتَ لَيْلَةً إِلَّا وَاللَّهُ مَعِي بَعْدَمَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Mundzir Al Hizami] telah menceritakan kepada kami [Muhammad bin Isma'il bin Abu Fudaik] telah menceritakan kepada kami [Sa'id bin Sufyan] mantan budak Bani Aslam dari [Ja'far bin Muhammad] dari [Ayahnya] dari [Abdullah bin Ja'far], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah bersama orang yang berhutang, hingga hutangnya dilunasi, selama bukan dalam perkara yang Allah benci.\" Dan [Abdullah bin Ja'far] pernah berkata kepada penjaganya; \"Pergi dan ambillah hutangku. Sesungguhnya aku tidak suka untuk tinggal malam hari ini kecuali Allah bersamaku, yaitu setelah aku mendengar dari Rasulullah shallallahu 'alaihi wasallam.\""},"2128":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْمِنْهَالِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْيَدِ مَا أَخَذَتْ حَتَّى تُؤَدِّيَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Minhal] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundub], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seseorang bertanggung jawab terhadap apa yang ia ambil, hingga ia menunaikannya.\""},"2129":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا طَلْقُ بْنُ غَنَّامٍ عَنْ شَرِيكٍ وَقَيْسٍ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَدِّ إِلَى مَنْ ائْتَمَنَكَ وَلَا تَخُنْ مَنْ خَانَكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Thalq bin Ghannam] dari [Syarik] dan [Qais] dari [Abu Hashin] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tunaikanlah amanah kepada orang yang mempercayaimu dan janganlah engkau mengkhianati orang yang telah mengkhianatimu.\""},"2130":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَ أَهْدَى بَعْضُ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهِ قَصْعَةً فِيهَا ثَرِيدٌ وَهُوَ فِي بَيْتِ بَعْضِ أَزْوَاجِهِ فَضَرَبَتْ الْقَصْعَةَ فَانْكَسَرَتْ فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْخُذُ الثَّرِيدَ فَيَرُدُّهُ فِي الصَّحْفَةِ وَهُوَ يَقُولُ كُلُوا غَارَتْ أُمُّكُمْ ثُمَّ انْتَظَرَ حَتَّى جَاءَتْ قَصْعَةٌ صَحِيحَةٌ فَأَخَذَهَا فَأَعْطَاهَا صَاحِبَةَ الْقَصْعَةِ الْمَكْسُورَةِ قَالَ عَبْد اللَّهِ نَقُولُ بِهَذَا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Humaid] dari [Anas], ia berkata; \"Sebagian isteri Nabi shallallahu 'alaihi wasallam pernah memberi hadiah kepada beliau sepiring tsarid, sementara beliau berada di rumah sebagian isterinya, kemudian isterinya itu memukul piring tersebut hingga pecah, maka Nabi shallallahu 'alaihi wasallam mengambil tsarid (yang terjatuh) dan mengembalikannya ke dalam piring, beliau lalu bersabda: \"Makanlah, ibu kalian telah cemburu.\" Kemudian beliau menunggu hingga datang piring yang baik, lalu beliau mengambilnya dan memberikannya kepada pemilik piring yang pecah.\" Abdullah berkata; \"Kami berpendapat dengan hal ini.\" "},"2131":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْوَلِيدِ بْنِ كَثِيرٍ قَالَ حَدَّثَنِي عَمْرُو بْنُ شُعَيْبٍ عَنْ عَمْرٍو وَعَاصِمٍ ابْنَيْ سُفْيَانَ بْنِ عَبْدِ اللَّهِ بْنِ رَبِيعَةَ الثَّقَفِيِّ أَنَّ سُفْيَانَ بْنَ عَبْدِ اللَّهِ وَجَدَ عَيْبَةً فَأَتَى بِهَا عُمَرَ بْنَ الْخَطَّابِ فَقَالَ عَرِّفْهَا سَنَةً فَإِنْ عُرِفَتْ فَذَاكَ وَإِلَّا فَهِيَ لَكَ فَلَمْ تُعْرَفْ فَلَقِيَهُ بِهَا فِي الْعَامِ الْمُقْبِلِ فِي الْمَوْسِمِ فَذَكَرَهَا لَهُ فَقَالَ عُمَرُ هِيَ لَكَ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَنَا بِذَلِكَ قَالَ لَا حَاجَةَ لِي بِهَا فَقَبَضَهَا عُمَرُ فَجَعَلَهَا فِي بَيْتِ الْمَالِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Abu Usamah] dari [Al Walid bin Katsir], ia berkata; telah menceritakan kepadaku ['Amr bin Syu'aib] dari ['Amr] serta ['Ashim] dua anak Sufyan bin Abdullah bin Rabi'ah Ats Tsaqafi bahwa Sufyan bin Abdullah pernah menemu tas besar, kemudian ia membawanya kepada [Umar bin Al Khathab], Umarpun berkata; \"Umumkan selama satu tahun, apabila diketahui, maka itu adalah miliknya, namun jika tidak diketahui, maka barang tersebut adalah milikmu.\" Ketika tas itu tidak diketahui pemiliknya, maka ia menemui Umar lagi sambil membawa tas itu pada tahun mendatang yaitu pada saat musim haji, lalu ia menyebutkan tas itu kepadanya. Umar berkata; \"Tas itu menjadi milikmu, sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah memerintahkan hal itu kepada kami.\" Kemudian Sufyan bin Abdullah berkata; \"Aku tidak butuh tas itu.\" Umar akhirnya mengambil tas itu dan meletakkannya di baitul mal.\""},"2132":{"ar":" أَخْبَرَنَا مُعَاذُ بْنُ هَانِئٍ مِنْ أَهْلِ الْبَصْرَةِ حَدَّثَنَا حَرْبُ بْنُ شَدَّادٍ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنَا أَبُو سَلَمَةَ حَدَّثَنَا أَبُو هُرَيْرَةَ أَنَّهُ عَامَ فُتِحَتْ مَكَّةُ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ اللَّهَ حَبَسَ عَنْ مَكَّةَ الْفِيلَ وَسَلَّطَ عَلَيْهِمْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمُؤْمِنِينَ أَلَا وَإِنَّهَا لَمْ تَحِلَّ لِأَحَدٍ قَبْلِي وَلَا تَحِلُّ لِأَحَدٍ بَعْدِي أَلَا وَإِنَّهَا سَاعَتِي هَذِهِ حَرَامٌ لَا يُخْتَلَى خَلَاهَا وَلَا يُعْضَدُ شَجَرُهَا وَلَا تُلْتَقَطُ سَاقِطَتُهَا إِلَّا لِمُنْشِدٍ","id":"Telah mengabarkan kepada kami [Mu'adz bin Hani`] dari penduduk Bashrah, telah menceritakan kepada kami [Harb bin Syaddad] telah menceritakan kepada kami [Yahya bin Abu Katsir] telah menceritakan kepada kami [Abu Salamah], telah menceritakan kepada kami [Abu Hurairah] bahwa pada tahun penaklukan kota Makkah, Rasulullah shallallahu 'alaihi wasallam berdiri sambil bersabda: \"Sesungguhnya Allah menahan gajah dari Makkah, dan memberikan kekuasaan kepada Rasulullah shallallahu 'alaihi wasallam serta orang-orang mukmin terhadap mereka, ketahuilah pada saat itu, tidak halal bagi seorangpun sebelumku dan tidak halal pula bagi seorangpun setelahku, ketahuilah sesungguhnya itu adalah saatku ini, (adalah tanah) haram, tidak boleh rumputnya dicabut dan pohonnya ditebang serta tidak boleh barang temuannya diambil, kecuali bagi orang yang hendak mengumumkannya.\""},"2133":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ أَبِي مُسْلِمٍ عَنْ الْجَارُودِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَالَّةُ الْمُسْلِمِ حَرَقُ النَّارِ","id":"Telah menceritakan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari [Khalid Al Hadzdza`] dari [Yazid bin Abdullah bin Asy Syikhkhir] dari [Abu Muslim] dari [Al Jarud], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang seorang muslim yang hilang akan membakar di Neraka.\" "},"2134":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْجُرَيْرِيُّ عَنْ أَبِي الْعَلَاءِ عَنْ أَبِي مُسْلِمٍ الْجَذْمِيِّ عَنْ الْجَارُودِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَالَّةُ الْمُسْلِمِ حَرَقُ النَّارِ ضَالَّةُ الْمُسْلِمِ حَرَقُ النَّارِ ضَالَّةُ الْمُسْلِمِ حَرَقُ النَّارِ لَا تَقْرَبَنَّهَا قَالَ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ اللُّقَطَةُ نَجِدُهَا قَالَ أَنْشِدْهَا وَلَا تَكْتُمْ وَلَا تُغَيِّبْ فَإِنْ جَاءَ رَبُّهَا فَادْفَعْهَا إِلَيْهِ وَإِلَّا فَمَالُ اللَّهِ يُؤْتِيهِ مَنْ يَشَاءُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Al Hurairi] dari [Abu Al 'Ala`] dari [Abu Muslim Al Jadzmi] dari [Al Jarud], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang seorang muslim yang hilang, akan membakar di Neraka, barang seorang muslim yang hilang, akan membakar di Neraka, barang seorang muslim yang hilang, akan membakar di Neraka, oelh Karena itu, janganlah mendekatinya! \" lalu seorang laki-laki berkata; \"Wahai Rasulullah, (bagaimana dengan) barang temuan yang kami temukan?\" Beliau bersabda: \"Umumkan, dan jangan engkau rahasiakan, serta jangan engkau sembunyikan. Apabila pemiliknya datang, maka serahkanlah barang tersebut kepada pemiliknya. Jika tidak, maka itu adalah harta Allah yang Allah berikan kepada orang yang Dia kehendaki.\""},"2135":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ يَعْقُوبَ الْكُوفِيُّ عَنْ إِسْمَعِيلَ بْنِ جَعْفَرٍ عَنْ الْعَلَاءِ عَنْ مَعْبَدِ بْنِ كَعْبٍ السَّلَمِيِّ عَنْ أَخِيهِ عَبْدِ اللَّهِ بْنِ كَعْبٍ عَنْ أَبِي أُمَامَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اقْتَطَعَ حَقَّ امْرِئٍ مُسْلِمٍ بِيَمِينِهِ فَقَدْ أَوْجَبَ اللَّهُ لَهُ النَّارَ وَحَرَّمَ عَلَيْهِ الْجَنَّةَ فَقَالَ لَهُ رَجُلٌ وَإِنْ كَانَ شَيْئًا يَسِيرًا يَا رَسُولَ اللَّهِ قَالَ وَإِنْ قَضِيبٌ مِنْ أَرَاكٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْوَلِيدِ بْنِ كَثِيرٍ عَنْ مُحَمَّدِ بْنِ كَعْبِ بْنِ مَالِكٍ أَنَّهُ سَمِعَ أَخَاهُ عَبْدَ اللَّهِ بْنَ كَعْبِ بْنِ مَالِكٍ يُحَدِّثُ أَنَّ أَبَا أُمَامَةَ الْحَارِثِيَّ حَدَّثَهُ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Ya'qub Al Kufi] dari [Isma'il bin Ja'far] dari [Al 'Ala`] dari [Ma'bad bin Ka'b As Sulami] dari saudaranya yaitu [Abdullah bin Ka'b] dari [Abu Umamah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengambil hak seorang muslim dengan sumpah (palsu) nya, sungguh Allah telah mewajibkan Neraka baginya dan mengharamkan Surga atasnya.\" Seorang laki-laki berkata kepada beliau; \"Walaupun hanya sesuatu yang sedikit wahai Rasulullah?\" Beliau bersabda: \"Walaupun hanya ranting pohon syiwak.\" Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Usamah] dari [Al Walid bin Katsir] dari [Muhammad bin Ka'b bin Malik] bahwa ia mendengar saudaranya yaitu [Abdullah bin Ka'b bin Malik] menceritakan, bahwa [Abu Umamah Al Haritsi] menceritakan kepadanya, bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam…\" Kemudian ia menyebutkan hadits seperti di atas."},"2136":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ وَحَجَّاجٌ قَالَا حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي عَلِيُّ بْنُ مُدْرِكٍ قَالَ سَمِعْتُ أَبَا زُرْعَةَ يُحَدِّثُ عَنْ خَرَشَةَ بْنِ الْحُرِّ عَنْ أَبِي ذَرٍّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ لَا يُكَلِّمُهُمْ اللَّهُ وَلَا يَنْظُرُ إِلَيْهِمْ يَوْمَ الْقِيَامَةِ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ فَقُلْتُ يَا رَسُولَ اللَّهِ مَنْ هُمْ خَابُوا وَخَسِرُوا فَأَعَادَهَا فَقُلْتُ مَنْ هُمْ يَا رَسُولَ اللَّهِ فَقَالَ الْمُسْبِلُ وَالْمَنَّانُ وَالْمُنَفِّقُ سِلْعَتَهُ بِالْحَلِفِ كَاذِبًا","id":"Telah mengabarkan kepada kami [Abu Al Walid] serta [Hajjaj] keduanya berkata; telah menceritakan kepada kami [Syu'bah], ia berkata; telah menceritakan kepadaku [Ali bin Mudrik], ia berkata; aku mendengar [Abu Zur'ah] menceritakan dari [Kharasyah bin Al Hurr] dari [Abu Dzar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga orang yang tidak diajak bicara oleh Allah dan Allah tidak melihat kepada mereka pada Hari Kiamat serta tidak mensucikannya dan mereka mendapatkan adzab yang pedih.\" Kemudian aku berkata; \"Wahai Rasulullah, siapkah mereka yang telah merugi itu?\" Beliau mengulangi sabdanya, akupun berkata; \"Siapakah mereka wahai Rasulullah?\" Beliau bersabda: \"Orang yang menjulurkan kainnya hingga melebihi mata kaki, orang yang mengungkit pemberiannya, serta orang yang menjual barangnya dengan sumpah palsu.\""},"2137":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ حَدَّثَنِي طَلْحَةُ بْنُ عَبْدِ اللَّهِ بْنِ عَوْفٍ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ سَهْلٍ أَخْبَرَهُ أَنَّ سَعِيدَ بْنَ زَيْدٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ ظَلَمَ مِنْ الْأَرْضِ شِبْرًا فَإِنَّهُ يُطَوَّقُهُ مِنْ سَبْعِ أَرَضِينَ","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] dari [Syu'aib] dari [Az Zuhri] telah menceritakan kepadaku [Thalhah bin Abdullah bin 'Auf] bahwa [Abdurrahman bin Sahl] telah mengabarkan kepadanya, bahwa [Sa'id bin Zaid] berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menzhalimi (orang lain dengan mengambil) satu jengkal tanah, sungguh ia akan dikalungi dengan tujuh lapis bumi.\""},"2138":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ رَافِعٍ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ أَخْبَرَهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحْيَا أَرْضًا مَيْتَةً فَلَهُ فِيهَا أَجْرٌ وَمَا أَكَلَتْ الْعَافِيَةُ مِنْهَا فَلَهُ فِيهَا صَدَقَةٌ قَالَ أَبُو مُحَمَّد الْعَافِيَةُ الطَّيْرُ وَغَيْرُ ذَلِكَ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin 'Urwah], ia berkata; telah mengabarkan kepadaku ['Ubaidullah bin Abdurrahman bin Rafi'], bahwa [Jabir bin Abdullah] telah mengabarkan kepadanya dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa menghidupkan lahan yang mati, maka ia mendapatkan pahala apa yang dimakan oleh segala (makhluq) yang mencari rizqi, dan baginya sedekah dari lahan tersebut.\" Abu Muhammad berkata; \"Al 'Afiyah adalah burung dan yang lainnya.\""},"2139":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ الْحُمَيْدِيُّ حَدَّثَنَا الْفَرَجُ بْنُ سَعِيدِ بْنِ عَلْقَمَةَ بْنِ سَعِيدِ بْنِ أَبْيَضَ بْنِ حَمَّالٍ السَّبَائِيُّ الْمَأْرِبِيُّ حَدَّثَنِي عَمِّي ثَابِتُ بْنُ سَعِيدِ بْنِ أَبْيَضَ أَنَّ أَبَاهُ سَعِيدَ بْنَ أَبْيَضَ حَدَّثَهُ عَنْ أَبْيَضَ بْنِ حَمَّالٍ أَنَّهُ اسْتَقْطَعَ الْمِلْحَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي يُقَالُ لَهُ مِلْحُ شَذَّا بِمَأْرِبَ فَأَقْطَعَهُ ثُمَّ إِنَّ الْأَقْرَعَ بْنَ حَابِسٍ التَّمِيمِيَّ قَالَ يَا نَبِيَّ اللَّهِ إِنِّي قَدْ وَرَدْتُ الْمِلْحَ فِي الْجَاهِلِيَّةِ وَهُوَ بِأَرْضٍ لَيْسَ بِهَا مَاءٌ وَمَنْ وَرَدَهُ أَخَذَهُ وَهُوَ مِثْلُ مَاءِ الْعِدِّ فَاسْتَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَبْ��َضَ فِي قَطِيعَتِهِ فِي الْمِلْحِ فَقُلْتُ قَدْ أَقَلْتُهُ عَلَى أَنْ تَجْعَلَهُ مِنِّي صَدَقَةً فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ مِنْكَ صَدَقَةٌ وَهُوَ مِثْلُ مَاءِ الْعِدِّ مَنْ وَرَدَهُ أَخَذَهُ قَالَ وَقَطَعَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْضًا وَكَذَا بِالْجَوْفِ جَوْفِ مُرَادٍ مَكَانَهُ حِينَ أَقَالَهُ مِنْهُ قَالَ الْفَرَجُ فَهُوَ عَلَى ذَلِكَ مَنْ وَرَدَهُ أَخَذَهُ","id":"Telah mengabarkan kepada kami [Abdullah bin Az Zubair Al Humairi] telah menceritakan kepada kami [Al Faraj bin Sa'id bin 'Alqamah bin Sa'id bin Abyadh bin Hammal As Saba`i Al Ma`ribi] telah menceritakan kepadaku pamanku yaitu [Tsabit bin Sa'id bin Abyadh] bahwa ayahnya yaitu [Sa'id bin Abyadh] menceritakan kepadanya dari [Abyadh bin Hammal], bahwa ia pernah meminta lahan garam dari Rasulullah shallallahu 'alaihi wasallam yang disebut garam Syadzdza di Ma`rib. Lalu beliau memberi lahan tersebut, lalu Al Aqra` bin Habis At Taimi berkata; \"Wahai Nabiyullah, sesungguhnya aku telah mendatangi garam itu pada masa Jahiliyah, yaitu dilahan yang tidak ada airnya, lalu orang-orangpun datang dan mengambilnya. Garam tersebut seperti air yang tidak habis-habisnya.\" Nabi shallallahu 'alaihi wasallam lalu meminta agar pemberian garam kepadanya dibatalkan, aku berkata; \"Akupun membatalkannya dengan syarat lahan tersebut sebagai sedekah dariku.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Garam itu merupakan sedekah darimu, seperti air yang tidak habisnya, dan orang datang boleh mengambilnya.\" Sa'id bin Al Abyadh berkata; Rasulullah shallallahu 'alaihi wasallam pernah memberinya lahan, begitu juga di Al Jauf (lembah di Yaman) yaitu Jauf Murad Makanah, ketika ia menggagalkan pemberian tersebut dari Nabi shallallahu 'alaihi wasallam.\" Al Faraj berkata; \"Atas hal itu, maka orang yang datang, boleh mengambilnya.\""},"2140":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْطَعَهُ أَرْضًا قَالَ فَأَرْسَلَ مَعِي مُعَاوِيَةَ قَالَ أَعْطِهَا إِيَّاهُ قَالَ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ بِهَذَا الْحَدِيثِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Simak bin Harb] dari ['Alqamah bin Wail] dari [Ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam pernah memberinya lahan. Wail berkata; kemudian beliau mengirim Mu'awiyah bersamaku dan mengatakan: \"Berikan lahan itu kepadanya.\" Yahya berkata; telah menceritakan kepada kami Muhammad bin Basyar telah menceritakan kepada kami Ghundar dengan hadits ini."},"2141":{"ar":" أَخْبَرَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا سُلَيْمَانُ الْأَعْمَشُ حَدَّثَنَا أَبُو سُفْيَانَ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ حَدَّثَتْنِي أُمُّ مُبَشِّرٍ امْرَأَةُ زَيْدِ بْنِ حَارِثَةَ قَالَتْ دَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَائِطٍ لِي فَقَالَ يَا أُمَّ مُبَشِّرٍ أَمُسْلِمٌ غَرَسَ هَذَا أَمْ كَافِرٌ قُلْتُ مُسْلِمٌ فَقَالَ مَا مِنْ مُسْلِمٍ يَغْرِسُ غَرْسًا فَيَأْكُلُ مِنْهُ إِنْسَانٌ أَوْ دَابَّةٌ أَوْ طَيْرٌ إِلَّا كَانَتْ لَهُ صَدَقَةٌ","id":"Telah mengabarkan kepada kami [Al Mu'alla bin Asad] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] telah menceritakan kepada kami [Sulaiman Al A'masy] telah menceritakan kepada kami [Abu Sufyan], ia berkata; aku mendengar [Jabir bin Abdullah] berkata; telah menceritakan kepadaku [Ummu Mubasysyir] isteri Zaid bin Haritsah, ia berkata; Rasulullah shallallahu 'alaihi wasallam menemuiku di suatu kebun milikku, kemudian beliau bersabda: \"Wahai Ummu Mubasysyir, apakah orang yang menanam ini seorang muslim ataukah kafir?\" Aku menjawab; \"Seorang muslim.\" Beliau bersabda: \"Tidaklah seorang muslim menanam suatu tanaman, kemudian sebagiannya dimakan manusia atau binatang melata atau burung, melainkan hal itu menjadi sedekah baginya.\""},"2142":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ حَدَّثَنَا الْفَرَجُ بْنُ سَعِيدٍ قَالَ أَخْبَرَنِي عَمِّي ثَابِتُ بْنُ سَعِيدٍ عَنْ أَبِيهِ سَعِيدٍ عَنْ جَدِّهِ أَبْيَضَ بْنِ حَمَّالٍ أَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ حِمَى الْأَرَاكِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حِمَى فِي الْأَرَاكِ فَقَالَ أَرَاكَةٌ فِي حِظَارِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حِمَى فِي الْأَرَاكِ قَالَ فَرَجٌ يَعْنِي أَبْيَضُ بِحِظَارِي الْأَرْضَ الَّتِي فِيهَا الزَّرْعُ الْمُحَاطُ عَلَيْهَا","id":"Telah mengabarkan kepada kami [Abdullah bin Az Zubair] telah menceritakan kepada kami [Al Faraj bin Sa'id], ia berkata; telah mengabarkan kepadaku pamanku yaitu [Tsabit bin Sa'id] dari ayahnya yaitu [Sa'id] dari kakeknya yaitu [Abyadh bin Hammal], bahwa ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai lahan Syiwak yang dilindungi. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada lahan syiwak yang dilindungi.\" Ia berkata lagi; \"(pohon) Syiwak ada dalam lahanku telah dipagari.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada lahan syiwak yang dilindungi.\" Faraj berkata; \"Yang dimaksud Abyadh dengan hazhari adalah lahan yang terdapat tanaman yang mengelilingi lahan tersebut.\""},"2143":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ أَبِي الْمِنْهَالِ قَالَ سَمِعْتُ إِيَاسَ بْنَ عَبْدٍ الْمُزَنِيَّ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَبِيعُوا الْمَاءَ فَإِنِّي سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ بَيْعِ الْمَاءِ وَقَالَ عَمْرُو بْنُ دِينَارٍ لَا نَدْرِي أَيَّ مَاءٍ قَالَ يَقُولُ لَا أَدْرِي مَاءً جَارِيًا أَوْ الْمَاءَ الْمُسْتَقَى","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] dari ['Amr bin Dinar] dari [Abu Al Minhal] ia berkata; aku mendengar [Iyas bin Abdul Muzani] -ia termsuk di antara para sahabat Nabi shallallahu 'alaihi wasallam- ia berkata; \"Janganlah kalian menjual air, sesungguhnya aku pernah mendengar Nabi shallallahu 'alaihi wasallam melarang menjual air.\" 'Amr bin Dinar berkata; \"Kami tidak mengetahui air apakah itu.\" Abu Al Minhal berkata; Iyas berkata; \"Aku tidak tahu, apakah yang dimaksud air yang mengalir ataukah air yang ditimba?.\""},"2144":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا كَهْمَسٌ عَنْ سَيَّارٍ رَجُلٍ مِنْ فَزَارَةَ عَنْ أَبِيهِ عَنْ بُهَيْسَةَ عَنْ أَبِيهَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَأْذَنَهُ فَدَخَلَ بَيْنَهُ وَبَيْنَ قَمِيصِهِ وَقَدْ قَالَ عُثْمَانُ فَالْتَزَمَهُ فَقَالَ مَا الشَّيْءُ الَّذِي لَا يَحِلُّ مَنْعُهُ فَقَالَ الْمِلْحُ وَالْمَاءُ قَالَ مَا الشَّيْءُ الَّذِي لَا يَحِلُّ مَنْعُهُ قَالَ إِنْ تَفْعَلْ الْخَيْرَ خَيْرٌ لَكَ قَالَ مَا الشَّيْءُ الَّذِي لَا يَحِلُّ مَنْعُهُ قَالَ إِنْ تَفْعَلْ الْخَيْرَ خَيْرٌ لَكَ وَانْتَهَى إِلَى الْمِلْحِ وَالْمَاءِ قِيلَ لِعَبْدِ اللَّهِ تَقُولُ بِهِ فَأَوْمَأَ بِرَأْسِهِ","id":"Telah menceritakan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Kahmas] dari [Sayyar] seorang laki-laki dari Fazarah dari [Ayahnya] dari [Buhaisah] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam bahwa, ayahnya pernah meminta izin kepada Nabi shallallahu 'alaihi wasallam, kemudian ia memasuki jubah beliau -Utsman mengatakan; lalu ia terus menyertai beliau- Kemudian berkata; \"Wahai Rasulullah, sesuatu apakah yang tidak boleh untuk dihalangi?\" Beliau bersabda: \"Garam dan air.\" Ia berkata; \"Wahai Rasulullah, sesuatu apakah yang tidak boleh untuk dihalangi?\" Beliau bersabda: \"Engkau melakukan kebaikan adalah lebih baik bagimu.\" Beliau berhenti dengan menyebutkan garam dan air saja. Abdullah ditanya; \"Apakah engkau berpendapat dengan hadits itu?\" Abdullah menganggukkan kepalanya."},"2145":{"ar":" حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَلَ خَيْبَرَ بِشَطْرِ مَا يَخْرُجُ مِنْهَا مِنْ ثَمَرَةٍ أَوْ زَرْعٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] telah menceritakan kepadaku [Nafi'] dari [Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah mempekerjakan (penduduk) Khaibar dengan upah setengah dari hasil buminya yaitu berupa buah atau tanaman.\""},"2146":{"ar":" أَخْبَرَنَا أَبُو الْحَسَنِ عَنْ زَكَرِيَّا بْنِ إِسْحَقَ حَدَّثَنَا أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا يَقُولُ كُنَّا نُخَابِرُ قَبْلَ أَنْ يَنْهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْخِبْرِ بَسَنَتَيْنِ أَوْ ثَلَاثٍ عَلَى الثُّلُثِ وَالشَّطْرِ وَشَيْءٍ مِنْ تِبْنٍ فَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ أَرْضٌ فَلْيَحْرُثْهَا فَإِنْ كَرِهَ أَنْ يَحْرُثَهَا فَلْيَمْنَحْهَا أَخَاهُ فَإِنْ كَرِهَ أَنْ يَمْنَحَهَا أَخَاهُ فَلْيَدَعْهَا","id":"Telah mengabarkan kepada kami [Abu Al Hasan] dari [Zakariya bin Ishaq], telah menceritakan kepada kami [Abu Az Zubair] bahwa ia mendengar [Jabir] berkata; Kami pernah melakukan mukhabarah sebelum Rasulullah shallallahu 'alaihi wasallam melarang kami selama dua atau tiga tahun dengan bagian sepertiga, setengah, atau dengan jerami. Lalu Rasulullah shallallahu 'alaihi wasallam mengatakan kepada kami, \"Barangsiapa yang memiliki lahan hendaklah ia menanaminya. Jika ia tidak berkenan, hendaklah ia menyerahikan kepada saudaranya (untuk ditanami tanpa kompensasi). Dan jika ia tidak berkenan menyerahkan kepada saudaranya, hendaklah ia membiarkan lahan tersebut (tidak ditanami).\" "},"2147":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ أَبِي إِسْحَقَ الشَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِ قَالَ سَأَلْتُ عَبْدَ اللَّهِ بْنَ مَعْقِلٍ عَنْ الْمُزَارَعَةِ فَقَالَ أَخْبَرَنِي ثَابِتُ بْنُ الضَّحَّاكِ الْأَنْصَارِيُّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُزَارَعَةِ قَالَ لِعَبْدِ اللَّهِ تَقُولُ بِهِ قَالَ لَا أَقُولُ بِالْأَوَّلِ","id":"Telah mengabarkan kepada kami [Muhammad bin Uyainah] dari [Ali bin Mushir] dari [Abu Ishaq Asy Syaibani] dari [Abdullah bin As Sa`ib] ia berkata; aku bertanya kepada [Abdullah bin Ma'qil] tentang muzara'ah, lalu ia menjawab; telah mengabarkan kepadaku [Tsabit bin Adl Dlahak Al Anshari] bahwa Rasulullah shallallahu 'alaihi wasallam melarang melakukan muzara'ah. Ia bertanya kepada Abdullah; Engkau berpendapat seperti itu? ia menjawab; Tidak, aku berpendapat seperti yang pertama. "},"2148":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْأَرْضِ الْبَيْضَاءِ سَنَتَيْنِ أَوْ ثَلَاثًا","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zuhair] dari [Abu Az Zubair] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang menjual tanah yang tidak ada pepohonan atau tanamannya selama dua atau tiga tahun."},"2149":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ مُحَمَّدِ بْنِ عِكْرِمَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَبِيبَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَ كُنَّا نُكْرِي الْأَرْضَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا عَلَى السَّوَاقِي مِنْ الزَّرْعِ وَبِمَا سَعِدَ مِنْ الْمَاءِ مِنْهَا فَنَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ وَأَذِنَ لَنَا أَوْ قَالَ رَخَّصَ لَنَا فِي أَنْ نُكْرِيَهَا بِالذَّهَبِ وَالْوَرِقِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Ibrahim bin Sa'ad] dari [Muhammad bin Ikrimah bin Abdurrahman bin Al Harits bin Hisyam] dari [Muhammad bin Abdurrahman bin Abu Labibah] dari [Sa'id bin Al Musayyab] dari [Sa'ad bin Abu Waqqash] ia berkata; Kami menyewa tanah pada masa Rasulullah shallallahu 'alaihi wasallam dengan (imbalan) tanaman yang tumbuh di lahan dekat dengan parit, dan tanaman yang tumbuh pada tempat saluran air. Lalu Rasulullah shallallahu 'alaihi wasallam melarang kami melakukan hal itu, dan beliau mengizinkan kami, atau ia mengatakan; beliau membolehkan kami untuk menyewanya dengan emas dan perak."},"2150":{"ar":" حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَسْعُودِ بْنِ نِيَارٍ الْأَنْصَارِيِّ قَالَ جَاءَ سَهْلُ بْنُ أَبِي حَثْمَةَ إِلَى مَجْلِسِنَا فَحَدَّثَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا خَرَصْتُمْ فَخُذُوا وَدَعُوا دَعُوا الثُّلُثَ فَإِنْ لَمْ تَدَعُوا الثُّلُثَ فَدَعُوا الرُّبُعَ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari [Khubaib bin Abdurrahman] dari [Abdurrahman bin Mas'ud bin Dinar Al Anshari] ia berkata; [Sahal bin Abu Hatsmah] datang ke majelis kami lalu ia menyampaikan hadits bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika kalian memperkirakan buah yang masih berada di atas pohon dengan taksiran, maka ambillah dan sisakanlah, hendaklah kalian tinggalkan sepertinganya. Jika kalian tidak meninggalkan sepertiganya, maka tinggalkanlah seperempatnya.\""},"2151":{"ar":" حَدَّثَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُحَمَّدُ بْنُ جُحَادَةَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كَسْبِ الْإِمَاءِ","id":"Telah menceritakan kepada kami [Sahal bin Hammad] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Muhammad bin Juhadah] dari [Abu Hazim] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang melacurkan para budak perempuan."},"2152":{"ar":" أَخْبَرَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ قَارِظٍ أَنَّ السَّائِبَ بْنَ يَزِيدَ حَدَّثَهُ أَنَّ رَافِعَ بْنَ خَدِيجٍ حَدَّثَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَسْبُ الْحَجَّامِ خَبِيثٌ وَمَهْرُ الْبَغِيِّ خَبِيثٌ وَثَمَنُ الْكَلْبِ خَبِيثٌ","id":"Telah mengabarkan kepada kami [Wahab bin Jarir] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Ibrahim bin Abdullah bin Qarizh] bahwa [As Sa`ib bin Yazid] menceritakan bahwa [Rafi' bin Khadij] menyampaikan hadits bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Uang hasil membekam itu kotor, uang hasil perzinaan itu kotor dan uang hasil penjualan anjing itu kotor.\""},"2153":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حُمَيْدٌ الطَّوِيلُ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَجَمَهُ أَبُو طَيْبَةَ وَأَمَرَ لَهُ بِصَاعَيْنِ مِنْ طَعَامٍ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Humaid Ath Thawil] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam dibekam oleh Abu Thaibah dan beliau menyuruh untuk memberinya dua sha' makanan. "},"2154":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ الْأَعْمَشِ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَمَنِ عَسْبِ الْفَحْلِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Ibnu Fudlail] dari [Al A'masy] dari [Abu Hazim] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang mengambil upah hasil hasil penyewaan unta pejantan untuk dikawinkan."},"2155":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْقَاسِمُ بْنُ الْفَضْلِ حَدَّثَنَا أَبِي عَنْ الْمَهْرِيِّ قَالَ قَالَ أَبُو هُرَيْرَةَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ عَسْبِ الْفَحْلِ وَأَجْرِ الْمُومِسَةِ","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Al Qasim bin Al Fadlal] telah menceritakan kepada kami [ayahku] dari [Al Mahri] ia berkata; [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam melarang mengambil upah hasil penyewaan unta pejantan untuk dikawinkan dan upah (uang) hasil pelacuran."},"2156":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِسْمَعِيلُ هُوَ ابْنُ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ قَالَ سَمِعْتُ عَبْدَ الْمَلِكِ بْنَ عُمَيْرٍ يُحَدِّثُ قَالَ سَمِعْتُ عَمْرَو بْنَ حُرَيْثٍ عَنْ أَخِيهِ سَعِيدِ بْنِ حُرَيْثٍ وَكَانَتْ لَهُ صُحْبَةٌ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ بَاعَ مِنْكُمْ دَارًا أَوْ عَقَارًا قَمِنٌ أَنْ لَا يُبَارَكَ لَهُ إِلَّا أَنْ يَجْعَلَهُ فِي مِثْلِهِ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Isma'il] ia adalah Ibnu Ibrahim bin Muhajir, ia berkata; Aku mendengar [Abdul Malik bin Umair] menceritakan, ia berkata; Aku mendengar [Amr bin Huraits] dari saudaranya, [Sa'id bin Huraits], ia adalah sahabatnya, ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjual rumah atau tempat tinggal, maka ia lebih pantas untuk tidak mendapatkan keberkahan, kecuali jika ia menetapkan (harganya) sesuai dengan harga (yang berlaku).\""},"2157":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عَرْعَرَةُ بْنُ الْبِرِنْدِ السَّامِيُّ حَدَّثَنَا إِسْمَعِيلُ بْنُ مُسْلِمٍ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ احْتَفَرَ بِئْرًا فَلَيْسَ لِأَحَدٍ أَنْ يَحْفِرَ حَوْلَهُ أَرْبَعِينَ ذِرَاعًا عَطَنًا لِمَاشِيَتِهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami ['Ar'arah bin Al Birindi As Sami] telah menceritakan kepada kami [Isma'il bin Muslim] dari [Al Hasan] dari [Abdullah bin Mughaffal] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa menggali sumur, maka tidak boleh seorang pun menggali di sekitarnya dalam radius empat puluh hasta, sebagai tempat untuk menggiring hewan ternaknya.\""},"2158":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الشُّفْعَةِ إِذَا كَانَ طَرِيقُهُمَا وَاحِدًا قَالَ يُنْظَرُ بِهَا وَإِنْ كَانَ صَاحِبُهَا غَائِبًا","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Abdul Malik] dari ['Atha`] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam tentang syuf'ah jika jalan ke rumah itu satu, beliau bersabda: \"(Hak syuf'ah) itu dipertimbangkan meskipun pemiliknya tidak ada di tempat.\" "},"2159":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَ قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالشُّفْعَةِ فِي كُلِّ شِرْكٍ لَمْ يُقْسَمْ رَبْعَةٍ أَوْ حَائِطٍ لَا يَحِلُّ لَهُ أَنْ يَبِيعَ حَتَّى يُؤْذِنَ شَرِيكَهُ فَإِنْ شَاءَ أَخَذَ وَإِنْ شَاءَ تَرَكَ فَإِنْ بَاعَ وَلَمْ يُؤْذِنْهُ فَهُوَ أَحَقُّ بِهِ قِيلَ لِأَبِي مُحَمَّدٍ تَقُولُ بِهَذَا قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Abdullah bin Idris] dari [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam menetapkan hak syuf'ah pada setiap benda yang dimiliki secara bersama (kongsi) dan belum dibagi, baik berupa rumah atau kebun. Salah seorang (yang berkongsi) tidak berhak menjual hingga ia meminta izin kepada rekan kongsinya. Jika rekan kongsinya menghendaki, ia boleh mengambil harta itu, namun jika ia menghendaki, ia pun boleh meninggalkan harta itu. Jika ia menjual harta itu namun rekan kongsinya tidak mengizinkannya, maka rekan kongsinya lebih berhak atas harta itu. Dikatakan kepada Abu Muhammad; Apakah engkau berpendapat seperti itu? Ia menjawab; Ya."},"2160":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا دَاوُدُ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّ أَبَا مُوسَى الْأَشْعَرِيَّ اسْتَأْذَنَ عَلَى عُمَرَ ثَلَاثَ مَرَّاتٍ فَلَمْ يُؤْذَنْ لَهُ فَرَجَعَ فَقَالَ مَا رَجَعَكَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا اسْتَأْذَنَ الْمُسْتَأْذِنُ ثَلَاثَ مَرَّاتٍ فَإِنْ أُذِنَ لَهُ وَإِلَّا فَلْيَرْجِعْ فَقَالَ لَتَأْتِيَنَّ بِمَنْ يَشْهَدُ مَعَكَ أَوْ لَأَفْعَلَنَّ وَلَأَفْعَلَنَّ قَالَ أَبُو سَعِيدٍ فَأَتَانَا وَأَنَا فِي قَوْمٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ وَهُوَ فَزِعٌ مِنْ وَعِيدِ عُمَرَ إِيَّاهُ فَقَامَ عَلَيْنَا فَقَالَ أَنْشُدُ اللَّهَ مِنْكُمْ رَجُلًا سَمِعَ ذَلِكَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا شَهِدَ لِي بِهِ قَالَ فَرَفَعْتُ رَأْسِي فَقُلْتُ أَخْبِرْهُ أَنِّي مَعَكَ عَلَى هَذَا وَقَالَ ذَاكَ آخَرُونَ فَسُرِّيَ عَنْ أَبِي مُوسَى","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Daud] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri] bahwa [Abu Musa Al Asy'ari] meminta izin kepada Umar sebanyak tiga kali namun ia tidak mengizinkannya, ia pun kembali. (Umar) bertanya; Apa yang membuat engkau kembali? ia menjawab; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seseorang meminta izin sebanyak tiga kali, jika ia diizinkan (boleh masuk), namun jika tidak diizinkan maka sebaiknya ia kembali.\" Lalu ia berkata; Hendaklah engkau mendatangkan orang yang menyaksikan (hadits itu) bersamamu atau aku akan menghukummu dan benar-benar menghukummu. Abu Sa'id berkata; Lalu (Abu Musa) mendatangi kami, saat itu aku bersama sekelompok sahabat Rasulullah shallallahu 'alaihi wasallam di dalam masjid. Ia gelisah dengan ancaman Umar terhadap dirinya. Ia pun berdiri dan berkata; Aku memohon kepada Allah semoga ada seseorang dari kalian mendengar hadits itu dari Rasulullah shallallahu 'alaihi wasallam dan memberikan kesaksian tentang hadits itu untukku. Ia melanjutkan; Lalu aku mengangkat kepalaku dan berkata; Kabarkan kepadanya bahwa aku bersamamu dalam hal ini. Sabahat yang lain juga mengatakan demikian. Maka, Abu Musa pun menjadi gembira."},"2161":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضَرَبْتُ بَابَهُ فَقَالَ مَنْ ذَا فَقُلْتُ أَنَا قَالَ أَنَا أَنَا فَكَرِهَ ذَاكَ","id":"Telah mengabarkan kepada kami [Sa'id bin Ar Rabi'] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Al Munkadir] ia berkata; Aku mendengar [Jabir bin Abdullah] berkata; Aku datang menemui Rasulullah shallallahu 'alaihi wasallam dan mengetuk pintu rumahnya. Beliau bertanya: \"Siapa itu?\" Aku menjawab; Aku. Beliau bertanya lagi: \"Aku, aku siapa?\" Beliau tidak menyukai jawaban seperti itu."},"2162":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ مُحَارِبَ بْنَ دِثَارٍ يَذْكُرُ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَطْرُقَ الرَّجُلُ أَهْلَهُ لَيْلًا أَوْ يُخَوِّنَهُمْ أَوْ يَلْتَمِسَ عَثَرَاتِهِمْ قَالَ سُفْيَانُ قَوْلُهُ أَوْ يُخَوِّنَهُمْ أَوْ يَلْتَمِسَ عَثَرَاتِهِمْ مَا أَدْرِي شَيْءٌ قَالَهُ مُحَارِبٌ أَوْ شَيْءٌ هُوَ فِي الْحَدِيثِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] ia berkata; Aku mendengar [Muharib bin Ditsar] menyebutkan dari [Jabir bin Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang seseorang mendatangi keluarganya secara tiba-tiba pada malam hari, meragukan keamanahan mereka atau mencari kesalahan mereka. Sufyan berkata; Aku tidak tahu mengenahi ucapannya; 'Atau meragukan keamanahan mereka atau mencari kesalahan mereka', apakah Muharib yang mengatakannya ataukah termasuk kandungan dalam hadits itu."},"2163":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ عَوْفٍ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ عَبْدِ اللَّهِ بْنِ سَلَامٍ قَالَ لَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ اسْتَشْرَفَهُ النَّاسُ فَقَالُوا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَخَرَجْتُ فِيمَنْ خَرَجَ فَلَمَّا رَأَيْتُ وَجْهَهُ عَرَفْتُ أَنَّ وَجْهَهُ لَيْسَ بِوَجْهِ كَذَّابٍ فَكَانَ أَوَّلَ مَا سَمِعْتُهُ يَقُولُ يَا أَيُّهَا النَّاسُ أَفْشُوا السَّلَامَ وَأَطْعِمُوا الطَّعَامَ وَصِلُوا الْأَرْحَامَ وَصَلُّوا وَالنَّاسُ نِيَامٌ تَدْخُلُوا الْجَنَّةَ بِسَلَامٍ","id":"Telah mengabarkan kepada kami [Sa'id bin Amir] dari ['Auf] dari [Zurarah bin Aufa] dari [Abdullah bin Salam] ia berkata; Ketika Rasulullah shallallahu 'alaihi wasallam datang ke Madinah, beliau dijemput oleh orang-orang, mereka berkata; Rasulullah shallallahu 'alaihi wasallam telah datang. Ia melanjutkan; Lalu aku keluar bersama orang-orang yang keluar, ketika aku melihat wajah beliau, aku mengetahui bahwa wajahnya bukanlah wajah seorang pendusta. Hal pertama yang aku dengar adalah sabda beliau: \"Wahai manusia, tebarkanlah salam, berikanlah makanan, sambunglah tali silaturrahim terhadap kerabat, dan shalatlah di saat manusia sedang tertidur, niscaya kalian akan masuk surga dengan aman dan damai.\" "},"2164":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْمُسْلِمِ عَلَى الْمُسْلِمِ سِتٌّ يُسَلِّمُ عَلَيْهِ إِذَا لَقِيَهُ وَيُشَمِّتُهُ إِذَا عَطَسَ وَيَعُودُهُ إِذَا مَرِضَ وَيُجِيبُهُ إِذَا دَعَاهُ وَيَشْهَدُهُ إِذَا تُوُفِّيَ وَيُحِبُّ لَهُ مَا يُحِبُّ لِنَفْسِهِ وَيَنْصَحُ لَهُ بِالْغَيْبِ","id":"Telah mengabarkan kepada kami [Ubaidullah] dari [Isra`il] dari [Abu Ishaq] dari [Al Harits] dari [Ali] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Hak) seorang muslim atas muslim yang lain ada enam; Mengucapkan salam jika bertemu dengannya, mendoakannya jika ia bersin, menjenguknya jika ia sakit, menghadiri undangan jika ia mengundang, mengiringi jenazahnya jika ia meninggal dunia, mencintainya seperti mencintai diri sendiri, dan mendoakannya di waktu tidak ada.\""},"2165":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا حَيْوَةُ أَخْبَرَنَا أَبُو هَانِىءٍ الْخَوْلَانِيُّ أَنَّ أَبَا عَلِيٍّ الْجَنْبِيَّ حَدَّثَهُ عَنْ فَضَالَةَ بْنِ عُبَيْدٍ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُسَلِّمُ الرَّاكِبُ عَلَى الْمَاشِي وَالْقَائِمُ عَلَى الْقَاعِدِ وَالْقَلِيلُ عَلَى الْكَثِيرِ","id":"Telah mengabarkan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Haiwah] telah mengabarkan kepada kami [Abu Hani` Al Khaulani] bahwa [Abu Ali Al Janbi] menceritakan dari [Fadlalah bin Ubaid] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Hendaklah pengendara memberi salam kepada pejalan kaki, orang yang berdiri memberi salam kepada orang yang duduk, dan kelompok yang sedikit memberi salam kepada kelompok yang banyak.\""},"2166":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْيَهُودَ إِذَا سَلَّمَ أَحَدُهُمْ فَإِنَّمَا يَقُولُ السَّامُ عَلَيْكَ قُلْ عَلَيْكَ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya jika salah seorang dari orang-orang yahudi memberi salam kepada salah seorang dari kalian, ia akan mengatakan; ASSAMU'ALAIKUM (semoga kecelakaan untukmu), maka jawablah; 'ALAIKA (melainkan untukmu).\""},"2167":{"ar":" حَدَّثَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ عَنْ سَيَّارٍ قَالَ كُنْتُ أَمْشِي مَعَ ثَابِتٍ الْبُنَانِيِّ فَمَرَّ بِصِبْيَانٍ فَسَلَّمَ عَلَيْهِمْ وَحَدَّثَ ثَابِتٌ أَنَّهُ كَانَ مَعَ أَنَسٍ فَمَرَّ بِصِبْيَانٍ فَسَلَّمَ عَلَيْهِمْ وَحَدَّثَ أَنَسٌ أَنَّهُ كَانَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَرَّ بِصِبْيَانٍ فَسَلَّمَ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Sahal bin Hammad] telah menceritakan kepada kami [Syu'bah] dari [Sayyar] ia berkata; Aku pernah berjalan bersama Tsabit Al Bunani, lalu ia melewati beberapa anak kecil dan memberi salam kepada mereka. [Tsabit] menceritakan bahwa ia pernah bersama Anas, lalu ia melewati beberapa anak kecil dan memberi salam kepada mereka. [Anas] menceritakan bahwa ia pernah berjalan bersama Nabi shallallahu 'alaihi wasallam, lalu beliau melewati beberapa anak kecil dan memberi salam kepada mereka."},"2168":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ عَنْ شُعَيْبِ بْنِ أَبِي حَمْزَةَ عَنْ ابْنِ أَبِي حُسَيْنٍ حَدَّثَنِي شَهْرٌ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ بْنِ السَّكَنِ إِحْدَى نِسَاءِ بَنِي عَبْدِ الْأَشْهَلِ أَنَّهَا بَيْنَا هِيَ فِي نِسْوَةٍ مَرَّ عَلَيْهِنَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ عَلَيْهِنَّ","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] dari [Syu'aib bin Abu Hamzah] dari [Ibnu Abu Husain] telah menceritakan kepadaku [Syahar] dari [Asma` bintu Yazid bin As Sakan], seorang wanita banu Abdul Asyhal, bahwa ia sedang bersama beberapa kaum wanita, Nabi shallallahu 'alaihi wasallam melewati mereka lalu beliau memberi salam kepada mereka."},"2169":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ عَنْ شُعَيْبِ بْنِ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَائِشُ هَذَا جِبْرِيلُ يَقْرَأُ عَلَيْكِ السَّلَامَ قَالَتْ وَعَلَيْهِ السَّلَامُ وَرَحْمَةُ اللَّهِ قَالَتْ وَهُوَ يَرَى مَا لَا أَرَى","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] dari [Syu'aib bin Abu Hamzah] dari [Az Zuhri] ia berkata; Telah menceritakan kepadaku [Abu Salamah bin Abdurrahman] bahwa [Aisyah], isteri Nabi shallallahu 'alaihi wasallam, berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Aisyah, ini Jibril menyampaikan salam untukmu.\" Ia menjawab; Semoga keselamatan dan rahmat Allah tercurah untuknya. Ia mengatakan lagi; Beliau melihat apa yang tidak aku lihat."},"2170":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا سُلَيْمَانُ هُوَ ابْنُ الْمُغِيرَةِ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُهُ حِينَ قَضَى صَلَاتَهُ فَكُنْتُ أَوَّلَ مَنْ حَيَّا بِتَحِيَّةِ الْإِسْلَامِ قَالَ عَلَيْكَ السَّلَامُ وَرَحْمَةُ اللَّهِ مِمَّنْ أَنْتَ قَالَ قُلْتُ مِنْ غِفَارٍ قَالَ فَأَهْوَى بِيَدِهِ قُلْتُ فِي نَفْسِي كَرِهَ أَنِّي انْتَمَيْتُ إِلَى غِفَارٍ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Sulaiman], ia adalah Ibnu Al Mughirah, dari [Humaid bin Hilal] dari [Abdullah bin Ash Shamit] dari [Abu Dzarr] ia berkata; Rasulullah shallallahu 'alaihi wasallam sedang melakukan shalat, lalu aku menghampirinya ketika beliau telah menyelesaikan shalat. Akulah orang pertama yang mengucapkan ucapan selamat yang Islami. Beliau menjawab: 'ALAIKASSALAM WA RAHMATULLAH (semoga keselamatan dan rahmat Allah juga tercurah untukmu) dari golongan mana engkau?\" ia mengatakan; Aku menjawab; Aku dari Ghifar. Ia melanjutkan; Lalu beliau menurunkan tangannya, aku berkata dalam hati; Beliau tidak suka aku bergabung ke kabilah Ghifar."},"2171":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ عَوْفٍ عَنْ أَبِي رَجَاءٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَ جَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ السَّلَامُ عَلَيْكُمْ فَرَدَّ عَلَيْهِ وَقَالَ عَشْرٌ ثُمَّ جَاءَ رَجُلٌ فَسَلَّمَ فَقَالَ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ فَرَدَّ عَلَيْهِ وَقَالَ عِشْرُونَ ثُمَّ جَاءَ رَجُلٌ فَسَلَّمَ فَقَالَ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ فَرَدَّ عَلَيْهِ وَقَالَ ثَلَاثُونَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah menceritakan kepada kami [Ja'far bin Sulaiman] dari ['Auf] dari [Abu Raja`] dari [Imran bin Hushain] ia berkata; Ada seseorang datang kepada Nabi shallallahu 'alaihi wasallam memberi salam dengan mengucapkan; ASSALAMU 'ALAIKUM, beliau membalasnya dan mengatakan: \"Sepuluh.\" Kemudian seseorang datang lagi seraya memberi salam dengan mengucapkan; ASSALAMU 'ALAIKUM WARAHMATULLAH, beliau membalasnya dan mengatakan: \"Dua puluh.\" Kemudian datang lagi seseorang memberi salam dengan mengucapkan; ASSALAMU 'ALAIKUM WA RAHMATULLAH WA BARAKATUH, beliau membalasnya dan mengatakan: \"Tiga puluh.\""},"2172":{"ar":" أَخْبَرَنَا إِسْحَقُ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ الْحُضَيْنِ عَنْ الْمُهَاجِرِ بْنِ قُنْفُذٍ أَنَّهُ سَلَّمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَبُولُ فَلَمْ يَرُدَّ عَلَيْهِ السَّلَامَ حَتَّى تَوَضَّأَ فَلَمَّا تَوَضَّأَ رَدَّهُ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Ishaq] telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [ayahku] dari [Qatadah] dari [Al Hasan] dari [Hudlain] dari [Al Muhajir bin Qunfudz] bahwa ia pernah memberi salam kepada Nabi shallallahu 'alaihi wasallam, saat itu beliau sedang buang air kecil, namun beliau tidak membalas salamnya hingga beliau berwudlu`, setelah selesai berwudlu` beliau membalas ucapan salamnya."},"2173":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ بِسْطَامَ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَدْخُلُوا عَلَى النِّسَاءِ قِيلَ يَا رَسُولَ اللَّهِ إِلَّا الْحَمْوُ قَالَ الْحَمْوُ الْمَوْتُ قَالَ يَحْيَى الْحَمْوُ يَعْنِي قَرَابَةَ الزَّوْجِ","id":"Telah mengabarkan kepada kami [Yahya bin Bistham] telah menceritakan kepada kami [Laits bin Sa'ad] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari [Uqbah bin Amir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menemui kaum perempuan.\" Dikatakan; Wahai Rasulullah, hanya Al Hamwu. Beliau menjawab: \"Al Hamwu adalah kematian.\" Yahya mengatakan; Al Hamwu adalah kerabat dekat suami."},"2174":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ وَأَبُو نُعَيْمٍ عَنْ سُفْيَانَ عَنْ يُونُسَ عَنْ عَمْرِو بْنِ سَعِيدٍ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ جَرِيرٍ قَالَ سَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نَظْرَةِ الْفَجْأَةِ فَقَالَ اصْرِفْ بَصَرَكَ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dan [Abu Nu'aim] dari [Sufyan] dari [Yunus] dari [Amr bin Sa'id] dari [Abu Zur'ah bin Amr bin Jarir] dari [Jarir] ia berkata; Aku pernah bertanya kepada Nabi shallallahu 'alaihi wasallam tentang melihat dengan pandangan sekilas tanpa sengaja. Beliau menjawab: \"Palingkanlah pandanganmu.\""},"2175":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ إِسْحَقَ عَنْ نَافِعٍ عَنْ صَفِيَّةَ بِنْتِ أَبِي عُبَيْدٍ عَنْ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ سُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَيْلِ الْمَرْأَةِ فَقَالَ شِبْرًا فَقُلْتُ يَا رَسُولَ اللَّهِ إِذَنْ تَبْدُوَ أَقْدَامُهُنَّ قَالَ قَدْرَ ذِرَاعٍ لَا يَزِدْنَ عَلَيْهِ قَالَ عَبْد اللَّهِ النَّاسُ يَقُولُونَ عَنْ نَافِعٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Khalid] telah menceritakan kepada kami [Muhammad], ia adalah Ibnu Ishaq, dari [Nafi'] dari [Shafiyyah bintu Abu Ubaid] dari [Ummu Salamah], isteri Nabi shallallahu 'alaihi wasallam, ia berkata; Nabi shallallahu 'alaihi wasallam pernah ditanya tentang panjang baju (yang menjulur ke tanah) bagi kaum wanita. Beliau menjawab: \"Satu jengkal.\" Lalu aku bertanya; Wahai Rasulullah, jika demikian, telapak kaki mereka akan terlihat. Beliau menjawab: \"Satu hasta, tidak lebih dari itu.\" Abdullah berkata; Orang-orang mengatakan dari Nafi' dari Sulaiman bin Yasar."},"2176":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ حَدَّثَنِي رِبْعِيُّ بْنُ حِرَاشٍ عَنْ امْرَأَتِهِ عَنْ أُخْتٍ لِحُذَيْفَةَ قَالَتْ خَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مَعْشَرَ النِّسَاءِ أَمَا لَكُنَّ فِي الْفِضَّةِ مَا تَحَلَّيْنَ بِهِ أَمَا إِنَّهُ لَيْسَتْ مِنْكُنَّ امْرَأَةٌ تَحَلَّى الذَّهَبَ فَتُظْهِرَهُ إِلَّا عُذِّبَتْ بِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Manshur] telah menceritakan kepadaku [Rib'i bin Hirasy] dari [isterinya] dari [saudari Hudzaifah], ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah menyampaikan khutbah kepada kami, beliau mengatakan: \"Wahai kaum wanita, ketahuilah, perak itu dapat dijadikan perhiasan oleh kalian. Tidaklah seseorang dari kalian mengenakan emas sebagai perhiasan, kemudian ia menampakkannya, kecuali ia akan disiksa karena hal itu.\""},"2177":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ثَابِتِ بْنِ عُمَارَةَ عَنْ غُنَيْمِ بْنِ قَيْسٍ عَنْ أَبِي مُوسَى أَيُّمَا امْرَأَةٍ اسْتَعْطَرَتْ ثُمَّ خَرَجَتْ لِيُوجَدَ رِيحُهَا فَهِيَ زَانِيَةٌ وَكُلُّ عَيْنٍ زَانٍ وَقَالَ أَبُو عَاصِمٍ يَرْفَعُهُ بَعْضُ أَصْحَابِنَا","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Tsabit bin Umarah] dari [Ghunaim bin Qais] dari [Abu Musa]; \"Wanita manapun yang memakai wewangian (parfum), lalu keluar rumah agar tercium aroma wewangian (parfum) nya, maka ia adalah wanita pezina dan setiap mata (yang memandang) adalah penyakit.\" Abu 'Ashim berkata; Sebagian sahabat kami memarfu'kannya."},"2178":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَ لَعَنَ اللَّهُ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ فَبَلَغَ ذَلِكَ امْرَأَةً مِنْ بَنِي أَسَدٍ يُقَالُ لَهَا أُمُّ يَعْقُوبَ فَجَاءَتْ فَقَالَتْ بَلَغَنِي أَنَّكَ لَعَنْتَ كَيْتَ وَكَيْتَ فَقَالَ وَمَا لِي لَا أَلْعَنُ مَنْ لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي كِتَابِ اللَّهِ فَقَالَتْ لَقَدْ قَرَأْتُ مَا بَيْنَ اللَّوْحَيْنِ فَمَا وَجَدْتُ فِيهِ مَا تَقُولُ قَالَ لَئِنْ كُنْتِ قَرَأْتِيهِ لَقَدْ وَجَدْتِيهِ أَمَا قَرَأْتِ { مَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا } فَقَالَتْ بَلَى قَالَ فَإِنَّهُ قَدْ نَهَى عَنْهُ فَقَالَتْ فَإِنِّي أَرَى أَهْلَكَ يَفْعَلُونَهُ قَالَ فَادْخُلِي فَانْظُرِي فَدَخَلَتْ فَنَظَرَتْ فَلَمْ تَرَ مِنْ حَاجَتِهَا شَيْئًا فَقَالَ لَوْ كَانَتْ كَذَلِكِ مَا جَامَعْتُهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] ia berkata; Allah melaknat para wanita yang menato dan yang minta ditato, wanita yang mencukur alisnya dan yang merenggangkan gigi agar terlihat cantik, yang dapat merubah ciptaan Allah. Berita itu sampai kepada seorang wanita dari Banu Asad yang dipanggil Ummu Ya'qub. Ia kemudian datang dan berkata; Telah sampai berita kepadaku bahwa engkau telah melaknat ini dan itu. Ia menjawab; Bagaimana aku tidak melaknat siapa yang telah dilaknat oleh Rasulullah shallallahu 'alaihi wasallam sedangkan hal itu terdapat di dalam Kitabullah. Ia mengatakan; Aku telah membaca kandungan (Al Qur`an), namun aku tidak menemukan apa yang engkau katakan. Ia mengatakan; Jika engkau membacanya, tentu engkau akan menemukannya. Tidakkah engkau membaca: (Apa yang diberikan Rasul kepadamu maka terimalah, dan apa yang dilarang olehnya maka tinggalkanlah). Maka ia menjawab; Benar. Ia mengatakan; Sesungguhnya beliau telah melarang hal itu. Maka wanita itu berkata; Sesungguhnya keluargamu melakukan hal itu. Ia mengatakan; Masuk dan lihatlah. Ia pun masuk dan melihatnya, namun ia tidak mendapat melihat dari sesuatu yang diperlukannya. (Abdullah) berkata; Seandainya ia (isteri Abdullah) seperti engkau, niscaya aku tidak akan menggaulinya."},"2179":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنِي يَحْيَى بْنُ أَيُّوبَ الْحَضْرَمِيُّ أَخْبَرَنِي عَيَّاشُ بْنُ عَبَّاسٍ الْحِمْيَرِيُّ عَنْ أَبِي الْحُصَيْنِ الْحَجْرِيِّ عَنْ أَبِي عَامِرٍ قَالَ سَمِعْتُ أَبَا رَيْحَانَةَ صَاحِبَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ عَشْرِ خِصَالٍ مُكَامَعَةِ الرَّجُلِ الرَّجُلَ فِي شِعَارٍ وَاحِدٍ لَيْسَ بَيْنَهُمَا شَيْءٌ وَمُكَامَعَةِ الْمَرْأَةِ الْمَرْأَةَ فِي شِعَارٍ وَاحِدٍ لَيْسَ بَيْنَهُمَا شَيْءٌ وَالنَّتْفِ وَالْوَشْمِ وَالنُّهْبَةِ وَرُكُوبِ النُّمُورِ وَاتِّخَاذِ الدِّيبَاجِ هَا هُنَا عَلَى الْعَاتِقَيْنِ وَفِي أَسْفَلِ الثِّيَابِ قَالَ عَبْد اللَّهِ أَبُو عَامِرٍ شَيْخٌ لَهُمْ وَالْمُكَامَعَةُ الْمُضَاجَعَةُ","id":"Telah mengabarkan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Zaid bin Al Hubab] telah menceritakan kepadaku [Yahya bin Ayyub Al Hadlrami] telah mengabarkan kepadaku ['Ayyasy bin Abbas Al Himyari] dari [Abu Al Hushain Al Hajari] dari [Abu Amir] ia berkata; Aku mendengar [Abu Raihanah], sahabat Rasulullah shallallahu 'alaihi wasallam, berkata; Rasulullah shallallahu 'alaihi wasallam melarang sepuluh perkara; Tidur berdua antara seorang laki-laki dengan laki-laki lain dalam satu tempat tidur tanpa ada penghalang antara keduanya, tidur berdua antara seorang wanita dengan wanita lain dalam satu tempat tidur tanpa ada penghalang antara keduanya, mencabut (bulu alis), tato, harta rampasan (berkhianat terhadap kaum muslimin dalam harta rampasan perang), menggunakan kulit harimau, memakai sutra kasar, mengenakan sutra di sini yakni di atas kedua bahu dan di bagian bawah baju. Abdullah berkata; Abu Amir adalah guru mereka dan mukama'ah adalah tidur."},"2180":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ وَوَه��بُ بْنُ جَرِيرٍ قَالَا حَدَّثَنَا هِشَامٌ هُوَ الدَّسْتَوَائِيُّ عَنْ يَحْيَى عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ الْمُخَنَّثِينَ مِنْ الرِّجَالِ وَالْمُتَرَجِّلَاتِ مِنْ النِّسَاءِ وَقَالَ أَخْرِجُوهُمْ مِنْ بُيُوتِكُمْ قَالَ فَأَخْرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فُلَانًا وَأَخْرَجَ عُمَرُ فُلَانًا أَوْ فُلَانَةً قَالَ عَبْد اللَّهِ فَأَشُكُّ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dan [Wahb bin Jarir] keduanya berkata; Telah menceritakan kepada kami [Hisyam], ia adalah Ad Dastawa`i, dari [Yahya] dari [Ikrimah] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam melaknat laki-laki yang menyerupai wanita dan wanita yang menyerupai laki-laki. Beliau bersabda: \"Usirlah mereka dari rumah-rumah kalian.\" Ia mengatakan; Nabi shallallahu 'alaihi wasallam pernah mengusir si Fulan dan Umar pernah mengusir si Fulan atau Fulanah. Abdullah berkata; Aku ragu."},"2181":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي النَّضْرِ عَنْ زُرْعَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ وَكَانَ مِنْ أَصْحَابِ الصُّفَّةِ قَالَ جَلَسَ عِنْدَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفَخِذِي مُنْكَشِفَةٌ فَقَالَ خَمِّرْ عَلَيْكَ أَمَا عَلِمْتَ أَنَّ الْفَخِذَ عَوْرَةٌ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah mengabarkan kepada kami [Malik] dari [Abu An Nadlr] dari [Zur'ah bin Abdurrahman] dari [ayahnya], ia adalah seorang sahabat ahlu suffah, ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah duduk di dekat kami sementara pahaku terbuka, beliau bersabda: \"Tutuplah, tidakkah engkau tahu bahwa paha itu aurat?\" "},"2182":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا الْأَعْمَشُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ قَالَ دَخَلَ عَلَى عَائِشَةَ نِسْوَةٌ مِنْ أَهْلِ حِمْصَ يَسْتَفْتِينَهَا فَقَالَتْ لَعَلَّكُنَّ مِنْ النِّسْوَةِ اللَّاتِي يَدْخُلْنَ الْحَمَّامَاتِ قُلْنَ نَعَمْ قَالَتْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ امْرَأَةٍ تَضَعُ ثِيَابَهَا فِي غَيْرِ بَيْتِ زَوْجِهَا إِلَّا هَتَكَتْ مَا بَيْنَهَا وَبَيْنَ اللَّهِ قَالَ أَبُو مُحَمَّد أَخْبَرَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ سَالِمٍ عَنْ أَبِي الْمَلِيحِ عَنْ عَائِشَةَ هَذَا الْحَدِيثَ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Al A'masy] dari [Amr bin Murrah] dari [Salim bin Abu Al Ja'd] ia berkata; Beberapa wanita penduduk Himsh masuk ke rumah Aisyah meminta fatwa kepadanya, lalu ia mengatakan; Boleh jadi kalian adalah kaum wanita yang sering memasuki tempat pemandian. Mereka menjawab; Ya. Ia mengatakan; Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang wanita meletakkan bajunya selain di rumah suaminya kecuali ia telah menghancurkan apa yang ada di antara ia dan Allah.\" Abu Muhammad berkata; Telah mengabarkan hadits ini kepada kami [Ubaidullah] dari [Isra`il] dari [Manshur] dari [Salim] dari [Abu Al Malih] dari [Aisyah]."},"2183":{"ar":" أَخْبَرَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُقِيمُ الرَّجُلُ يَعْنِي أَخَاهُ مِنْ مَجْلِسِهِ ثُمَّ يَقْعُدُ فِيهِ وَلَكِنْ تَفَسَّحُوا وَتَوَسَّعُوا","id":"Telah mengabarkan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seseorang membangunkan saudaranya dari tempat duduknya, kemudian ia duduk di tempat itu, tetapi lapangkanlah dan luaskanlah (merapatlah) kalian.\""},"2184":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا سُهَيْلٌ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ أَحَدُكُمْ أَوْ الرَّجُلُ مِنْ مَجْلِسِهِ ثُمَّ رَجَعَ إِلَيْهِ فَهُوَ أَحَقُّ بِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Suhail] dari [ayahnya] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian berdiri dari tempat duduknya kemudian kembali lagi, maka ia yang paling berhak atas tempat duduk itu.\""},"2185":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ الْبَرَاءِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِنَاسٍ جُلُوسٍ مِنْ الْأَنْصَارِ فَقَالَ إِنْ كُنْتُمْ لَا بُدَّ فَاعِلِينَ فَاهْدُوا السَّبِيلَ وَأَفْشُوا السَّلَامَ وَأَعِينُوا الْمَظْلُومَ قَالَ شُعْبَةُ لَمْ يَسْمَعْ هَذَا الْحَدِيثَ أَبُو إِسْحَقَ مِنْ الْبَرَاءِ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abu Ishaq] dari [Al Bara`] bahwa Rasulullah shallallahu 'alaihi wasallam pernah melewati sekelompok orang-orang Anshar yang sedang duduk-duduk. Lalu beliau mengatakan: \"Jika kalian tidak bisa untuk meninggalkan ini (kebiasaan duduk-duduk di pinggir jalan), maka tunjukkanlah jalan (orang yang lewat), tebarkanlah salam, dan tolonglah orang-orang yang teraniaya.\" Syu'bah berkata; Abu Ishaq tidak mendengar hadits ini dari Al Bara`."},"2186":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي خَلَفٍ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ الزُّهْرِيَّ يُحَدِّثُ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسْتَلْقِيًا فِي الْمَسْجِدِ وَاضِعًا إِحْدَى رِجْلَيْهِ عَلَى الْأُخْرَى","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad bin Abu Khalaf] telah menceritakan kepada kami [Sufyan] ia berkata; Aku mendengar [Az Zuhri] menceritakan dari [Abbad bin Tamim] dari [pamannya] ia berkata; Aku melihat Rasulullah shallallahu 'alaihi wasallam berbaring di masjid, seraya meletakkan salah satu kakinya di atas kaki yang lain."},"2187":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كُنْتُمْ ثَلَاثَةً فَلَا يَتَنَاجَى اثْنَانِ دُونَ صَاحِبِهِمَا فَإِنَّ ذَلِكَ يُحْزِنُهُ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Al A'masy] dari [Abu Wa`il] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian bertiga maka janganlah dua orang (dari kalian) berbisik-bisik tanpa menyertakan teman yang lain, karena hal itu dapat membuatnya sedih.\""},"2188":{"ar":" حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا حَجَّاجٌ يَعْنِي ابْنَ دِينَارٍ عَنْ أَبِي هَاشِمٍ عَنْ رُفَيْعٍ أَبِي الْعَالِيَةِ عَنْ أَبِي بَرْزَةَ الْأَسْلَمِيِّ قَالَ لَمَّا كَانَ بِأَخَرَةٍ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَلَسَ فِي الْمَجْلِسِ فَأَرَادَ أَنْ يَقُومَ قَالَ سُبْحَانَكَ اللَّهُمَّ وَبِحَمْدِكَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا أَنْتَ أَسْتَغْفِرُكَ وَأَتُوبُ إِلَيْكَ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّكَ لَتَقُولُ الْآنَ كَلَامًا مَا كُنْتَ تَقُولُهُ فِيمَا خَلَا فَقَالَ هَذَا كَفَّارَةٌ لِمَا يَكُونُ فِي الْمَجَالِسِ","id":"Telah menceritakan kepada kami [Ya'la bin Ubaid] telah menceritakan kepada kami [Hajjaj], yakni Ibnu Dinar, dari [Abu Hasyim] dari [Rufai' Abu Al 'Aliyah] dari [Abu Barzah Al Aslami] ia berkata; Ketika di penghujung majlis, ketika Rasulullah shallallahu 'alaihi wasallam duduk di suatu majlis lalu hendak berdiri, beliau mengucapkan: SUBHANAKA ALLAHUMMA WA BIHAMDIKA ASYHADU ALLA ILAAHA ILLA ANTA ASTAGHFIRUKA WA ATUBU ILAIK (Maha Suci Engkau, Ya Allah, dengan memujiMu, aku bersaksi bahwa tidak ada tuhan yang hak selain Engkau. Aku memohon ampunan kepadaMu dan aku bertaubat kepadaMu).\" Mereka bertanya; Wahai Rasulullah, engkau mengatakan perkataan yang tidak pernah engkau katakan sebelumnya. Beliau menjawab: \"(Doa) ini merupakan kafarat bagi dosa-dosa yang pernah terjadi di majlis-majlis.\""},"2189":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَخِيهِ عِيسَى عَنْ أَبِيهِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعَاطِسُ يَقُولُ الْحَمْدُ لِلَّهِ عَلَى كُلِّ حَالٍ وَيَقُولُ الَّذِي يُشَمِّتُهُ يَرْحَمُكُمْ اللَّهُ وَيَرُدُّ عَلَيْهِ يَهْدِيكُمُ اللَّهُ وَيُصْلِحُ بَالَكُمْ","id":"Telah mengabarkan kepada kami [Sa'id bin Amir] dari [Syu'bah] dari [Muhammad bin Abdurrahman bin Abu Laila] dari saudaranya, [Isa], dari ayahnya, [Abdurrahman bin Abu Laila], dari [Abu Ayyub Al Anshari] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang yang bersin hendaklah mengucapkan; ALHAMDULILLAH 'ALA KULLI HAL (segala puji bagi Allah pada setiap keadaan), sementara orang yang mendoakan hendaklah mengucapkan; YARHAMUKUMULLAH (semoga Allah merahmatimu), lalu orang yang bersin itu menjawab; YAHDIKUMULLAH WA YUSHLIH BALAKUM (semoga Allah menunjukimu dan memperbaiki keadaanmu) \""},"2190":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا زُهَيْرٌ عَنْ سُلَيْمَانَ عَنْ أَنَسٍ قَالَ عَطَسَ رَجُلَانِ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَمَّتَ أَوْ سَمَّتَ أَحَدَهُمَا وَلَمْ يُشَمِّتْ الْآخَرَ فَقِيلَ لَهُ يَا رَسُولَ اللَّهِ شَمَّتَّ هَذَا وَلَمْ تُشَمِّتْ الْآخَرَ فَقَالَ إِنَّ هَذَا حَمِدَ اللَّهَ وَإِنَّ هَذَا لَمْ يَحْمَدْ اللَّهَ قَالَ عَبْد اللَّهِ سُلَيْمَانُ هُوَ التَّيْمِيُّ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Zuhair] dari [Sulaiman] dari [Anas] ia berkata; Ada dua orang yang bersin di dekat Nabi shallallahu 'alaihi wasallam, lalu beliau mendoakan salah satunya namun tidak mendoakan yang lain. Maka dikatakan kepada beliau; Wahai Rasulullah, mengapa engkau mendoakan yang ini namun tidak mendoakan yang lain? Beliau menjawab: \"Karena orang ini memuji Allah, sedangkan yang lain tidak memuji Allah.\" Abdullah berkata; Sulaiman adalah At Taimi."},"2191":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا عِكْرِمَةُ هُوَ ابْنُ عَمَّارٍ قَالَ حَدَّثَنِي إِيَاسُ بْنُ سَلَمَةَ قَالَ حَدَّثَنِي أَبِي قَالَ عَطَسَ رَجُلٌ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَرْحَمُكَ اللَّهُ ثُمَّ عَطَسَ أُخْرَى فَقَالَ الرَّجُلُ مَزْكُومٌ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Ikrimah] ia adalah Ibnu Ammar, ia berkata; telah menceritakan kepadaku [Iyas bin Salamah] ia berkata; telah menceritakan kepadaku [ayahku] ia berkata; Seseorang bersin di dekat Nabi shallallahu 'alaihi wasallam, lalu beliau mendoakan: \"Semoga Allah merahmatimu.\" Kemudian orang itu bersin lagi, lalu beliau mengatakan: \"Orang itu terkena flu.\""},"2192":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ قَالَ قَالَتْ عَائِشَةُ كَانَ لَنَا ثَوْبٌ فِيهِ تَصَاوِيرُ فَجَعَلْتُهُ بَيْنَ يَدَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي فَنَهَانِي أَوْ قَالَتْ فَكَرِهَهُ قَالَتْ فَجَعَلْتُهُ وَسَائِدَ","id":"Telah mengabarkan kepada kami [Sa'id bin Amir] dari [Syu'bah] dari [Abdurrahman bin Al Qasim] dari [ayahnya] ia berkata; [Aisyah] berkata; Kami pernah mempunyai baju yang bergambar, lalu aku memasangnya di hadapan Nabi shallallahu 'alaihi wasallam yang sedang shalat. Beliau pun melarangku, atau ia mengatakan; Beliau membencinya, kemudian aku menjadikannya sebagai bantal."},"2193":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا عُمَارَةُ بْنُ الْقَعْقَاعِ حَدَّثَنَا الْحَارِثُ الْعُكْلِيُّ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ نُجَيٍّ عَنْ عَلِيٍّ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَلَكَ لَا يَدْخُلُ بَيْتًا فِيهِ كَلْبٌ وَلَا صُورَةٌ وَلَا جُنُبٌ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] telah menceritakan kepada kami [Umarah bin Al Qa'qa'] telah menceritakan kepada kami [Al Harits Al 'Ukli] dari [Abu Zur'ah bin Amr bin Jarir] dari [Abdullah bin Nujay] dari [Ali] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya malaikat itu tidak akan memasuki rumah yang terdapat anjing, gambar dan orang yang junub.\""},"2194":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ قَالَ عَدِيُّ بْنُ ثَابِتٍ أَخْبَرَنِي قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَ يُحَدِّثُ عَنْ أَبِي مَسْعُودٍ الْبَدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الْمُسْلِمُ إِذَا أَنَفْقَ نَفَقَةً عَلَى أَهْلِهِ وَهُوَ يَحْتَسِبُهَا فَهِيَ لَهُ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah], [Adi bin Tsabit] berkata; Ia telah mengabarkan kepadaku, ia mengatakan; Aku mendengar [Abdullah bin Yazid] menceritakan dari [Abu Mas'ud Al badri] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Seorang muslim, jika memberikan nafkah kepada keluarganya, sementara ia ikhlas, maka nafkah itu akan menjadi sedekah baginya.\""},"2195":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا ثَابِتُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ مُوَرِّقٍ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَفَلَ تُلُقِّيَ بِي وَبِالْحَسَنِ أَوْ بِالْحُسَيْنِ قَالَ وَأُرَاهُ قَالَ الْحَسَنَ فَحَمَلَنِي بَيْنَ يَدَيْهِ وَالْحَسَنَ وَرَاءَهُ قَدِمْنَا الْمَدِينَةَ وَنَحْنُ عَلَى الدَّابَّةِ الَّتِي عَلَيْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Tsabit bin Yazid] ia berkata; Telah menceritakan kepada kami ['Ashim Al Ahwal] dari [Muwarriq] dari [Abdullah bin Ja'far] ia berkata; Rasulullah shallallahu 'alaihi wasallam jika kembali dari bepergian, maka beliau membawaku dan Hasan atau Husain. Ia mengatakan; Menurutku ia mengatakan; Hasan, lalu beliau memboncengku di depannya sedangkan Hasan di belakangnya. Ketika tiba di Madinah, kami berada di atas kendaraan yang ditunggangi Nabi shallallahu 'alaihi wasallam."},"2196":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ إِسْحَقَ بْنِ يَحْيَى بْنِ طَلْحَةَ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ وَمَعْبَدِ بْنِ خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ الْخَطْمِيِّ وَكَانَ أَمِيرًا عَلَى الْكُوفَةِ قَالَ أَتَيْنَا قَيْسَ بْنَ سَعْدِ بْنِ عُبَادَةَ فِي بَيْتِهِ فَأَذَّنَ الْمُؤَذِّنِ لِلصَّلَاةِ وَقُلْنَا لِقَيْسٍ قُمْ فَصَلِّ لَنَا فَقَالَ لَمْ أَكُنْ لِأُصَلِّيَ بِقَوْمٍ لَسْتُ عَلَيْهِمْ بِأَمِيرٍ فَقَالَ رَجُلٌ لَيْسَ بِدُونِهِ يُقَالُ لَهُ عَبْدُ اللَّهِ بْنُ حَنْظَلَةَ بْنِ الْغَسِيلِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّجُلُ أَحَقُّ بِصَدْرِ دَابَّتِهِ وَصَدْرِ فِرَاشِهِ وَأَنْ يَؤُمَّ فِي رَحْلِهِ قَالَ قَيْسُ بْنُ سَعْدٍ عِنْدَ ذَاكَ يَا فُلَانُ لِمَوْلًى لَهُ قُمْ فَصَلِّ لَهُمْ","id":"Telah mengabarkan kepada kami [Sa'id bin Sulaiman] dari [Ishaq bin Yahya bin Thalhah] dari [Al Musayyab bin Rafi'] dan [Ma'bad bin Khalid] dari [Abdullah bin Yazid Al Khathmi], saat itu ia adalah gubernur Kufah, ia mengatakan; Kami pergi menemui Qais bin Sa'd bin Ubadah di rumahnya, lalu seorang muadzin mengumandangkan adzan untuk shalat. Kami katakan kepada Qais; Berdirilah dan lakukan shalat bersama kami. Ia pun berkata; Aku tidak pernah mengimami shalat suatu kaum yang tidak aku pimpin. Maka ada seseorang bukan bawahan Qais yang bernama [Abdullah bin Hanzhalah bin Al Ghasil], ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Seseorang itu lebih berhak berada di bagian depan hewannya, di bagian depan ranjangnya dan lebih berhak untuk mengimami di rumahnya.\" Ketika itu Qais bin Sa'd mengatakan kepada mantan budaknya; Wahai fulan, shalatlah bersama mereka."},"2197":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ مُحَمَّدِ بْنِ حَمْزَةَ بْنِ عَمْرٍو الْأَسْلَمِيِّ قَالَ وَقَدْ صَحِبَ أَبُوهُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَمِعْتُ أَبِي يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى ذِرْوَةِ كُلِّ بَعِيرٍ شَيْطَانٌ فَإِذَا رَكِبْتُمُوهَا فَسَمُّوا اللَّهَ وَلَا تُقَصِّرُوا عَنْ حَاجَاتِكُمْ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Usamah bin Zaid] dari [Muhammad bin Hamzah bin Amr Al Aslami] ia berkata; Bahwa ayahnya yang bersahabat dengan Rasulullah shallallahu 'alaihi wasallam berkata; Aku mendengar [ayahku] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Di setiap punggung unta terdapat setan, jika kalian hendak menungganginya, maka sebutlah nama Allah dan janganlah kalian hanya sekedar memenuhi keperluan kalian (tanpa berdoa).\""},"2198":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَبَابَةُ بْنُ سَوَّارٍ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سَهْلِ بْنِ مُعَاذِ بْنِ أَنَسٍ عَنْ أَبِيهِ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ارْكَبُوا هَذِهِ الدَّوَابَّ سَالِمَةً وَلَا تَتَّخِذُوهَا كَرَاسِيَّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ عَنْ اللَّيْثِ إِلَّا أَنَّهُ يُخَالِفُ شَبَابَةَ فِي شَيْءٍ","id":"Telah mengabarkan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Syababah bin Sawwar] telah menceritakan kepada kami [Laits bin Sa'ad] dari [Yazid bin Abu Habib] dari [Sahal bin Mu'adz bin Anas] dari [ayahnya], ia adalah sahabat Nabi shallallahu 'alaihi wasallam, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Kendarailah hewan tunggangan ini dengan baik dan jangan menjadikannya sebagi kursi.\" Telah mengabarkan kepada kami [Abdullah bin Shalih] dari [Al Laits], hanya saja ia meriwayatkan hadits yang berbeda dengan [Syababah]."},"2199":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّفَرُ قِطْعَةٌ مِنْ الْعَذَابِ يَمْنَعُ أَحَدَكُمْ نَوْمَهُ وَطَعَامَهُ وَشَرَابَهُ فَإِذَا قَضَى نَهْمَتَهُ مِنْ وَجْهِهِ فَلْيُعَجِّلْ الرَّجْعَةَ إِلَى أَهْلِهِ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Sumayyi] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perjalanan itu sebagian dari siksaan yang akan menghalangi salah seorang dari kalian tidur, makan dan minumnya. Jika salah seorang dari kalian telah menyelesaikan keperluan dari perjalanannya, hendaklah segera kembali ke keluarganya.\""},"2200":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي كَعْبٍ أَبُو الْحَسَنِ الْعَبْدِيُّ قَالَ حَدَّثَنِي مُوسَى بْنُ مَيْسَرَةَ الْعَبْدِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ جَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ يَا نَبِيَّ اللَّهِ إِنِّي أُرِيدُ السَّفَرَ فَقَالَ لَهُ مَتَى قَالَ غَدًا إِنْ شَاءَ اللَّهُ قَالَ فَأَتَاهُ فَأَخَذَ بِيَدِهِ فَقَالَ لَهُ فِي حِفْظِ اللَّهِ وَفِي كَنَفِهِ زَوَّدَكَ اللَّهُ التَّقْوَى وَغَفَرَ لَكَ ذَنْبَكَ وَوَجَّهَكَ لِلْخَيْرِ أَيْنَمَا تَوَخَّيْتَ أَوْ أَيْنَمَا تَوَجَّهْتَ شَكَّ سَعِيدٌ فِي إِحْدَى الْكَلِمَتَيْنِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Sa'id bin Abu Ka'ab Abu Al Hasan Al Abdi] ia berkata; telah menceritakan kepadaku [Musa bin Maisarah Al Abdi] dari [Anas bin Malik] ia berkata; Ada seseorang datang kepada Nabi shallallahu 'alaihi wasallam seraya bertanya kepadanya; Wahai Nabiyullah, sesungguhnya aku hendak bepergian. Maka beliau mengatakan kepadanya: \"Kapan?\" ia menjawab; Besok, insya Allah. Ia mengatakan; Lalu beliau mendatanginya dan meraih tangannya seraya mengatakan kepadanya: \"Semoga engkau selalu berada dalam perlindungan dan pemeliharaan Allah. Semoga Allah membekalimu dengan ketaqwaan, mengampuni dosamu dan mengarahkanmu kepada kebaikan, kemana pun engkau menuju.\" Atau: \"Ke mana pun engkau menghadap.\" Sa'id ragu terhadap salah satu dari dua kata tersebut."},"2201":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا عَاصِمٌ هُوَ الْأَحْوَلُ قَالَ وَثَبَّتَنِي شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسٍ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَافَرَ قَالَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ وَعْثَاءِ السَّفَرِ وَكَآبَةِ الْمُنْقَلَبِ وَالْحَوْرِ بَعْدَ الْكَوْرِ وَدَعْوَةِ الْمَظْلُومِ وَسُوءِ الْمَنْظَرِ فِي الْأَهْلِ وَالْمَالِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami ['Ashim] ia adalah Al Ahwal, ia berkata; [Syu'bah] menguatkanku dari [Abdullah bin Sarjis] ia berkata; Nabi shallallahu 'alaihi wasallam jika hendak bepergian beliau mengucapkan: ALLAHUMMA INNI A'UDZU BIKA MIN WA'TSA`IS SAFARI WA KA'ABATIL MUNQALABI WAL HAURI BA'DAL KAURI WA DA'WATIL MAZHLUMI WA SU`IL MANZHARI FIL AHLI WAL MAL (Ya Allah, sesungguhnya aku berlindung kepadaMu dari kesulitan dalam perjalanan, kesusahan saat kembali, kehancuran perkara setelah kebaikannya, doa orang yang teraniaya dan pandangan buruk terhadap keluarga dan harta) \""},"2202":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ عَلِيِّ بْنِ عَبْدِ اللَّهِ الْبَارِقِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَافَرَ فَرَكِبَ رَاحِلَتَهُ كَبَّرَ ثَلَاثًا وَيَقُولُ { سُبْحَانَ الَّذِي سَخَّرَ لَنَا هَذَا وَمَا كُنَّا لَهُ مُقْرِنِينَ وَإِنَّا إِلَى رَبِّنَا لَمُنْقَلِبُونَ } اللَّهُمَّ إِنِّي أَسْأَلُكَ فِي سَفَرِي هَذَا الْبِرَّ وَالتَّقْوَى وَمِنْ الْعَمَلِ مَا تَرْضَى اللَّهُمَّ هَوِّنْ عَلَيْنَا السَّفَرَ وَاطْوِ لَنَا بُعْدَ الْأَرْضِ اللَّهُمَّ أَنْتَ الصَّاحِبُ فِي السَّفَرِ وَالْخَلِيفَةُ فِي الْأَهْلِ اللَّهُمَّ اصْحَبْنَا فِي سَفَرِنَا وَاخْلُفْنَا فِي أَهْلِنَا بِخَيْرٍ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu Az Zubair] dari [Ali bin Abdullah Al Bariqi] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam jika hendak bepergian, beliau menunggang kendaraannya seraya bertakbir tiga kali dan membaca: SUBHANALLADZI SAKHKHARA LANA HADZA WA MA KUNNA LAHU MUQRININ WA INNA ILA RABBINA LAMUNQALIBUN ALLAHUMMA INNI AS`ALUKA FI SAFARI HADZAL BIRRA WAT TAQWA WA MINAL 'AMALI MA TARDLA ALLAHUMMA HAWWIN 'ALAINAS SAFARA WATHWI LANA BU'DAL ARDLI ALLAHUMMA ANTASH SHAHIBU FIS SAFARI WAL KHALIFATU FIL AHLI ALLAHUMMASH HABNA FI SAFARINA WAKHLUFNA FI AHLINA BI KHAIR (Maha Suci Dzat yang telah menundukkan tunggangan ini kepada kami, padahal kami tidak mampu menguasainya. Ya Allah, sesungguhnya aku memohon kepadaMu dalam perjalananku ini kebajikan, ketaqwaan dan amalan yang Engkau ridlai. Ya Allah, mudahkanlah perjalanan untuk kami dan lipatkanlah jauhnya bumi untuk kami. Ya Alah, Engkau adalah penjaga dalam perjalanan dan pengganti dalam mengurusi urusan keluarga. Ya Allah, temanilah kami dalam perjalanan kami dan jadilah pengganti kami dalam mengurusi keluarga kami dengan baik).\""},"2203":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو زُبَيْدٍ عَنْ حُصَيْنٍ عَنْ سَالِمٍ عَنْ جَابِرٍ قَالَ كُنَّا إِذَا صَعِدْنَا كَبَّرْنَا وَإِذَا هَبَطْنَا سَبَّحْنَا","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Zubaid] dari [Hushain] dari [Salim] dari [Jabir] ia berkata; Jika kami naik (kendaraan), kami bertakbir dan jika turun (kendaraan), kami bertasbih."},"2204":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ سَالِمٍ عَنْ أَبِي الْجَرَّاحِ مَوْلَى أَمِّ حَبِيبَةَ عَنْ أُمِّ حَبِيبَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَا��َ الْعِيرُ الَّتِي فِيهَا الْجَرَسُ لَا تَصْحَبُهَا الْمَلَائِكَةُ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Salim] dari [Abu Al Jarrah] mantan budak Ummu Habibah, dari [Ummu Habibah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kafilah (rombongan) yang membawa lonceng itu tidak akan ditemani oleh para malaikat.\""},"2205":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا سُهَيْلُ بْنُ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَصْحَبُ الْمَلَائِكَةُ رِفْقَةً فِيهَا كَلْبٌ أَوْ جَرَسٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Suhail bin Abu Shalih] dari [ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Malaikat tidak akan menyertai kafilah (rombongan) yang membawa anjing atau lonceng.\" "},"2206":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي سَفَرٍ فَسَمِعَ لَعْنَةً فَقَالَ مَا هَذَا قَالُوا فُلَانَةُ لَعَنَتْ رَاحِلَتَهَا فَقَالَ ضَعُوا عَنْهَا فَإِنَّهَا مَلْعُونَةٌ قَالَ فَوَضَعُوا عَنْهَا قَالَ عِمْرَانُ كَأَنِّي أَنْظُرُ إِلَيْهَا نَاقَةً وَرْقَاءَ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Abu Al Muhallab] dari [Imran bin Hushain] bahwa Nabi shallallahu 'alaihi wasallam pernah mendengar suara orang melaknat ketika sedang bepergian, beliau bertanya: \"Suara apa ini?\" Mereka menjawab; Seorang wanita melaknat kendaraannya. Lalu beliau bersabda mengatakan: \"Tinggalkan ia, sesungguhnya ia dilaknat.\" Maka, mereka pun meninggalkan wanita itu. 'Imran berkata; Seakan-akan aku melihatnya seperti unta yang loreng (hitam bercampur putih)."},"2207":{"ar":" حَدَّثَنَا يَعْلَى حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُسَافِرْ الْمَرْأَةُ سَفَرًا ثَلَاثَةَ أَيَّامٍ فَصَاعِدًا إِلَّا وَمَعَهَا أَبُوهَا أَوْ أَخُوهَا أَوْ زَوْجُهَا أَوْ ذُو مَحْرَمٍ مِنْهَا","id":"Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh seorang wanita bepergian selama tiga hari atau lebih kecuali bersama ayah, saudara, suami atau mahramnya.\""},"2208":{"ar":" أَخْبَرَنَا الْهَيْثَمُ بْنُ جَمِيلٍ حَدَّثَنَا عَاصِمٌ هُوَ ابْنُ مُحَمَّدٍ الْعُمَرِيُّ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ يَعْلَمُ النَّاسُ مَا فِي الْوَحْدَةِ لَمْ يَسْرِ رَاكِبٌ بِلَيْلٍ وَحْدَهُ أَبَدًا","id":"Telah mengabarkan kepada kami [Al Haitsam bin Jamil] telah menceritakan kepada kami ['Ashim] ia adalah Ibnu Muhammad Al Umari, dari [ayahnya] dari [Ibnu Umar] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Seandainya manusia mengetahui bahaya yang ada dalam kesendirian, niscaya tidak akan ada seorang pengendara pun berjalan pada malam hari sendirian selamanya.\""},"2209":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ إِسْحَقَ وَعَفَّانُ قَالَا حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ عَجْلَانَ عَنْ يَعْقُوبَ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ سَعْدِ بْنِ مَالِكٍ عَنْ خَوْلَةَ بِنْتِ حَكِيمٍ قَالَتْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَوْ أَنَّ أَحَدَكُمْ إِذَا نَزَلَ مَنْزِلًا قَالَ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ مِنْ شَرِّ مَا خَلَقَ لَمْ يَضُرَّهُ فِي ذَلِكَ الْمَنْزِلِ شَيْءٌ حَتَّى يَرْتَحِلَ مِنْهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Ishaq] dan ['Affan] keduanya berkata; Telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu 'Ajlan] dari [Ya'qub bin Abdullah bin Al Asyajj] dari [Sa'id bin Al Musayyab] dari [Sa'd bin Malik] dari [Khaulah bintu Hakim] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian singgah di suatu tempat dan membaca; A'UDZU BIKALIMATILLAHIT TAMMAH MIN SYARRI MA KHALAQ (aku berlindung dengan kalimat-kalimat Allah yang sempurna dari kejahatan sesuatu yang Dia ciptakan), maka tidak akan ada sesuatu pun yang akan mencelakainya di tempat itu hingga ia menginggalkannya.\""},"2210":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ عُثْمَانَ بْنِ سَعْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا نَزَلَ مَنْزِلًا لَمْ يَرْتَحِلْ مِنْهُ حَتَّى يُصَلِّيَ رَكْعَتَيْنِ أَوْ يُوَدِّعَ الْمَنْزِلَ بِرَكْعَتَيْنِ قَالَ عَبْد اللَّهِ عُثْمَانُ بْنُ سَعْدٍ ضَعِيفٌ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Utsman bin Sa'd] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam jika singgah di suatu tempat, beliau tidak akan pergi dari tempat tersebut hingga shalat dua rakaat, atau beliau akan meninggalkan tempat itu dengan shalat dua rakaat. Abdullah berkata; Utsman bin Sa'd adalah dla'if."},"2211":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ عَلِيِّ بْنِ عَبْدِ اللَّهِ الْبَارِقِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا رَجَعَ مِنْ سَفَرِهِ قَالَ آيِبُونَ إِنْ شَاءَ اللَّهُ تَائِبُونَ عَابِدُونَ لِرَبِّنَا حَامِدُونَ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu Az Zubair] dari [Ali bin Abdullah Al Bariqi] dari [Abdullah bin Umar] bahwa Nabi shallallahu 'alaihi wasallam jika kembali dari bepergian, beliau mengucapkan: AYIBUN INSYAALLAH TA'IBUN 'ABIDUN LIRABBINA HAMIDUN (Kami adalah orang-orang yang kembali, insya Allah, bertaubat, beribadah dan memuji kepada Rabb kami.\""},"2212":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا أَبُو إِسْحَقَ قَالَ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ يَقُولُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ رَجُلًا إِذَا أَخَذَ مَضْجَعَهُ أَنْ يَقُولَ اللَّهُمَّ أَسْلَمْتُ نَفْسِي إِلَيْكَ وَوَجَّهْتُ وَجْهِي إِلَيْكَ وَفَوَّضْتُ أَمْرِي إِلَيْكَ وَأَلْجَأْتُ ظَهْرِي إِلَيْكَ رَغْبَةً وَرَهْبَةً إِلَيْكَ لَا مَلْجَأَ وَلَا مَنْجَى مِنْكَ إِلَّا إِلَيْكَ آمَنْتُ بِكِتَابِكَ الَّذِي أَنْزَلْتَ وَنَبِيِّكَ الَّذِي أَرْسَلْتَ فَإِنْ مَاتَ مَاتَ عَلَى الْفِطْرَةِ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] ia berkata; Telah menceritakan kepada kami [Abu Ishaq] ia berkata; Aku mendengar [Al Bara` bin 'Azib] berkata; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam memerintahkan seseorang ketika hendak berbaring di atas tempat tidurnya agar membaca: ALLAHUMMA ASLAMTU NAFSI ILAIKA WAWAJJAHTU WAJHI ILAIKA WA FAWWADLTU AMRI ILAIKA WA ALJA`TU ZHAHRI ILAIKA RAGHBATAN WA RAHBATAN ILAIKA LA MALJA`A WA LA MANJA MINKA ILLA ILAIKA AMANTU BIKITABIKALLADZI ANJALTA WA NABIYYAKA-LLADZI ARSALTA (Ya Allah, aku pasrahkan diriku kepadaMu, aku hadapkan wajahku kepadaMu, aku serahkan urusanku kepadaMu dan aku kembalikan punggungku kepadaMu, karena cinta dan takut kepadaMu. Tidak ada tempat kembali dan tidak ada tempat mencari kesempatan dariMu selain hanya kepadaMu. Aku beriman kepada kitabMu yang Engkau turunkan dan nabiMu yang Engkau utus.\" Jika ia meninggal, maka ia meninggal dalam keadaan fitrah."},"2213":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَوَى أَحَدُكُمْ إِلَى فِرَاشِهِ فَلْيَنْفُضْ فِرَاشَهُ بِدَاخِلَةِ إِزَارِهِ فَإِنَّهُ لَا يَدْرِي مَا خَلَفَهُ فِيهِ وَلْيَقُلْ اللَّهُمَّ بِكَ وَضَعْتُ جَنْبِي وَبِكَ أَرْفَعُهُ اللَّهُمَّ إِنْ أَمْسَكْتَ نَفْسِي فَاغْفِرْ لَهَا وَإِنْ أَرْسَلْتَهَا فَاحْفَظْهَا بِمَا تَحْفَظُ بِهِ عِبَادَكَ الصَّالِحِينَ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ubaidullah bin Umar] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian hendak berbaring di atas tempat tidurnya, hendaklah ia mengibas tempat tidurnya dengan bagian ujung dalam kainnya. Karena ia tidak tahu apa yang ada di bagian ujung dalam kainnya itu. Dan hendaklah ia membaca; ALLAHUMMA BIKA WADLA'TU JANBI WA BIKA ARFA'UHU ALLAHUMMA IN AMSAKTA NAFSI FAGHFIR LAHA WA IN ARSALTAHA FAHFAZH-HA BIMA TAHFAZHU BIHI 'IBADAKASH SHALIHIN (Ya Allah, karenaMu aku meletakkan lambungku dan karenaMu aku mengangkatnya. Jika Engkau mengambil nyawaku, maka ampunilah aku. Jika Engkau membiarkannya tetap hidup maka peliharalah ia dengan sesuatu yang Engkau gunakan untuk memelihara hamba-hambaMu yang shalih) \" "},"2214":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْعَوَّامُ بْنُ حَوْشَبٍ قَالَ حَدَّثَنِي عَمْرُو بْنُ مُرَّةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَلِيٍّ قَالَ أَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى وَضَعَ قَدَمَهُ بَيْنِي وَبَيْنَ فَاطِمَةَ فَعَلَّمَنَا مَا نَقُولُ إِذَا أَخَذْنَا مَضَاجِعَنَا ثَلَاثًا وَثَلَاثِينَ تَسْبِيحَةً وَثَلَاثًا وَثَلَاثِينَ تَحْمِيدَةً وَأَرْبَعًا وَثَلَاثِينَ تَكْبِيرَةً قَالَ عَلِيٌّ فَمَا تَرَكْتُهَا بَعْدُ فَقَالَ لَهُ رَجُلٌ وَلَا لَيْلَةَ صِفِّينَ قَالَ وَلَا لَيْلَةَ صِفِّينَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Al 'Awwam bin Hausyab] ia berkata; telah menceritakan kepadaku [Amr bin Murrah] dari [Abdurrahman bin Abu Laila] dari [Ali] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah mendatangi kami hingga beliau meletakkan kakinya di antara aku dan Fathimah. Lalu beliau mengajarkan sesuatu yang kami baca ketika berbaring di tempat tidur, yaitu membaca tasbih tiga puluh tiga, tahmid tiga puluh tiga dan takbir tiga puluh tiga kali. Ali berkata; Aku tidak pernah meninggalkannya setelah itu. Ada seseorang bertanya kepadanya; Tidak juga pada malam Shiffin? Ia menjawab; Tidak juga pada malam Shiffin."},"2215":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ حُذَيْفَةَ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَيْقَظَ قَالَ الْحَمْدُ لِلَّهِ الَّذِي أَحْيَانَا بَعْدَ مَا أَمَاتَنَا وَإِلَيْهِ النُّشُورُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Abdul Malik bin Umair] dari [Rib'i bin Hirasy] dari [Hudzaifah] ia berkata; Nabi shallallahu 'alaihi wasallam jika bangun dari tidur, beliau mengucapkan: ALHAMDU LILLAHIL LADZI AHYANA BA'DA MA AMATANA WA ILIHIN NUSYUR (Segala puji bagi Allah yang telah menghidupkan kami setelah mematikan kami, dan kepadaNyalah tempat kembali kami) \""},"2216":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ الْحِزَامِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي عُمَيْرُ بْنُ هَانِىءٍ الْعَنْسِيُّ قَالَ حَدَّثَنِي جُنَادَةُ بْنُ أَبِي أُمَيَّةَ قَالَ حَدَّثَنِي عُبَادَةُ بْنُ الصَّامِتِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَعَارَّ مِنْ اللَّيْلِ فَقَالَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ سُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَاللَّهُ أَكْبَرُ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ ثُمَّ قَالَ رَبِّ اغْفِرْ لِي أَوْ قَالَ ثُمَّ دَعَا اسْتُجِيبَ لَهُ فَإِنْ عَزَمَ فَتَوَضَّأَ ثُمَّ صَلَّى قُبِلَتْ صَلَاتُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid Al Hizami] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Al Auza'i] ia berkata; Telah menceritakan kepadaku [Umair bin Hani` Al 'Ansi] ia berkata; Telah menceritakan kepadaku [Junadah bin Abu Umayyah] ia berkata; telah menceritakan kepadaku [Ubadah bin Ash Shamit] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang terjaga dari tidurnya di malam hari, lalu ia membaca; LAA ILAHA ILLAALLAH WAHDAHU LA SYARIKA LAH LAHUL MULKU WA LAHUL HAMDU WA HUWA 'ALA KULLI SYA`IN QADIR SUBHANALLAH WAL HAMDULILLAH WALLAHU AKBAR WA LA HAULA WALA QUWWATA ILLA BILLAH (Tidak ada tuhan yang haq selain Allah semata, tiada sekutu bagiNya, bagiNya kerajaan dan pujian dan Dia Maha Kuasa atas segala sesuatu. Maha Suci Allah, segala puji bagi Allah, Allah Maha Besar, tidak ada daya dan kekuatan melainkan karena Allah). Lalu membaca; RABBIGH FIRLI (Ya Allah, ampunilah aku) \" Atau beliau mengatakan: \"Kemudian berdoa, maka (permohonan) nya akan dikabulkan. Jika ia telah berketetapan hati, kemudian berwudlu dan shalat maka shalatnya akan diterima.\""},"2217":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَصْبَحَ قَالَ أَصْبَحْنَا عَلَى فِطْرَةِ الْإِسْلَامِ وَكَلِمَةِ الْإِخْلَاصِ وَدِينِ نَبِيِّنَا مُحَمَّدٍ وَمِلَّةِ أَبِينَا إِبْرَاهِيمَ حَنِيفًا مُسْلِمًا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Salamah bin Kuhail] dari [Abdullah bin Abdurrahman bin Abza] dari [ayahnya] ia berkata; Nabi shallallahu 'alaihi wasallam jika memasuki waktu shubuh, beliau mengucapkan: \"Kami memasuki pagi dengan fitrah Islam, kalimat ikhlas dan agama Nabi kami, Muhammad, kepercayaan bapak-bapak kami, Ibrahim, yang lurus lagi berserah diri.\""},"2218":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ عَمْرِو بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ أَبُو بَكْرٍ يَا رَسُولَ اللَّهِ مُرْنِي بِشَيْءٍ أَقُولُهُ إِذَا أَصْبَحْتُ وَإِذَا أَمْسَيْتُ قَالَ قُلْ اللَّهُمَّ فَاطِرَ السَّمَوَاتِ وَالْأَرْضِ عَالِمَ الْغَيْبِ وَالشَّهَادَةِ رَبَّ كُلِّ شَيْءٍ وَمَلِيكَهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا أَنْتَ أَعُوذُ بِكَ مِنْ شَرِّ نَفْسِي وَمِنْ شَرِّ الشَّيْطَانِ وَشِرْكِهِ قَالَ قُلْهُ إِذَا أَصْبَحْتَ وَإِذَا أَمْسَيْتَ وَإِذَا أَخَذْتَ مَضْجَعَكَ","id":"Telah mengabarkan kepada kami [Sa'id bin Amir] dari [Syu'bah] dari [Ya'la bin 'Atha`] dari [Amr bin 'Ashim] dari [Abu Hurairah] ia berkata; Abu Bakar berkata; Wahai Rasulullah, perintahkan sesuatu kepadaku yang bisa aku baca ketika berada di waktu pagi dan petang. Beliau menjawab: ALLAHUMMA FATHIRIS SAMAWATI WAL ARDHI 'ALIMAL GHAIB WASY-SYAHADATI RABBA KULLI SYA`IN WA MALIKAHU ASYHADU ANLA ILAHA ILLA ANTA A'UDZU BIKA MIN SYARRI NAFSI WA MIN SYARRISY SYAITHANI WA SYIRKIHI (Ya Allah, Pencipta langit dan bumi, Maha Mengetahui yang ghaib dan nampak, Penguasa dan Pemilik segala sesuatu. Aku bersaksi tidak ada tuhan yang haq kecuali Engkau, aku berlindung kepadaMu dari kejahatan diriku dan kejahatan setan serta sekutunya) \" Beliau melanjutkan: \"Bacalah ketika engkau berada di waktu pagi dan petang serta jika engkau hendak tidur.\""},"2219":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا سَعِيدٌ هُوَ ابْنُ أَبِي أَيُّوبَ عَنْ أَبِي مَرْحُومٍ عَنْ سَهْلِ بْنِ مُعَاذِ بْنِ أَنَسٍ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَبِسَ ثَوْبًا فَقَالَ الْحَمْدُ لِلَّهِ الَّذِي كَسَانِي هَذَا وَرَزَقَنِيهِ مِنْ غَيْرِ حَوْلٍ مِنِّي وَلَا قُوَّةٍ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Abdullah bin Yazid Al Muqri`] telah menceritakan kepada kami [Sa'id] ia adalah Ibnu Abu Ayyub, dari [Abu Marhum] dari [Sahal bin Mu'adz bin Anas] dari [ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengenakan pakaian lalu mengucapkan; ALHAMDULILLAHIL LADZI KASANI HADZA WA RAZAQANI MIN GHAIRI HAULIN MINNI WA LA QUWWATIN (Segala puji bagi Allah yang telah mengenakan dan memberikannya kepadaku, tanpa ada daya kekuatan dariku), maka Allah akan mengampuni dosa-dosanya yang telah lalu.\""},"2220":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ بِلَالٍ عَنْ رَبِيعَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدٍ عَنْ أَبِي حُمَيْدٍ أَوْ أَبِي أُسَيْدٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ أَحَدُكُمْ الْمَسْجِدَ فَلْيَقُلْ اللَّهُمَّ افْتَحْ لِي أَبْوَابَ رَحْمَتِكَ وَإِذَا خَرَجَ فَلْيَقُلْ اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ فَضْلِكَ","id":"Telah mengabarkan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Sulaiman] ia adalah Ibnu Bilal, dari [Rabi'ah] dari [Abdul Malik bin Sa'id] dari [Abu Humaid] atau [Abu Usaid], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian masuk masjid, hendaklah mengucapkan; ALLAHUMMAFTAH LI ABWABA RAHMATIKA (Ya Allah, bukakanlah pintu-pintu rahmatMu untukku). Dan jika keluar maka hendaklah ia mengucapkan; ALLAHUMMA INNI AS`ALUKA MIN FADL-LIKA (Ya Allah, sesungguhnya aku memohon karuniaMu).\""},"2221":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا أَزْهَرُ بْنُ سِنَانٍ عَنْ مُحَمَّدِ بْنِ وَاسِعٍ قَالَ قَدِمْتُ مَكَّةَ فَلَقِيتُ بِهَا أَخِي سَالِمَ بْنَ عَبْدِ اللَّهِ فَحَدَّثَنِي عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ دَخَلَ السُّوقَ فَقَالَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ يُحْيِي وَيُمِيتُ وَهُوَ حَيٌّ لَا يَمُوتُ بِيَدِهِ الْخَيْرُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ كَتَبَ اللَّهُ لَهُ أَلْفَ أَلْفِ حَسَنَةٍ وَمَحَا عَنْهُ أَلْفَ أَلْفِ سَيِّئَةٍ وَرَفَعَ لَهُ أَلْفَ أَلْفِ دَرَجَةٍ قَالَ فَقَدِمْتُ خُرَاسَانَ فَلَقِيتُ قُتَيْبَةَ بْنَ مُسْلِمٍ فَقُلْتُ إِنِّي أَتَيْتُكَ بِهَدِيَّةٍ فَحَدَّثْتُهُ فَكَانَ يَرْكَبُ فِي مَوْكِبِهِ فَيَأْتِي السُّوقَ فَيَقُومُ فَيَقُولُهَا ثُمَّ يَرْجِعُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Azhar bin Sinan] dari [Muhammad bin Wasi'] ia berkata; Ketika aku tiba di Makkah, aku bertemu dengan saudaraku yaitu [Salim bin Abdullah], lalu Ia menceritakan dari [ayahnya] dari [kakeknya] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang memasuki pasar lalu mengucapkan; LAA ILAHA ILLAALLAH WAHDAHU LAA SYRIKALAH LAHUL MULKU WA LAHL HAMDU YUHYI WA YUMIT WA HUWA HAYYUN LAA YAMUT BIYADIHIL KHAIR WA HUWA 'ALA KULLI SYAI`IN QADIR (Tidak ada tuhan yang haq kecuali Allah semata, tiada sekutu bagiNya, bagiNya kerajaan dan pujian. Dia Maha Menghidupkan dan Maha Mematikan, Dia Hidup dan tidak mati, seluruh kebaikan ada di TanganNya, dan Dia Maha Kuasa atas segala sesuatu). Maka Allah akan mencatat beribu-ribu kebaikan untuknya, menghapus beribu-ribu keburukan darinya dan mengangkat kedudukannya beribu-beribu derajat.\" Ketika aku tiba di Khurasan dan bertemu dengan Qutaibah bin Muslim, aku berkata; Aku datang kepadamu membawa sebuah hadiah, lalu aku menceritakan hadits itu kepadanya. Ia pun segera mengendarai tungganganya dan menuju ke pasar. Ia berdiri dan membacanya, kemudian kembali pulang."},"2222":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ هِشَامٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسَمَّوْا بِاسْمِي وَلَا تَكَنَّوْا بِكُنْيَتِي","id":"Telah mengabarkan kepada kami [Sa'id bin Amir] dari [Hisyam] dari [Muhammad bin Sirin] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berilah nama-nama kalian dengan namaku, namun jangan memberi julukan dengan julukanku.\""},"2223":{"ar":" حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا دَاوُدُ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ أَبِي زَكَرِيَّا الْخُزَاعِيِّ عَنْ أَبِي الدَّرْدَاءِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكُمْ تُدْعَوْنَ يَوْمَ الْقِيَامَةِ بِأَسْمَائِكُمْ وَأَسْمَاءِ آبَائِكُمْ فَأَحْسِنُوا أَسْمَاءَكُمْ","id":"Telah menceritakan kepada kami ['Affan bin Muslim] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Daud bin Amr] dari [Abdullah bin Abu Zakariya Al Khuza'i] dari [Abu Ad Darda`] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kalian akan dipanggil pada hari kiamat dengan nama-nama kalian dan nama-nama bapak kalian. Oleh karena itu baguskanlah nama-nama kalian.\""},"2224":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا عَبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَبُّ الْأَسْمَاءِ إِلَى اللَّهِ عَبْدُ اللَّهِ وَعَبْدُ الرَّحْمَنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Nama-nama yang paling dicintai oleh Allah adalah Abdullah dan Abdurrahman.\""},"2225":{"ar":" أَخْبَرَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا مُعْتَمِرٌ عَنْ الرُّكَيْنِ عَنْ أَبِيهِ عَنْ سَمُرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ نُسَمِّيَ أَرِقَّاءَنَا أَرْبَعَةَ أَسْمَاءٍ أَفْلَحُ وَنَافِعٌ وَرَبَاحٌ وَيَسَارٌ","id":"Telah mengabarkan kepada kami [Zakariya bin Adi] telah menceritakan kepada kami [Mu'tamir] dari [Rukain] dari [ayahnya] dari [Samurah] bahwa Nabi shallallahu 'alaihi wasallam melarang kami memberi nama budak-budak kami dengan empat nama; Aflah, Nafi', Rabah dan Yasar."},"2226":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادٌ هُوَ ابْنُ سَلَمَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ أُمَّ عَاصِمٍ كَانَ يُقَالُ لَهَا عَاصِيَةُ فَسَمَّاهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمِيلَةَ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad] ia adalah Ibnu Salamah, dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa Ummu 'Ashim dulu dipanggil 'Ashiyah lalu Nabi shallallahu 'alaihi wasallam memberinya nama Jamilah."},"2227":{"ar":" حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَطَاءُ بْنُ أَبِي مَيْمُونَةَ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَ��ْرَةَ قَالَ كَانَ اسْمُ زَيْنَبَ بَرَّةَ فَسَمَّاهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْنَبَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami ['Atha` bin Abu Maimunah] dari [Abu Rafi'] dari [Abu Hurairah] ia berkata; Dulu Zainab bernama Barrah, lalu Nabi shallallahu 'alaihi wasallam memberinya nama Zainab."},"2228":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ الطُّفَيْلِ أَخِي عَائِشَةَ قَالَ قَالَ رَجُلٌ مِنْ الْمُشْرِكِينَ لِرَجُلٍ مِنْ الْمُسْلِمِينَ نِعْمَ الْقَوْمُ أَنْتُمْ لَوْلَا أَنَّكُمْ تَقُولُونَ مَا شَاءَ اللَّهُ وَشَاءَ مُحَمَّدٌ فَسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا تَقُولُوا مَا شَاءَ اللَّهُ وَشَاءَ مُحَمَّدٌ وَلَكِنْ قُولُوا مَا شَاءَ اللَّهُ ثُمَّ شَاءَ مُحَمَّدٌ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Syu'bah] dari [Abdul Malik bin Umair] dari [Rib'i bin Hirasy] dari [Ath Thufail] saudara Aisyah ia berkata; Ada seseorang dari kaum musyrikin mengatakan kepada seseorang dari kaum muslimin; Sebaik-baik kaum adalah kalian seandainya kalian tidak mengatakan; Apa yang dikehendaki oleh Allah dan dikehendaki Muhammad. Lalu Nabi shallallahu 'alaihi wasallam mendengarnya, maka beliau bersabda: \"Janganlah kalian mengatakan; Apa yang dikehendaki Allah dan dikehendaki Muhammad, tetapi katakanlah; Apa yang dikehendaki Allah kemudian yang dikehendaki Muhammad.\""},"2229":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدٌ هُوَ ابْنُ إِسْحَقَ عَنْ صَالِحِ بْنِ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُولُوا لِحَائِطِ الْعِنَبِ الْكَرْمُ إِنَّمَا الْكَرْمُ الرَّجُلُ الْمُسْلِمُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad] ia adalah Ibnu Ishaq, dari [Shalih bin Ibrahim] dari [Abdurrahman Al A'raj] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menyebut kebun kurma dengan karm, sesungguhnya karm adalah seorang laki-laki muslim.\""},"2230":{"ar":" حَدَّثَنَا أَبُو عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدٍ عَنْ أَنَسٍ قَالَ كَانَ غُلَامٌ يَسُوقُ بِأَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا أَنْجَشَةُ رُوَيْدًا سَوْقَكَ بِالْقَوَارِيرِ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Abdullah bin Ubaid] dari [Anas] ia berkata; Seorang budak berkendaraan dengan membawa para isteri Nabi shallallahu 'alaihi wasallam, beliau pun mengatakan: \"Wahai Anjasyah, pelan-pelanlah dalam mengendara, karena engkau membawa botol-botol kaca.\" "},"2231":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا بَهْزُ بْنُ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَيْلٌ لِلَّذِي يُحَدِّثُ فَيَكْذِبُ لِيُضْحِكَ بِهِ الْقَوْمَ وَيْلٌ لَهُ وَيْلٌ لَهُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Bahz bin Hakim] dari [ayahnya] dari [kakeknya] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Celakalah orang yang bercerita, lalu berdusta untuk membuat orang-orang tertawa. Celakalah ia, celakalah ia.\""},"2232":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَعْقُوبَ بْنِ عُتْبَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ صَدَّقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمَيَّةَ بْنَ أَبِي الصَّلْتِ فِي بَيْتَيْنِ مِنْ الشِّعْرِ فَقَالَ رَجُلٌ وَثَوْرٌ تَحْتَ رِجْلِ يَمِينِهِ وَالنَّسْرُ لِلْأُخْرَى وَلَيْثٌ مُرْصَدُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَ قَالَ وَالشَّمْسُ تَطْلُعُ كُلَّ آخِرِ لَيْلَةٍ حَمْرَاءَ يُصْبِحُ لَوْنُهَا يَتَوَرَّدُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَ قَالَ تَأْبَى فَمَا تَطْلُعُ لَنَا فِي رِسْلِهَا إِلَّا مُعَذَّبَةً وَإِلَّا تُجْلَدُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Muhammad bin Ishaq] dari [Ya'qub bin Utbah] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Nabi shallallahu 'alaihi wasallam membenarkan Umayyah bin Abu Ash Shalt dalam dua bait sya'irnya; Seorang laki-laki dan kerbau berada di bawah kaki kanannya sedangkan burung elang berada di kaki lain serta singa yang senantiasa diawasi. Maka Nabi shallallahu 'alaihi wasallam mengatakan: \"ia benar.\" Ia melantunkan lagi; Matahari terbit setiap akhir malam, warnanya menjadi merah merona. Nabi shallallahu 'alaihi wasallam mengatakan: \"Ia benar.\" Ia melanjutkan; Ia enggan terbit, sehingga ia muncul secara lamban. Hanya karena mengikut terhadap apa yang diperintahkan. Sebab jika tidak terbit, ia akan diadzab atau didera. Nabi shallallahu 'alaihi wasallam mengatakan: \"Ia benar.\""},"2233":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ زِيَادٍ هُوَ ابْنُ سَعْدٍ أَخْبَرَنِي أَنَّ ابْنَ شِهَابٍ أَخْبَرَهُ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ هِشَامٍ عَنْ مَرْوَانَ بْنِ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ بْنِ عَبْدِ يَغُوثَ عَنْ أُبَيِّ بْنِ كَعْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ الشِّعْرِ حِكْمَةً","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Ziyad] ia adalah Ibnu Sa'ad, ia telah mengabarkan kepadaku bahwa [Ibnu Syihab] mengabarkan kepadanya dari [Abu Bakr bin Abdurrahman bin Hisyam] dari [Marwan bin Al Hakam] dari [Abdurrahman bin Al Aswad bin Abdu Yaqhuts] dari [Ubay bin Ka'b] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya sebagian sya'ir itu mengandung hikmah.\""},"2234":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى حَدَّثَنَا حَنْظَلَةُ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ يَمْتَلِئَ جَوْفُ أَحَدِكُمْ قَيْحًا أَوْ دَمًا خَيْرٌ مِنْ أَنْ يَمْتَلِئَ شِعْرًا","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] telah menceritakan kepada kami [Hanzhalah] dari [Salim] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, sekiranya perut salah seorang dari kalian dipenuhi dengan nanah atau darah lebih baik dari pada dipenuhi dengan sya'ir.\""},"2235":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ إِسْمَعِيلَ بْنِ جَعْفَرٍ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يُرِدْ اللَّهُ بِهِ خَيْرًا يُفَقِّهْهُ فِي الدِّينِ","id":"Telah mengabarkan kepada kami [Sa'id bin Sulaiman] dari [Isma'il bin Ja'far] dari [Abdullah bin Sa'id bin Abu Hind] dari [ayahnya] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa dikehendaki kebaikan oleh Allah, Dia akan memberikan kefahaman agama kepadanya.\""},"2236":{"ar":" أَخْبَرَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ اللَّهِ هُوَ ابْنُ سَعِيدٍ أَنَّهُ سَمِعَ أَبَاهُ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الصِّحَّةَ وَالْفَرَاغَ نِعْمَتَانِ مِنْ نِعَمِ اللَّهِ مَغْبُونٌ فِيهِمَا كَثِيرٌ مِنْ النَّاسِ","id":"Telah mengabarkan kepada kami [Al Makki bin Ibrahim] telah menceritakan kepada kami [Abdullah] ia adalah Ibnu Sa'id, bahwa ia mendengar [ayahnya] menceritakan dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kesehatan dan waktu luang adalah dua kenikmatan dari kenikmatan-kenikmatan Allah yang sering dilalaikan oleh kebanyakan manusia.\""},"2237":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا خَالِدٌ يَعْنِي ابْنَ عَبْدِ اللَّهِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اسْتَمَعَ إِلَى حَدِيثِ قَوْمٍ وَهُمْ لَهُ كَارِهُونَ صُبَّ فِي أُذُنِهِ الْآنُكُ","id":"Telah mengabarkan kepada kami [Amr bin 'Auf] telah mengabarkan kepada kami [Khalid] yakni Ibnu Abdullah, dari [Khalid Al Hadzdza`i] dari [Ikrimah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang mendengar pembicaraan suatu kaum, sementara mereka membenci hal itu (untuk didengar orang lain), niscaya akan dituangkan timah panas ke telinganya.\""},"2238":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ سَلَمَةَ بْنِ أَبِي الطُّفَيْلِ عَنْ عَلِيٍّ قَالَ لِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُتْبِعْ النَّظْرَةَ النَّظْرَةَ فَإِنَّ الْأُولَى لَكَ وَالْآخِرَةَ عَلَيْكَ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Hammad bin Salamah] dari [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim] dari [Salamah bin Abu Ath Thufail] dari [Ali] ia berkata kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah engkau terus menerus memandang (sesuatu yang haram), karena pandangan pertama adalah boleh untukmu, sedangkan pandangan selanjutnya adalah haram bagimu.\""},"2239":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ سُفْيَانَ عَنْ أَبِيهِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ أَخْبِرْنِي بِعَمَلٍ فِي الْإِسْلَامِ لَا أَسْأَلُ عَنْهُ أَحَدًا قَالَ اتَّقِ اللَّهَ ثُمَّ اسْتَقِمْ قَالَ قُلْتُ ثُمَّ أَيُّ شَيْءٍ قَالَ فَأَشَارَ إِلَى لِسَانِهِ","id":"Telah mengabarkan kepada kami [Sa'id bin Ar Rabi'] telah menceritakan kepada kami [Syu'bah] dari [Ya'la bin 'Atha`] ia berkata; Aku mendengar [Abdullah bin Sufyan] dari [ayahnya] ia berkata; Aku berkata; Wahai Rasulullah, kabarkanlah kepada amalan dalam Islam yang tidak akan aku tanyakan kepada seorang pun. Beliau bersabda: \"Bertaqwalah kepada Allah kemudian istiqamahlah.\" Ia mengatakan; Aku berkata lagi; Kemudian apa? Ia mengatakan; Lalu beliau menujuk ke arah lidahnya."},"2240":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِبْرَاهِيمُ يَعْنِي ابْنَ إِسْمَعِيلَ بْنِ مُجَمِّعٍ قَالَ أَخْبَرَنِي ابْنُ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُعَاذٍ عَنْ سُفْيَانَ بْنِ عَبْدِ اللَّهِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ مُرْنِي بِأَمْرٍ أَعْتَصِمُ بِهِ قَالَ قُلْ رَبِّيَ اللَّهُ ثُمَّ اسْتَقِمْ قَالَ قُلْتُ يَا نَبِيَّ اللَّهِ مَا أَكْثَرُ مَا تَخَوَّفُ عَلَيَّ قَالَ فَأَخَذَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلِسَانِهِ ثُمَّ قَالَ هَذَا","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ibrahim] yakni Ibnu Isma'il bin Mujammi', ia berkata; Telah mengabarkan kepadaku [Ibnu Syihab] dari [Abdurrahman bin Mu'adz] dari [Sufyan bin Abdullah] ia berkata; Aku berkata; Wahai Rasulullah, perintahkanlah kepadaku suatu urusan yang akan aku pegang teguh. Beliau bersabda: \"Katakanlah; Rabbku adalah Allah, kemudian istiqamahlah.\" Ia mengatakan; Aku bertanya; Wahai Nabiyullah, apa yang harus lebih banyak aku takuti? Maka beliau memegang lidahnya kemudian mengatakan: \"Ini.\" "},"2241":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَ قِيلَ يَا رَسُولَ اللَّهِ أَيُّ الْإِسْلَامِ أَفْضَلُ قَالَ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Malik bin Mighwal] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] ia berkata; Dikatakan; Wahai Rasulullah, siapakah orang paling mulia dalam Islam? Beliau menjawab: \"Seseorang dimana kaum muslimin merasa selamat dari lisan dan tangannya.\""},"2242":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ عِيسَى عَنْ عَبْدِ اللَّهِ بْنِ عُقْبَةَ ع��نْ يَزِيدَ بْنِ عَمْرٍو عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَمَتَ نَجَا","id":"Telah mengabarkan kepada kami [Ishaq bin Isa] dari [Abdullah bin Uqbah] dari [Yazid bin Amr] dari [Abu Abdurrahman Al Hubuli] dari [Abdullah bin Amr bin Al 'Ash] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa diam, ia akan selamat.\""},"2243":{"ar":" أَخْبَرَنَا نُعَيْمُ بْنُ حَمَّادٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ مُحَمَّدٍ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قِيلَ لَهُ مَا الْغِيبَةُ قَالَ ذِكْرُكَ أَخَاكَ بِمَا يَكْرَهُ قِيلَ وَإِنْ كَانَ فِي أَخِي مَا أَقُولُ قَالَ فَإِنْ كَانَ فِيهِ فَقَدْ اغْتَبْتَهُ وَإِنْ لَمْ يَكُنْ فِيهِ فَقَدْ بَهَتَّهُ","id":"Telah mengabarkan kepada kami [Nu'aim bin Hammad] dari [Abdul Aziz bin Muhammad] dari [Al 'Ala`] dari [ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bahwa dikatakan kepada beliau; Apa ghibah itu? Beliau menjawab: \"Engkau menyebut-nyebut saudaramu dengan apa yang ia benci.\" Dikatakan; Meskipun apa yang aku katakan tentang saudaraku itu benar? Beliau menjawab: \"Jika apa yang kamu katakan tentangnya itu benar, maka engkau telah berbuat ghibah padanya, namun jika hal itu tidak benar, maka engkau telah berdusta kepadanya.\""},"2244":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا جَرِيرٌ عَنْ إِدْرِيسَ الْأَوْدِيِّ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ أَنَّ عَبْدَ اللَّهِ يَرْفَعُ الْحَدِيثَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ شَرَّ الرَّوَايَا رَوَايَا الْكَذِبِ وَلَا يَصْلُحُ مِنْ الْكَذِبِ جِدٌّ وَلَا هَزْلٌ وَلَا يَعِدُ الرَّجُلُ ابْنَهُ ثُمَّ لَا يُنْجِزُ لَهُ إِنَّ الصِّدْقَ يَهْدِي إِلَى الْبِرِّ وَإِنَّ الْبِرَّ يَهْدِي إِلَى الْجَنَّةِ وَإِنَّ الْكَذِبَ يَهْدِي إِلَى الْفُجُورِ وَإِنَّ الْفُجُورَ يَهْدِي إِلَى النَّارِ وَإِنَّهُ يُقَالُ لِلصَّادِقِ صَدَقَ وَبَرَّ وَيُقَالُ لِلْكَاذِبِ كَذَبَ وَفَجَرَ وَإِنَّ الرَّجُلَ لَيَصْدُقُ حَتَّى يُكْتَبَ عِنْدَ اللَّهِ صِدِّيقًا وَيَكْذِبُ حَتَّى يُكْتَبَ عِنْدَ اللَّهِ كَذَّابًا وَإِنَّهُ قَالَ لَنَا هَلْ أُنَبِّئُكُمْ مَا الْعَضْهُ وَإِنَّ الْعَضْهَ هِيَ النَّمِيمَةُ الَّتِي تُفْسِدُ بَيْنَ النَّاسِ","id":"Telah mengabarkan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Jarir] dari [Idris Al Audi] dari [Abu Ishaq] dari [Abu Al Ahwash] bahwa [Abdullah] memarfu'kan hadits kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya cerita yang paling buruk adalah cerita dusta, dan sebagian dusta itu tidak pantas dijadikan sesuatu yang serius dan canda. Seorang laki-laki tidak boleh berjanji kepada anaknya kemudian ia tidak menunaikan janjinya itu. Sesungguhnya kebenaran itu membimbing kepada kebajikan dan kebajikan itu membimbing ke surga. Sesungguhnya dusta itu menunjukkan pada kedurhakaan dan kedurhakaan itu membimbing ke neraka. Sesungguhnya akan dikatakan kepada orang yang jujur; Ia jujur dan bajik. Dan akan dikatakan kepada orang yang berdusta; Ia berdusta dan durhaka. Sesungguhnya seseorang akan berlaku jujur hingga ia dicatat di sisi Allah sebagai orang yang sangat jujur dan berlaku dusta hingga dicatat di sisi Allah sebagai pendusta.\" Beliau bersabda kepada kami: \"Maukah aku beritahukan kepada kalian apa itu Al 'Adlhu itu? Sesungguhnya Al 'Adlhu adalah mengadu domba yang akan menghancurkan antara manusia.\""},"2245":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَكَرِيَّا عَنْ الشَّعْبِيِّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْلِمُ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zakariya] dari [Asy Sya'bi] ia berkata; Aku mendengar [Abdullah bin Amr] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang muslim (yang sejati) adalah jika kaum muslimin selamat dari lisan dan tangannya.\""},"2246":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا الْفُضَيْلُ بْنُ مَرْزُوقٍ حَدَّثَنَا عَدِيُّ بْنُ ثَابِتٍ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَيُّهَا النَّاسُ إِنَّ اللَّهَ طَيِّبٌ لَا يَقْبَلُ إِلَّا الطَّيِّبَ إِنَّ اللَّهَ أَمَرَ الْمُؤْمِنِينَ بِمَا أَمَرَ بِهِ الْمُرْسَلِينَ قَالَ { يَا أَيُّهَا الرُّسُلُ كُلُوا مِنْ الطَّيِّبَاتِ وَاعْمَلُوا صَالِحًا إِنِّي بِمَا تَعْمَلُونَ عَلِيمٌ } وَقَالَ { يَا أَيُّهَا الَّذِينَ آمَنُوا كُلُوا مِنْ طَيِّبَاتِ مَا رَزَقْنَاكُمْ } قَالَ ثُمَّ ذَكَرَ الرَّجُلَ يُطِيلُ السَّفَرَ أَشْعَثَ أَغْبَرَ يَمُدُّ يَدَيْهِ إِلَى السَّمَاءِ يَا رَبِّ يَا رَبِّ وَمَطْعَمُهُ حَرَامٌ وَمَلْبَسُهُ حَرَامٌ وَمَشْرَبُهُ حَرَامٌ وَغُذِّيَ بِالْحَرَامِ فَأَنَّى يُسْتَجَابُ لِذَلِكَ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Fudlail bin Marzuq] telah menceritakan kepada kami [Adi bin Tsabit] dari [Abu Hazim] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai manusia, sesungguhnya Allah itu Maha Baik, tidak menerima kecuali yang baik. Sesungguhnya Allah telah memerintahkan kepada orang-orang yang beriman apa yang Dia perintahkan kepada para rasul. Allah berfirman: (Hai para rasul, makanlah dari makanan yang baik-baik dan kerjakanlah amal shalih. Sesungguhnya Aku Maha Mengetahui apa yang kamu kerjakan). Allah juga berfirman: (Hai orang-orang yang beriman, makanlah dari rezeki yang baik-baik yang Kami berikan kepadamu).\" Ia mengatakan; Kemudian beliau menyebutkan tentang seorang laki-laki yang telah melakukan perjalanan panjang dengan rambut kusut dan berdebu, ia menengadahkan kedua tangannya ke langit; Ya Rabbku ya Rabbku, sementara makanannya haram, pakaiannya haram, minumannya haram dan tumbuh dengan makanan yang haram, maka bagaimana mungkin doanya akan dikabulkan? "},"2247":{"ar":" حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَوَلَةَ عَنْ بُرَيْدَةَ الْأَسْلَمِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكْفِي أَحَدَكُمْ مِنْ الدُّنْيَا خَادِمٌ وَمَرْكَبٌ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] dari [Al Jurairi] dari [Abu An Nadlrah] dari [Abdullah bin Mawalah] dari [Buraidah Al Aslami] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sudah cukup (nikmat) dunia bagi salah seorang dari kalian, yakni pelayan dan kendaraan.\""},"2248":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ بَيَانٍ هُوَ ابْنُ بِشْرٍ الْأَحْمَسِيُّ عَنْ قَيْسٍ عَنْ مِرْدَاسٍ الْأَسْلَمِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْهَبُ الصَّالِحُونَ أَسْلَافًا وَيَبْقَى حُثَالَةٌ كَحُثَالَةِ الشَّعِيرِ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Abu 'Awanah] dari [Bayan] ia adalah Ibnu Bisyr Al Ahmasi, dari [Qais] dari [Mirdas Al Aslami] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang shalih itu akan pergi lebih dahulu dan tersisalah orang-orang buruk, seperti gandum yang buruk.\""},"2249":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي الزِّنَادِ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَمْ مِنْ صَائِمٍ لَيْسَ لَهُ مِنْ صِيَامِهِ إِلَّا الظَّمَأُ وَكَمْ مِنْ قَائِمٍ لَيْسَ لَهُ مِنْ قِيَامِهِ إِلَّا السَّهَرُ","id":"Telah menceritakan kepada kami [Ishaq bin Isa] dari [Abdurrahman bin Abu Az Zinad] dari [Amr bin Abu Amr] dari [Sa'id bin Al Maqburi] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Berapa banyak orang yang melaksanakan puasa, namun ia tidak mendapatkan apapun dari puasanya kecuali dahaga. Berapa banyak orang yang beribadah di malam hari, namun ia tidak mendapatkan apapun dari ibadanya selain hanya begadang.\""},"2250":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا سَعِيدٌ هُوَ ابْنُ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي كَعْبُ بْنُ عَلْقَمَةَ عَنْ عِيسَى بْنِ هِلَالٍ الصَّدَفِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ ذَكَرَ الصَّلَاةَ يَوْمًا فَقَالَ مَنْ حَافَظَ عَلَيْهَا كَانَتْ لَهُ نُورًا وَبُرْهَانًا وَنَجَاةً مِنْ النَّارِ يَوْمَ الْقِيَامَةِ وَمَنْ لَمْ يُحَافِظْ عَلَيْهَا لَمْ تَكُنْ لَهُ نُورًا وَلَا نَجَاةً وَلَا بُرْهَانًا وَكَانَ يَوْمَ الْقِيَامَةِ مَعَ قَارُونَ وَفِرْعَوْنَ وَهَامَانَ وَأُبَيِّ بْنِ خَلَفٍ","id":"Telah mengabarkan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Sa'id] ia adalah Ibnu Abu Ayyub, ia berkata; Telah menceritakan kepadaku [Ka'ab bin 'Alqamah] dari [Isa bin Hilal Ash Shadafi] dari [Abdullah bin Amr] dari Nabi shallallahu 'alaihi wasallam bahwa suatu hari beliau menyebutkan tentang shalat. Beliau bersabda: \"Barangsiapa yang menjaganya (shalat) maka ia akan menjadi cahaya, hujjah dan keselamatan baginya dari neraka pada hari kiamat. Barangsiapa yang tidak menjaganya (shalat) maka ia tidak akan menjadi cahaya, tidak pula keselamatan dan hujjah baginya, dan pada hari kiamat, ia akan bersama Qarun, Fir'aun, Haman dan Ubay bin Khalaf.\""},"2251":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي ابْنُ عَجْلَانَ عَنْ حُسَيْنِ بْنِ عَبْدِ اللَّهِ بْنِ عُبَيْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَرْغَبُ فِي قِيَامِ اللَّيْلِ حَتَّى قَالَ وَلَوْ رَكْعَةً","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] ia berkata; Telah menceritakan kepadaku [Laits] ia berkata; Telah menceritakan kepadaku [Ibnu 'Ajlan] dari [Husain bin Abdullah bin Ubaidullah bin Abbas] dari [Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam sangat menganjurkan shalat malam hingga beliau mengatakan: \"Walaupun hanya satu rakaat.\""},"2252":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عُبَيْدِ بْنِ عَمْرٍو أَبِي الْمُغِيرَةِ عَنْ حُذَيْفَةَ قَالَ كَانَ فِي لِسَانِي ذَرَبٌ عَلَى أَهْلِي وَلَمْ يَكُنْ يَعْدُهُمْ إِلَى غَيْرِهِمْ فَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيْنَ أَنْتَ عَنْ الِاسْتِغْفَارِ إِنِّي لَأَسْتَغْفِرُ اللَّهَ كُلَّ يَوْمٍ مِائَةَ مَرَّةٍ قَالَ أَبُو إِسْحَقَ فَحَدَّثْتُ أَبَا بُرْدَةَ وَأَبَا بَكْرٍ ابْنَيْ أَبِي مُوسَى قَالَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْتَغْفِرُ اللَّهَ كُلَّ يَوْمٍ مِائَةَ مَرَّةٍ أَسْتَغْفِرُ اللَّهَ وَأَتُوبُ إِلَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Isra`il] telah menceritakan kepada kami [Abu Ishaq] dari [Ubaid bin Amr Abu Al Mughirah] dari [Hudzaifah] ia berkata; Lidahku tajam terhadap keluargaku, namun tidak kepada orang lain. Lalu aku bertanya kepada Nabi shallallahu 'alaihi wasallam, beliau pun bertanya: \"Mengapa engkau tidak beristighfar (meminta ampunan kepada Allah)? Sesungguhnya aku beristighfar (meminta ampunan kepada Allah) setiap hari seratus kali.\" Abu Ishaq berkata; Aku pun menceritakan hadits itu kepada [Abu Buradah] dan [Abu Bakr] keduanya adalah anak Abu Musa, mereka berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Aku memohon ampunan kepada Allah setiap hari seratus kali, aku selalu memohon ampunan kepada Allah dan bertaubat kepadaNya.\""},"2253":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ الْمُبَارَكِ عَنْ سَلْمِ بْنِ قُتَيْبَةَ عَنْ سُهَيْلٍ الْقُطَعِيِّ عَنْ ثَابِتٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَرَأَ { أَهْلُ التَّقْوَى وَأَهْلُ الْمَغْفِرَةِ } قَالَ قَالَ رَبُّكُمْ أَنَا أَهْلٌ أَنْ أُتَّقَى فَمَنْ اتَّقَانِي فَأَنَا أَهْلٌ أَنْ أَغْفِرَ لَهُ","id":"Telah menceritakan kepada kami [Al Hakam bin Al Mubarak] dari [Salm bin Qutaibah] dari [Suhail Al Qutha'i] dari [Tsabit] dari [Anas] dari Nabi shallallahu 'alaihi wasallam bahwa beliau membaca: (Adalah Rabb yang patut (kita) bertaqwa kepadaNya dan berhak memberi ampunan). Beliau bersabda: \"Rabb kalian berfirman: (Aku adalah Rabb yang berhak untuk ditaqwai. Barangsiapa yang bertaqwa kepadaKu, maka Aku adalah Rabb yang berhak memberi ampunan kepadanya.\""},"2254":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا مُعْتَمِرٌ عَنْ كَهْمَسِ بْنِ الْحَسَنِ عَنْ أَبِي السَّلِيلِ عَنْ أَبِي ذَرٍّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَعْلَمُ آيَةً لَوْ أَخَذَ بِهَا النَّاسُ لَكَفَتْهُمْ { وَمَنْ يَتَّقِ اللَّهَ يَجْعَلْ لَهُ مَخْرَجًا }","id":"Telah menceritakan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Mu'tamir] dari [Kahmas bin Al Hasan] dari [Abu As Salil] dari [Abu Dzarr] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku mengetahui sebuah ayat yang seandainya orang-orang mengambilnya niscaya ayat itu akan mencukupi mereka, yaitu (Barangsiapa bertaqwa kepada Allah, niscaya Dia akan mengadakan baginya jalan keluar).\""},"2255":{"ar":" أَخْبَرَنَا مَنْصُورُ بْنُ سَلَمَةَ حَدَّثَنَا سَعِيدٌ هُوَ ابْنُ مُسْلِمِ بْنِ بَانَكَ عَنْ مَالِكٍ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَوْفِ بْنِ الْحَارِثِ عَنْ عَائِشَةَ قَالَتْ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَائِشُ إِيَّاكِ وَمُحَقَّرَاتِ الذُّنُوبِ فَإِنَّ لَهَا مِنْ اللَّهِ طَالِبًا","id":"Telah mengabarkan kepada kami [Manshur bin Salamah] telah menceritakan kepada kami [Sa'id] ia adalah Ibnu Muslim bin Banak, dari [Malik] dari [Amir bin Abdullah bin Az Zubair] dari ['Auf bin Al Harits] dari [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam mengatakan kepadaku: \"Wahai Aisyah, takutlah engkau terhadap dosa-dosa kecil, karena dosa-dosa kecil itu akan dimintai pertanggungjawaban di hadapan Allah.\""},"2256":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَلِيُّ بْنُ مَسْعَدَةَ الْبَاهِلِيُّ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ بَنِي آدَمَ خَطَّاءٌ وَخَيْرُ الْخَطَّائِينَ التَّوَّابُونَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Ali bin Mas'adah Al Bahili] telah menceritakan kepada kami [Qatadah] dari [Anas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap anak cucu Adam itu melakukan kesalahan dan sebaik-baik orang yang melakukan kesalahan adalah orang yang bertaubat.\""},"2257":{"ar":" أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ النُّعْمَانِ هُوَ ابْنُ بَشِيرٍ أَنَّهُ سَمِعَهُ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَافَرَ رَجُلٌ فِي أَرْضٍ تَنُوفَةٍ فَقَالَ تَحْتَ شَجَرَةٍ وَمَعَهُ رَاحِلَتُهُ عَلَيْهَا زَادُهُ وَطَعَامُهُ فَاسْتَيْقَظَ وَقَدْ ذَهَبَتْ رَاحِلَتُهُ فَعَلَا شَرَفًا فَلَمْ يَرَ شَيْئًا ثُمَّ عَلَا شَرَفًا فَلَمْ يَرَ شَيْئًا ثُمَّ عَلَا شَرَفًا فَلَمْ يَرَ شَيْئًا قَالَ فَالْتَفَتَ فَإِذَا هُوَ بِهَا تَجُرُّ خِطَامَهَا فَمَا هُوَ بِأَشَدَّ فَرَحًا بِهَا مِنْ اللَّهِ بِتَوْبَةِ عَبْدِهِ إِذَا تَابَ إِلَيْهِ","id":"Telah mengabarkan kepada kami [An Nadlr bin Syumail] telah menceritakan kepada kami [Hammad bin Salamah] dari [Simak bin Harb] dari [An Nu'man] ia adalah Ibnu Basyir, bahwa ia mendengarnya mengatakan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dulu ada seorang musafir berada di tanah gersang. Lalu Ia tidur di bawah pohon. Ketika itu ia membawa hewan tunggangan yang memuat perbekalan dan makanannya. Ketika bangun, hewan tunggangannya telah pergi. Ia pun naik ke tempat yang tinggi, namun ia tidak melihat apapun. Kemudian ia naik ke tempat lain yang tinggi, ia pun tidak melihat apapun. Kemudian ia kembali naik ke tempat tinggi, ia pun tidak melihat apapun.\" Beliau melanjutkan: \"Setelah itu ia menoleh ternyata hewan itu ada, dan sedang menarik-narik tali kekangnya. Rasa gembiranya ketika itu tidak melebihi rasa gembiranya Allah karena taubat bambaNya, ketika ia bertaubat kepadanya.\""},"2258":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ أَبِيهِ عَنْ أَبِي يَعْلَى عَنْ الرَّبِيعِ بْنِ خُثَيْمٍ عَنْ عَبْدِ اللَّهِ قَالَ خَطَّ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطًّا مُرَبَّعًا ثُمَّ خَطَّ وَسَطَهُ خَطًّا ثُمَّ خَطَّ حَوْلَهُ خُطُوطًا وَخَطَّ خَطًّا خَارِجًا مِنْ الْخَطِّ فَقَالَ هَذَا الْإِنْسَانُ لِلْخَطِّ الْأَوْسَطِ وَهَذَا الْأَجَلُ مُحِيطٌ بِهِ وَهَذِهِ الْأَعْرَاضُ لِلْخُطُوطِ فَإِذَا أَخْطَأَهُ وَاحِدٌ نَهَشَهُ الْآخَرُ وَهَذَا الْأَمَلُ لِلْخَطِّ الْخَارِجِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] dari [ayahnya] dari [Abu Ya'la] dari [Ar Rabi' bin Khutsaim] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah membuatkan kami garis berbentuk persegi empat. Kemudian beliau membuat sebuah garis di tengahnya, lalu membuat beberapa garis di sekitarnya dan membuat sebuah garis yang berada di luar garis tengah itu. Beliau pun bersabda: \"Ini adalah manusia, yaitu garis tengah, ini adalah ajal yang mengelilingnya. Ini adalah hal-hal yang akan terjadi (pada manusia, berupa bala`, ujian, dan cobaan sewaktu di dunia) pada garis-garis ini. Jika tidak terkena satu garis, maka akan digigit (terkena) garis yang lain (bala' dan cobaan itu akan selalu datang silih berganti tanpa henti). Dan ini adalah harapan, yaitu garis yang berada di luar.\""},"2259":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ زَكَرِيَّا عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ زُرَارَةَ عَنْ ابْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا ذِئْبَانِ جَائِعَانِ أُرْسِلَا فِي غَنَمٍ بِأَفْسَدَ لَهَا مِنْ حِرْصِ الْمَرْءِ عَلَى الْمَالِ وَالشَّرَفِ لِدِينِهِ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Zakariya] dari [Muhammad bin Abdurrahman bin Sa'd bin Zurarah] dari [Ibnu Ka'ab bin Malik] dari [ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua serigala lapar yang dilepaskan di dalam kawanan kambing tidak lebih menghancuran dari pada ketamakan seseorang terhadap harta dan kemuliaan agamanya.\""},"2260":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ حَدَّثَنَا هِشَامُ بْنُ الْغَازِ عَنْ حَيَّانَ أَبِي النَّضْرِ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ تَبَارَكَ وَتَعَالَى أَنَا عِنْدَ ظَنِّ عَبْدِي بِي فَلْيَظُنَّ بِي مَا شَاءَ","id":"Telah mengabarkan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Abdullah bin Al Mubarak] telah menceritakan kepada kami [Hisyam bin Al Ghazi] dari [Hayyan Abu An Nadlr] dari [Watsilah bin Al Asqa'] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah Tabaraka wa Ta'ala berfirman: Aku tergantung pada sangkaan hambaKu kepadaKu, karena itu, bersangkalah kepadaKu dengan sesuatu yang dikehendaki.\""},"2261":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَ قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أَنْزَلَ اللَّهُ تَعَالَى { وَأَنْذِرْ عَشِيرَتَكَ الْأَقْرَبِينَ } فَقَالَ يَا مَعْشَرَ قُرَيْشٍ اشْتَرُوا أَنْفُسَكُمْ مِنْ اللَّهِ لَا أُغْنِي عَنْكُمْ مِنْ اللَّهِ شَيْئًا يَا بَنِي عَبْدِ مَنَافٍ لَا أُغْنِي عَنْكُمْ مِنْ اللَّهِ شَيْئًا يَا عَبَّاسُ بْنَ عَبْدِ الْمُطَلِّبِ لَا أُغْنِي عَنْكَ مِنْ اللَّهِ شَيْئًا يَا صَفِيَّةُ عَمَّةَ رَسُولِ اللَّهِ لَا أُغْنِي عَنْكِ مِنْ اللَّهِ شَيْئًا يَا فَاطِمَةُ بِنْتَ مُحَمَّدٍ سَلِينِي مَا شِئْتِ لَا أُغْنِي عَنْكِ مِنْ اللَّهِ شَيْئًا","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] dari [Syu'aib] dari [Az Zuhri] ia berkata; Telah mengabarkan kepada kami [Sa'id bin Al Musayyab] dan [Abu Salamah bin Abdurrahman] bahwa [Abu Hurairah] berkata; Nabi shallallahu 'alaihi wasallam berdiri ketika Allah menurunkan ayat: (Dan berilah peringatan kepada kerabat-kerabatmu yang terdekat). Lalu beliau mengatakan: \"Wahai sekalian orang-orang Quraisy, juallah diri kalian dari siksa Allah, karena aku tidak bisa menyelamatkan kalian sedikit pun dari siksa Allah. Wahai banu Abdu Manaf, aku tidak bisa menyelamatkan kalian sedikit pun dari siksa Allah. Wahai Abbas bin Abdul Muthallib, aku tidak bisa menyelamatkanmu sedikit pun dari siksa Allah. Wahai Shafiyyah bibi Rasulullah, aku tidak bisa menyelamatkanmu sedikit pun dari siksa Allah. Wahai Fathimah bintu Muhammad, mintalah kepadaku apa yang engkau kehendaki, karena aku tidak bisa menyelamatkanmu sedikit pun dari siksa Allah.\" "},"2262":{"ar":" أَخْبَرَنَا الْحَسَنُ بْنُ الرَّبِيعِ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَارِبُوا وَسَدِّدُوا وَاعْلَمُوا أَنَّ أَحَدًا مِنْكُمْ لَنْ يُنْجِيَهُ عَمَلُهُ قَالُوا يَا رَسُولَ اللَّهِ وَلَا أَنْتَ قَالَ وَلَا أَنَا إِلَّا أَنْ يَتَغَمَّدَنِيَ اللَّهُ بِرَحْمَةٍ مِنْهُ وَفَضْلٍ","id":"Telah mengabarkan kepada kami [Al Hasan bin Ar Rabi'] telah menceritakan kepada kami [Abu Al Ahwash] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bersikaplah pertengahan, istiqamahlah dalam perbuatan dan ucapan, ketahuilah bahwa tak ada seorang pun dari kalian yang akan diselamatkan oleh perbuatannya.\" Mereka berkata; Wahai Rasulullah, tidak juga engkau? Beliau menjawab: \"Tidak juga aku, hanya saja Allah menganugerahiku rahmat dan karuniaNya.\""},"2263":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْكُمْ مِنْ أَحَدٍ إِلَّا وَمَعَهُ قَرِينُهُ مِنْ الْجِنِّ وَقَرِينُهُ مِنْ الْمَلَائِكَةِ قَالُوا وَإِيَّاكَ قَالَ نَعَمْ وَإِيَّايَ وَلَكِنَّ اللَّهَ أَعَانَنِي عَلَيْهِ فَأَسْلَمُ قَالَ أَبُو مُحَمَّد مِنْ النَّاسِ مَنْ يَقُولُ أَسْلَمَ اسْتَسْلَمَ يَقُولُ ذَلَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Manshur] dari [Salim bin Abu Al Ja'd] dari [ayahnya] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorang pun dari kalian kecuali ia ditemani oleh qarin (pendamping) dari bangsa jin dan qarin dari bangsa malaikat.\" Mereka bertanya; Juga denganmu? Beliau menjawab: \"Ya, begitu juga denganku, tapi Allah membantuku untuk mengalahkannya, sehingga ia masuk Islam.\" Abu Muhammad berkata; Ada orang yang mengatakan; Ia masuk Islam dan menyerahkan diri, ia mengatakan; Ia tunduk."},"2264":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ مُوسَى بْنِ أَنَسٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ تَعْلَمُونَ مَا أَعْلَمُ لَضَحِكْتُمْ قَلِيلًا وَلَبَكَيْتُمْ كَثِيرًا حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ هَذَا","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Musa bin Anas] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seandainya kalian mengetahui apa yang aku ketahui, tentu kalian akan sedikit tertawa dan banyak menangis.\" Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam seperti hadits ini."},"2265":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي الْمُهَزِّمِ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِسَخْلَةٍ جَرْبَاءَ قَدْ أَخْرَجَهَا أَهْلُهَا قَالَ تُرَوْنَ هَذِهِ هَيِّنَةً عَلَى أَهْلِهَا قَالُوا نَعَمْ قَالَ وَاللَّهِ لَلدُّنْيَا أَهْوَنُ عَلَى اللَّهِ مِنْ هَذِهِ عَلَى أَهْلِهَا","id":"Telah mengabarkan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu Al Muhazzim] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam melewati bangkai kambing busuk yang telah dibuang pemiliknya. Beliau mengatakan: \"Menurut kalian, apakah bangkai ini hina bagi pemiliknya?\" Mereka menjawab; Ya. Beliau bersabda: \"Demi Allah, sesungguhnya dunia itu lebih hina di sisi Allah dari pada bangkai ini bagi pemiliknya.\""},"2266":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ أَبِي الْمُرَاوِحِ عَنْ أَبِي ذَرٍّ قَالَ سَأَلَ رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ إِيمَانٌ بِاللَّهِ وَجِهَادٌ فِي سَبِيلِ اللَّهِ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Hisyam bin Urwah] dari [ayahnya] dari [Abu Al Murawih] dari [Abu Dzarr] ia berkata; Ada seseorang bertanya kepada Nabi shallallahu 'alaihi wasallam, ia pun mengatakan; Amal apakah yang paling utama? Beliau menjawab: \"Iman kepada Allah dan berjihad fi sabilillah.\""},"2267":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي جَعْفَرٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ الْأَعْمَالِ عِنْدَ اللَّهِ إِيمَانٌ لَا شَكَّ فِيهِ قَالَ أَبُو مُحَمَّد أَبُو جَعْفَرٍ رَجُلٌ مِنْ الْأَنْصَارِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Ja'far] bahwa ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Amalan yang paling utama di sisi Allah adalah iman yang tidak disertai dengan keraguan.\" Abu Muhammad berkata; Abu Ja'far adalah orang Anshar."},"2268":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى يُحِبَّ لِأَخِيهِ مَا يُحِبُّ لِنَفْسِهِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak sempurna iman salah seorang dari kalian hingga ia mencintai saudaranya seperti ia mencintai dirinya sendiri.\""},"2269":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ وَهَاشِمُ بْنُ الْقَاسِمِ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى أَكُونَ أَحَبَّ إِلَيْهِ مِنْ وَالِدِهِ وَوَلَدِهِ وَالنَّاسِ أَجْمَعِينَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dan [Hasyim bin Al Qasim] keduanya berkata; Telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak sempurna iman salah seorang dari kalian hingga aku menjadi orang yang paling ia cintai dari pada orang tuanya, anaknya dan seluruh manusia.\""},"2270":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ عَلِيِّ بْنِ زَيْدِ بْنِ جُدْعَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِي بَكْرَةَ أَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ أَيُّ النَّاسِ خَيْرٌ قَالَ مَنْ طَالَ عُمُرُهُ وَحَسُنَ عَمَلُهُ قَالَ فَأَيُّ النَّاسِ شَرٌّ قَالَ مَنْ طَالَ عُمُرُهُ وَسَاءَ عَمَلُهُ حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ بِإِسْنَادِهِ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zuhair] dari [Ali bin Zaid bin Jud'an] dari [Abdurrahman bin Abu Bakrah] dari [Abu Bakrah] bahwa ada seseorang berkata; Wahai Rasulullah, siapa manusia yang paling baik? Beliau menjawab: \"Orang yang panjang usianya dan bagus amalnya.\" Orang itu bertanya lagi; Siapa manusia yang paling hina? Beliau menjawab: \"Orang yang panjang usianya dan buruk amalnya.\" Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ali bin Zaid] dengan sanad yang serupa."},"2271":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا أَسِيدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ خَالِدِ بْنِ دُرَيْكٍ عَنْ ابْنِ مُحَيْرِيزٍ قَالَ قُلْتُ لِأَبِي جُمُعَةَ رَجُلٍ مِنْ الصَّحَابَةِ حَدِّثْنَا حَدِيثًا سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ أُحَدِّثُكَ حَدِيثًا جَيِّدًا تَغَدَّيْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَنَا أَبُو عُبَيْدَةَ بْنُ الْجَرَّاحِ فَقَالَ يَا رَسُولَ اللَّهِ أَحَدٌ خَيْرٌ مِنَّا أَسْلَمْنَا وَجَاهَدْنَا مَعَكَ قَالَ نَعَمْ قَوْمٌ يَكُونُونَ مِنْ بَعْدِكُمْ يُؤْمِنُونَ بِي وَلَمْ يَرَوْنِي","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] ia berkata; Telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepada kami [Asid bin Abdurrahman] dari [Khalid bin Duraik] dari [Ibnu Muhairiz] ia berkata; Aku bertanya kepada [Abu Jumu'ah], ia adalah seorang sahabat; Ceritakan sebuah hadits kepadaku yang engkau dengar dari Rasulullah shallallahu 'alaihi wasallam. Ia mengatakan; Baik, aku akan menceritakan kepadamu sebuah hadits yang bagus. Kami pernah makan siang bersama Rasulullah shallallahu 'alaihi wasallam, kami bersama Abu Ubaidah bin Al Jarrah. Ketika itu Abu Ubaidah berkata; Wahai Rasulullah, adakah orang yang lebih baik dari kami yang telah masuk Islam dan berjihad bersama engkau? Beliau bersabda: 'Iya, yaitu orang-orang yang hidup setelah kalian. Mereka beriman kepadaku padahal mereka tidak pernah melihatku.\""},"2272":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ قَالَ سَمِعْتُ أَبَا وَائِلٍ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بِئْسَمَا لِأَحَدِكُمْ أَنْ يَقُولَ نَسِيتُ آيَةَ كَيْتَ وَكَيْتَ بَلْ هُوَ نُسِّيَ فَاسْتَذْكِرُوا الْقُرْآنَ فَإِنَّهُ أَسْرَعُ تَفَصِّيًا مِنْ صُدُورِ الرِّجَالِ مِنْ النَّعَمِ مِنْ عُقُلِهَا","id":"Telah mengabarkan kepada kami [Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Syu'bah] dari [Manshur] ia berkata; Aku mendengar [Abu Wa`il] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Alangkah buruknya bagi salah seorang dari kalian yang berkata; Aku lupa ayat ini dan itu, tetapi ia dibuat lupa. Maka jagalah Al Qur`an sebab sesungguhnya Al Qur`an itu lebih cepat hilang dari dada (hafalan) seseorang dari pada binatang ternak dari tali pengikatnya.\""},"2273":{"ar":" أَخْبَرَنَا أَبُو نُعْيَمٍ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقُولَنَّ أَحَدُكُمْ أَنَا خَيْرٌ مِنْ يُونُسَ بْنِ مَتَّى","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Wa`il] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah salah seorang dari kalian tidak mengatakan; Aku lebih baik dari Yunus bin Matta.\""},"2274":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ الْمَدَائِنِيُّ حَدَّثَنَا شُعْبَةُ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى كُلِّ مُسْلِمٍ صَدَقَةٌ قَالُوا يَا رَسُولَ اللَّهِ فَإِنْ لَمْ يَسْتَطِعْ أَوْ لَمْ يَفْعَلْ قَالَ يَعْتَمِلُ بِيَدَيْهِ فَيَأْكُلُ مِنْهُ وَيَتَصَدَّقُ قَالُوا أَفَرَأَيْتَ إِنْ لَمْ يَفْعَلْ قَالَ يُعِينُ ذَا الْحَاجَةِ الْمَلْهُوفَ قَالُوا أَفَرَأَيْتَ إِنْ لَمْ يَفْعَلْ قَالَ يَأْمُرُ بِالْخَيْرِ قَالُوا أَفَرَأَيْتَ إِنْ لَمْ يَفْعَلْ قَالَ يُمْسِكُ عَنْ الشَّرِّ فَإِنَّهَا لَهُ صَدَقَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Ja'far Al Mada`ini] telah menceritakan kepada kami [Syu'bah] dari [Sa'id bin Abu Burdah] dari [ayahnya] dari [Abu Musa Al Asy'ari] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap muslim wajib bersedekah.\" Mereka bertanya; Wahai Rasulullah, jika ia tidak mampu atau tidak dapat melakukannya? Beliau menjawab: \"Hendaklah ia bekerja dengan tangannya lalu makan dari hasil kerjanya dan bersedekah.\" Mereka bertanya lagi; Menurut engkau, jika ia belum bisa melakukannya? Beliau menjawab: \"Menolong orang butuh yang teraniaya (terzhalimi).\" Mereka bertanya lagi; Menurut engkau, jika ia belum bisa melakukannya? Beliau menjawab: \"Hendaklah ia menyuruh kepada kebaikan.\" Mereka bertanya lagi; Menurut engkau, jika ia belum bisa melakukannya? Beliau menjawab: \"Hendaklah ia mencegah perbuatan buruk, karena hal itu juga sedekah baginya.\""},"2275":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا حَيْوَةُ قَالَ حَدَّثَنِي أَبُو صَخْرٍ أَنَّهُ سَمِعَ مَكْحُولًا يَقُولُ حَدَّثَنِي أَبُو هِنْدٍ الدَّارِيُّ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ قَامَ مَقَامَ رِيَاءٍ وَسُمْعَةٍ رَاءَى اللَّهُ بِهِ يَوْمَ الْقِيَامَةِ وَسَمَّعَ","id":"Telah mengabarkan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Haiwah] ia berkata; telah menceritakan kepadaku [Abu Shakhr] bahwa ia mendengar [Makhul] ia berkata; telah menceritakan kepadaku [Abu Hind ad Dari] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melakukan sesuatu karena riya` dan sum'ah, maka pada hari kiamat Allah akan memperlihatkan dan memperdengarkannya.\""},"2276":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبٍ عَنْ أَبِيهِ كَعْبِ بْنِ مَالِكٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْمُؤْمِنِ مَثَلُ الْخَامَةِ مِنْ الزَّرْعِ تُفَيِّئُهَا الرِّيَاحُ تُعَدِّلُهَا مَرَّةً وَتُضْجِعُهَا أُخْرَى حَتَّى يَأْتِيَهُ الْمَوْتُ وَمَثَلُ الْكَافِرِ كَمَثَلِ الْأَرْزَةِ الْمُجْذِيَةِ عَلَى أَصْلِهَا لَا يُصِيبُهَا شَيْءٌ حَتَّى يَكُونَ انْجِعَافُهَا مَرَّةً وَاحِدَةً قَالَ أَبُو مُحَمَّد الْخَامَةُ الضَّعِيفُ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Sa'ad bin Ibrahim] dari [Abdullah bin Ka'ab] dari ayahnya [Ka'ab bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan orang mukmin seperti tanaman yang elastis digoyang oleh angin. Sesekali tegak dan sesekali miring hingga tanaman itu mati. Sedangkan perumpamaan orang kafir seperti tanaman yang keras, tidak dapat digoyang oleh apapun hingga ia jatuh dan tercabut sekaligus.\" Abu Muhammad berkata; Al Khamah adalah elastis (lemah)."},"2277":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ الْأَوْزَاعِيِّ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَعُرْوَةَ بْنِ الزُّبَيْرِ أَنَّ حَكِيمَ بْنَ حِزَامٍ قَالَ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا حَكِيمُ إِنَّ هَذَا الْمَالَ خَضِرٌ حُلْوٌ فَمَنْ أَخَذَهُ بِسَخَاوَةِ نَفْسٍ بُورِكَ لَهُ فِيهِ وَمَنْ أَخَذَهُ بِإِشْرَافِ نَفْسٍ لَمْ يُبَارَكْ لَهُ فِيهِ وَكَانَ كَالَّذِي يَأْكُلُ وَلَا يَشْبَعُ وَالْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Al Auza'i] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dan [Urwah bin Az Zubair] bahwa [Hakim bin Hizam] berkata; Aku meminta kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau memberiku, kemudian aku memintanya lagi, beliau pun memberiku, lalu aku memintanya lagi, beliau pun memberiku, kemudian aku memintanya lagi, lalu beliau bersabda: \"Wahai Hakim, sesungguhnya harta ini hijau lagi manis (sangat memikat dan menggiurkan), maka barangsiapa yang mengambilnya dengan kedermawanan diri niscaya ia mendapatkan berkah dan barangsiapa yang mengambilnya dengan rakus niscaya ia tidak akan mendapat berkah, ia seperti orang yang makan dan tidak pernah kenyang. Tangan di atas lebih baik dari pada tangan di bawah.\""},"2278":{"ar":" حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو الرَّقِّيُّ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ وَرَّادٍ مَوْلَى الْمُغِيرَةِ عَنْ الْمُغِيرَةِ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ وَأْدِ الْبَنَاتِ وَعُقُوقِ الْأُمَّهَاتِ وَعَنْ مَنْعٍ وَهَاتِ وَعَنْ قِيلَ وَقَالَ وَكَثْرَةِ السُّؤَالِ وَإِضَاعَةِ الْمَالِ","id":"Telah menceritakan kepada kami [Zakariya bin Adi] telah menceritakan kepada kami [Ubaidullah bin Amr Ar Raqqi] dari [Abdul Malik bin Umair] dari [Warrad] mantan budak Al Mughirah dari [Al Mughirah] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang mengubur anak perempuan hidup-hidup, durhaka kepada ibu, tidak memberi tapi mau menerima, banyak bicara, banyak bertanya dan menyia-nyiakan harta."},"2279":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ عَنْ ثَوْبَانَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا أَخَافُ عَلَى أُمَّتِي الْأَئِمَّةَ الْمُضِلِّينَ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Abu Asma`] dari [Tsauban] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang aku takutkan terhadap umatku adalah para pemimpin yang menyesatkan.\""},"2280":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ أَن��َ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِيَنْصُرْ الرَّجُلُ أَخَاهُ ظَالِمًا أَوْ مَظْلُومًا فَإِنْ كَانَ ظَالِمًا فَلْيَنْهَهُ فَإِنَّهُ لَهُ نُصْرَةٌ وَإِنْ كَانَ مَظْلُومًا فَلْيَنْصُرْهُ","id":"Telah menceritakan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Zuhair] dari [Abu Az Zubair] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah seseorang menolong saudaranya yang menzhalimi atau yang dizhalimi. Jika ia orang yang menzhalimi maka hendaklah ia dicegah, karena itu adalah cara menolongnya. Dan jika ia orang yang dizhalimi, maka hendaklah ia ditolong.\""},"2281":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ هِشَامِ بْنِ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ وَنَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الدِّينُ النَّصِيحَةُ قَالَ قُلْنَا لِمَنْ يَا رَسُولَ اللَّهِ قَالَ لِلَّهِ وَلِرَسُولِهِ وَلِكِتَابِهِ وَلِأَئِمَّةِ الْمُسْلِمِينَ وَعَامَّتِهِمْ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] dari [Hisyam bin Sa'd] dari [Zaid bin Aslam] dan [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Agama itu nasehat.\" Ia mengatakan; Kami bertanya; Bagi siapa wahai Rasulullah? Beliau menjawab: \"Bagi Allah, RasulNya, kitabNya, para pemimpin kaum muslimin dan seluruh umatnya.\""},"2282":{"ar":" حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْإِسْلَامَ بَدَأَ غَرِيبًا وَسَيَعُودُ غَرِيبًا أَظُنُّ حَفْصًا قَالَ فَطُوبَى لِلْغُرَبَاءِ قِيلَ وَمَنْ الْغُرَبَاءُ قَالَ النُّزَّاعُ مِنْ الْقَبَائِلِ","id":"Telah menceritakan kepada kami [Zakariya bin Adi] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Al A'masy] dari [Abu Ishaq] dari [Al Ahwash] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Islam diawali dalam keadaan asing dan akan kembali dalam keadaan asing pula.\" Aku kira Hafsh berkata; Maka berbahagialah orang-orang asing itu. Dikatakan; Siapakah orang-orang asing itu? Ia menjawab; Orang-orang yang menjauhkan diri dari sanak saudaranya (untuk menegakkan ajaran agama Islam)."},"2283":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ عُبَادَةَ بْنِ الصَّامِتِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُ فَقَالَتْ عَائِشَةُ أَوْ بَعْضُ أَزْوَاجِهِ إِنَّا لَنَكْرَهُ الْمَوْتَ قَالَ لَيْسَ ذَلِكَ وَلَكِنَّ الْمُؤْمِنَ إِذَا حَضَرَهُ الْمَوْتُ بُشِّرَ بِرِضْوَانِ اللَّهِ وَكَرَامَتِهِ فَلَيْسَ شَيْءٌ أَحَبَّ إِلَيْهِ مِمَّا أَمَامَهُ فَأَحَبَّ لِقَاءَ اللَّهِ وَأَحَبَّ اللَّهُ لِقَاءَهُ وَإِنَّ الْكَافِرَ إِذَا حَضَرَهُ الْمَوْتُ بُشِّرَ بِعَذَابِ اللَّهِ وَعُقُوبَتِهِ فَلَيْسَ شَيْءٌ أَكْرَهَ إِلَيْهِ مِمَّا أَمَامَهُ فَكَرِهَ لِقَاءَ اللَّهِ وَكَرِهَ اللَّهُ لِقَاءَهُ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas] dari [Ubadah bin Ash Shamit] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang suka berjumpa dengan Allah maka Allah suka berjumpa dengannya. Dan barangsiapa benci berjumpa dengan Allah maka Allah pun benci berjumpa dengannya.\" Aisyah atau salah seorang dari isteri-isteri beliau berkata; Sesungguhnya kami tidak suka mati. Beliau bersabda: \"Bukan seperti itu, tetapi jika kematian telah menghampiri orang mukmin maka ia diberi kabar gembira dengan ridla Allah dan kemuliaanNya. Tidak ada sesuatu yang paling ia sukai dari pada apa yang ada di hadapannya. Oleh karena itu ia suka berjumpa Alah dan Allah pun suka berjumpa dengannya. Sedangkan jika kematian telah menghampiri orang kafir maka ia diberi kabar gembira tentang adzab Allah dan siksaanNya. Maka tidak ada sesuatu yang paling dibencinya dari pada apa yang ada di hadapannya. Oleh karena itu ia tidak suka berjumpa Allah dan Allah pun tidak suka berjumpa dengannya.\""},"2284":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ مَعْمَرٍ عَنْ أَبِي الْحُبَابِ سَعِيدِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَعَالَى يَقُولُ يَوْمَ الْقِيَامَةِ أَيْنَ الْمُتَحَابُّونَ بِجَلَالِ الْيَوْمَ أُظِلُّهُمْ فِي ظِلِّي يَوْمَ لَا ظِلَّ إِلَّا ظِلِّي","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Malik] dari [Abdullah bin Abdurrahman bin Ma'mar] dari [Abu Al Hubab Sa'id bin Yasar] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah Ta'ala berfirman pada hari kiamat; Manakah orang-orang yang saling mencintai karena keagunganKu? Hari ini aku menaungi mereka di bawah naunganKu pada hari yang tidak ada naungan selain naunganKu.\""},"2285":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنِي شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو عُبَيْدٍ مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّ أَبَا هُرَيْرَةَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَتَمَنَّى أَحَدُكُمْ الْمَوْتَ إِمَّا مُحْسِنًا فَلَعَلَّهُ أَنْ يَزْدَادَ إِحْسَانًا وَإِمَّا مُسِيئًا فَلَعَلَّهُ أَنْ يَسْتَعْتِبَ","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] telah mengabarkan kepadaku [Syu'aib] dari [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [Abu Ubaid] mantan budak Abdurrahman bin 'Auf bahwa [Abu Hurairah] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian berangan-angan untuk mati, jika ia orang baik semoga ia dapat menambah kebaikannya dan jika ia orang jahat semoga ia bertaubat.\""},"2286":{"ar":" حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بُعِثْتُ أَنَا وَالسَّاعَةُ كَهَاتَيْنِ وَأَشَارَ وَهْبٌ بِالسَّبَّاحَةِ وَالْوُسْطَى","id":"Telah menceritakan kepada kami [Wahab bin Jarir] telah menceritakan kepada kami [Syu'bah] dari [Abu At Tayyah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jarak aku diutus dengan hari kiamat adalah seperti antara kedua ini.\" Wahab mengisyaratkan dengan jari telunjuk dan jari tengah."},"2287":{"ar":" أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ حَدَّثَنَا بَهْزُ بْنُ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّكُمْ وَفَّيْتُمْ سَبْعِينَ أُمَّةً أَنْتُمْ آخِرُهَا وَأَكْرَمُهَا عَلَى اللَّهِ","id":"Telah mengabarkan kepada kami [An Nadlr bin Syumail] telah menceritakan kepada kami [Bahz bin Hakim] dari [ayahnya] dari [kakeknya] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kalian telah menyempurnakan tujuh puluh umat. Kalian adalah umat yang terakhir dan yang paling mulia di sisi Allah.\""},"2288":{"ar":" حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَاصِمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيْنَ فُلَانٌ فَغَمَزَهُ رَجُلٌ مِنْهُمْ فَقَالَ إِنَّهُ وَإِنَّهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَيْسَ قَدْ شَهِدَ بَدْرًا قَالُوا بَلَى قَالَ فَلَعَلَّ اللَّهَ اطَّلَعَ عَلَى أَهْلِ بَدْرٍ فَقَالَ اعْمَلُوا مَا شِئْتُمْ فَقَدْ غَفَرْتُ لَكُمْ","id":"Telah menceritakan kepada kami [Amr bin 'Ashim] telah menceritakan kepada kami [Hammad bin Salamah] dari ['Ashim] dari [Abu Shalih] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bertanya: \"Di mana fulan?\" Lalu salah seorang sahabat mencelanya; Sesungguhnya ia itu begini dan begitu. Nabi shallallahu 'alaihi wasallam pun bertanya: \"Bukankah ia ikut dalam perang Badr?\" Mereka menjawab; Benar. Beliau bersabda: \"Semoga Allah menemui ahlu Badr, Dia telah berfirman: (Berbuatlah apa yang kalian suka, sebab Aku telah mengampuni kalian) \""},"2289":{"ar":" حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ أَخْبَرَنَا عَمْرُو بْنُ دِينَارٍ عَنْ عَتَّابِ بْنِ حُنَيْنٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ حَبَسَ اللَّهُ الْقَطْرَ عَنْ أُمَّتِي عَشْرَ سِنِينَ ثُمَّ أُنْزِلَ لَأَصْبَحَتْ طَائِفَةٌ مِنْ أُمَّتِي بِهَا كَافِرِينَ يَقُولُونَ هُوَ بِنَوْءِ مِجْدَحٍ قَالَ الْمِجْدَحُ كَوْكَبٌ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] ia berkata; Telah mengabarkan kepada kami [Amr bin Dinar] dari ['Attab bin Hunain] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya Allah menahan tetesan hujan terhadap umatku selama sepuluh tahun kemudian Dia menurunkannya, niscaya ada segolongan umatku yang kafir karenanya. Mereka berkata; Hujan itu turun karena bintang Mijdah.\" Abu Sa'id Al Khudri berkata; Mijdah adalah nama salah satu bintang."},"2290":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ وَاصِلٍ مَوْلَى أَبِي عُيَيْنَةَ عَنْ بَشَّارِ بْنِ أَبِي سَيْفٍ عَنْ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عِيَاضِ بْنِ غُطَيْفٍ قَالَ أَتَيْنَا أَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ نَعُودُهُ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْحَسَنَةُ بِعَشْرِ أَمْثَالِهَا","id":"Telah mengabarkan kepada kami [Amr bin 'Aun] telah mengabarkan kepada kami [Khalid bin Abdullah] dari [Washil] mantan budak Abu Uyainah dari [Basysyar bin Abu Saif] dari [Al Walid bin Abdurrahman] dari ['Iyadl bin Ghuthaif] ia berkata; Kami pernah menjenguk [Abu Ubaidah bin Al Jarrah] saat ia sakit, lalu ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu kebaikan dibalas dengan sepuluh kebaikan yang semisal.\""},"2291":{"ar":" أَخْبَرَنَا الْأَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شَرِيكٌ عَنْ الرُّكَيْنِ عَنْ نُعَيْمِ بْنِ حَنْظَلَةَ قَالَ شَرِيكٌ وَرُبَّمَا قَالَ النُّعْمَانِ بْنِ حَنْظَلَةَ عَنْ عَمَّارٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ ذَا وَجْهَيْنِ فِي الدُّنْيَا كَانَ لَهُ يَوْمَ الْقِيَامَةِ لِسَانَانِ مِنْ نَارٍ","id":"Telah mengabarkan kepada kami [Al Aswad bin Amir] telah menceritakan kepada kami [Syarik] dari [Rukain] dari [Nu'aim bin Hanzhalah], [Syarik] berkata; Kemungkinan [An Nu'man bin Hanzhalah] berkata; Dari [Ammar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang memiliki dua muka (bermuka dua, munafik) sewaktu di dunia, maka pada hari kiamat ia akan memiliki dua lidah dari api neraka.\""},"2292":{"ar":" حَدَّثَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنَّمَا أَنَا بَشَرٌ فَأَيُّ الْمُسْلِمِينَ لَعَنْتُهُ أَوْ شَتَمْتُهُ أَوْ جَلَدْتُهُ فَاجْعَلْهَا لَهُ صَلَاةً وَرَحْمَةً وَقُرْبَةً تُقَرِّبُهُ بِهَا إِلَيْكَ يَوْمَ الْقِيَامَةِ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ عَنْ أَبِيهِ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ إِلَّا أَنَّ فِيهِ زَكَاةً وَرَحْمَةً","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, sesungguhnya aku adalah manusia biasa. Maka dari itu, siapa saja dari kaum muslimin yang pernah aku laknat, aku cela, atau aku dera, jadikanlah hal itu sebagai shalawat (doa), rahmat dan ibadah yang dapat mendekatkannya kepadaMu pada hari kiamat.\" Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dari [ayahnya] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam seperti hadits itu, hanya saja di dalamnya terdapat kata zakat dan rahmat."},"2293":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ سُوَيْدَ بْنَ الْحَارِثِ عَنْ أَبِي ذَرٍّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا يَسُرُّنِي أَنَّ جَبَلَ أُحُدٍ لِي ذَهَبًا أَمُوتُ يَوْمَ أَمُوتُ عِنْدِي دِينَارٌ أَوْ نِصْفُ دِينَارٍ إِلَّا لِغَرِيمٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Amr bin Murrah] ia berkata; Aku mendengar [Suwaid bin Al Harits] dari [Abu Dzar] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Alangkah senangnya aku seandainya gunung Uhud menjadi emas untukku, jika aku meninggal pada hari aku meninggal, sementara aku hanya memiliki satu dinar atau setengah dinar yang (aku berikan) untuk orang yang terlilit hutang.\""},"2294":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْفَضْلِ وَسُلَيْمَانُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا حَمَّادٌ هُوَ ابْنُ زَيْدٍ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ عُبَادَةَ بْنِ قُرْطٍ قَالَ إِنَّكُمْ لَتَأْتُونَ أُمُورًا هِيَ أَدَقُّ فِي أَعْيُنِكُمْ مِنْ الشَّعْرِ كُنَّا نَعُدُّهَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمُوبِقَاتِ فَذُكِرَ لِمُحَمَّدٍ يَعْنِي ابْنَ سِيرِينَ فَقَالَ صَدَقَ فَأَرَى جَرَّ الْإِزَارِ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Fadlal] dan [Sulaiman bin Harb] keduanya berkata; Telah menceritakan kepada kami [Hammad] ia adalah Ibnu Zaid, ia berkata; Telah menceritakan kepada kami [Ayyub] dari [Humaid bin Hilal] dari [Ubadah bin Qurth] ia berkata; Sesungguhnya kalian akan melakukan perbuatan-perbuatan yang lebih kecil dari sehelai rambut dalam pandangan kalian, di mana dahulu kami pada masa Rasulullah shallallahu 'alaihi wasallam menganggapnya termasuk dosa-dosa besar. Ketika hal ini disebutkan kepada Muhammad yakni Ibnu Sirin, ia menjawab; Benar, dan menurutku, salah satunya adalah menjulurkan kain sarung (Isbal)."},"2295":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ أَبِيهِ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحُمَّى مِنْ فَيْحِ جَهَنَّمَ أَوْ مِنْ فَوْرِ جَهَنَّمَ فَأَبْرِدُوهَا بِالْمَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [ayahnya] dari ['Abayah bin Rifa'ah] dari [Rafi' bin Khadij] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demam itu berasal dari panas api neraka.\" Atau: \"Kobaran api neraka, oleh karena itu dinginkanlah dengan air.\""},"2296":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا سُفْيَانُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ الْقَاسِمِ بْنِ مُخَيْمِرَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَحَدٌ مِنْ الْمُسْلِمِينَ يُصَابُ بِبَلَاءٍ فِي جَسَدِهِ إِلَّا أَمَرَ اللَّهُ الْحَفَظَةَ الَّذِينَ يَحْفَظُونَهُ فَقَالَ اكْتُبُوا لِعَبْدِي فِي كُلِّ يَوْمٍ وَلَيْلَةٍ مِثْلَ مَا كَانَ يَعْمَلُ مِنْ الْخَيْرِ مَا كَانَ مَحْبُوسًا فِي وِثَاقِي","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Sufyan] dari ['Alqamah bin Martsad] dari [Al Qasim bin Mukhaimirah] dari [Abdullah bin Amr] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah salah seorang dari kaum muslimin tertimpa musibah pada tubuhnya kecuali Allah memerintahkan kepada para malaikat penjaga yang menjaganya. Dia berfirman: Tuliskan untuk hambaKu pada setiap hari dan malam seperti kebaikan yang biasa ia lakukan, selama ia terikat dalam ikatanKu (sakit atau dalam kondisi sulit).\""},"2297":{"ar":" أَخْبَرَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ عَنْ عَبْدِ اللَّهِ قَالَ دَخَلْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُوعَكُ فَوَضَعْتُ يَدِي عَلَيْهِ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّكَ لَتُوعَكُ وَعْكًا شَدِيدًا فَقَالَ إِنِّي أُوعَكُ كَمَا يُوعَكُ رَجُلَانِ مِنْكُمْ قَالَ قُلْتُ ذَلِكَ بِأَنَّ لَكَ أَجْرَيْنِ قَالَ أَجَلْ وَمَا مِنْ مُسْلِمٍ يُصِيبُهُ أَذًى مَرَضٌ فَمَا سِوَاهُ إِلَّا حُطَّ عَنْهُ مِنْ سَيِّئَاتِهِ كَمَا تَحُطُّ الشَّجَرَةُ وَرَقَهَا","id":"Telah mengabarkan kepada kami [Ya'la bin Ubaid] telah menceritakan kepada kami [Al A'masy] dari [Ibrahim At Taimi] dari [Al Harits bin Suwaid] dari [Abdullah] ia berkata; Aku masuk ke rumah Rasulullah shallallahu 'alaihi wasallam, saat itu beliau sedang sakit, lalu aku letakkan tanganku padanya. Aku pun berkata; Wahai Rasulullah, sesungguhnya engkau sakit parah dan demam yang tinggi? Lalu beliau menjawab: \"Sesungguhnya aku mengalami sakit seperti sakit yang dialami dua orang dari kalian.\" Aku bertanya; Hal itu karena engkau mendapatkan dua palaha? Beliau menjawab: \"Benar, tidaklah seorang muslim yang menderita karena suatu penyakit atau yang lainnya, kecuali kesalahan-kesalahannya akan dihapus sebagaimana dedaunan yang berguguran dari pohon.\""},"2298":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ الْمَدَنِيُّ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى عَلَيَّ صَلَاةً وَاحِدَةً صَلَّى اللَّهُ عَلَيْهِ عَشْرًا","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Isma'il bin Ja'far Al Madani] dari [Al 'Ala` bin Abdurrahman] dari [ayahnya] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaca shalawat kepadaku satu kali, maka Allah akan membalas shalawatnya sebanyak sepuluh kali.\""},"2299":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ سُلَيْمَانَ مَوْلَى الْحَسَنِ بْنِ عَلِيٍّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَبِيهِ قَالَ جَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا وَهُوَ يُرَى الْبِشْرُ فِي وَجْهِهِ فَقِيلَ يَا رَسُولَ اللَّهِ إِنَّا نَرَى فِي وَجْهِكَ بِشْرًا لَمْ نَكُنْ نَرَاهُ قَالَ أَجَلْ إِنَّ مَلَكًا أَتَانِي فَقَالَ لِي يَا مُحَمَّدُ إِنَّ رَبَّكَ يَقُولُ لَكَ أَمَا يُرْضِيكَ أَنْ لَا يُصَلِّيَ عَلَيْكَ أَحَدٌ مِنْ أُمَّتِكَ إِلَّا صَلَّيْتُ عَلَيْهِ عَشْرًا وَلَا يُسَلِّمَ عَلَيْكَ إِلَّا سَلَّمْتُ عَلَيْهِ عَشْرًا قَالَ قُلْتُ بَلَى","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Sulaiman] mantan budak Al Hasan bin Ali] dari [Abdullah bin Abu Thalhah] dari [ayahnya] ia berkata; Suatu hari Nabi shallallahu 'alaihi wasallam datang dengan wajah berseri-seri, lalu dikatakan; Wahai Rasulullah, sesungguhnya kami melihat kebahagiaan di wajahmu yang belum pernah kami lihat sebelumnya. Beliau menjawab: \"Benar, sesungguhnya malaikat mendatangiku seraya berkata kepadaku; Wahai Muhammad, sesungguhnya Rabbmu mengatakan: Tidakkah engkau senang bahwa tidak ada seorang pun yang bershalawat untukmu dari salah seorang umatmu, kecuali Aku bershalawat untuknya sepuluh kali dan tidaklah ia mengucapkan salam satu kali kepadamu kecuali Aku mengucapkan salam kepadanya sepuluh kali? Beliau berkata; Maka aku jawab: Tentu.\""},"2300":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِ عَنْ زَاذَانَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِلَّهِ مَلَائِكَةً سَيَّاحِينَ فِي الْأَرْضِ يُبَلِّغُونِي عَنْ أُمَّتِي السَّلَامَ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin As Sa`ib] dari [Zadzan] dari [Abdullah bin Mas'ud] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah memiliki beberapa malaikat yang selalu berjalan di muka bumi untuk menyampaikan kepadaku salam dari umatku.\""},"2301":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبُ بْنُ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ لِي أَسْمَاءً أَنَا مُحَمَّدٌ وَأَنَا أَحْمَدُ وَأَنَا الْمَاحِي الَّذِي يَمْحُو اللَّهُ بِيَ الْكُفْرَ وَأَنَا الْحَاشِرُ الَّذِي يُحْشَرُ النَّاسُ عَلَى قَدَمِي وَأَنَا الْعَاقِبُ وَالْعَاقِبُ الَّذِي لَيْسَ بَعْدَهُ أَحَدٌ","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] telah mengabarkan kepada kami [Syu'aib bin Abu Hamzah] dari [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [Muhammad bin Jubair bin Muth'im] dari [ayahnya] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku memiliki beberapa nama, aku adalah Muhammad, aku adalah Ahmad, aku adalah Al Mahi yang denganku Allah membasmi kekufuran, aku adalah Al Hasyir di mana manusia dikumpulkan di bawah kakiku dan aku adalah Al 'Aqib, Al 'Aqib adalah seorang nabi yang tidak ada seorang nabi pun setelahnya.\""},"2302":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَابِطٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا كَعْبُ بْنَ عُجْرَةَ إِنَّهُ لَنْ يَدْخُلَ الْجَنَّةَ لَحْمٌ نَبَتَ مِنْ سُحْتٍ","id":"Telah mengabarkan kepada kami [Al Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Abdullah bin Utsman bin Khutsaim] dari [Abdurrahman bin Sabith] dari [Jabir bin Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam mengatakan: \"Wahai Ka'b bin 'Ujrah, sesungguhnya tidak akan masuk surga daging yang tumbuh dari makanan haram.\" "},"2303":{"ar":" أَخْبَرَنَا أَبُو حَاتِمٍ الْبَصْرِيُّ هُوَ رَوْحُ بِنُ أَسْلَمَ الْبَصْرِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا ثَابِتٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍ قَالَ بَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ إِذْ ضَحِكَ فَقَالَ أَلَا تَسْأَلُونِي مِمَّا أَضْحَكُ فَقَالُوا مِمَّ تَضْحَكُ قَالَ عَجَبًا مِنْ أَمْرِ الْمُؤْمِنِ كُلُّهُ لَهُ خَيْرٌ إِنْ أَصَابَهُ مَا يُحِبُّ حَمِدَ اللَّهَ عَلَيْهِ فَكَانَ لَهُ خَيْرٌ وَإِنْ أَصَابَهُ مَا يَكْرَهُ فَصَبَرَ كَانَ لَهُ خَيْرٌ وَلَيْسَ كُلُّ أَحَدٍ أَمْرُهُ لَهُ خَيْرٌ إِلَّا الْمُؤْمِنَ","id":"Telah mengabarkan kepada kami [Abu Hatim Al Bashri] ia adalah Rauh bin Aslam Al Bashri, telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Tsabit] dari [Abdurrahman bin Abu Laili] dari [Shuhaib] ia berkata; Ketika Rasulullah shallallahu 'alaihi wasallam sedang duduk, tiba-tiba beliau tertawa seraya mengatakan: \"Tidakkah kalian tanyakan kepadaku apa yang membuatku tertawa?\" Mereka bertanya; Apa yang membuat engkau tertawa? Beliau menjawab: \"Sungguh mengagumkan perkara orang mu`min yang seluruhnya adalah baik baginya. Jika ditimpa sesuatu yang disukai, lalu ia memuji Allah karenanya, maka hal itu adalah baik baginya. Jika ditimpa sesuatu yang tidak disukai, lalu ia bersabar, maka itu pun baik baginya. Tidak ada seorang pun yang seluruh perkaranya baik baginya kecuali orang mu`min.\""},"2304":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَ كُنْتُ أَسْمَعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَدْرِي أَشَيْءٌ أُنْزِلَ عَلَيْهِ أَمْ شَيْءٌ يَقُولُهُ وَهُوَ يَقُولُ لَوْ كَانَ لِابْنِ آدَمَ وَادِيَانِ مِنْ مَالٍ لَابْتَغَى إِلَيْهِمَا ثَالِثًا وَلَا يَمْلَأُ جَوْفَ ابْنِ آدَمَ إِلَّا التُّرَابُ وَيَتُوبُ اللَّهُ عَلَى مَنْ تَابَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] ia berkata; Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam namun aku tidak tahu apakah sesuatu telah diturunkan kepadanya atau hanya sesuatu yang beliau ucapkan, yaitu beliau mengatakan: \"Seandainya anak cucu Adam memiliki harta sepenuh dua lembah niscaya ia akan mencari harta ketiga sepenuh lembah. Dan sesuatu yang akan memenuhi rongga anak Adam adalah tanah. Allah menerima taubat kepada orang yang bertaubat.\""},"2305":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقُصُّ إِلَّا أَمِيرٌ أَوْ مَأْمُورٌ أَوْ مُرَاءٍ قُلْتُ لِعَمْرِو بْنِ شُعَيْبٍ إِنَّا كُنَّا نَسْمَعُ مُتَكَلِّفٌ فَقَالَ هَذَا مَا سَمِعْتُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Abdullah bin Amir] dari [Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah bercerita kecuali orang yang memerintah, orang yang diperintah atau orang yang berbuat riya`.\" Aku berkata kepada Amir bin Syu'aib; Sesungguhnya kami pernah mendengar redaksi; mutakallif (orang yang suka mengada-ada sesuatu yang tidak berguna). Lalu ia berkata; inilah yang aku dengar."},"2306":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ عَنْ شُعْبَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ مَيْسَرَةَ قَالَ سَمِعْتُ كُرْدُوسًا وَكَانَ قَاصًّا يَقُولُ أَخْبَرَنِي رَجُلٌ مِنْ أَهْلِ بَدْرٍ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَأَنْ أَقْعُدَ فِي مِثْلِ هَذَا الْمَجْلِسِ أَحَبُّ إِلَيَّ مِنْ أَنْ أُعْتِقَ أَرْبَعَ رِقَابٍ قَالَ قُلْتُ أَنَا أَيَّ مَجْلِسٍ يَعْنِي قَالَ كَانَ حِينَئِذٍ يَقُصُّ قَالَ أَبُو مُحَمَّد الرَّجُلُ مِنْ أَصْحَابِ بَدْرٍ هُوَ عَلِيٌّ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Yahya bin Abu Bukair] dari [Syu'bah] dari [Abdul Malik bin Maisarah] ia berkata; Aku mendengar [Kurdus], ia adalah tukang cerita, berkata; Telah mengabarkan kepadaku [seseorang ahlu Badr] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh duduk di majelis seperti ini lebih aku sukai dari pada memerdekakan empat orang budak.\" Ia mengatakan; Aku bertanya; Beritahukan kepadaku majelis apa yang beliau maksud? Ia menjawab; Waktu itu beliau sedang bercerita. Abu Muhammad berkata; Orang itu dari kalangan sahabat Badr yaitu Ali."},"2307":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنَا عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُلْدَغُ الْمُؤْمِنُ مِنْ جُحْرٍ وَاحِدٍ مَرَّتَيْنِ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] ia berkata; telah menceritakan kepadaku [Al Laits] ia berkata; Telah menceritakan kepada kami [Uqail] dari [Ibnu Syihab] ia berkata; telah mengabarkan kepadaku [Sa'id bin Al Musayyab] bahwa [Abu Hurairah] mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang beriman tidak sepantasnya terjerumus ke dalam lubang yang sama dua kali.\""},"2308":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ مُجَالِدٍ عَنْ عَامِرٍ عَنْ جَابِرٍ قَالَ وَرُبَّمَا سَكَتَ عَنْ جَابِرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَدْخُلُوا عَلَى الْمُغِيبَاتِ فَإِنَّ الشَّيْطَانَ يَجْرِي مِنْ ابْنِ آدَمَ كَمَجْرَى الدَّمِ قَالُوا وَمِنْكَ قَالَ نَعَمْ وَلَكِنَّ اللَّهَ أَعَانَنِي عَلَيْهِ فَأَسْلَمُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Abu Usamah] dari [Mujalid] dari [Amir] dari [Jabir] ia berkata; Terkadang berdiam dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian masuk menemui para isteri yang ditinggal suami, karena sesungguhnya setan berjalan dalam tubuh anak Adam seperti aliran darah.\" Mereka bertanya; Juga dalam tubuh engkau? Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya, tetapi Allah menolongku atasnya, maka aku pun selamat.\""},"2309":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ سَعْدٍ قَالَ سُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ النَّاسِ أَشَدُّ بَلَاءً قَالَ الْأَنْبِيَاءُ ثُمَّ الْأَمْثَلُ فَالْأَمْثَلُ يُبْتَلَى الرَّجُلُ عَلَى حَسَبِ دِينِهِ فَإِنْ كَانَ فِي دِينِهِ صَلَابَةٌ زِيدَ صَلَابَةً وَإِنْ كَانَ فِي دِينِهِ رِقَّةٌ خُفِّفَ عَنْهُ وَلَا يَزَالُ الْبَلَاءُ بِالْعَبْدِ حَتَّى يَمْشِيَ عَلَى الْأَرْضِ مَا لَهُ خَطِيئَةٌ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari ['Ashim] dari [Mush'ab bin Sa'd] dari [Sa'ad] ia berkata; Nabi shallallahu 'alaihi wasallam pernah ditanya; Siapakah orang yang paling berat cobaannya? Beliau menjawab: \"Para nabi, kemudian orang-orang yang mulia sesudahnya (derajat keimanannya setingkat di bawahnya), dan orang-orang yang mulia sesudahnya (derajat keimanannya setingkat di bawahnya). Seseorang akan diuji sesuai dengan tingkat agamanya. Jika agamanya teguh, maka ia akan bertambah teguh, namun jika agamanya lemah maka ia pun bertambah lemah. Musibah akan terus menimpa seorang hamba hingga ia berjalan di muka bumi ini tanpa ada satu doa pada dirinya.\""},"2310":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا مَالِكٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُطْرُونِي كَمَا تُطْرِي النَّصَارَى عِيسَى ابْنَ مَرْيَمَ وَلَكِنْ قُولُوا عَبْدُ اللَّهِ وَرَسُولُهُ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Malik] dari [Az Zuhri] dari [Ubaidullah] dari [Ibnu Abbas] dari [Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian berlebihan dalam memujiku seperti orang-orang Nashrani yang berlebihan memuji Isa bin Maryam. Akan tetapi katakanlah; Hamba Allah dan RasulNya.\""},"2311":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ جَعَلَ اللَّهُ الرَّحْمَةَ مِائَةَ جُزْءٍ فَأَمْسَكَ عِنْدَهُ تِسْعَةً وَتِسْعِينَ وَأَنْزَلَ فِي الْأَرْضِ جُزْءًا وَاحِدًا فَمِنْ ذَلِكَ الْجُزْءِ يَتَرَاحَمُ الْخَلْقُ حَتَّى تَرْفَعَ الْفَرَسُ حَافِرَهَا عَنْ وَلَدِهَا خَشْيَةَ أَنْ تُصِيبَهُ","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi] dari [Syu'aib] dari [Az Zuhri] ia berkata; telah mengabarkan kepadaku [Sa'id bin Al Musayyab] dari [Abu Hurairah] ia berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Allah menjadikan rahmat seratus bagian, namun Dia menahan sembilan puluh sembilan di sisiNya dan hanya menurunkan satu bagian ke bumi. Dari satu bagian itulah seluruh makhluk saling mengasihi hingga kuda yang rela mengangkat tapak kakinya karena khawatir akan menginjak anaknya.\""},"2312":{"ar":" حَدَّثَنَا عَفَّانُ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ حَدَّثَنَا الْجَعْدُ أَبُو عُثْمَانَ قَالَ سَمِعْتُ أَبَا رَجَاءٍ الْعُطَارِدِيَّ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا يَرْوِيهِ عَنْ رَبِّهِ عَزَّ وَجَلَّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ رَبَّكُمْ رَحِيمٌ مَنْ هَمَّ بِحَسَنَةٍ فَلَمْ يَعْمَلْهَا كُتِبَتْ لَهُ حَسَنَةً فَإِنْ عَمِلَهَا كُتِبَتْ عَشْرًا إِلَى سَبْعِ مِائَةٍ إِلَى أَضْعَافٍ كَثِيرَةٍ وَمَنْ هَمَّ بِسَيِّئَةٍ فَلَمْ يَعْمَلْهَا كُتِبَتْ لَهُ حَسَنَةً فَإِنْ عَمِلَهَا كُتِبَتْ وَاحِدَةً أَوْ يَمْحُوهَا وَلَا يَهْلِكُ عَلَى اللَّهِ إِلَّا هَالِكٌ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Ja'far bin Sulaiman] telah menceritakan kepada kami [Ja'd Abu Utsman] ia berkata; Aku mendengar [Abu Raja` Al 'Utharidi] ia berkata; Aku mendengar [Ibnu Abbas] dari Rasulullah shallallahu 'alaihi wasallam tentang apa yang beliau riwayatkan dari Rabbnya 'azza wajalla. Ia mengatakan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Rabb kalian Maha Penyayang, barangsiapa yang berniat melakukan suatu kebaikan lalu ia tidak melakukannya maka ditulis satu kebaikan baginya dan jika ia melakukannya maka ditulis sepuluh hingga tujuh ratus kali lipat kebaikan baginya, bahkan berkali-kali lipat banyaknya. Dan barangsiapa yang berniat melakukan suatu kejahatan lalu ia tidak melakukannya maka ditulis satu kebaikan baginya, namun jika ia melakukannya maka ditulis satu kejahatan baginya atau Dia akan menghapusnya. Tidaklah Allah membinasakan kecuali orang yang dikehendaki binasa.\""},"2313":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ سُلَيْمَانَ بْنِ الْمُغِيرَةِ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ الرَّجُلُ يُحِبُّ الْقَوْمَ لَا يَسْتَطِيعُ أَنْ يَعْمَلَ مِثْلَ عَمَلِهِمْ قَالَ أَنْتَ يَا أَبَا ذَرٍّ مَعَ مَنْ أَحْبَبْتَ قُلْتُ فَإِنِّي أُحِبُّ اللَّهَ وَرَسُولَهُ قَالَ أَنْتَ مَعَ مَنْ أَحْبَبْتَ","id":"Telah mengabarkan kepada kami [Sa'id bin Sulaiman] dari [Sulaiman bin Al Mughirah] dari [Humaid bin Hilal] dari [Abdullah Ash Shamit] dari [Abu Dzarr] ia berkata; Aku bertanya; Wahai Rasulullah, ada seseorang yang cinta kepada suatu kaum namun ia tidak mampu beramal seperti amalan mereka.? Beliau menjawab: \"Engkau wahai Abu Dzarr, akan bersama orang yang engkau cintai.\" Aku bertanya; Sesungguhnya aku mencintai Allah dan RasulNya. Beliau bersabda: \"Engkau akan bersama orang yang kamu cintai.\""},"2314":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا مَهْدِيٌّ حَدَّثَنَا غَيْلَانُ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ مَعْدِي كَرِبَ عَنْ أَبِي ذَرٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْوِيهِ عَنْ رَبِّهِ قَالَ يَا ابْنَ آدَمَ إِنَّكَ مَا دَعَوْتَنِي وَرَجَوْتَنِي غَفَرْتُ لَكَ مَا كَانَ فِيكَ ابْنَ آدَمَ إِنَّكَ إِنْ تَلْقَانِي بِقُرَابِ الْأَرْضِ خَطَايَا لَقِيتُكَ بِقُرَابِهَا مَغْفِرَةً بَعْدَ أَنْ لَا تُشْرِكَ بِي شَيْئًا ابْنَ آدَمَ إِنَّكَ إِنْ تُذْنِبْ حَتَّى يَبْلُغَ ذَنْبُكَ عَنَانَ السَّمَاءِ ثُمَّ تَسْتَغْفِرُنِي أَغْفِرْ لَكَ وَلَا أُبَالِي","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Mahdi] telah menceritakan kepada kami [Ghaylan] dari [Syahr bin Hausyab] dari [Ma'di Karib] dari [Abu Dzarr] dari Nabi shallallahu 'alaihi wasallam, beliau meriwayatkan dari Rabbnya: \"Dia berfirman: Hai anak cucu Adam, sesungguhnya selama kamu memohon dan mengharapkan dariKu niscaya Aku akan mengampuni dosa-dosamu. Hai anak Adam, sesungguhnya jika kamu menemuiku dengan dosa sepenuh bumi maka Aku akan menemuimu dengan pengampunan sepenuh itu juga, selama kamu tidak menyekutukanKu dengan suatu apa pun. Hai anak Adam, sesungguhnya jika kamu berbuat dosa hingga dosamu itu mencapai angkasa kemudian kamu memohon ampun kepadaKu niscaya Aku akan mengampunimu, dan Aku tidak peduli.\""},"2315":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا صَفْوَانُ هُوَ ابْنُ عَمْرٍو قَالَ حَدَّثَنِي يَحْيَى بْنُ جَابِرٍ الْقَاضِي عَنْ النَّوَّاسِ بْنِ سَمْعَانَ قَالَ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْبِرِّ وَالْإِثْمِ فَقَالَ الْبِرُّ حُسْنُ الْخُلُقِ وَالْإِثْمُ مَا حَاكَ فِي نَفْسِكَ وَكَرِهْتَ أَنْ يَعْلَمَهُ النَّاسُ أَخْبَرَنَا إِسْحَقُ بْنُ عِيسَى عَنْ مَعْنِ بْنِ عِيسَى عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ النَّوَّاسِ بْنِ سَمْعَانَ قَالَ سَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ بِنَحْوِهِ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Shafwan] ia adalah Ibnu Amr, ia berkata; Telah menceritakan kepadaku [Yahya bin Jabir Al Qadli] dari [An Nawas bin Sam'an] ia berkata; Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang kebaikan dan dosa. Beliau menjawab: \"Kebaikan adalah akhlak yang baik, sedangkan dosa adalah sesuatu yang mengganggu dalam dirimu dan kamu tidak ingin orang lain mengetahuinya.\" Telah mengabarkan kepada kami [Ishaq bin Isa] dari [Ma'an bin Isa] dari [Mu'awiyah bin Shalih] dari [Abdurrahman bin Jubair bin Nufair] dari [ayahnya] dari [An Nawas bin Sam'an] ia berkata; Aku bertanya kepada Nabi shallallahu 'alaihi wasallam, lalu ia menyebutkan seperti hadits itu."},"2316":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ مَيْمُونِ بْنِ أَبِي شَبِيبٍ عَنْ أَبِي ذَرٍّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّقِ اللَّهَ حَيْثُمَا كُنْتَ وَأَتْبِعْ السَّيِّئَةَ الْحَسَنَةَ وَخَالِقْ النَّاسَ بِخُلُقٍ حَسَنٍ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Habib bin Abu Tsabit] dari [Maimun bin Abu Syabib] dari [Abu Dzarr] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bertaqwalah engkau kepada Allah di mana saja berada, ikutilah perbuatan buruk dengan perbuatan baik, dan bergaullah terhadap manusia dengan akhlaq yang baik.\""},"2317":{"ar":" حَ��َّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا سَعِيدٌ هُوَ ابْنُ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْمَلُ الْمُؤْمِنِينَ إِيمَانًا أَحْسَنُهُمْ خُلُقًا","id":"Telah menceritakan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Sa'id] ia adalah Ibnu Abu Ayyub, ia berkata; Telah menceritakan kepadaku [Muhammad bin 'Ajlan] dari [Al Qa'qa' bin Hakim] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang mukmin yang paling sempurna keimanannya adalah yang paling baik akhlaqnya.\""},"2318":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادٌ هُوَ ابْنُ سَلَمَةَ عَنْ يُونُسَ وَحُمَيْدٍ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ رَفِيقٌ يُحِبُّ الرِّفْقَ وَيُعْطِي عَلَيْهِ مَا لَا يُعْطِي عَلَى الْعُنْفِ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad] ia adalah Ibnu Salamah, dari [Yunus] dan [Humaid] dari [Al Hasan] dari [Abdullah bin Mughaffal] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah Maha Lembut, Dia suka kelembutan dan memberi padanya apa yang tidak Dia berikan karena sikap kasar.\""},"2319":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يُحِبُّ الرِّفْقَ فِي الْأَمْرِ كُلِّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yunus] dari [Al Auza'i] dari [Az Zuhri] dari [Urwah] dari [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah mencintai kelembutan dalam segala hal.\""},"2320":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الْكَرْمَانِيُّ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَذْهَبْتُ حَبِيبَتَيْهِ فَصَبَرَ وَاحْتَسَبَ لَمْ أَرْضَ لَهُ بِثَوَابٍ دُونَ الْجَنَّةِ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad Al Karmani] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Ash Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Allah Subhanahu wa Ta'ala berfirman); Barangsiapa yang kedua matanya buta lalu ia bersabar dan mengharap pahala, maka Aku tidak akan ridla baginya kecuali mendapat pahala surga.\""},"2321":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا أَبُو الْأَشْهَبِ عَنْ الْحَسَنِ أَنَّ عُبَيْدَ اللَّهِ بْنَ زِيَادٍ عَادَ مَعْقِلَ بْنَ يَسَارٍ فِي مَرَضِهِ الَّذِي مَاتَ فِيهِ فَقَالَ لَهُ مَعْقِلٌ إِنِّي مُحَدِّثُكَ بِحَدِيثٍ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ عَلِمْتُ أَنَّ بِي حَيَاةً مَا حَدَّثْتُكَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ عَبْدٍ يَسْتَرْعِيهِ اللَّهُ رَعِيَّةً يَمُوتُ يَوْمَ يَمُوتُ وَهُوَ غَاشٌّ لِرَعِيَّتِهِ إِلَّا حَرَّمَ اللَّهُ عَلَيْهِ الْجَنَّةَ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Abu Al Asyhab] dari [Al Hasan] bahwa Ubaidullah bin Ziyad mengunjungi Ma'qil bin Yasar ketika sedang sakit yang menyebabkan kematiannya, maka [Ma'qil] berkata kepadanya; Sesungguhnya aku akan menceritakan satu hadits kepadamu yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam; Seandainya aku mengetahui aku masih dapat hidup, aku tidak akan menceritakannya kepadamu. Bahwa aku mendegar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang hamba yang diberikan tanggungjawab oleh Allah sebagai pemimpin lalu ia meninggal dunia pada hari yang telah ditetapkan dalam keadaan menipu rakyatnya, kecuali Allah mengharamkan surga untuknya.\""},"2322":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ قَالَ أَخْبَرَنِي زُرَيْقُ بْنُ حَيَّانَ مَوْلَى بَنِي فَزَارَةَ أَنَّهُ سَمِعَ مُسْلِمَ بْنَ قَرَظَةَ الْأَشْجَعِيَّ يَقُولُ سَمِعْتُ عَوْفَ بْنَ مَالِكٍ الْأَشْجَعِيَّ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ خِيَارُ أَئِمَّتِكُمْ الَّذِينَ تُحِبُّونَهُمْ وَيُحِبُّونَكُمْ وَتُصَلُّونَ عَلَيْهِمْ وَيُصَلُّونَ عَلَيْكُمْ وَشِرَارُ أَئِمَّتِكُمْ الَّذِينَ تُبْغِضُونَهُمْ وَيُبْغِضُونَكُمْ وَتَلْعَنُونَهُمْ وَيَلْعَنُونَكُمْ قُلْنَا أَفَلَا نُنَابِذُهُمْ يَا رَسُولَ اللَّهِ عِنْدَ ذَلِكَ قَالَ لَا مَا أَقَامُوا فِيكُمْ الصَّلَاةَ أَلَا مَنْ وُلِّيَ عَلَيْهِ وَالٍ فَرَآهُ يَأْتِي شَيْئًا مِنْ مَعْصِيَةِ اللَّهِ فَلْيَكْرَهْ مَا يَأْتِي مِنْ مَعْصِيَةِ اللَّهِ وَلَا يَنْزِعَنَّ يَدًا مِنْ طَاعَةٍ قَالَ ابْنُ جَابِرٍ فَقُلْتُ آللَّهِ يَا أَبَا الْمِقْدَامِ أَسَمِعْتَ هَذَا مِنْ مُسْلِمِ بْنِ قَرَظَةَ فَاسْتَقْبَلَ الْقِبْلَةَ وَجَثَا عَلَى رُكْبَتَيْهِ فَقَالَ آللَّهِ لَسَمِعْتُ هَذَا مِنْ مُسْلِمِ بْنِ قَرَظَةَ يَقُولُ سَمِعْتُ عَمِّي عَوْفَ بْنَ مَالِكٍ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُهُ","id":"Telah menceritakan kepada kami [Al Hakam bin Al Mubarak] telah mengabarkan kepada kami [Al Walid bin Muslim] dari [Abdurrahman bin Yazid bin Jabir] ia berkata; telah mengabarkan kepadaku [Zuraiq bin Hayyan] mantan budak banu Fazarah, bahwa ia mendengar [Muslim bin Qarazhah Al Asyja'i] ia berkata; aku mendengar ['Auf bin Malik Al Asyja'i] berkata; Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik pemimpin kalian adalah orang yang kalian cintai dan mereka pun mencintai kalian, kalian mendoakan mereka dan mereka pun mendoakan kalian. Dan seburuk-buruk pemimpin kalian adalah orang yang kalian benci dan mereka pun membenci kalian, kalian melaknat mereka dan mereka pun melaknat kalian.\" Kami bertanya; Bolehkah kami memerangi mereka, wahai Rasulullah? Beliau menjawab: \"Tidak, selama mereka masih mendirikan shalat di antara kalian. Ingatlah, barangsiapa yang mengangkat seseorang sebagai pemimpin lalu ia melihatnya melakukan kemaksiatan kepada Allah maka hendaklah ia membenci apa yang ia lakukan dari kemasiatan kepada Allah tersebut dan janganlah ia menarik dukungan ketaatan kepadanya.\" Ibnu Jabir berkata; Aku berkata; Demi Allah, wahai Abu Al Miqdam, apakah engkau mendengar hadits ini dari Muslim bin Qarazhah? Ia pun menghadap kiblat dan bersila lalu ia berkata; Demi Allah, aku mendengar hadits ini dari Muslim bin Qarazhah ia berkata; Aku mendengar pamanku 'Auf bin Malik berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam mengatakannya."},"2323":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَسْلَمَ الْعِجْلِيِّ عَنْ بِشْرِ بْنِ شَغَافٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ سُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصُّورِ فَقَالَ قَرْنٌ يُنْفَخُ فِيهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Sulaiman At Taimi] dari [Aslam Al 'Ijli] dari [Bisyr bin Syaghaf] dari [Abdullah bin Amr] ia berkata; Nabi shallallahu 'alaihi wasallam pernah ditanya tentang sangkakala. Beliau menjawab: \"Ia adalah tanduk yang ditiup.\""},"2324":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ سَمِعْتُ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَقْبِضُ اللَّهُ الْأَرْضَ وَيَطْوِي السَّمَوَاتِ بِيَمِينِهِ ثُمَّ يَقُولُ أَنَا الْمَلِكُ أَيْنَ مُلُوكُ الْأَرْضِ","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] telah menceritakan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; Aku mendengar [Abu Salamah bin Abdurrahman] berkata; Aku mendengar [Abu Hurairah] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah memegang bumi dan melipat langit dengan tangan kananNya kemudian Dia berfirman: Aku adalah Raja, di manakah raja-raja dunia?\""},"2325":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْفَضْلِ حَدَّثَنَا الصَّعْقُ بْنُ حَزْنٍ عَنْ عَلِيِّ بْنِ الْحَكَمِ عَنْ عُثْمَانَ بْنِ عُمَيْرٍ عَنْ أَبِي وَائِلٍ عَنْ ابْنِ مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قِيلَ لَهُ مَا الْمَقَامُ الْمَحْمُودُ قَالَ ذَاكَ يَوْمٌ يَنْزِلُ اللَّهُ تَعَالَى عَلَى كُرْسِيِّهِ يَئِطُّ كَمَا يَئِطُّ الرَّحْلُ الْجَدِيدُ مِنْ تَضَايُقِهِ بِهِ وَهُوَ كَسَعَةِ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَيُجَاءُ بِكُمْ حُفَاةً عُرَاةً غُرْلًا فَيَكُونُ أَوَّلَ مَنْ يُكْسَى إِبْرَاهِيمُ يَقُولُ اللَّهُ تَعَالَى اكْسُوا خَلِيلِي فَيُؤْتَى بِرَيْطَتَيْنِ بَيْضَاوَيْنِ مِنْ رِيَاطِ الْجَنَّةِ ثُمَّ أُكْسَى عَلَى إِثْرِهِ ثُمَّ أَقُومُ عَنْ يَمِينِ اللَّهِ مَقَامًا يَغْبِطُنِي الْأَوَّلُونَ وَالْآخِرُونَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Fadlal] telah menceritakan kepada kami [Ash Sh'q bin Hazn] dri [Ali bin Al Hakam] dari [Utsman bin Umair] dari [Abu Wa`il] dari [Ibnu Mas'ud] dari Nabi shallallahu 'alaihi wasallam, ia mengatakan; Dikatakan kepada beliau; Apa maksud tempat yang terpuji itu? Beliau menjawab: \"Pada hari itu Allah turun ke kursiNya yang mengeluarkan suara seperti suara kendaraan yang baru karena sempitnya, padahal kursi itu seluas antara langit dan bumi. Kalian akan didatangkan dalam keadaan telanjang kaki, telanjang badan dan tidak berkhitan, orang pertama yang diberi pakaian adalah Ibrahim. Allah Ta'ala berfirman: Berikan pakaian untuk kekasihKu. Lalu ia diberi dua buah pakaian dari pakaian-pakaian surga yang sangat halus dan berwarna putih. Kemudian aku yang diberi pakaian setelahnya, lalu aku pun berdiri di sisi kanan Allah, sebuah tempat yang menyebabkan orang-orang terdahulu dan terakhir merasa iri terhadapku.\""},"2326":{"ar":" حَدَّثَنَا أَبُو الْيَمَانِ الْحَكَمُ بْنُ نَافِعٍ عَنْ شُعَيْبِ بْنِ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَعَطَاءُ بْنُ يَزِيدَ اللَّيْثِيُّ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرَهُمَا أَنَّ النَّاسَ قَالُوا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ نَرَى رَبَّنَا يَوْمَ الْقِيَامَةِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ تُمَارُونَ فِي الْقَمَرِ لَيْلَةَ الْبَدْرِ لَيْسَ دُونَهُ سَحَابٌ قَالُوا لَا يَا رَسُولَ اللَّهِ قَالَ فَهَلْ تُمَارُونَ فِي الشَّمْسِ لَيْسَ دُونَهَا سَحَابٌ قَالُوا لَا قَالَ فَإِنَّكُمْ تَرَوْنَهُ كَذَلِكَ","id":"Telah menceritakan kepada kami [Abu Al Yaman Al Hakam bin Nafi'] dari [Syu'aib bin Abu Hamzah] dari [Az Zuhri] telah mengabarkan kepadaku [Sa'id bin Al Musayyab] dan ['Atha` bin Yazid Al Laitsi] bahwa [Abu Hurairah] telah mengabarkan kepada mereka berdua bahwa orang-orang bertanya kepada Nabi shallallahu 'alaihi wasallam; Apakah kami akan melihat Rabb kami pada hari kiamat? Nabi shallallahu 'alaihi wasallam pun menjawab: \"Apakah kalian berselisih pendapat dan ragu dapat melihat bulan di saat malam purnama, ketika langit bersih tanpa awan?\" Mereka menjawab; Tidak, wahai Rasulullah. Beliau bertanya: \"Apakah kalian berselisih pendapat dan ragu dapat melihat melihat matahari pada saat langit tanpa awan?\" mereka menjawab; Tidak, wahai Rasulullah. Beliau bersabda: \"Sesungguhnya kalian akan melihat Allah (pada hari kiamat nanti) seperti itu.\""},"2327":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا الْمُغِيرَةُ بْنُ النُّعْمَانِ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍ قَالَ خَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّكُمْ مَحْشُورُونَ إِلَى اللَّهِ تَعَالَى حُفَاةً عُرَاةً غُرْلًا ثُمَّ قَرَأَ { كَمَا بَدَأْنَا أَوَّلَ خَلْقٍ نُعِيدُهُ وَعْدًا عَلَيْنَا إِنَّا كُنَّا فَاعِلِينَ }","id":"Telah menceritakan kepada kami [Abu Al Walid Ath thayalisi] telah menceritakan kepada kami [Syu'bah] ia berkata; Telah menceritakan kepada kami [Al Mughirah bin An Nu'man] ia berkata; Aku mendengar [Sa'id bin Jubair] menceritakan hadits dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah berkhutbah seraya bersabda: \"Wahai manusia, sesungguhnya kalian akan dikumpulkan di hadapan Allah dalam keadaan telanjang kaki, telanjang badan dan tidak berkhitan.\" Kemudian beliau membaca firmanNya: (Sebagaimana Kami telah memulai penciptaan pertama begitulah Kami akan mengulanginya. Itulah suatu janji yang pasti Kami tepati, sesungguhnya Kamilah yang akan melaksanakannya)."},"2328":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ الْبَزَّازُ عَنْ يُونُسَ بْنِ بُكَيْرٍ قَالَ أَخْبَرَنِي ابْنُ إِسْحَقَ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ يَسَارٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا جَمَعَ اللَّهُ الْعِبَادَ فِي صَعِيدٍ وَاحِدٍ نَادَى مُنَادٍ لِيَلْحَقْ كُلُّ قَوْمٍ بِمَا كَانُوا يَعْبُدُونَ فَيَلْحَقُ كُلُّ قَوْمٍ بِمَا كَانُوا يَعْبُدُونَ وَيَبْقَى النَّاسُ عَلَى حَالِهِمْ فَيَأْتِيهِمْ فَيَقُولُ مَا بَالُ النَّاسِ ذَهَبُوا وَأَنْتُمْ هَا هُنَا فَيَقُولُونَ نَنْتَظِرُ إِلَهَنَا فَيَقُولُ هَلْ تَعْرِفُونَهُ فَيَقُولُونَ إِذَا تَعَرَّفَ إِلَيْنَا عَرَفْنَاهُ فَيَكْشِفُ لَهُمْ عَنْ سَاقِهِ فَيَقَعُونَ سُجُودًا فَذَلِكَ قَوْلُ اللَّهِ تَعَالَى { يَوْمَ يُكْشَفُ عَنْ سَاقٍ وَيُدْعَوْنَ إِلَى السُّجُودِ فَلَا يَسْتَطِيعُونَ } يَبْقَى كُلُّ مُنَافِقٍ فَلَا يَسْتَطِيعُ أَنْ يَسْجُدَ ثُمَّ يَقُودُهُمْ إِلَى الْجَنَّةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid Al Bazzaz] dari [Yunus bin Bukair] ia berkata; telah mengabarkan kepadaku [Ibnu Ishaq] ia berkata; telah mengabarkan kepadaku [Sa'id bin Yasar] ia berkata; Aku mendengar [Abu Hurairah] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika Allah telah mengumpulkan seluruh hamba di satu tempat yang luas, terdengar suara penyeru; Hendaklah setiap kaum bergabung dengan apa yang mereka sembah. Maka setiap kaum pun bergabung dengan apa yang mereka sembah. Sementara ada segolongan manusia masih pada tempat mereka. Lalu penyeru mendatangi mereka seraya bertanya; Mengapa manusia lainnya telah pergi sedangkan kalian masih di sini? Mereka menjawab; Kami menunggu Rabb kami. Ia bertanya lagi; Apakah kalian mengenalNya? Mereka menjawab; Apabila Dia memperkenalkan diri kepada kami maka kami pasti mengenalNya. Maka dibukakan untuk mereka hijab dariNya, lalu mereka pun langsung tersungkur sujud. Itulah firman Allah: (Pada hari betis disingkapkan dan mereka dipanggil untuk bersujud, maka mereka tidak kuasa). Tinggallah setiap orang munafik tidak kuasa untuk bersujud, kemudian mereka digiring ke dalam surga.\""},"2329":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ زِيَادٍ حَدَّثَنَا دُخَيْنٌ الْحَجْرِيُّ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا جَمَعَ اللَّهُ الْأَوَّلِينَ وَالْآخِرِينَ فَقَضَى بَيْنَهُمْ وَفَرَغَ مِنْ الْقَضَاءِ قَالَ الْمُؤْمِنُونَ قَدْ قَضَى بَيْنَنَا رَبُّنَا فَمَنْ يَشْفَعُ لَنَا إِلَى رَبِّنَا فَيَقُولُونَ انْطَلِقُوا إِلَى آدَمَ فَإِنَّ اللَّهَ خَلَقَهُ بِيَدِهِ وَكَلَّمَهُ فَيَأْتُونَهُ فَيَقُولُونَ قُمْ فَاشْفَعْ لَنَا إِلَى رَبِّنَا فَيَقُولُ آدَمُ عَلَيْكُمْ بِنُوحٍ فَيَأْتُونَ نُوحًا فَيَدُلُّهُمْ عَلَى إِبْرَاهِيمَ فَيَأْتُونَ إِبْرَاهِيمَ فَيَدُلُّهُمْ عَلَى مُوسَى فَيَأْتُونَ مُوسَى فَيَدُلُّهُمْ عَلَى عِيسَى فَيَأْتُونَ عِيسَى فَيَقُولُ أَدُلُّكُمْ عَلَى النَّبِيِّ الْأُمِّيِّ قَالَ فَيَأْتُونِي فَيَأْذَنُ اللَّهُ عَزَّ وَجَلَّ لِي أَنْ أَقُومَ إِلَيْهِ فَيَثُورُ مَجْلِسِي أَطْيَبَ رِيحٍ شَمَّهَا أَحَدٌ قَطُّ حَتَّى آتِيَ رَبِّي فَيُشَفِّعَنِي وَيَجْعَلَ لِي نُورًا مِنْ شَعْرِ رَأْسِي إِلَى ظُفْرِ قَدَمِي فَيَقُولُ الْكَافِرُونَ عِنْدَ ذَلِكَ لِإِبْلِيسَ قَدْ وَجَدَ الْمُؤْمِنُونَ مَنْ يَشْفَعُ لَهُمْ فَقُمْ أَنْتَ فَاشْفَعْ لَنَا إِلَى رَبِّكَ فَإِنَّكَ أَنْتَ أَضْلَلْتَنَا قَالَ فَيَقُومُ فَيَثُورُ مَجْلِسُهُ أَنْتَنَ رِيحٍ شَمَّهَا أَحَدٌ قَطُّ ثُمَّ يَعْظُمُ لِجَهَنَّمَ فَيَقُولُ عِنْدَ ذَلِكَ { وَقَالَ الشَّيْطَانُ لَمَّا قُضِيَ الْأَمْرُ إِنَّ اللَّهَ وَعَدَكُمْ وَعْدَ الْحَقِّ وَوَعَدْتُكُمْ فَأَخْلَفْتُكُمْ } إِلَى آخِرِ الْآيَةِ","id":"Telah menceritakan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Abdurrahman bin Ziyad] telah menceritakan kepada kami [Dukhain Al Hajri] dari [Uqbah bin Amir Al Juhani] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika Allah telah mengumpulkan orang-orang terdahulu dan terakhir lalu melakukan hisab di antara mereka. Selesai dari hisab tersebut orang-orang mukmin berkata; Rabb kami telah melakukan hisab di antara kami, lalu siapakah yang akan memberikan syafaat untuk kami di sisi Rabb kami? Maka sebagian mereka berkata; Pergilah kepada Adam karena Allah menciptakannya dengan tanganNya dan Dia telah berbicara kepadanya, lalu mereka pun mendatanginya dan mengatakan; Berdirilah, berilah syafaat kepada kami di sisi Rabb kami. Adam menjawab; Kalian harus mendatangi Nuh, lalu mereka pun mendatangi Nuh namun ia menunjukkan mereka kepada Ibrahim. Mereka pun mendatangi Ibrahim namun ia menunjukkan mereka kepada Musa. Lalu mereka pun mendatangi Musa namun ia menunjukkan mereka kepada Isa. Maka mereka mendatangi Isa namun ia berkata; Aku akan menunjukkan kalian kepada seorang Nabi yang tidak dapat membaca dan menulis.\" Beliau melanjutkan: \"Lalu mereka mendatangiku dan Allah 'azza wajalla pun memberi izin kepadaku untuk memberikan syafaat. Tempat dudukku pun menghembuskan bau harum yang hanya tercium oleh satu orang hingga aku mendatangi Rabbku, lalu Dia pun mengizinkanku untuk memberi syafaat dan menjadikan untukku cahaya dari rambut kepalaku sampai kuku kakiku. Ketika itulah orang-orang kafir berkata kepada Iblis; Orang-orang mukmin telah menemukan orang yang dapat memberikan syafaat kepada mereka, maka berdirilah engkau dan berilah syafaat kepada kami di sisi Tuhanmu karena engkau telah menyesatkan kami.\" Beliau melanjutkan: \"Lalu ia berdiri dan tempat duduknya menghembuskan bau yang sangat busuk, yang hanya dapat tercium oleh satu orang. Dia memimpin mereka menuju neraka jahannam.\" Maka ketika itu ia berkata seperti difirmankanNya: (Dan berkatalah setan tatkala perkara hisab telah diselesaikan; Sesungguhnya Allah telah menjanjikan kepadamu janji yang benar dan aku pun telah menjanjikan kepadamu tetapi aku menyalahinya) hingga akhir ayat.\""},"2330":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِكُلِّ نَبِيٍّ دَعْوَةٌ وَأُرِيدُ إِنْ شَاءَ اللَّهُ تَعَالَى أَنْ أَخْتَبِئَ دَعْوَتِي شَفَاعَةً لِأُمَّتِي يَوْمَ الْقِيَامَةِ حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عَمْرُو بْنُ أَبِي سُفْيَانَ بْنِ أَسِيدِ بْنِ جَارِيَةَ مِثْلَ ذَلِكَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Al Hakam bin nafi'] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; Telah menceritakan kepadaku [Abu Salamah bin Abdurrahman] bahwa [Abu Hurairah] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Setiap Nabi itu memiliki doa yang dipanjatkan dan aku ingin jika Allah menghendaki untuk menangguhkan doaku sebagai syafaat bagi umatku pada hari kiamat.\" Telah menceritakan kepada kami [Al Hakam bin Nafi'] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [Amr bin Abu Sufyan bin Asid bin Jariyah] seperti itu dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam."},"2331":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ زِيَادٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يُحَدِّثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ يَدْخُلُ الْجَنَّةَ سَبْعُونَ أَلْفًا مِنْ أُمَّتِي بِغَيْرِ حِسَابٍ فَقَالَ عُكَّاشَةُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ فَدَعَا فَقَالَ آخَرُ ادْعُ اللَّهَ لِي فَقَالَ سَبَقَكَ بِهَا عُكَّاشَةُ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Ziyad] ia berkata; Aku mendengar [Abu Hurairah] menceritakan dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Akan masuk ke surga tujuh puluh orang dari umatku tanpa hisab.\" Lalu Ukasyah bertanya; Wahai Rasulullah, doakan aku kepada Allah untuk menjadikanku bagian dari mereka. Beliau pun mendoakannya. Orang lain pun berkata; Doakan aku kepada Allah, beliau mengatakan: \"Ukasyah telah mendahuluimu.\""},"2332":{"ar":" أَخْبَرَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي الْجَدْعَاءِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيَدْخُلَنَّ الْجَنَّةَ بِشَفَاعَةِ رَجُلٍ مِنْ أُمَّتِي أَكْثَرُ مِنْ بَنِي تَمِيمٍ قَالُوا سِوَاكَ يَا رَسُولَ اللَّهِ قَالَ سِوَايَ","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] telah menceritakan kepada kami [Wuhaib] dari [Khalid] dari [Abdullah bin Syaqiq] dari [Abdullah bin Abu Al Jad'a`] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, akan masuk surga disebabkan syafaat seseorang dari umatku, jumlahnya lebih banyak dari banu Tamim.\" Mereka bertanya; Selain engkau, wahai Rasulullah? Beliau menjawab: \"Selain aku.\""},"2333":{"ar":" حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا خَالِدٌ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ قُلْتُ لِعَائِشَةَ يَا أُمَّ الْمُؤْمِنِينَ أَرَأَيْتِ قَوْلَ اللَّهِ تَعَالَى { يَوْمَ تُبَدَّلُ الْأَرْضُ غَيْرَ الْأَرْضِ وَالسَّمَوَاتُ وَبَرَزُوا لِلَّهِ الْوَاحِدِ الْقَهَّارِ } أَيْنَ النَّاسُ يَوْمَئِذٍ قَالَتْ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ عَلَى الصِّرَاطِ","id":"Telah menceritakan kepada kami [Amr bin 'Aun] telah mengabarkan kepada kami [Khalid] dari [Dawud] dari [Asy Sya'bi] dari [Masruq] ia berkata; aku bertanya kepada [Aisyah]; Wahai Ummul mukminin, bagaimana pendapatmu tentang firman Allah Ta'ala: ((yaitu) pada hari (ketika) bumi diganti dengan bumi yang lain dan (demikian pula) langit, dan meraka semuanya (di padang Mahsyar) berkumpul menghadap ke hadirat Allah yang Maha Esa lagi Maha Perkasa), di manakah manusia ketika itu? Ia menjawab; Aku pernah bertanya tentang hal itu kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau menjawab: \"Di atas titian.\" "},"2334":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ السُّدِّيِّ قَالَ سَأَلْتُ مُرَّةَ عَنْ قَوْلِ اللَّهِ عَزَّ وَجَلَّ { وَإِنْ مِنْكُمْ إِلَّا وَارِدُهَا } فَحَدَّثَنِي أَنَّ عَبْدَ اللَّهِ حَدَّثَهُمْ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرِدُ النَّاسُ النَّارَ ثُمَّ يَصْدُرُونَ عَنْهَا بِأَعْمَالِهِمْ فَأَوَّلُهُمْ كَلَمْحِ الْبَرْقِ ثُمَّ كَالرِّيحِ ثُمَّ كَحُضْرِ الْفَرَسِ ثُمَّ كَالرَّاكِبِ فِي رَحْلِهِ ثُمَّ كَشَدِّ الرَّجُلِ ثُمَّ كَمَشْيِهِ","id":"Telah mengabarkan kepada kami [Ubaidullah] dari [Isra`il] dari [As Suddi] ia berkata; Aku pernah bertanya kepada [Murrah] tentang firman Allah 'azza wajalla: (Dan tidak ada seorangpun dari padamu, melainkan mendatangi neraka itu). Lalu ia menceritakan kepadaku bahwa [Abdullah] menceritakan kepada mereka, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia akan mendatangi neraka, lalu mereka muncul dari neraka dengan amalan-amalan mereka. Orang yang pertama keluar di antara mereka muncul seperti kilatan petir, kemudian seperti angin, lalu seperti kencangnya lari kuda, seperti pengendara di atas hewan tunggangannya, kemudian seperti cepatnya lari seseorang dan seperti berjalannya.\" "},"2335":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ عَاصِمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُؤْتَى بِالْمَوْتِ بِكَبْشٍ أَغْبَرَ فَيُوقَفُ بَيْنَ الْجَنَّةِ وَالنَّارِ فَيُقَالُ يَا أَهْلَ الْجَنَّةِ فَيَشْرَئِبُّونَ وَيَنْظُرُونَ وَيُقَالُ يَا أَهْلَ النَّارِ فَيَشْرَئِبُّونَ وَيَنْظُرُونَ وَيَرَوْنَ أَنْ قَدْ جَاءَ الْفَرَجُ فَيُذْبَحُ وَيُقَالُ خُلُودٌ لَا مَوْتَ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] dari [Hammad bin Salamah] dari ['Ashim] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kematian akan didatangkan seperti seekor kambing berwarna abu-abu lalu ia dihentikan di antara surga dan neraka. Maka dikatakan; Wahai penduduk surga. Mereka pun mendongakkan kepala dan melihatnya. Dan dikatakan; Wahai penduduk neraka. Mereka pun mendongakkan kepala dan melihatnya, mereka beranggapan bahwa kelapangan telah tiba. Lalu hewan kematian itu disembelih dan dikatakan; Kekal dan tidak ada kematian.\""},"2336":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا شُعْبَةُ عَنْ سِمَاكٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ أَنْذَرْتُكُمْ النَّارَ أَنْذَرْتُكُمْ النَّارَ أَنْذَرْتُكُمْ النَّارَ فَمَا زَالَ يَقُولُهَا حَتَّى لَوْ كَانَ فِي مَقَامِي هَذَا لَسَمِعَهُ أَهْلُ السُّوقِ حَتَّى سَقَطَتْ خَمِيصَةٌ كَانَتْ عَلَيْهِ عِنْدَ رِجْلَيْهِ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Syu'bah] dari [Simak] dari [An Nu'man bin Basyir] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam ketika berkhutbah beliau bersabda: \"Aku peringatkan kalian terhadap neraka, aku peringatkan kalian terhadap neraka, aku peringatkan kalian terhadap neraka.\" Beliau terus-menerus mengatakan hal itu hingga seandainya beliau berada di tempatku ini niscaya suara beliau akan terdengar oleh orang-orang di pasar itu. Dan hingga pakaian sutera yang ada di kedua kaki mereka terjatuh."},"2337":{"ar":" أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ قَالَ أَخْبَرَنَا بَهْزُ بْنُ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كَانَ عَبْدٌ مِنْ عِبَادِ اللَّهِ وَكَانَ لَا يَدِينُ لِلَّهِ دِينًا وَإِنَّهُ لَبِثَ حَتَّى ذَهَبَ مِنْهُ عُمُرٌ وَبَقِيَ عُمُرٌ فَعَلِمَ أَنَّهُ لَمْ يَبْتَئِرْ عِنْدَ اللَّهِ خَيْرًا فَدَعَا بَنِيهِ فَقَالَ أَيُّ أَبٍ تَعْلَمُونِي قَالُوا خَيْرُهُ يَا أَبَانَا قَالَ فَإِنِّي لَا أَدَعُ عِنْدَ أَحَدٍ مِنْكُمْ مَالًا هُوَ مِنِّي إِلَّا أَخَذْتُهُ مِنْكُمْ أَوْ لَتَفْعَلُنَّ مَا آمُرُكُمْ قَالَ فَأَخَذَ مِنْهُمْ مِيثَاقًا وَرَبِّي قَالَ أَمَّا أَنَا إِذَا مُتُّ فَخُذُونِي فَأَحْرِقُونِي بِالنَّارِ حَتَّى إِذَا كُنْتُ حُمَمًا فَدُقُّونِي ثُمَّ اذْرُونِي فِي الرِّيحِ قَالَ فَفَعَلُوا ذَلِكَ بِهِ وَرَبِّ مُحَمَّدٍ حِينَ مَاتَ فَجِيءَ بِهِ أَحْسَنَ مَا كَانَ قَطُّ فَعُرِضَ عَلَى رَبِّهِ فَقَالَ مَا حَمَلَكَ عَلَى النَّارِ قَالَ خَشْيَتُكَ يَا رَبِّ قَالَ إِنِّي أَسْمَعُكَ لَرَاهِبًا قَالَ فَتِيبَ عَلَيْهِ قَالَ أَبُو مُحَمَّد يَبْتَئِرُ يَدَّخِرُ","id":"Telah mengabarkan kepada kami [An Nadlr bin Syumail] ia berkata; Telah mengabarkan kepada kami [Bahz bin Hakim] dari [ayahnya] dari [kakeknya] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dahulu ada seorang hamba Allah di antara hamba-hambaNya yang tidak menganut agama Allah dan hidup hingga dari masa ke masa. Lalu ia menyadari bahwa dirinya belum menyimpan kebaikan di sisi Allah. Ia pun memanggil anak-anaknya seraya berkata; Ayah macam apa yang kalian ketahui tenga aku ini? Mereka menjawab; Yang terbaik, wahai ayahku. Ia berkata; Sesungguhnya aku tidak pernah meninggalkan harta pada salah seorang dari kalian yang bersumber dariku, kecuali aku mengambil harta itu dari kalian atau kalian harus melakukan apa yang aku perintahkan.\" Beliau melanjutkan: \"Lalu ia sumpah kepada mereka, demi Rabbku. Ia berkata; Jika aku mati maka bawalah dan bakarlah aku dengan api hingga ketika aku telah menjadi arang, tumbuklah kemudian tebarkanlah aku di angin.\" Beliau melanjutkan lagi: \"Ketika ia mati, demi Rabb Muhammad, mereka pun melakukan perintah itu. Kemudian ia didatangkan ke hadapan Rabbnya dalam keadaan yang terbaik dari keadaannya yang pernah ada. Dia berfirman: Apa yang mendorongmu dibakar dengan api? Ia menjawab; Rasa takutku kepadaMu ya Rabb. Allah berfirman: Sesungguhnya Aku mendengarmu sebagai seorang yang takut kepadaKu.\" Beliau mengatakan: \"Ia pun diterima taubatnya.\" Abu Ahmad berkata; Yabta`ir artinya menyimpan."},"2338":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَتْ امْرَأَةٌ النَّارَ فِي هِرَّةٍ فَقِيلَ لَا أَنْتِ أَطْعَمْتِيهَا وَسَقَيْتِيهَا وَلَا أَنْتِ أَرْسَلْتِيهَا فَتَأْكُلَ مِنْ خَشَاشِ الْأَرْضِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang wanita masuk neraka karena seekor kucing. Lalu dikatakan kepadanya; Kamu tidak memberinya makan, tidak memberinya minum, dan kamu tidak melepaskannya sehingga ia dapat memakan serangga bumi.\""},"2339":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ بْنِ مِقْلَاصٍ مَوْلَى أَبِي هُرَيْرَةَ وَكُنْيَتُهُ أَبُو يَحْيَى قَالَ سَمِعْتُ دَرَّاجًا أَبَا السَّمْحِ يَقُولُ سَمِعْتُ أَبَا الْهَيْثَمِ يَقُولُ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَلَّطُ عَلَى الْكَافِرِ فِي قَبْرِهِ تِسْعَةٌ وَتِسْعُونَ تِنِّينًا تَنْهَشُهُ وَتَلْدَغُهُ حَتَّى تَقُومَ السَّاعَةُ وَلَوْ أَنَّ تِنِّينًا مِنْهَا نَفَخَ فِي الْأَرْضِ مَا نَبَتَتْ خَضْرَاءُ","id":"Telah menceritakan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Sa'id bin Abu Ayyub bin Miqlash] mantan budak Abu Hurairah dan julukannya Abu Yahya, ia berkata; Aku mendengar [Darraj Abu As Samh] ia berkata; Aku mendengar [Abu Al Haitsam] berkata; Aku mendengar [Abu Sa'id Al Khudri] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang kafir di dalam kuburnya akan ditemani oleh sembilan puluh sembilan ular besar yang menggigitnya dan menyengatnya hingga hari kiamat. Seandainya seekor dari ular besar tersebut menghembuskan angin ke bumi, maka tidak akan tumbuh pepohonan (tanaman) yang hijau.\""},"2340":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا أَزْهَرُ بْنُ سِنَانٍ عَنْ مُحَمَّدِ بْنِ وَاسِعٍ قَالَ دَخَلْتُ عَلَى بِلَالِ بْنِ أَبِي بُرْدَةَ فَقُلْتُ إِنَّ أَبَاكَ حَدَّثَنِي عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي جَهَنَّمَ وَادِيًا يُقَالُ لَهُ هَبْهَبُ يَسْكُنُهُ كُلُّ جَبَّارٍ فَإِيَّاكَ أَنْ تَكُونَ مِنْهُمْ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Azhar bin Sinan] dari [Muhammad bin Wasi'] ia berkata; Aku masuk ke rumah Bilal bin Abi Burdah, lalu aku berkata kepadanya; Bahwa [ayahmu] telah menceritakan kepadaku dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya di dalam neraka ada sebuah lembah yang disebut Habhab, yang dihuni oleh orang-orang yang lalim. Maka takutlah engkau menjadi bagian dari mereka.\""},"2341":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ سَعِيدِ بْنِ يَزِيدَ أَبِي مَسْلَمَةَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا أَهْلُ النَّارِ الَّذِينَ هُمْ أَهْلُ النَّارِ فَإِنَّهُمْ لَا يَمُوتُونَ فِي النَّارِ وَأَمَّا نَاسٌ مِنْ النَّاسِ فَإِنَّ النَّارَ تُصِيبُهُمْ عَلَى قَدْرِ ذُنُوبِهِمْ فَيُحْرَقُونَ فِيهَا حَتَّى إِذَا صَارُوا فَحْمًا أُذِنَ فِي الشَّفَاعَةِ فَيَخْرُجُونَ مِنْ النَّارِ ضَبَائِرَ ضَبَائِرَ فَيُنْثَرُونَ عَلَى أَنْهَارِ الْجَنَّةِ فَيُقَالُ لِأَهْلِ الْجَنَّةِ يُفِيضُوا عَلَيْهِمْ مِنْ الْمَاءِ قَالَ فَيُفِيضُونَ عَلَيْهِمْ فَتَنْبُتُ لُحُومُهُمْ كَمَا تَنْبُتُ الْحِبَّةُ فِي حَمِيلِ السَّيْلِ","id":"Telah mengabarkan kepada kami [Amru bin 'Aun] dari [Khalid bin Abdullah] dari [Sa'id bin Yazid Abu Maslamah] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Adapun penghuni neraka, yakni mereka yang menghuni neraka, sesungguhnya mereka tidak mati di dalam neraka. Ada juga sebagian manusia yang disiksa dalam api neraka sesuai dengan kadar dosa-dosanya, lalu mereka dibakar di dalam neraka hingga ketika telah menjadi arang, mereka diberi izin mendapat syafaat. Kemudian mereka keluar dari neraka secara berkelompok lalu ditaburkan ke sungai-sungai surga. Dikatakan kepada penghuni surga; Siramkanlah air kepada mereka.\" Beliau melanjutkan: \"Maka para penghuni surga menyiramkan air kepada mereka sehingga tumbuhlah daging-daging mereka sebagaimana tumbuhnya benih yang terbawa banjir.\""},"2342":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ حُمَيْدٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ عَنْ شَرِيكٍ عَنْ عُثْمَانَ الثَّقَفِيِّ عَنْ أَبِي صَادِقٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْجَنَّةِ ثَمَانِيَةُ أَبْوَابٍ","id":"Telah menceritakan kepada kami [Ahmad bin Humaid] telah menceritakan kepada kami [Mu'awiyah bin Hisyam] dari [Syarik] dari [Utsman Ats Tsaqafi] dari [Abu Shadiq] dari [Abdurrahman bin Yazid] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Surga memiliki delapan pintu.\""},"2343":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَيُّوبَ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ دَخَلَ الْجَنَّةَ يَنْعَمُ لَا يَبْؤُسُ لَا تَبْلَى ثِيَابُهُ وَلَا يَفْنَى شَبَابُهُ فِي الْجَنَّةِ مَا لَا عَيْنٌ رَأَتْ وَلَا أُذُنٌ سَمِعَتْ وَلَا خَطَرَ عَلَى قَلْبِ بَشَرٍ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ayyub] dari [Abu Rafi'] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa masuk surga, niscaya ia akan mendapat kenikmatan, tidak akan sengsara, pakaiannya tidak akan usang, masa mudanya tidak pernah pudar dan di dalam surga ia akan memperoleh sesuatu yang belum pernah dilihat oleh mata, belum pernah didengar oleh telinga, dan belum pernah terbersit dalam hati manusia.\""},"2344":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمَوْضِعُ سَوْطٍ فِي الْجَنَّةِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَاقْرَءُوا إِنْ شِئْتُمْ { فَمَنْ زُحْزِحَ عَنْ النَّارِ وَأُدْخِلَ الْجَنَّةَ فَقَدْ فَازَ } الْآيَةَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sungguh, seukuran cemeti di dalam surga adalah lebih baik dari pada dunia dan seisinya. Bacalah jika kalian menghendaki: (Barangsiapa dijauhkan dari neraka dan dimasukkan ke dalam surga, maka sungguh ia telah beruntung).\" "},"2345":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ سَعْدَانَ الْجُهَنِيِّ عَنْ أَبِي مُجَاهِدٍ حَدَّثَنَا أَبُو مُدِلَّةَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُ قُلْنَا يَا رَسُولَ اللَّهِ الْجَنَّةُ مَا بِنَاؤُهَا قَالَ لَبِنَةٌ مِنْ ذَهَبٍ وَلَبِنَةٌ مِنْ فِضَّةٍ مِلَاطُهَا الْمِسْكُ الْأَذْفَرُ وَحَصْبَاؤُهَا الْيَاقُوتُ وَاللُّؤْلُؤُ وَتُرَابُهَا الزَّعْفَرَانُ مَنْ يَدْخُلْهَا يَخْلُدْ فِيهَا يَنْعَمُ لَا يَبْؤُسُ لَا يَفْنَى شَبَابُهُمْ وَلَا تَبْلَى ثِيَابُهُمْ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Sa'dan Al Juhani] dari [Abu Mujahid] telah menceritakan kepada kami [Abu Mudillah] bahwa ia mendengar [Abu Hurairah] berkata; Kami bertanya; Wahai Rasulullah, dibangun dari apakah surga itu? Beliau menjawab: \"Batu bata emas, batu bata perak dan adukannya adalah minyak misik yang harum baunya. Barangsiapa yang memasukinya, maka ia akan kekal di dalamnya, bergelimang kenikmatan, tidak akan sengsara, masa mudanya tidak akan pernah pudar, dan pakaiannya tidak akan pernah usang.\""},"2346":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا أَبُو قُدَامَةَ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ اللَّهِ بْنِ قَيْسٍ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَنَّاتُ الْفِرْدَوْسِ أَرْبَعٌ ثِنْتَانِ مِنْ ذَهَبٍ حِلْيَتُهُمَا وَآنِيَتُهُمَا وَمَا فِيهِمَا وَثِنْتَانِ مِنْ فِضَّةٍ حِلْيَتُهُمَا وَآنِيَتُهُمَا وَمَا فِيهِمَا وَلَيْسَ بَيْنَ الْقَوْمِ وَبَيْنَ أَنْ يَنْظُرُوا إِلَى رَبِّهِمْ إِلَّا رِدَاءُ الْكِبْرِيَاءِ عَلَى وَجْهِهِ فِي جَنَّاتِ عَدْنٍ وَهَذِهِ الْأَنْهَارُ تَشْخُبُ مِنْ جَنَّاتِ عَدْنٍ فِي جَوْبَةٍ ثُمَّ تَصْعَدُ بَعْدُ أَنْهَارًا قَالَ عَبْد اللَّهِ جَوْبَةٌ مَا يُجَابُ عَنْهُ الْأَرْضُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Abu Qudamah] dari [Abu Imran Al Jauni] dari [Abu Bakr bin Abdullah bin Qais] dari [ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Surga Firdaus memiliki empat bagian; Dua bagian terbuat dari emas yaitu perhiasan, perabotan dan segala isi keduanya dan dua bagian yang terbuat dari perak, yaitu perhiasan, perabotan dan segala isinya. Tidak ada yang menghalangi suatu kaum untuk melihat Rabb mereka selain selendang keagungan yang ada di hadapan mereka di surga 'Adn. Sungai-sungai mengalir dari surga 'Adn itu menuju ke jaubah (semacam danau). Kemudian air itu naik ke sungai-sungai.\" Abdullah berkata; Jaubah adalah lubang bulat yang luas di bumi (semacam danau)."},"2347":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَوَّلَ زُمْرَةٍ يَدْخُلُونَ الْجَنَّةَ مِنْ أُمَّتِي عَلَى صُورَةِ الْقَمَرِ لَيْلَةَ الْبَدْرِ ثُمَّ الَّذِينَ يَلُونَهُمْ عَلَى أَحْسَنِ كَوْكَبٍ إِضَاءَةً فِي السَّمَاءِ فَقَامَ عُكَّاشَةُ فَقَالَ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ فَقَالَ اللَّهُمَّ اجْعَلْهُ مِنْهُمْ ثُمَّ قَامَ رَجُلٌ آخَرُ فَقَالَ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ فَقَالَ سَبَقَكَ بِهَا عُكَّاشَةُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin Amr] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kelompok pertama yang akan masuk surga dari umatku adalah orang-orang yang rupanya seperti bulan pada malam purnama kemudian setelah mereka adalah orang-orang yang rupanya seindah bintang yang bersinar di langit.\" Maka Ukasyah berdiri seraya berkata; Wahai Rasulullah, berdoalah kepada Allah agar menjadikanku bagian dari mereka. Beliau pun berdoa: \"Ya Allah, jadikanlah ia sebagai bagian dari mereka.\" Setelah itu ada seseorang berdiri dan berkata; Ya Rasulullah, berdoalah kepada Allah agar menjadikanku bagian dari mereka. Beliau bersabda: \"Engkau telah didahului oleh Ukasyah.\""},"2348":{"ar":" أَخْبَرَنَا عُبَيْدُ بْنُ يَعِيشَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ حَمْزَةَ بْنِ حَبِيبٍ عَنْ أَبِي إِسْحَقَ عَنْ الْأَغَرِّ عَنْ أَبِي هُرَيْرَةَ وَأَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ { وَنُودُوا أَنْ تِلْكُمْ الْجَنَّةُ } قَالَ نُودُوا صِحُّوا فَلَا تَسْقَمُوا وَانْعَمُوا فَلَا تَبْؤُسُوا وَشِبُّوا فَلَا تَهْرَمُوا وَاخْلُدُوا فَلَا تَمُوتُوا","id":"Telah mengabarkan kepada kami [Ubaid bin Ya'isy] telah menceritakan kepada kami [Yahya bin Adam] dari [Hamzah bin Habib] dari [Abu Ishaq] dari [Al Agharr] dari [Abu Hurairah] dan [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam: (Dan diserukan kepada mereka; Itulah surga yang diwariskan kepadamu). Beliau bersabda: \"Diserukan kepada mereka; Sehatlah kalian dan jangan sakit, nikmatilah kenikmatan dan jangan sengsara, mudalah dan jangan menjadi tua, kekallah kalian dan janganlah kalian mati.\""},"2349":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ الْأَعْمَشِ عَنْ ثُمَامَةَ بْنِ عُقْبَةَ الْمُحَلِّمِيِّ قَالَ سَمِعْتُ زَيْدَ بْنَ أَرْقَمَ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الرَّجُلَ مِنْ أَهْلِ الْجَنَّةِ لَيُعْطَى قُوَّةَ مِائَةِ رَجُلٍ فِي الْأَكْلِ وَالشُّرْبِ وَالْجِمَاعِ وَالشَّهْوَةِ فَقَالَ رَجُلٌ مِنْ الْيَهُودِ إِنَّ الَّذِي يَأْكُلُ وَيَشْرَبُ تَكُونُ مِنْهُ الْحَاجَةُ قَالَ يَفِيضُ مِنْ جِلْدِهِ عَرَقٌ فَإِذَا بَطْنُهُ قَدْ ضَمَرَ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] dari [Al A'masy] dari [Tsumamah bin Uqbah Al Muhallimi] ia berkata; Aku mendengar [Zaid bin Arqam] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang penghuni surga akan diberikan kekuatan seratus orang laki-laki dalam hal makan, minum, hubungan badan dan syahwat.\" Lalu ada seorang yahudi berkata; Sesungguhnya orang yang makan dan minum itu akan kencing dan buang hajat. Beliau bersabda: \"(kotoran itu) akan keluar dari kulitnya melalui keringat dan perutnya telah menyatu (tidak berfungsi lagi).\""},"2350":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ الرِّفَاعِيُّ حَدَّثَنَا مُعَاذٌ يْعَنِي ابْنَ هِشَامٍ عَنْ أَبِيهِ عَنْ عَامِرٍ الْأَحْوَلِ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَهْلُ الْجَنَّةِ شَبَابٌ جُرْدٌ مُرْدٌ كُحْلٌ لَا تَبْلَى ثِيَابُهُمْ وَلَا يَفْنَى شَبَابُهُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid Ar Rifa'i] telah menceritakan kepada kami [Mu'adz] yakni Ibnu Hisyam dari [ayahnya] dari [Amir Al Ahwal] dari [Syahr bin Hausyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Penghuni surga adalah pemuda yang tidak memiliki bulu pada kulitnya, tidak memiliki rambut pada jenggotnya, tampan lagi memakai celak, pakaiannya tidak pernah usang dan kemudaannya tidak pernah pudar.\""},"2351":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا قِيلَ لِأَبِي عَاصِمٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ أَهْلُ الْجَنَّةِ لَا يَبُولُونَ وَلَا يَمْتَخِطُونَ وَلَا يَتَغَوَّطُونَ وَيَكُونُ ذَلِكَ مِنْهُمْ جُشَاءً يَأْكُلُونَ وَيَشْرَبُونَ وَيُلْهَمُونَ التَّسْبِيحَ وَالْحَمْدَ كَمَا يُلْهَمُونَ النَّفَسَ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] ia berkata; telah mengabarkan kepadaku [Abu Az Zubair] bahwa ia mendengar [Jabir], ditanyakan kepada Abu 'Ashim; Apakah dari Nabi shallallahu 'alaihi wasallam? Ia menjawab; Benar. \"Penghuni surga itu tidak buang air kecil, tidak beringus dan tidak buang air besar. Semua itu menjadi suara perut yang mencerna makanan mereka. Mereka makan, minum dan menghembuskan tasbih dan tahmid sebagaimana mereka menghembuskan nafas.\""},"2352":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ عَزَّ وَجَلَّ أَعْدَدْتُ لِعِبَادِي الصَّالِحِينَ مَا لَا عَيْنٌ رَأَتْ وَلَا أُذُنٌ سَمِعَتْ وَلَا خَطَرَ عَلَى قَلْبِ بَشَرٍ وَاقْرَءُوا إِنْ شِئْتُمْ { فَلَا تَعْلَمُ نَفْسٌ مَا أُخْفِيَ لَهُمْ مِنْ قُرَّةِ أَعْيُنٍ جَزَاءً بِمَا كَانُوا يَعْمَلُونَ }","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin Amr] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah 'azza wajalla berfirman: Aku telah mempersiapkan bagi hamba-hamba yang shalih sesuatu yang tidak pernah dilihat mata, tidak pernah didengar telinga, dan tidak pernah terlintas di dalam hati manusia. Bacalah jika kalian menghendaki: (Seorang pun tidak mengetahui apa yang disembunyikan untuk mereka yaitu (bermacam-macam nikmat) yang menyedapkan pandangan mata sebagai balasan terhadap apa yang telah mereka kerjakan.\""},"2353":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَدْنَى أَهْلِ الْجَنَّةِ مَنْزِلًا مَنْ يَتَمَنَّى عَلَى اللَّهِ فَيُقَالُ لَهُ لَكَ ذَاكَ وَمِثْلُهُ مَعَهُ إِلَّا أَنَّهُ يُلَقَّى سِوَى كَذَا وَكَذَا فَيُقَالُ لَهُ ذَاكَ لَكَ وَمِثْلُهُ مَعَهُ قَالَ أَبُو سَعِيدٍ الْخُدْرِيُّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيُقَالُ لَهُ ذَاكَ وَعَشْرَةُ أَمْثَالِهِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin Amr] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya penghuni surga yang paling rendah derajatnya adalah orang yang mempunyai angan-angan kepada Allah. Dikatakan kepadanya; Engkau berhak mendapatkan angan-angan itu dan yang seperti angan-angan itu, ia hanya mengatakan ini dan ini. Dikatakan kepadanya; Engkau berhak mendapatkan itu dan yang seperti itu.\" [Abu Sa'id Al Khudri] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maka dikatakan kepadanya; Itulah milikmu dan sepuluh perkara seperti itu.\""},"2354":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَهْلَ الْجَنَّةِ لَيَتَرَاءَوْنَ أَهْلَ الْغُرَفِ فِي الْجَنَّةِ كَمَا تَرَوْنَ الْكَوْكَبَ الدُّرِّيَّ فِي السَّمَاءِ قَالَ أَبُو حَازِمٍ فَحَدَّثْتُ بِهَذَا الْحَدِيثِ النُّعْمَانَ بْنَ أَبِي عَيَّاشٍ فَحَدَّثَنِي عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُ قَالَ الْكَوْكَبُ الدُّرِّيُّ فِي السَّمَاءِ الشَّرْقِيُّ وَالْغَرْبِيُّ ","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Abu Hazim] dari [Sahal bin Sa'd] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya penghuni surga itu dapat melihat para penghuni ruangan yang ada di surga sebagaimana mereka dapat melihat bintang yang bersinar di langit.\" Abu Hazim berkata; Maka aku ceritakan hadits ini kepada [An Nu'man bin Abu 'Ayyasy] lalu ia menceritakan kepadaku dari [Abu Sa'id Al Khudri] bahwa ia berkata; Bintang yang bersinar di langit baik di timur maupun di barat."},"2355":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْمِنْهَالِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا هِشَامٌ الْقُرْدُوسِيُّ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا فِي الْجَنَّةِ أَحَدٌ إِلَّا لَهُ زَوْجَتَانِ إِنَّهُ لَيَرَى مُخَّ سَاقِهِمَا مِنْ وَرَاءِ سَبْعِينَ حُلَّةً مَا فِيهَا مِنْ عَزَبٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Minhal] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Hisyam Al Qurdusi] dari [Muhammad bin Sirin] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorang pun di dalam surga melainkan ia memiliki dua orang isteri. Sesungguhnya ia dapat melihat mulusnya betis kedua isteri itu dari balik tujuh puluh dua hullah (pakaian). Tidak ada seorang pun di dalamnya yang membujang.\" "},"2356":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هَمَّامٌ حَدَّثَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ اللَّهِ بْنِ قَيْسٍ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَيْمَةُ دُرَّةٌ مُجَوَّفَةٌ طُولُهَا فِي السَّمَاءِ سِتُّونَ مِيلًا فِي كُلِّ زَاوِيَةٍ مِنْهَا أَهْلٌ لِلْمُؤْمِنِ لَا يَرَاهُمْ الْآخَرُونَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammam] telah menceritakan kepada kami [Abu Imran Al Jauni] dari [Abu Bakr bin Abdullah bin Qais] dari [ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tenda (di surga) berupa permata besar yang berlubang, tingginya di langit enam puluh mil. Pada setiap sudut dari tenda itu terdapat tempat bagi orang-orang beriman, yang tidak dapat dilihat orang lain.\""},"2357":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ وَالْقَوَارِيرِيُّ عَنْ مُعَاذِ بْنِ هِشَامٍ عَنْ أَبِيهِ عَنْ عَامِرٍ الْأَحْوَلِ عَنْ أَبِي الصِّدِّيقِ النَّاجِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمُؤْمِنَ إِذَا اشْتَهَى الْوَلَدَ فِي الْجَنَّةِ كَانَ حَمْلُهُ وَوَضْعُهُ وَسِنُّهُ فِي سَاعَةٍ كَمَا اشْتَهَى","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid] dan [Al Qawariri] dari [Mu'adz bin Hisyam] dari [ayahnya] dari [Amir Al Ahwal] dari [Abu Ash Shiddiq An Naji] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya seorang mukmin di surga apabila menginginkan seorang anak, maka (waktu) kehamilan, melahirkan dan usia anak itu berlangsung dalam sekejap sebagaimana yang ia inginkan.\""},"2358":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ قَالَ أُرَاهُ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْلُ الْجَنَّةِ عِشْرُونَ وَمِائَةُ صَفٍّ ثَمَانُونَ مِنْهَا أُمَّتِي وَأَرْبَعُونَ سَائِرُ النَّاسِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`] ia berkata; Telah menceritakan kepada kami [Mu'awiyah bin Hisyam] dari [Sufyan] dari ['Alqamah bin Martsad] dari [Sulaiman bin Buraidah] ia berkata; Aku kira dari [ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penghuni surga itu berjumlah seratus dua puluh barisan, delapan puluh di antaranya adalah umatku, sedangkan empat puluh (barisan) lainnya adalah seluruh umat manusia (yang bukan umatku).\""},"2359":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا الْجُرَيْرِيُّ عَنْ حَكِيمِ بْنِ مُعَاوِيَةَ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجَنَّةِ بَحْرَ اللَّبَنِ وَبَحْرَ الْعَسَلِ وَبَحْرَ الْخَمْرِ ثُمَّ تَشَقَّقُ مِنْهُ الْأَنْهَارُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] ia berkata; Telah mengabarkan kepada kami [Al Jurairi] dari [Hakim bin Mu'awiyah] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di dalam surga terdapat lautan susu, lautan madu dan lautan khamr, kemudian dari lautan itu mengalirlah sungai-sungai.\""},"2360":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ مُحَارِبِ بْنِ دِثَارٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ قَالَ لَمَّا نَزَلَتْ { إِنَّا أَعْطَيْنَاكَ الْكَوْثَرَ } قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ نَهْرٌ فِي الْجَنَّةِ حَافَّتَاهُ مِنْ ذَهَبٍ يَجْرِي عَلَى الدُّرِّ وَالْيَاقُوتِ تُرْبَتُهُ أَطْيَبُ مِنْ رِيحِ الْمِسْكِ وَطَعْمُهُ أَحْلَى مِنْ الْعَسَلِ وَمَاؤُهُ أَشَدُّ بَيَاضًا مِنْ الثَّلْجِ","id":"Telah mengabarkan kepada kami [Amr bin 'Aun] telah mengabarkan kepada kami [Abu 'Awanah] dari ['Atha` bin As Sa`ib] dari [Muharib bin Ditsar] ia berkata; Telah menceritakan kepada kami [Abdullah bin Umar] ia berkata; Ketika turun ayat: INNA A'THAINA KAL KAUTSAR (Sesungguhnya Kami telah memberikan kepadamu nikmat yang banyak), Rasulullah shallallahu 'alaihi wasallam bersabda: \"Itu adalah sungai di dalam surga, kedua tepinya terbuat dari emas, airnya mengalir di atas permata dan yaqut, tanahnya lebih wangi dari minyak misik, rasanya lebih manis dari pada madu, dan airnya lebih putih dari pada salju.\""},"2361":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ فِي الْجَنَّةِ شَجَرَةً يَسِيرُ الرَّاكِبُ فِي ظِلِّهَا مِائَةَ عَامٍ لَا يَقْطَعُهَا وَاقْرَءُوا إِنْ شِئْتُمْ { وَظِلٍّ مَمْدُودٍ }","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin Amr] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di dalam surga terdapat sebatang pohon, jika seorang pengendara menyusuri naungannya selama seratus tahun, niscaya ia tidak dapat mencapai ujungnya. Bacalah jika kalian menghendaki: (Dan naungan yang terbentang luas).\""},"2362":{"ar":" أَخْبَرَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي الضَّحَّاكِ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجَنَّةِ شَجَرَةً يَسِيرُ الرَّاكِبُ فِي ظِلِّهَا مِائَةَ عَامٍ لَا يَقْطَعُهَا هِيَ شَجَرَةُ الْخُلْدِ","id":"Telah mengabarkan kepada kami [Abdush Shamad bin Abdul Warits] telah menceritakan kepada kami [Syu'bah] dari [Abu Adl Dlahak] ia berkata; Aku mendengar [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya di dalam surga terdapat sebatang pohon, jika seorang pengendara menyusuri naungannya selama seratus tahun, niscaya ia tidak dapat mencapai ujungnya. Pohon itu adalah pohon Al Khuldi.\""},"2363":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا عَبَّادٌ هُوَ ابْنُ مَنْصُورٍ قَالَ سَمِعْتُ شَهْرَ بْنَ حَوْشَبٍ يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَجْوَةُ مِنْ الْجَنَّةِ وَهِيَ شِفَاءٌ مِنْ السُّمِّ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami ['Abbad] ia adalah Ibnu Manshur, ia berkata; Aku mendengar [Syahar bin Hausyab] berkata; Aku mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kurma 'ajwah itu berasal dari surga, ia adalah penawar racun.\""},"2364":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حُمَيْدٌ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجَنَّةِ لَسُوقًا قَالُوا وَمَا هِيَ قَالَ كُثْبَانٌ مِنْ مِسْكٍ يَخْرُجُونَ إِلَيْهَا فَيَجْتَمِعُونَ فِيهَا فَيَبْعَثُ اللَّهُ عَلَيْهِمْ رِيحًا فَتُدْخِلُهُمْ بُيُوتَهُمْ فَيَقُولُ لَهُمْ أَهْلُوهُمْ لَقَدْ ازْدَدْتُمْ بَعْدَنَا حُسْنًا وَيَقُولُونَ لِأَهْلِيهِمْ مِثْلَ ذَلِكَ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الْجَبَّارِ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Humaid] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya di dalam surga terdapat sebuah pasar.\" Mereka bertanya; Pasar apa itu? Beliau menjawab: \"Terdapat di dalamnya tumpukan minyak misik. Para penghuni surga mendatanginya dan berkumpul di sana. Lalu Allah mengirim angin kepada mereka dan angin itu menghempaskan mereka masuk ke rumah-rumah mereka. Para penghuni rumah berkata kepada mereka; Sesungguhnya kalian semakin tampan setelah kami. Mereka juga mengatakan demikian.\" Telah menceritakan kepada kami [Sa'id bin Abdul Jabbar] dari [Hammad bin Salamah] dari [Tsabit] dari [Anas] dari Nabi shallallahu 'alaihi wasallam seperti itu."},"2365":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُفَّتْ الْجَنَّةُ بِالْمَكَارِهِ وَحُفَّتْ النَّارُ بِالشَّهَوَاتِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Surga itu dikelilingi oleh hal-hal yang tidak disukai dan neraka dikelilingi oleh hal-hal yang disenangi.\""},"2366":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ قَالَ حَدَّثَنِي مُعَاوِيَةُ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ جُبَيْرٍ حَدَّثَهُ عَنْ أَبِيهِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ بَيْنَا أَنَا قَاعِدٌ فِي الْمَسْجِدِ وَحَلْقَةٌ مِنْ فُقَرَاءِ الْمُهَاجِرِينَ قُعُودٌ إِذْ دَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَعَدَ إِلَيْهِمْ فَقُمْتُ إِلَيْهِمْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُمْ لِيُبْشِرْ فُقَرَاءُ الْمُهَاجِرِينَ بِمَا يَسُرُّ وُجُوهَهُمْ فَإِنَّهُمْ يَدْخُلُونَ الْجَنَّةَ قَبْلَ الْأَغْنِيَاءِ بِأَرْبَعِينَ عَامًا قَالَ فَلَقَدْ رَأَيْتُ أَلْوَانَهُمْ أَسْفَرَتْ قَالَ عَبْدُ اللَّهِ بْنُ عَمْرٍو حَتَّى تَمَنَّيْتُ أَنْ أَكُونَ مَعَهُمْ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] ia berkata; Telah menceritakan kepadaku [Mu'awiyah] bahwa [Abdurrahman bin Jubair] menceritakannya dari ayahnya [Jubair bin Nufair] dari [Abdullah bin Amr] ia berkata; Ketika aku sedang duduk di masjid bersama sekelompok kaum fakir Muhajirin, tiba-tiba Nabi shallallahu 'alaihi wasallam masuk lalu duduk di hadapan mereka, aku pun menghampiri mereka. Nabi shallallahu 'alaihi wasallam bersabda: \"Hendaklah kaum fakir Muhajirin bahagia karena sesuatu yang membuat wajah mereka berseri. Sesungguhnya mereka akan masuk surga empat puluh tahun sebelum orang-orang kaya.\" Ia mengatakan; Lalu aku melihat warna wajah mereka bersinar. Abdullah bin Amr melanjutkan; Hingga aku berandai-andai diriku bersama mereka."},"2367":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ سَمِعَهُ يَقُولُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَكَتْ النَّارُ إِلَى رَبِّهَا فَقَالَتْ رَبِّ أَكَلَ بَعْضِي بَعْضًا فَأَذِنَ لَهَا بِنَفَسَيْنِ نَفَسٍ فِي الشِّتَاءِ وَنَفَسٍ فِي الصَّيْفِ فَهُوَ أَشَدُّ مَا تَجِدُونَ مِنْ الْحَرِّ وَأَشَدُّ مَا تَجِدُونَ مِنْ الزَّمْهَرِيرِ أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَاصِمِ بْنِ بَهْدَلَةَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; telah mengabarkan kepadaku [Abu Salamah] dari [Abu Hurairah] bahwa ia mendengarnya berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Neraka mengadu kepada Rabbnya, ia berkata; Ya Rabb, sebagian dariku memakan sebagian yang lain. Maka Dia mengizinkannya memiliki dua nafas; Nafas pada musim dingin dan nafas pada musim panas. Nafas itu lebih panas dari pada hawa yang sangat panas yang kalian rasakan dan lebih dingin dari pada hawa yang sangat dingin yang kalian rasakan.\" Telah mengabarkan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad bin Salamah] dari ['Ashim bin Bahdalah] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti itu."},"2368":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا الْهَجَرِيُّ عَنْ أَبِي عِيَاضٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ نَارَكُمْ هَذِهِ جُزْءٌ م��نْ سَبْعِينَ جُزْءًا مِنْ نَارِ جَهَنَّمَ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah mengabarkan kepada kami [Al Hajari] dari [Abu 'Iyadl] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya (panasnya) api kalian ini (di dunia) adalah satu dari tujuh puluh (1/70) dari panasnya api neraka jahannam.\" "},"2369":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ عَجْلَانَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَهْوَنُ النَّاسِ عَذَابًا مَنْ لَهُ نَعْلَانِ يَغْلِي مِنْهُمَا دِمَاغُهُ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu 'Ajlan] dari [ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Manusia yang paling ringan siksanya adalah orang yang mengenakan sandalnya hingga (panasnya api itu) membuat otaknya mendidih.\""},"2370":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَمَّارِ بْنِ أَبِي عَمَّارٍ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُلْقَى فِي النَّارِ أَهْلُهَا وَتَقُولُ { هَلْ مِنْ مَزِيدٍ } { هَلْ مِنْ مَزِيدٍ } ثَلَاثًا حَتَّى يَأْتِيَهَا رَبُّهَا فَيَضَعَ قَدَمَهُ عَلَيْهَا فَتُزْوَى وَتَقُولُ قَطْ قَطْ قَطْ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ammar bin Abu Ammar] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penghuni neraka akan dilemparkan ke dalam neraka. Lalu neraka itu mengatakan; Masih adakah tambahan? Ia mengatakannya tiga kali hingga Rabbnya mendatanginya, kemudian meletakkan telapak kakiNya padanya, sehingga ia pun berkumpul (dengan yang lain) dan berkata; Cukup, cukup, cukup.\""},"2371":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا عَاصِمٌ عَنْ مُوَرِّقٍ الْعِجْلِيِّ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِ تَعَلَّمُوا الْفَرَائِضَ وَاللَّحْنَ وَالسُّنَنَ كَمَا تَعَلَّمُونَ الْقُرْآنَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami ['Ashim] dari [Muwarriq Al 'Ijli] ia berkata; [Umar bin Khaththab] berkata; Pelajarilah faraidl, bahasa Arab dan sunnah sebagaimana kalian mempelajari Al Qur`an."},"2372":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ قَالَ قَالَ عُمَرُ تَعَلَّمُوا الْفَرَائِضَ فَإِنَّهَا مِنْ دِينِكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] ia berkata; [Umar] berkata; Pelajarilah faraidl, karena faraidl itu bagian dari agama kalian."},"2373":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا يُوسُفُ الْمَاجِشُونُ قَالَ قَالَ ابْنُ شِهَابٍ لَوْ هَلَكَ عُثْمَانُ وَزَيْدٌ فِي بَعْضِ الزَّمَانِ لَهَلَكَ عِلْمُ الْفَرَائِضِ لَقَدْ أَتَى عَلَى النَّاسِ زَمَانٌ وَمَا يَعْلَمُهَا غَيْرُهُمَا","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Yusuf Al Majisyun] ia berkata; [Ibnu Syihab] berkata; Seandainya Utsman dan Zaid meninggal di suatu masa, niscaya hilanglah ilmu faraidl. Sungguh telah datang masa di mana tidak ada yang mengetahuinya selain mereka berdua."},"2374":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ الْقَاسِمِ قَالَ قَالَ عَبْدُ اللَّهِ تَعَلَّمُوا الْقُرْآنَ وَالْفَرَائِضَ فَإِنَّهُ يُوشِكُ أَنْ يَفْتَقِرَ الرَّجُلُ إِلَى عِلْمٍ كَانَ يَعْلَمُهُ أَوْ يَبْقَى فِي قَوْمٍ لَا يَعْلَمُونَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Al Mas'udi] dari [Al Qasim] ia berkata; [Abdullah] berkata; Pelajarilah Al Qur`an dan ilmu faraidl, karena seseorang akan membutuhkan ilmu yang telah ia pelajari, atau ia berada di suatu kaum yang tidak mengetahui."},"2375":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زِيَادُ بْنُ أَبِي مُسْلِمٍ عَنْ أَبِي الْخَلِيلِ قَالَ قَالَ أَبُو مُوسَى مَنْ عَلِمَ الْقُرْآنَ وَلَمْ يَعْلَمْ الْفَرَائِضَ فَإِنَّ مَثَلَهُ مَثَلُ الْبُرْنُسِ لَا وَجْهَ لَهُ أَوْ لَيْسَ لَهُ وَجْهٌ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ziyad bin Abu Muslim] dari [Abu Al Khalil] ia berkata; [Abu Musa] berkata; Barangsiapa mempelajari Al Qur`an namun tidak mengetahui ilmu faraidl, maka perumpamaannya seperti burnus yang tidak ada wajah padanya atau tidak memiliki wajah. "},"2376":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو شِهَابٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ قَالَ قُلْتُ لِعَلْقَمَةَ مَا أَدْرِي مَا أَسْأَلُكَ عَنْهُ قَالَ أَمِتْ جِيرَانَكَ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Syihab] dari [Al A'masy] dari [Ibrahim] ia berkata; Aku bertanya kepada ['Alqamah]; Aku tidak tahu apa yang harus aku tanyakan kepadamu? Ia mengatakan; Anggap tetanggamu telah meninggal dunia."},"2377":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مُحَمَّدُ بْنُ طَلْحَةَ عَنْ الْقَاسِمِ بْنِ الْوَلِيدِ الْهَمْدَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَ تَعَلَّمُوا الْفَرَائِضَ وَالطَّلَاقَ وَالْحَجَّ فَإِنَّهُ مِنْ دِينِكُمْ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Muhammad bin Thalhah] dari [Al Qasim bin Al Walid Al Hamdani] dari [Abdullah bin Mas'ud] ia berkata; Pelajarilah (tentang masalah) faraidl, thalaq dan haji, sebab masalah-masalah tersebut adalah bagian dari agama kalian."},"2378":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ كَثِيرٍ عَنْ الْحَسَنِ قَالَ كَانُوا يُرَغِّبُونَ فِي تَعْلِيمِ الْقُرْآنِ وَالْفَرَائِضِ وَالْمَنَاسِكِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Katsir] dari [Al Hasan] ia berkata; Mereka sangat menganjurkan untuk mempelajari Al Qur`an, faraidl dan manasik haji."},"2379":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ قَالَ مَنْ قَرَأَ الْقُرْآنَ فَلْيَتَعَلَّمْ الْفَرَائِضَ فَإِنْ لَقِيَهُ أَعْرَابِيٌّ قَالَ يَا مُهَاجِرُ أَتَقْرَأُ الْقُرْآنَ فَإِنْ قَالَ نَعَمْ قَالَ تَفْرِضُ فَإِنْ قَالَ نَعَمْ فَهُوَ زِيَادَةٌ وَخَيْرٌ وَإِنْ قَالَ لَا قَالَ فَمَا فَضْلُكَ عَلَيَّ يَا مُهَاجِرُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Abu Ishaq] dari [Abu Ubaidah] dari [Abdullah] ia berkata; Barangsiapa membaca Al Qur`an, hendaklah ia mempelajari faraidl. Karena, jika ia bertemu dengan seorang Arab desa (badui), ia akan bertanya; Wahai muhajir (pendatang), apakah engkau membaca Al Qur`an? Jika ia menjawab; Ya, ia akan bertanya; Engkau mengerti faraidl? Jika ia menjawab; Ya, maka itu merupakan kelebihan dan kebaikan. Jika ia menjawab; Tidak, ia akan berkata; Engkau tidak lebih utama dariku, wahai muhajir (pendatang)."},"2380":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ قَالَ سَأَلْنَا مَسْرُوقًا كَانَتْ عَائِشَةُ تُحْسِنُ الْفَرَائِضَ قَالَ وَالَّذِي لَا إِلَهَ غَيْرُهُ لَقَدْ رَأَيْتُ الْأَكَابِرَ مِنْ أَصْحَابِ مُحَمَّدٍ يَسْأَلُونَهَا عَنْ الْفَرَائِضِ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Uqbah bin Khalid] dari [Al A'masy] dari [Muslim] ia berkata; Kami bertanya kepada [Masruq]; Benarkah [Aisyah] ahli dalam faraidl? Ia menjawab; Demi Dzat yang tidak ada tuhan yang haq selain Dia, sungguh aku melihat para tokoh sahabat Muhammad bertanya kepadanya tentang faraidl."},"2381":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ عَاصِمٍ عَنْ أَبِي عُثْمَانَ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ وَعَنْ أَبِي بَكْرَةَ قَالَ شُعْبَةُ هَذَا أَوَّلُ مَنْ رَمَى بِسَهْمٍ فِي سَبِيلِ اللَّهِ وَهَذَا تَدَلَّى مِنْ حِصْنِ الطَّائِفِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُمَا حَدَّثَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ادَّعَى إِلَى غَيْرِ أَبِيهِ وَهُوَ يَعْلَمُ أَنَّهُ غَيْرُ أَبِيهِ فَالْجَنَّةُ عَلَيْهِ حَرَامٌ","id":"Telah mengabarkan kepada kami [Sa'id bin Amir] dari [Syu'bah] dari ['Ashim] dari [Abu Utsman] dari [Sa'd bin Abu Waqqash] dan dari [Abu Bakrah], Syu'bah berkata; Ini adalah orang pertama yang melepaskan anak panah fi sabilillah sedangkan yang ini adalah orang pertama yang turun dari benteng Tha`if untuk bergabung dengan Rasulullah shallallahu 'alaihi wasallam. Sesungguhnya mereka berdua menceritakan bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengakui orang lain sebagai ayah kandungnya, padahal ia tahu bahwa orang itu bukan ayah kandungnya, maka surga haram atasnya.\""},"2382":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ أَبِي مَعْمَرٍ عَنْ أَبِي بَكْرٍ الصِّدِّيقِ قَالَ كُفْرٌ بِاللَّهِ ادِّعَاءٌ إِلَى نَسَبٍ لَا يُعْرَفُ وَكُفْرٌ بِاللَّهِ تَبَرُّؤٌ مِنْ نَسَبٍ وَإِنْ دَقَّ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ زَكَرِيَّا أَبِي يَحْيَى قَالَ سَمِعْتُ أَبَا وَائِلٍ يُحَدِّثُ عَنْ ابْنِ مَسْعُودٍ نَحْوًا مِنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Abdullah bin Murrah] dari [Abu Ma'mar] dari [Abu Bakr Ash Shiddiq] ia berkata; Termasuk perbuatan kufur kepada Allah adalah orang yang mengakui keturunan orang lain yang tidak dikenal dan berlepas diri dari nasabnya, sekali pun itu hal yang sepele. Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Zakariya Abu Yahya] ia berkata; aku mendengar [Abu Wa`il] menceritakan dari [Ibnu Mas'ud] seperti riwayat itu."},"2383":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ السَّلُولِيُّ عَنْ جَعْفَرٍ الْأَحْمَرِ عَنْ السَّرِيِّ بْنِ إِسْمَعِيلَ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ قَالَ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأُبَايِعَهُ فَجِئْتُ وَقَدْ قُبِضَ وَأَبُو بَكْرٍ قَائِمٌ فِي مَقَامِهِ فَأَطَابَ الثَّنَاءَ وَأَكْثَرَ الْبُكَاءَ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كُفْرٌ بِاللَّهِ انْتِفَاءٌ مِنْ نَسَبٍ وَإِنْ دَقَّ وَادِّعَاءُ نَسَبٍ لَا يُعْرَفُ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Ishaq bin Manshur As Saluli] dari [Ja'far Al Ahmar] dari [As Sari bin Isma'il] dari [Qais bin Abu Hazim] ia berkata; Aku datang menemui Nabi shallallahu 'alaihi wasallam untuk melakukan janji setia (baiat) kepada beliau. Kemudian ketika aku datang lagi, beliau telah wafat dan [Abu Bakr] yang menggantikan kepemimpinan beliau. Ia mengucapkan puji-pujian begitu indah dan menangis begitu lama. Lalu ia berkata; Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Termasuk perbuatan kufur kepada Allah adalah mengaku bukan keturunan seseorang (padahal sebenarnya ia anaknya), sekalipun itu hal yang remeh, dan mengakui keturunan orang lain yang tidak dikenal.\""},"2384":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ بَهْرَامَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا رَجُلٍ ادَّعَى إِلَى غَيْرِ وَالِدِهِ أَوْ تَوَلَّى غَيْرَ مَوَالِيهِ الَّذِينَ أَعْتَقُوهُ فَإِنَّ عَلَيْهِ لَعْنَةَ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ إِلَى يَوْمِ الْقِيَامَةِ لَا يُقْبَلُ مِنْهُ صَرْفٌ وَلَا عَدْلٌ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Abdul Hamid bin Bahram] dari [Syahr bin Hausyab] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa saja yang mengaku menisbatkan kepada selain ayahnya atau setia kepada orang lain selain tuan yang memerdekakannya, maka ia akan mendapat laknat Allah, malaikat, dan seluruh manusia hingga hari kiamat. Dan tidak akan diterima taubat dan fidyah (tebusan) nya.\" "},"2385":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شَرِيكٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ قَالَ قَالَ عَبْ��ُ اللَّهِ كَانَ عُمَرُ إِذَا سَلَكَ بِنَا طَرِيقًا وَجَدْنَاهُ سَهْلًا وَإِنَّهُ قَالَ فِي زَوْجٍ وَأَبَوَيْنِ لِلزَّوْجِ النِّصْفُ وَلِلْأُمِّ ثُلُثُ مَا بَقِيَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Syarik] dari [Al A'masy] dari [Ibrahim] ia berkata; [Abdullah] berkata; Apabila Umar berjalan bersama kami di suatu jalan, kami akan mendapatkan kemudahan. [Beliau] berkata tentang masalah (bagian warisan) suami dan kedua orang tua; Suami mendapatkan setengah harta warisan dan ibu mendapatkan sepertiga dari yang tersisa."},"2386":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا يَزِيدُ الرِّشْكُ قَالَ سَأَلْتُ سَعِيدَ بْنَ الْمُسَيَّبِ عَنْ رَجُلٍ تَرَكَ امْرَأَتَهُ وَأَبَوَيْهِ فَقَالَ قَسَّمَهَا زَيْدُ بْنُ ثَابِتٍ مِنْ أَرْبَعَةٍ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Yazid Ar Risyk] ia berkata; Aku bertanya kepada [Sa'id bin Al Musayyab] tentang seorang laki-laki yang (meninggal dunia dengan) meninggalkan isteri dan kedua orang tuanya. Lalu ia menjawab; [Zaid bin Tsabit] membaginya dari empat. "},"2387":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ أَنَّ عُثْمَانَ بْنَ عَفَّانَ قَالَ فِي امْرَأَةٍ وَأَبَوَيْنِ لِلْمَرْأَةِ الرُّبُعُ وَلِلْأُمِّ ثُلُثُ مَا بَقِيَ","id":"Telah menceritakan kepada kami [Sa'id bin Amir] dari [Syu'bah] dari [Ayyub] dari [Abu Qilabah] dari [Abu Al Muhallab] bahwa [Utsman bin 'Affan] berkata tentang bagian seorang isteri dan kedua orang tua; Isteri mendapat seperempat dan ibu mendapat sepertiga dari harta yang tersisa."},"2388":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عُثْمَانَ بْنِ عَفَّانَ أَنَّهُ قَالَ لِلْمَرْأَةِ الرُّبُعُ سَهْمٌ مِنْ أَرْبَعَةٍ وَلِلْأُمِّ ثُلُثُ مَا بَقِيَ سَهْمٌ وَلِلْأَبِ سَهْمَانِ أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ حَجَّاجٍ عَنْ عُمَيْرِ بْنِ سَعِيدٍ أَنَّهُ سَأَلَ الْحَارِثَ الْأَعْوَرَ عَنْ امْرَأَةٍ وَأَبَوَيْنِ فَقَالَ مِثْلَ قَوْلِ عُثْمَانَ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ayyub] dari [Abu Qilabah] dari [Abu Al Muhallab] dari [Utsman bin 'Affan] bahwa ia berkata; Seorang isteri mendapat seperempat bagian dari empat, ibu mendapat sepertiga bagian yang tersisa dan ayah mendapat dua bagian. Telah mengabarkan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad] dari [Hajjaj] dari [Umair bin [Sa'id] bahwa ia pernah bertanya kepada [Al Harits Al A'war] tentang seorang isteri dan kedua orang tua. Lalu ia menjawab seperti jawaban Utsman."},"2389":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ زَيْدِ بْنِ ثَابِتٍ أَنَّهُ قَالَ فِي امْرَأَةٍ تَرَكَتْ زَوْجَهَا وَأَبَوَيْهَا لِلزَّوْجِ النِّصْفُ وَلِلْأُمِّ ثُلُثُ مَا بَقِيَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Sa'id bin Al Musayyab] dari [Zaid bin Tsabit] bahwa ia berkata tentang seorang isteri yang meninggalkan suami dan kedua orang tuanya; Suami mendapat setengah bagian dan ibu mendapat sepertiga yang tersisa."},"2390":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ ابْنِ أَبِي لَيْلَى عَنْ عَامِرٍ الشَّعْبِيِّ عَنْ عَلِيٍّ فِي امْرَأَةٍ وَأَبَوَيْنِ قَالَ مِنْ أَرْبَعَةٍ لِلْمَرْأَةِ الرُّبُعُ وَلِلْأُمِّ ثُلُثُ مَا بَقِيَ وَمَا بَقِيَ فَلِلْأَبِ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Ibnu Abu Laila] dari [Amir Asy Sya'bi] dari [Ali] tentang seorang isteri dan kedua orang tua. Ia mengatakan; Dari empat (asal masalahnya empat), isteri mendapat seperempat, ibu mendapat sepertiga (dari harta) yang tersisa dan yang tersisa lagi untuk ayah."},"2391":{"ar":" أَخْبَرَنَا مُحَمَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِيهِ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ عَبْدِ اللَّهِ قَالَ كَانَ يَقُولُ مَا كَانَ اللَّهُ لِيَرَانِي أَنْ أُفَضِّلَ أُمًّا عَلَى أَبٍ","id":"Telah mengabarkan kepada kami [Muhammad] telah menceritakan kepada kami [Sufyan] dari [ayahnya] dari [Al Musayyab bin Rafi'] dari [Abdullah], ia berkata; (Abdullah) pernah berkata; Allah tidak akan senang melihatku jika aku melebihkan bagian ibu atas ayah."},"2392":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ أَخْبَرَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ عِكْرِمَةَ قَالَ أَرْسَلَ ابْنُ عَبَّاسٍ إِلَى زَيْدِ بْنِ ثَابِتٍ أَتَجِدُ فِي كِتَابِ اللَّهِ لِلْأُمِّ ثُلُثُ مَا بَقِيَ فَقَالَ زَيْدٌ إِنَّمَا أَنْتَ رَجُلٌ تَقُولُ بِرَأْيِكَ وَأَنَا رَجُلٌ أَقُولُ بِرَأْيِي","id":"Telah mengabarkan kepada kami [Sa'id bin Amir] telah mengabarkan kepada kami [Syu'bah] dari [Al Hakam] dari [Ikrimah] ia berkata; Ibnu Abbas mengirim surat kepada Zaid bin Tsabit; Apakah engkau pernah menemukan dalam kitab Allah; Ibu mendapat sepertiga dari warisan yang tersisa? [Zaid] menjawab; Sesungguhnya engkau adalah orang yang dapat berbicara berdasarkan pendapatmu dan aku juga orang yang dapat berbicara dengan pendapatku."},"2393":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلِيٍّ قَالَ لِلْأُمِّ ثُلُثُ جَمِيعِ الْمَالِ فِي امْرَأَةٍ وَأَبَوَيْنِ وَفِي زَوْجٍ وَأَبَوَيْنِ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah mengabarkan kepada kami [Abu 'Awanah] dari [Al A'masy] dari [Ibrahim] dari [Ali] ia berkata; Ibu mendapatkan sepetiga dari seluruh harta dalam masalah isteri dan kedua orang tua serta dalam masalah suami dan kedua orang tua."},"2394":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ أَبِيهِ عَنْ الْفُضَيْلِ بْنِ عَمْرٍو عَنْ إِبْرَاهِيمَ قَالَ خَالَفَ ابْنُ عَبَّاسٍ أَهْلَ الْقِبْلَةِ فِي امْرَأَةٍ وَأَبَوَيْنِ جَعَلَ لِلْأُمِّ الثُّلُثَ مِنْ جَمِيعِ الْمَالِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Ibnu Idris] dari [ayahnya] dari [Al Fudlail bin Amr] dari [Ibrahim] ia berkata; [Ibnu Abbas] menyelisihi pendapat ahlu qiblat dalam masalah isteri dan kedua orang tua, ia menjadikan bagian ibu sepertiga dari seluruh harta."},"2395":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ قَالَ قَضَى مُعَاذُ بْنُ جَبَلٍ بِالْيَمَنِ فِي بِنْتٍ وَأُخْتٍ فَأَعْطَى الْبِنْتَ النِّصْفَ وَالْأُخْتَ النِّصْفَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan Ats Tsauri] dari [Asy'ats bin Abu Asy Sya'tsa`] dari [Al Aswad bin Yazid] ia berkata; [Mu'adz bin Jabal] memutuskan hukum di Yaman dalam masalah bagian anak perempuan dan saudara perempuan, ia memberikan bagian anak perempuan setengah dan saudara perempuan setengah."},"2396":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ أَنَّ ابْنَ الزُّبَيْرِ كَانَ لَا يُوَرِّثُ الْأُخْتَ مِنْ الْأَبِ وَالْأُمِّ مَعَ الْبِنْتِ حَتَّى حَدَّثَهُ الْأَسْوَدُ أَنَّ مُعَاذَ بْنَ جَبَلٍ جَعَلَ لِلْبِنْتِ النِّصْفَ وَلِلْأُخْتِ النِّصْفَ فَقَالَ أَنْتَ رَسُولِي إِلَى عَبْدِ اللَّهِ بْنِ عُتْبَةَ فَأَخْبِرْهُ بِذَاكَ وَكَانَ قَاضِيَهُ بِالْكُوفَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad bin Yazid] bahwa Ibnu Az Zubair tidak menetapkan warisan pada saudara perempuan seayah dan seibu bersama anak perempuan hingga Al Aswad menceritakannya bahwa [Mu'adz bin Jabal] menjadikan anak perempuan mendapat bagian setengah dan saudara perempuan mendapat bagian setengah. Ia pun berkata; Engkau adalah utusanku kepada Abdullah bin Utbah. Kabarkan hal ini kepadanya, ketika itu ia menjabat sebagai hakim di Kufah."},"2397":{"ar":" حَدَّثَنَا بِشْرُ بْنُ عُمَرَ قَالَ سَأَلْتُ ابْنَ أَبِي الزِّنَادِ عَنْ رَجُلٍ تَرَكَ بِنْتًا وَأُخْتًا فَقَالَ لِابْنَتِهِ النِّصْفُ وَلِأُخْتِهِ مَا بَقِيَ وَقَالَ أَخْبَرَنِي أَبِي عَنْ خَارِجَةَ بْنِ زَيْدٍ أَنَّ زَيْدَ بْنَ ثَابِتٍ كَانَ يَجْعَلُ الْأَخَوَاتِ مَعَ الْبَنَاتِ عَصَبَةً لَا يَجْعَلُ لَهُنَّ إِلَّا مَا بَقِيَ","id":"Telah menceritakan kepada kami [Bisyr bin Umar] ia berkata; Aku bertanya kepada [Ibnu Abu Az Zinad] tentang seorang laki-laki yang meninggalkan anak perempuan dan saudara perempuan. Ia pun menjawab; Anak perempuan mendapat bagian setengah dan saudara perempuan mendapatkan yang tersisa. Ia juga berkata; Telah mengabarkan kepadaku [ayahnya] dari [Kharijah bin Zaid] bahwa [Zaid bin Tsabit] menjadikan bagian para saudara perempuan bersama para anak perempuan adalah ashabah. Ia tidak memberikan warisan untuk mereka kecuali apa yang tersisa. "},"2398":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ وَالْأَعْمَشِ عَنْ إِبْرَاهِيمَ فِي زَوْجٍ وَأُمٍّ وَإِخْوَةٍ لِأَبٍ وَأُمٍّ وَإِخْوَةٍ لِأُمٍّ قَالَ كَانَ عُمَرُ وَعَبْدُ اللَّهِ وَزَيْدٌ يُشَرِّكُونَ وَقَالَ عُمَرُ لَمْ يَزِدْهُمْ الْأَبُ إِلَّا قُرْبًا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Manshur] dan [Al A'masy] dari [Ibrahim] tentang suami, isteri saudara perempuan seayah seibu dan saudara perempuan seibu. Ia berkata; [Umar], [Abdullah] dan [Zaid] menetapkan musyarrakah bagi mereka. Umar berkata; Ayah tidak menambah mereka kecuali kedekatan. "},"2399":{"ar":" حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ أَنَّهُ كَانَ لَا يُشَرِّكُ","id":"Telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Al Harits] dari [Ali] bahwa ia tidak menetapkan musyarrakah."},"2400":{"ar":" أَخْبَرَنَا مُحَمَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي مِجْلَزٍ أَنَّ عُثْمَانَ كَانَ يُشَرِّكُ وَعَلِيٌّ كَانَ لَا يُشَرِّكُ","id":"Telah mengabarkan kepada kami [Muhammad] telah menceritakan kepada kami [Sufyan] dari [Sulaiman At Taimi] dari [Abu Mijlaz] bahwa [Utsman] menetapkan musyarrakah namun [Ali] tidak menetapkan musyarrakah."},"2401":{"ar":" حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ ذَكْوَانَ أَنَّ زَيْدًا كَانَ يُشَرِّكُ","id":"Telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami [Sufyan] dari [Ibnu Dzakwan] bahwa [Zaid] menetapkan musyarrakah."},"2402":{"ar":" حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ شُرَيْحٍ أَنَّهُ كَانَ يُشَرِّكُ","id":"Telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami [Sufyan] dari [Abdul Malik bin Umair] dari [Syuraih] bahwa ia menetapkan musyarrakah."},"2403":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ حَدَّثَنَا أَبُو شِهَابٍ عَنْ الْحَجَّاجِ عَنْ عَبْدِ الْمَلِكِ بْنِ الْمُغِيرَةِ عَنْ سَعِيدِ بْنِ فَيْرُوزَ عَنْ أَبِيهِ أَنَّ عُمَرَ قَالَ فِي الْمُشَرَّكَةِ لَمْ يَزِدْهُمْ الْأَبُ إِلَّا قُرْبًا","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shalt] telah menceritakan kepada kami [Abu Syihab] dari [Al Hajjaj] dari [Abdul Malik bin Al Mughirah] dari [Sa'id bin Fairuz] dari [ayahnya] bahwa [Umar] berkata tentang musyarrakah; Ayah tidak menambah mereka kecuali kedekatan."},"2404":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ الْأَعْوَرِ قَالَ أُتِيَ عَبْدُ اللَّهِ فِي فَرِيضَةِ بَنِي عَمٍّ أَحَدُهُمْ أَخٌ لِأُمٍّ فَقَالَ الْمَالُ أَجْمَعُ لِأَخِيهِ لِأُمِّهِ فَأَنْزَلَهُ بِحِسَابِ أَوْ بِمَنْزِلَةِ الْأَخِ مِنْ الْأَبِ وَالْأُمِّ فَلَمَّا قَدِمَ عَلِيٌّ سَأَلْتُهُ عَنْهَا وَأَخْبَرْتُهُ بِقَوْلِ عَبْدِ اللَّهِ فَقَالَ يَرْحَمُهُ اللَّهُ إِنْ كَانَ لَفَقِيهًا أَمَّا أَنَا فَلَمْ أَكُنْ لِأَزِيدَهُ عَلَى مَا فَرَضَ اللَّهُ لَهُ سَهْمٌ السُّدُسُ ثُمَّ يُقَاسِمُهُمْ كَرَجُلٍ مِنْهُمْ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari [Al Harits Al A'war] ia berkata; [Abdullah] pernah dihadapkan dengan masalah warisan dua anak paman dari pihak ayah. Salah satunya adalah saudara laki-laki seibu. Ia berkata; Harta seluruhnya untuk saudara laki-laki seibu. Ia menempatkan saudara laki-laki seibu dengan hitungan atau pada kedudukan saudara laki-laki seayah dan seibu. Ketika Ali datang, aku bertanya kepadanya tentang masalah ini. Aku juga memberitahukan perkataan Abdullah kepadanya. Maka [dia] menjawab; Semoga Allah merahmatinya, sesungguhnya ia adalah seorang faqih. Sedangkan aku tidak akan menambahkan bagian untuknya atas apa yang telah ditetapkan Allah, yaitu bagian seperenam. Lalu ia membagi harta untuk mereka seperti bagian laki-laki dari mereka."},"2405":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ أَنَّهُ أُتِيَ فِي ابْنَيْ عَمٍّ أَحَدُهُمَا أَخٌ لِأُمٍّ فَقِيلَ لِعَلِيٍّ إِنَّ ابْنَ مَسْعُودٍ كَانَ يُعْطِيهِ الْمَالَ كُلَّهُ فَقَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ إِنْ كَانَ لَفَقِيهًا وَلَوْ كُنْتُ أَنَا أَعْطَيْتُهُ السُّدُسَ وَمَا بَقِيَ كَانَ بَيْنَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Al Harits] dari [Ali] bahwa ia pernah dihadapkan dengan masalah warisan dua anak paman dari pihak ayah, salah satunya adalah saudara laki-laki seibu. Kemudian ketika Ali diberitahukan bahwa Ibnu Mas'ud memberikan kepada saudara laki-laki seibu seluruh harta, maka Ali radliallahu 'anhu berkata; Ia adalah seorang faqih. Seandainya aku yang memutuskan maka aku akan memberikan bagian seperenam untuknya dan yang tersisa dibagikan di antara mereka."},"2406":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ أَبِي قَيْسٍ الْأَوْدِيِّ عَنْ هُزَيْلِ بْنِ شُرَحْبِيلَ قَالَ جَاءَ رَجُلٌ إِلَى أَبِي مُوسَى الْأَشْعَرِيِّ وَإِلَى سَلْمَانَ بْنِ رَبِيعَةَ فَسَأَلَهُمَا عَنْ بِنْتٍ وَبِنْتِ ابْنٍ وَأُخْتٍ لِأُمٍّ وَأَبٍ فَقَالَا لِلِابْنَةِ النِّصْفُ وَمَا بَقِيَ فَلِلْأُخْتِ وَأْتِ ابْنَ مَسْعُودٍ فَإِنَّهُ سَيُتَابِعُنَا فَجَاءَ الرَّجُلُ إِلَى عَبْدِ اللَّهِ فَسَأَلَهُ عَنْ ذَلِكَ فَقَالَ لَقَدْ ضَلَلْتُ إِذًا وَمَا أَنَا مِنْ الْمُهْتَدِينَ وَإِنِّي أَقْضِي بِمَا قَضَى بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلِابْنَةِ النِّصْفُ وَلِابْنَةِ الِابْنِ السُّدُسُ وَمَا بَقِيَ فَلِلْأُخْتِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan Ats Tsauri] dari [Abu Qais Al Audi] dari [Huzail bin Syurahbil] ia berkata; Ada seseorang mendatangi Abu Musa Al Asy'ari dan Salman bin Rabi'ah lalu menanyakan kepada keduanya tentang anak perempuan, anak perempuan dari anak laki-laki dan saudara perempuan seibu dan seayah. Mereka berdua menjawab; Anak perempuan mendapat setengah dan warisan yang tersisa untuk saudara perempuan. Datanglah kepada [Ibnu Mas'ud], tentu ia akan mengikuti pendapat kami. Lalu orang itu datang menemui Abdullah menanyakan tentang hal itu kepadanya. Ia pun mengatakan; Kalau tidak menjawab berarti aku telah tersesat dan tidak termasuk orang-orang yang mendapat petunjuk. Sesungguhnya aku memutuskan sesuatu dengan apa yang pernah diputuskan oleh Rasulullah shallallahu 'alaihi wasallam; Anak perempuan mendapat setengah, anak perempuan dari anak laki-laki mendapat seperenam, dan warisan yang tersisa untuk saudara perempuan."},"2407":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو شِهَابٍ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ أَنَّهُ كَانَ يَقُولُ فِي أَخَوَاتٍ لِأَبٍ وَأُمٍّ وَإِخْوَةٍ وَأَخَوَاتٍ لِأَبٍ قَالَ لِلْأَخَوَاتِ لِلْأَبِ وَالْأُمِّ الثُّلُثَانِ وَمَا بَقِيَ فَلِلذُّكُورِ دُونَ الْإِنَاثِ فَقَدِمَ مَسْرُوقٌ الْمَدِينَةَ فَسَمِعَ قَوْلَ زَيْدٍ فِيهَا فَأَعْجَبَهُ فَقَالَ لَهُ بَعْضُ أَصْحَابِهِ أَتَتْرُكُ قَوْلَ عَبْدِ اللَّهِ فَقَالَ إِنِّي أَتَيْتُ الْمَدِينَةَ فَوَجَدْتُ زَيْدَ بْنَ ثَابِتٍ مِنْ الرَّاسِخِينَ فِي الْعِلْمِ قَالَ أَحْمَدُ فَقُلْتُ لِأَبِي شِهَابٍ وَكَيْفَ قَالَ زَيْدٌ فِيهَا قَالَ شَرَّكَ بَيْنَهُمْ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Syihab] dari [Al A'masy] dari [Muslim] dari [Masruq] dari [Abdullah] bahwa ia pernah berkata dalam masalah beberapa saudara perempuan seayah dan seibu, beberapa saudara laki-laki dan beberapa saudara perempuan seayah, ia berkata; Beberapa saudara perempuan seayah dan seibu mendapat dua pertiga dan yang tersisa hanya untuk para laki-laki tidak untuk perempuan. Lalu ketika Masruq datang ke Madinah, ia mendengar perkataan [Zaid] dalam masalah itu, ia pun heran, lalu sebagian sahabatnya menanyakannya; Apakah engkau akan meninggalkan perkataan Abdullah? Ia menjawab; Aku datang ke Madinah dan menemukan Zaid bin Tsabit termasuk orang-orang yang mendalam ilmunya. Ahmad berkata; Aku bertanya kepada Abu Syihab; Bagaimana jawabannya itu? Ia menjawab; Ia membagi harta secara musyarrakah di antara mereka."},"2408":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ الْمُغِيرَةِ عَنْ عِيسَى بْنِ يُونُسَ عَنْ إِسْمَعِيلَ قَالَ ذَكَرْنَا عِنْدَ حَكِيمِ بْنِ جَابِرٍ أَنَّ ابْنَ مَسْعُودٍ قَالَ فِي أَخَوَاتٍ لِأَبٍ وَأُمٍّ وَإِخْوَةٍ وَأَخَوَاتٍ لِأَبٍ أَنَّهُ كَانَ يُعْطِي لِلْأَخَوَاتِ مِنْ الْأَبِ وَالْأُمِّ الثُّلُثَيْنِ وَمَا بَقِيَ فَلِلذُّكُورِ دُونَ الْإِنَاثِ فَقَالَ حَكِيمٌ قَالَ زَيْدُ بْنُ ثَابِتٍ هَذَا مِنْ عَمَلِ الْجَاهِلِيَّةِ أَنْ يَرِثَ الرِّجَالُ دُونَ النِّسَاءِ إِنَّ إِخْوَتَهُنَّ قَدْ رُدُّوا عَلَيْهِنَّ","id":"Telah menceritakan kepada kami [Sa'id bin Al Mughirah] dari [Isa bin Yunus] dari [Isma'il] ia berkata; Kami menyebutkan kepada [Hakim bin Jabir] bahwa [Ibnu Mas'ud] berkata dalam masalah beberapa saudara perempuan seayah dan seibu, beberapa saudara laki-laki dan beberapa saudara perempuan seayah, bahwa ia memberi bagian kepada beberapa saudara peremuan seayah dan seibu dua pertiga, dan yang tersisa untuk para laki-laki saja. Lalu Hakim berkata; [Zaid bin Tsabit] berkata; Hal ini termasuk perbuatan jahiliyah, yaitu memberi hak waris kepada para laki-laki tidak kepada para perempuan. Sesungguhnya (bagian) para saudara laki-laki telah dikembalikan kepada mereka."},"2409":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَعْبَدِ بْنِ خَالِدٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ أَنَّهَا كَانَتْ تُشَرِّكُ بَيْنَ ابْنَتَيْنِ وَابْنَةِ ابْنٍ وَابْنِ ابْنٍ تُعْطِي الِابْنَتَيْنِ الثُّلُثَيْنِ وَمَا بَقِيَ فَشَرِيكُهُمْ وَكَانَ عَبْدُ اللَّهِ لَا يُشَرِّكُ يُعْطِي الذُّكُورَ دُونَ الْإِنَاثِ وَقَالَ الْأَخَوَاتُ بِمَنْزِلَةِ الْبَنَاتِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ma'bad bin Khalid] dari [Masruq] dari [Aisyah] bahwa ia melakukan musyarrakah di antara dua anak perempuan, anak perempuan dari anak laki-laki dan anak laki-laki dari anak laki-laki; Dua anak perempuan mendapat dua pertiga dan yang tersisa dibagikan secara musyarrakah. Abdullah tidak melakukan musyarrakah, ia memberi bagian para laki-laki tidak kepada para perempuan. Ia berkata; Para saudara perempuan sama kedudukannya dengan para anak perempuan."},"2410":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي سَهْلٍ عَنْ الشَّعْبِيِّ أَنَّ ابْنَ مَسْعُودٍ كَانَ يَقُولُ فِي بِنْتٍ وَبَنَاتِ ابْنٍ وَابْنِ ابْنٍ إِنْ كَانَتْ الْمُقَاسَمَةُ بَيْنَهُمْ أَقَلَّ مِنْ السُّدُسِ أَعْطَاهُمْ السُّدُسَ وَإِنْ كَانَ أَكْثَرَ مِنْ السُّدُسِ أَعْطَاهُمْ السُّدُسَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Abu Sahl] dari [Asy Sya'bi] bahwa [Ibnu Mas'ud] pernah berkata dalam masalah anak perempuan dan para anak perempuan dari anak laki-laki serta anak laki-laki dari anak laki-laki; Jika pembagian di antara mereka kurang dari seperenam, maka diberkan kepada mereka seperenam dan jika lebih dari seperenam maka diberikan kepada mereka seperenam juga."},"2411":{"ar":" حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ مَسْرُوقٍ أَنَّهُ كَانَ يُشَرِّكُ فَقَالَ لَهُ عَلْقَمَةُ هَلْ أَحَدٌ مِنْهُمْ أَثْبَتُ مِنْ عَبْدِ اللَّهِ فَقَالَ لَا وَلَكِنِّي رَأَيْتُ زَيْدَ بْنَ ثَابِتٍ وَأَهْلَ الْمَدِينَةِ يُشَرِّكُونَ فِي ابْنَتَيْنِ وَبِنْتِ ابْنٍ وَابْنِ ابْنٍ وَأُخْتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari [Masruq] bahwa ia melakukan musyarrakah. Maka 'Alqamah berkata kepadanya; Adakah orang di antara mereka yang lebih memastikan dari pada Abdullah? Ia menjawab; Tidak ada, akan tetapi aku pernah melihat [Zaid bin Tsabit] dan ulama Madinah membagi harta warisan secara musyarrikah dalam masalah; Dua anak perempuan, seorang anak perempuan dari anak laki-laki, seorang anak laki-laki dari anak laki-laki dan dua saudara perempuan."},"2412":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ شُرَيْحٍ فِي امْرَأَةٍ تَرَكَتْ زَوْجَهَا وَأُمَّهَا وَأُخْتَهَا لِأَبِيهَا وَأُمِّهَا وَأُخْتَهَا لِأَبِيهَا وَإِخْوَتَهَا لِأُمِّهَا جَعَلَهَا مِنْ سِتَّةٍ ثُمَّ رَفَعَهَا فَبَلَغَتْ عَشْرَةً لِلزَّوْجِ النِّصْفُ ثَلَاثَةُ أَسْهُمٍ وَلِلْأُخْتِ مِنْ الْأَبِ وَالْأُمِّ النِّصْفُ ثَلَاثَةُ أَسْهُمٍ وَلِلْأُمِّ السُّدُسُ سَهْمٌ وَلِلْإِخْوَةِ مِنْ الْأُمِّ الثُّلُثُ سَهْمَانِ وَلِلْأُخْتِ مِنْ الْأَبِ سَهْمٌ تَكْمِلَةُ الثُّلُثَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Hisyam] dari [Muhammad bin Sirin] dari [Syuraih] dalam masalah seorang isteri yang meninggalkan suami, ibu, saudara perempuan seayah dan seibu, saudara perempuan seayah dan saudara perempuannya seibu. Ia menjadikannya dari enam (asal masalahnya enam) kemudian menambahnya menjadi sepuluh (asal masalahnya menjadi sepuluh). Suami mendapat setengah, yaitu tiga bagian. Saudara perempuan seayah dan seibu mendapat setengah, yaitu tiga bagian. Ibu mendapat seperenam, yaikni tiga bagian. Para saudara laki-laki seibu mendapat sepertiga, yakni dua bagian. Saudara perempuan seayah satu bagian sebagai penyempurna dua pertiga."},"2413":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ ع��نْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ أَشْعَثَ عَنْ الشَّعْبِيِّ أَنَّ عَلِيًّا وَزَيْدًا كَانَا لَا يَحْجُبَانِ بِالْكُفَّارِ وَلَا بِالْمَمْلُوكِينَ وَلَا يُوَرِّثَانِهِمْ شَيْئًا وَكَانَ عَبْدُ اللَّهِ يَحْجُبُ بِالْكُفَّارِ وَبِالْمَمْلُوكِينَ وَلَا يُوَرِّثُهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Uyainah] dari [Ali bin Mushir] dari [Asy'ats] dari [Asy Sya'bi] bahwa [Ali] dan [Zaid] keduanya tidak menjadikan orang-orang kafir dan para budak sebagai hijab (penghalang) bagi ahli waris lainnya dan keduanya tidak masuk dalam kelompok ahli waris. Sementara [Abdullah] menjadikan orang-orang kafir dan para budak sebagai hijab namun tidak memasukkan mereka dalam kelompok ahli waris."},"2414":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ أَنَّ عَلِيًّا وَزَيْدًا قَالَا الْمَمْلُوكُونَ وَأَهْلُ الْكِتَابِ لَا يَحْجُبُونَ وَلَا يَرِثُونَ وَقَالَ عَبْدُ اللَّهِ يَحْجُبُونَ وَلَا يَرِثُونَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] bahwa [Ali] dan [Zaid] berkata; Para budak dan ahlu kitab tidak menghalangi dan tidak dapat menjadi ahli waris. Sedangkan [Abdullah] berkata; Mereka dapat menghalangi, namun tidak dapat menjadi ahli waris."},"2415":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا يَحْيَى عَنْ سَعِيدٍ أَنَّ عُمَرَ كَانَ كَتَبَ مِيرَاثَ الْجَدِّ حَتَّى إِذَا طُعِنَ دَعَا بِهِ فَمَحَاهُ ثُمَّ قَالَ سَتَرَوْنَ رَأْيَكُمْ فِيهِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] Telah mengabarkan kepada kami [Yahya] dari [Sa'id] bahwa [Umar] pernah menulis bagian warisan untuk kakek hingga ketika setelah ditikam, ia meminta tulisannya tersebut dan menghapusnya. Kemudian ia berkata; Kalian dapat berpendapat dengan pendapat kalian tentang bagian ini."},"2416":{"ar":" أَخْبَرَنَا يَزِيدُ أَخْبَرَنَا أَشْعَثُ عَنْ ابْنِ سِيرِينَ قَالَ قُلْتُ لِعَبِيدَةَ حَدِّثْنِي عَنْ الْجَدِّ فَقَالَ إِنِّي لَأَحْفَظُ فِي الْجَدِّ ثَمَانِينَ قَضِيَّةً مُخْتَلِفَةً","id":"Telah mengabarkan kepada kami [Yazid] telah mengabarkan kepada kami [Asy'ats] dari [Ibnu Sirin] ia berkata; Aku berkata kepada [Abidah]; Ceritakanlah kepadaku tentang bagian kakek. Lalu ia berkata; Sesungguhnya aku hafal delapan puluh masalah yang berbeda tentang bagian warisan kakek."},"2417":{"ar":" أَخْبَرَنَا أَبُو غَسَّانَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ عُبَيْدِ بْنِ عَمْرٍو الْخَارِفِيِّ عَنْ عَلِيٍّ قَالَ أَتَاهُ رَجُلٌ فَسَأَلَهُ عَنْ فَرِيضَةٍ فَقَالَ إِنْ لَمْ يَكُنْ فِيهَا جَدٌّ فَهَاتِهَا","id":"Telah mengabarkan kepada kami [Abu Ghassan] telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Ubaid bin Amr Al Kharifi] dari [Ali] ia berkata; Seseorang datang kepadanya lalu bertanya tentang pembagian harta warisan. Maka ia menjawab; Jika di dalam ahli waris tidak ada kakek, maka bagikanlah."},"2418":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ عُبَيْدِ بْنِ عَمْرٍو قَالَ جَاءَ رَجُلٌ إِلَى عَلِيٍّ فَسَأَلَهُ عَنْ فَرِيضَةٍ فَقَالَ إِنْ لَمْ يَكُنْ فِيهَا جَدٌّ فَهَاتِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Ubaid bin Amr] ia berkata; Seseorang datang kepada [Ali] menanyakannya tentang pembagian harta warisan. Maka ia menjawab; Jika di dalam ahli waris tidak ada kakek maka bagikanlah."},"2419":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ السَّخْتِيَانِيِّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ رَجُلٍ مِنْ مُرَادٍ سَمِعَ عَلِيًّا يَقُولُ مَنْ سَرَّهُ أَنْ يَتَقَحَّمَ جَرَاثِيمَ جَهَنَّمَ فَلْيَقْضِ بَيْنَ الْجَدِّ وَالْإِخْوَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ayyub As Sakhtiyani] dari [Sa'id bin Jubair] dari [seorang laki-laki dari Murad] ia mendengar [Ali] berkata; Barangsiapa yang senang menceburkan diri ke dasar neraka Jahannam, maka silahkan memutuskan masalah warisan antara kakek dan para saudara laki-laki."},"2420":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا خَالِدٌ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ ح وَعَنْ عِكْرِمَةَ أَنَّ أَبَا بَكْرٍ الصِّدِّيقَ جَعَلَ الْجَدَّ أَبًا","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Khalid] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri], dalam riwayat lain dari [Ikrimah] bahwa [Abu Bakr Ash Shiddiq] menjadikan kakek pada posisi ayah dalam warisan."},"2421":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ سُلَيْمَانَ الشَّيْبَانِيِّ عَنْ كُرْدُوسٍ عَنْ أَبِي مُوسَى عَنْ أَبِي بَكْرٍ الصِّدِّيقِ أَنَّهُ جَعَلَ الْجَدَّ أَبًا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Sulaiman Asy Syaibani] dari [Kurdus] dari [Abu Musa] dari [Abu Bakr Ash Shiddiq] bahwa ia menjadikan kakek pada posisi ayah dalam warisan."},"2422":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو شِهَابٍ عَنْ الشَّيْبَانِيِّ عَنْ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى عَنْ كُرْدُوسٍ عَنْ أَبِي مُوسَى أَنَّ أَبَا بَكْرٍ جَعَلَ الْجَدَّ أَبًا","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Syihab] dari [Asy Syaibani] dari [Abu Burdah bin Abu Musa] dari [Kurdus] dari [Abu Musa] bahwa [Abu Bakr] menjadikan kakek pada posisi ayah dalam warisan."},"2423":{"ar":" أَخْبَرَنَا الْأَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي بُرْدَةَ عَنْ مَرْوَانَ عَنْ عُثْمَانَ أَنَّ أَبَا بَكْرٍ كَانَ يَجْعَلُ الْجَدَّ أَبًا","id":"Telah mengabarkan kepada kami [Al Aswad bin Amir] telah menceritakan kepada kami [Syu'bah] dari [Amr bin Murrah] dari [Abu Burdah] dari [Marwan] dari [Utsman] bahwa [Abu Bakr] menjadikan kakek pada posisi ayah dalam warisan."},"2424":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى وَمُحَمَّدُ بْنُ يُوسُفَ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي بُرْدَةَ قَالَ لَقِيتُ مَرْوَانَ بْنَ الْحَكَمِ بِالْمَدِينَةِ فَقَالَ يَا ابْنَ أَبِي مُوسَى أَلَمْ أُخْبَرْ أَنَّ الْجَدَّ لَا يُنَزَّلُ فِيكُمْ مَنْزِلَةَ الْأَبِ وَأَنْتَ لَا تُنْكِرُ قَالَ قُلْتُ وَلَوْ كُنْتَ أَنْتَ لَمْ تُنْكِرْ قَالَ مَرْوَانُ فَأَنَا أَشْهَدُ عَلَى عُثْمَانَ بْنِ عَفَّانَ أَنَّهُ شَهِدَ عَلَى أَبِي بَكْرٍ أَنَّهُ جَعَلَ الْجَدَّ أَبًا إِذَا لَمْ يَكُنْ دُونَهُ أَبٌ","id":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dan [Muhammad bin Yusuf] dari [Isra`il] dari [Abu Ishaq] dari [Abu Burdah] ia berkata; Aku bertemu Marwan bin Al Hakam di Madinah, lalu ia berkata kepadaku; Wahai Ibnu Abu Musa, bukankah telah diberitahukan bahwa menurut kalian, kakek tidak menempati pada posisi ayah dan kamu tidak mengingkarinya? Ia mengatakan; Aku menjawab; Meskipun dulunya engkau tidak akan mengingkari? [Marwan] berkata; Sebab aku menyaksikan bahwasanya [Utsman bin 'Affan] pernah menyaksikan [Abu Bakar] menempatkan kakek pada posisi ayah dalam warisan, jika mayit tidak memiliki ayah."},"2425":{"ar":" حَدَّثَنَا الْأَسْوَدُ بْنُ عَامِرٍ أَخْبَرَنَا شُعْبَةُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي نَضْرَةَ وَعَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ أَبَا بَكْرٍ كَانَ يَجْعَلُ الْجَدَّ أَبًا","id":"Telah menceritakan kepada kami [Al Aswad bin Amir] Telah mengabarkan kepada kami [Syu'bah] dari [Khalid Al Hadza`] dari [Abu An Nadlr] dan dari [Ikrimah] dari [Ibnu Abbas] bahwa [Abu Bakr] menjadikan kakek pada posisi ayah dalam warisan."},"2426":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ جَعَلَهُ الَّذِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كُنْتُ مُتَّخِذًا أَحَدًا خَلِيلًا لَاتَّخَذْتُهُ خَلِيلًا وَلَكِنْ أُخُوَّةُ الْإِسْلَامِ أَفْضَلُ يَعْنِي أَبَا بَكْرٍ جَعَلَهُ أَبًا يَعْنِي الْجَدَّ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; [Orang] yang menyebabkan Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya aku boleh menjadikan seseorang sebagai kekasih maka tentu aku akan menjadikannya (Abu Bakar) sebagai kekasih. Tetapi persaudaraan dalam Islam lebih baik.\" Yakni Abu Bakar, ia menjadikannya pada posisi ayah yakni kakek."},"2427":{"ar":" حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ ابْنِ الزُّبَيْرِ أَنَّ أَبَا بَكْرٍ جَعَلَ الْجَدَّ أَبًا","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ayyub] dari [Ibnu Abu Mulaikah] dari [Ibnu Az Zubair] bahwa [Abu Bakr] menjadikan kakek pada posisi ayah dalam warisan."},"2428":{"ar":" حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْأَشْعَثُ عَنْ الْحَسَنِ قَالَ إِنَّ الْجَدَّ قَدْ مَضَتْ سُنَّتُهُ وَإِنَّ أَبَا بَكْرٍ جَعَلَ الْجَدَّ أَبًا وَلَكِنَّ النَّاسَ تَحَيَّرُوا","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Al Asy'ats] dari [Al Hasan] ia berkata; Sesungguhnya kakek telah ditetapkan dalam sunnah dan sesungguhnya [Abu Bakr] telah menjadikan kakek pada posisi ayah, tetapi manusia menjadi bingung."},"2429":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ قَالَ إِنَّ أَوَّلَ جَدٍّ وَرِثَ فِي الْإِسْلَامِ عُمَرُ","id":"Telah mengabarkan kepada kami [Muhammad bin Uyainah] dari [Ali bin Mushir] dari ['Ashim] dari [Asy Sya'bi] ia berkata; Sesungguhnya (posisi seorang) kakek yang pertama kali memperoleh warisan di dalam Islam adalah [Umar]."},"2430":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَسَنٌ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ قَالَ أَوَّلُ جَدٍّ وَرِثَ فِي الْإِسْلَامِ عُمَرُ فَأَخَذَ مَالَهُ فَأَتَاهُ عَلِيٌّ وَزَيْدٌ فَقَالَا لَيْسَ لَكَ ذَاكَ إِنَّمَا أَنْتَ كَأَحَدِ الْأَخَوَيْنِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hasan] dari ['Ashim] dari [Asy Sya'bi] ia berkata; (Posisi seorang) kakek yang pertama memperoleh warisan di dalam Islam adalah Umar. Setelah mengambil bagiannya, [Ali] dan] Zaid] datang menemuinya, lalu keduanya berkata; Engkau tidak boleh melakukan hal itu, sesungguhnya posisimu seperti salah seorang dari dua saudara laki-laki."},"2431":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ عِيسَى الْحَنَّاطِ عَنْ الشَّعْبِيِّ قَالَ كَانَ عُمَرُ يُقَاسِمُ بِالْجَدِّ مَعَ الْأَخِ وَالْأَخَوَيْنِ فَإِذَا زَادُوا أَعْطَاهُ الثُّلُثَ وَكَانَ يُعْطِيهِ مَعَ الْوَلَدِ السُّدُسَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Isa Al Hannath] dari [Asy Sya'bi] ia berkata; [Umar] membagi harta warisan kepada kakek bersama satu saudara laki-laki dan dua saudara laki-laki. Jika lebih dari dua orang bersaudara, Umar memberi kakek sepertiga. Umar juga memberi seperenam kepada kakek ketika bersama anak."},"2432":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ مَرْوَانَ بْنِ الْحَكَمِ أَنَّ عُمَرَ بْنَ الْخَطَّابِ لَمَّا طُعِنَ اسْتَشَارَهُمْ فِي الْجَدِّ فَقَالَ إِنِّي كُنْتُ رَأَيْتُ فِي الْجَدِّ رَأْيًا فَإِنْ رَأَيْتُمْ أَنْ تَتَّبِعُوهُ فَاتَّبِعُوهُ فَقَالَ لَهُ عُثْمَانُ إِنْ نَتَّبِعْ رَأْيَكَ فَإِنَّهُ رَشَدٌ وَإِنْ نَتَّبِعْ رَأْيَ الشَّيْخِ فَلَنِعْمَ ذُو الرَّأْيِ كَانَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Hisyam bin Urwah] dari [ayahnya] dari [Marwan bin Al Hakam] bahwa [Umar bin Al Khaththab] ketika tertikam, ia bermusyawarah dengan mereka tentang bagian kakek. Ia berkata; Sesungguhnya aku memiliki pendapat tentang bagian kakek. Jika kalian setuju untuk mengikutinya maka ikutilah pendapatku itu. [Utsman] berkata kepadanya; Jika kami mengikuti pendapatmu, maka sesungguhnya pendapatmu itu benar, namun jika kami mengikuti pendapat asy syaikh (orang yang lebih tua dan faham tentang agamanya), maka ia memang sebaik-baik orang yang memiliki pendapat."},"2433":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ الشَّيْبَانِيِّ عَنْ الشَّعْبِيِّ قَالَ كَتَبَ ابْنُ عَبَّاسٍ إِلَى عَلِيٍّ وَابْنُ عَبَّاسٍ بِالْبَصْرَةِ إِنِّي أُتِيتُ بِجَدٍّ وَسِتَّةِ إِخْوَةٍ فَكَتَبَ إِلَيْهِ عَلِيٌّ أَنْ أَعْطِ الْجَدَّ سُبُعًا وَلَا تُعْطِهِ أَحَدًا بَعْدَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Uyainah] dari [Ali bin Mushir] dari [Asy Syaibani] dari [Asy Sya'bi] ia berkata; Ibnu Abbas menulis surat kepada Ali, saat itu Ibnu Abbas berada di Bashrah; Sesungguhnya aku telah dihadapkan dengan masalah bagian kakek dan enam saudara laki-laki. Maka [Ali] berkata; Berikan kepada kakek seperenam dan jangan engkau berikan seperenam kepada siapa pun setelahnya."},"2434":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَسَنٌ عَنْ إِسْمَعِيلَ عَنْ الشَّعْبِيِّ فِي سِتَّةِ إِخْوَةٍ وَجَدٍّ قَالَ أَعْطِ الْجَدَّ السُّدُسَ قَالَ أَبُو مُحَمَّد كَأَنَّهُ يَعْنِي عَلِيًّا الشَّعْبِيُّ يَرْوِيهِ عَنْ عَلِيٍّ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hasan] dari [Isma'il] dari [Asy Sya'bi] tentang masalah enam saudara laki-laki dan kakek, ia berkata; Berikan seperenam kepada kakek. Abu Muhammad berkata; Sepertinya Asy Sya'bi meriwayatkan langsung dari Ali."},"2435":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ سَلَمَةَ أَنَّ عَلِيًّا كَانَ يَجْعَلُ الْجَدَّ أَخًا حَتَّى يَكُونَ سَادِسًا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Amr bin Murrah] dari [Abdullah bin Salamah] bahwa [Ali] menjadikan kakek pada posisi saudara laki-laki dalam warisan selama jumlah saudara enam orang. "},"2436":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ أَنَّ عَلِيًّا كَانَ يُشَرِّكُ الْجَدَّ مَعَ الْإِخْوَةِ إِلَى السُّدُسِ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Yunus] dari [Al Hasan] bahwa [Ali] memberikan pembagian warisan secara musyarrakah dalam masalah kakek ketika bersama para saudara laki-laki sebanyak seperenam."},"2437":{"ar":" حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ سَلَمَةَ قَالَ كَانَ عَلِيٌّ يُشَرِّكُ بَيْنَ الْجَدِّ وَالْإِخْوَةِ حَتَّى يَكُونَ سَادِسًا","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari [Amr bin Murrah] dari [Abdullah bin Salamah] ia berkata; [Ali] membagi harta secara musyarrakah antara kakek dan para saudara laki-laki, sampai berjumlah enam orang."},"2438":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ قَالَ كَانَ عَلِيٌّ يُشَرِّكُ الْجَدَّ إِلَى سِتَّةٍ مَعَ الْإِخْوَةِ يُعْطِي كُلَّ صَاحِبِ فَرِيضَةٍ فَرِيضَتَهُ وَلَا يُوَرِّثُ أَخًا لِأُمٍّ مَعَ جَدٍّ وَلَا أُخْتًا لِأُمٍّ وَلَا يَزِيدُ الْجَدَّ مَعَ الْوَلَدِ عَلَى السُّدُسِ إِلَّا أَنْ يَكُونَ غَيْرُهُ وَلَا يُقَاسِمُ بِأَخٍ لِأَبٍ مَعَ أَخٍ لِأَبٍ وَأُمٍّ وَإِذَا كَانَتْ أُخْتٌ لِأَبٍ وَأُمٍّ وَأَخٌ لِأَبٍ أَعْطَى الْأُخْتَ النِّصْفَ وَالنِّصْفَ الْآخَرَ بَيْنَ الْجَدِّ وَالْأَخِ نِصْفَيْنِ وَإِذَا كَانُوا إِخْوَةً وَأَخَوَاتٍ شَرَّكَهُمْ مَعَ الْجَدِّ إِلَى السُّدُسِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] ia berkata; [Ali] pernah membagi harta secara musyarrakah pada kakek ketika bersama enam saudara laki-laki. Setiap orang yang memiliki bagian yang telah ditetapkan mendapatkan bagiannya, namun saudara laki-laki seibu tidak dapat mewarisi bersama kakek, begitu juga saudara perempuan seibu. Ali tidak memberikan bagian kakek bersama anak lebih dari seperenam kecuali jika bersama yang lainnya. Ia tidak memberi bagian untuk kakek dengan saudara laki-laki seayah bersama saudara laki-laki seayah dan seibu. Jika saudara perempuan seayah dan seibu dan saudara laki-laki seayah, ia memberikan saudara perempuan setengah dan setengah lainnya dibagikan kepada kakek dan saudara laki-laki dengan pembagian masing-masing mendapat setengah. Jika mereka beberapa saudara laki-laki dan beberapa saudara perempuan maka ia menggabungkan mereka bersama kakek dalam bagian seperenam."},"2439":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ الْعَبْسِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَعْقِلٍ قَالَ سُئِلَ ابْنُ عَبَّاسٍ عَنْ الْجَدِّ فَقَالَ أَيُّ أَبٍ لَكَ أَكْبَرُ فَقُلْتُ أَنَا آدَمُ قَالَ أَلَمْ تَسْمَعْ إِلَى قَوْلِ اللَّهِ تَعَالَى { يَا بَنِي آدَمَ }","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Al 'Absi] dari [Abdurrahman bin Ma'qil] ia berkata; [Ibnu Abbas] pernah ditanya tentang kakek, lalu ia menjawab; Ayah mana yang lebih tua menurutmu? Aku menjawab; Adam. Ia bertanya lagi; Tidakkah engkau mendengar firman Allah: (Hai bani Adam)."},"2440":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَعِيلَ بْنِ سُمَيْعٍ عَنْ رَجُلٍ عَنْ ابْنِ عَبَّاسٍ قَالَ لَوَدِدْتُ أَنِّي وَالَّذِينَ يُخَالِفُونِي فِي الْجَدِّ تَلَاعَنَّا أَيُّنَا أَسْوَأُ قَوْلًا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Isma'il bin Sumai'] dari [seseorang] dari [Ibnu Abbas] ia berkata; Aku berharap bahwa aku dan orang-orang yang menyelisiku dalam masalah kakek melakukan li'an, untuk mengetahui perkataan siapa yang paling buruk."},"2441":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ جَعَلَ الْجَدَّ أَبًا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu Thawus] dari [ayahnya] dari [Ibnu Abbas] bahwa ia menjadikan kakek pada posisi ayah dalam warisan."},"2442":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ قَالَ دَخَلْتُ عَلَى شُرَيْحٍ وَعِنْدَهُ عَامِرٌ وَإِبْرَاهِيمُ وَعَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ فِي فَرِيضَةِ امْرَأَةٍ مِنَّا الْعَالِيَةِ تَرَكَتْ زَوْجَهَا وَأُمَّهَا وَأَخَاهَا لِأَبِيهَا وَجَدَّهَا فَقَالَ لِي هَلْ مِنْ أُخْتٍ قُلْتُ لَا قَالَ هَلْ مِنْ أُخْتٍ قُلْتُ لَا قَالَ لِلْبَعْلِ الشَّطْرُ وَلِلْأُمِّ الثُّلُثُ قَالَ فَجَهِدْتُ عَلَى أَنْ يُجِيبَنِي فَلَمْ يُجِبْنِي إِلَّا بِذَلِكَ فَقَالَ إِبْرَاهِيمُ وَعَامِرٌ وَعَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ مَا جَاءَ أَحَدٌ بِفَرِيضَةٍ أَعْضَلَ مِنْ فَرِيضَةٍ جِئْتَ بِهَا قَالَ فَأَتَيْتُ عَبِيدَةَ السَّلْمَانِيَّ وَكَانَ يُقَالُ لَيْسَ بِالْكُوفَةِ أَحَدٌ أَعْلَمَ بِفَرِيضَةٍ مِنْ عَبِيدَةَ وَالْحَارِثِ الْأَعْوَرِ وَكَانَ عَبِيدَةُ يَجْلِسُ فِي الْمَسْجِدِ فَإِذَا وَرَدَتْ عَلَى شُرَيْحٍ فَرِيضَةٌ فِيهَا جَدٌّ رَفَعَهُمْ إِلَى عَبِيدَةَ فَفَرَضَ فَسَأَلْتُهُ فَقَالَ إِنْ شِئْتُمْ نَبَّأْتُكُمْ بِفَرِيضَةِ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ فِي هَذَا جَعَلَ لِلزَّوْجِ ثَلَاثَةَ أَسْهُمٍ النِّصْفَ وَلِلْأُمِّ ثُلُثُ مَا بَقِيَ السُّدُسُ مِنْ رَأْسِ الْمَالِ وَلِلْأَخِ سَهْمٌ وَلِلْجَدِّ سَهْمٌ قَالَ أَبُو إِسْحَقَ الْجَدُّ أَبُو الْأَبِ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] ia berkata; Aku pernah menemui Syuraih, saat itu sedang bersama Amir, Ibrahim dan Abdurrahman bin Abdulah untuk menanyakan masalah bagian (warisan) seorang perempuan yang meninggalkan seorang suami, ibu, saudara laki-laki seayah dan kakeknya. Maka ia bertanya kepadaku; Adakah suadara perempuan? Aku menjawab; Tidak ada. Ia Syuraih berkata; Suami mendapat setengah dan ibu mendapat sepertiga. Ia melanjutkan; Aku terus mendesaknya agar ia menjawab selain jawaban itu, namun ia tidak menjawab selain itu. Maka Ibrahim, Amir dan Abdurrahman bin Abdullah berkata; Tidak ada seorang pun yang datang membawa masalah faraidl yang lebih rumit dari pada masalah faraidl yang engkau bawa. Lalu aku menemui [Abidah As Salmani], ada yang mengatakan bahwa di Kufah tidak ada seorang pun yang lebih mengetahui tentang faraidl dari pada Abidah dan Al Harits Al A'war. Ketika itu Abidah sedang duduk di dalam masjid. Jika ada masalah faraidl yang sulit dipecahkan oleh Syuraih, ia menyuruh mereka kepada Abidah dan ia pun dapat memecahkannya. Aku bertanya kepadanya lalu ia pun menjawab; Jika kalian mau, aku dapat memberitahukan kepada kalian pembagian [Abdullah bin Mas'ud] dalam masalah ini. Ia menjadikan suami mendapat tiga bagian yakni setengah, Ibu mendapat sepertiga dari yang tersisa, yakni seperenam dari harta warisan. Saudara laki-laki mendapat satu bagian dan kakek mendapat satu bagian. Abu Ishaq berkata; Kakek adalah ayahnya ayah."},"2443":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ أَنَّ زَيْدًا كَانَ يُشَرِّكُ الْجَدَّ مَعَ الْإِخْوَةِ إِلَى الثُّلُثِ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Yunus] dari [Al Hasan] bahwa [Zaid] melakukan musyarrakah kepada kakek bersama para saudara laki-laki dalam bagian sepertiga."},"2444":{"ar":" حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ زَيْدِ بْنِ ثَابِتٍ أَنَّهُ كَانَ يُقَاسِمُ بِالْجَدِّ مَعَ الْإِخْوَةِ إِلَى الثُّلُثِ ثُمَّ لَا يُنْقِصُهُ","id":"Telah menceritakan kepada kami [Umar bin Hafsh bin Ghiyats] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari [Zaid bin Tsabit] bahwa ia memberi bagian sepertiga kepada kakek (yang ada) bersama para saudara laki-laki kemudian ia tidak pernah menguranginya."},"2445":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ الْمُغِيرَةِ عَنْ عِيسَى بْنِ يُونُسَ عَنْ إِسْمَعِيلَ قَالَ قَالَ عُمَرُ خُذْ مِنْ أَمْرِ الْجَدِّ مَا اجْتَمَعَ النَّاسُ عَلَيْهِ قَالَ أَبُو مُحَمَّد يَعْنِي قَوْلَ زَيْدٍ","id":"Telah menceritakan kepada kami [Sa'id bin Al Mughirah] dari [Isa bin Yunus] dari [Isma'il] ia berkata; [Umar] berkata; Ambillah keputusan (tentang masalah warisan) kakek yang disepakati oleh orang-orang. Abu Muhammad bierkata; Maksudnya pendapat Zaid."},"2446":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ هَمَّامٍ عَنْ قَتَادَةَ أَنَّ زَيْدَ بْنَ ثَابِتٍ قَالَ فِي أُخْتٍ وَأُمٍّ وَزَوْجٍ وَجَدٍّ قَالَ جَعَلَهَا مِنْ سَبْعٍ وَعِشْرِينَ لِلْأُمِّ سِتَّةٌ وَلِلزَّوْجِ تِسْعَةٌ وَلِلْجَدِّ ثَمَانِيَةٌ وَلِلْأُخْتِ أَرْبَعَةٌ","id":"Telah menceritakan kepada kami [Sa'id bin Amir] dari [Hammam] dari [Qatadah] bahwa [Zaid bin Tsabit] berkata dalam masalah bagian warisan seorang saudara perempuan, ibu, suami dan kakek. Ia melanjutkan; Ia menjadikan dari dua puluh tujuh (asal masalahnya dalam penghitungan dua puluh tujuh), ibu mendapat enam (bagian), suami mendapat sembilan (bagian), kakek mendapat delapan (bagian), dan seorang saudara perempuan mendapatkan empat (bagian)."},"2447":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا الْأَشْعَثُ عَنْ ابْنِ سِيرِينَ عَنْ ابْنِ مَسْعُودٍ قَالَ إِنَّ أَوَّلَ جَدَّةٍ أُطْعِمَتْ فِي الْإِسْلَامِ سَهْمًا أَمُّ أَبٍ وَابْنُهَا حَيٌّ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Al Asy'ats] dari [Ibnu Sirin] dari [Ibnu Mas'ud] ia berkata; Sesungguhnya (posisi) nenek yang diberi bagian (warisan) dalam Islam adalah ibu dari seorang ayah, sedang anak laki-lakinya masih hidup."},"2448":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَرِيكٌ عَنْ لَيْثٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَطْعَمَ جَدَّةً سُدُسًا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syarik] dari [Laits] dari [Thawus] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam memberi bagian seperenam untuk nenek."},"2449":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ إِبْرَاهِيمَ بْنِ مَيْسَرَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ أَنَّ عُمَرَ وَرَّثَ جَدَّةً مَعَ ابْنِهَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij] dari [Ibrahim bin Maisarah] dari [Sa'id bin Al Musayyab] bahwa [Umar] memberi hak waris kepada nenek ketika bersama anak laki-lakinya."},"2450":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي مَنْصُورُ بْنُ الْمُعْتَمِرِ قَالَ سَمِعْتُ إِبْرَاهِيمَ قَالَ أَطْعَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَ جَدَّاتٍ سُدُسًا قَالَ قُلْتُ لِإِبْرَاهِيمَ مَنْ هُنَّهْ قَالَ جَدَّتَاكَ مِنْ قِبَلِ أَبِيكَ وَجَدَّتُكَ مِنْ قِبَلِ أُمِّكَ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Manshur bin Al Mu'tamir] ia berkata; Aku pernah mendengar [Ibrahim] berkata; Rasulullah shallallahu 'alaihi wasallam memberi bagian seperenam untuk tiga nenek. Ia berkata; Aku bertanya kepada Ibrahim; Siapa mereka. Ia menjawab; Ia adalah dua nenek dari pihak ayahmu dan satu nenek dari pihak ibumu."},"2451":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا يَزِيدُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنِي الْحَسَنُ قَالَ تَرِثُ الْجَدَّةُ وَابْنُهَا حَيٌّ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Yazid bin Ibrahim] ia berkata; Telah memberitakan kepadaku [Al Hasan] ia berkata; Nenek berhak mendapat warisan bila anak laki-lakinya masih hidup."},"2452":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ قَالَ لَا تَرِثُ أُمُّ أَبِ الْأُمِّ ابْنُهَا الَّذِي تُدْلِي بِهِ لَا يَرِثُ فَكَيْفَ تَرِثُ هِيَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Dawud] dari [Asy Sya'bi] ia berkata; Ibu dari ayahnya ibu tidak dapat hak waris. Anaknya yang menjadikan ibu dari ayahnya ibu memiliki hubungan dengan mayit tidak dapat hak waris, bagaimana dengannya (apakah menerima warisan)? "},"2453":{"ar":"أَخْبَرَنَا أَبُو مَعْمَرٍ عَنْ إِسْمَعِيلَ ابْنِ عُلَيَّةَ عَنْ سَلَمَةَ بْنِ عَلْقَمَةَ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي الدَّهْمَاءِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَ تَرِثُ الْجَدَّةُ وَابْنُهَا حَيٌّ","id":"Telah mengabarkan kepada kami [Abu Ma'mar] dari [Isma'il bin 'Ulaiyah] dari [Salamah bin 'Alqamah] dari [Humaid bin Hilal] dari [Abu Ad Dahma`] dari [Imran bin Hushain] ia berkata; Nenek berhak mendapat warisan bila anaknya masih hidup."},"2454":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْأَشْعَثُ عَنْ الزُّهْرِيِّ قَالَ جَاءَتْ إِلَى أَبِي بَكْرٍ جَدَّةٌ أُمُّ أَبٍ أَوْ أُمُّ أُمٍّ فَقَالَتْ إِنَّ ابْنَ ابْنِي أَوْ ابْنَ ابْنَتِي تُوُفِّيَ وَبَلَغَنِي أَنَّ لِي نَصِيبًا فَمَا لِي فَقَالَ أَبُو بَكْرٍ مَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِيهَا شَيْئًا وَسَأَسْأَلُ النَّاسَ فَلَمَّا صَلَّى الظُّهْرَ قَالَ أَيُّكُمْ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْجَدَّةِ شَيْئًا فَقَالَ الْمُغِيرَةُ بْنُ شُعْبَةَ أَنَا قَالَ مَاذَا قَالَ أَعْطَاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُدُسًا قَالَ أَيَعْلَمُ ذَاكَ أَحَدٌ غَيْرُكَ فَقَالَ مُحَمَّدُ بْنُ مَسْلَمَةَ صَدَقَ فَأَعْطَاهَا أَبُو بَكْرٍ السُّدُسَ فَجَاءَتْ إِلَى عُمَرَ مِثْلُهَا فَقَالَ مَا أَدْرِي مَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا شَيْئًا وَسَأَسْأَلُ النَّاسَ فَحَدَّثُوهُ بِحَدِيثِ الْمُغِيرَةِ بْنِ شُعْبَةَ وَمُحَمَّدِ بْنِ مَسْلَمَةَ فَقَالَ عُمَرُ أَيُّكُمَا خَلَتْ بِهِ فَلَهَا السُّدُسُ فَإِنْ اجْتَمَعْتُمَا فَهُوَ بَيْنَكُمَا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Al Asy'ats] dari [Az Zuhri] ia berkata; Seorang nenek dari ibunya ayah atau ibunya ibu datang menemui Abu Bakr dan berkata; Sesungguhnya anak laki-laki dari anak laki-lakiku atau anak laki-laki dari anak perempuanku telah meninggal dan telah sampai kepadaku bahwa aku mendapatkan bagian harta warisannya, maka berapakah bagianku? Abu Bakr berkata; Aku belum pernah mendengar Rasulullah shallallahu 'alaihi wasallam memberikan kepada seorang nenek sedikitpun, aku akan bertanya kepada orang lain! Setelah dia selesai melaksanakan shalat dzuhur, dia bertanya: siapakah di antara kalian yang mendengar Rasulullah shallallahu 'alaihi wasallam telah memberikan seorang nenek dari bagian harta warisan? [Maka Al Mughirah bin Syu'bah] berkata: Saya! Dia berkata: Berapa? Al Mughirah menjawab: Rasulullah shallallahu 'alaihi wasallam memberikannya seperenam. Dia bertanya lagi: adakah orang lain selain kamu yang mengetahuinya? Maka [Muhammad bin Maslamah] berkata: Iya, dia benar! Maka Abu Bakar memberikan nenek tersebut seperenam. Kemudian datang kepada Umar seperti yang datang kepada Abu Bakar, lalu Umar berkata: aku tidak mengetahui dan tidak pernah mendengar bahwa Rasulullah shallallahu 'alaihi wasallam memberikan seorang nenek-nenek dari harta warisan, tapi aku akan bertanya kepada orang-orang! Maka mereka memberitahukan kepadanya tentang hadits Al Mughirah bin Syu'bah dan Muhammad bin Maslamah. Maka Umar berkata: siapa yang di antara kalian berdua yang (keberadaannya) sendiri ketika pembagian warisan, maka seperenam itu untuknya, dan apabila berdua maka seperenam untuk kalian berdua."},"2455":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا الْأَشْعَثُ عَنْ الشَّعْبِيِّ عَنْ عَلِيٍّ وَزَيْدٍ قَالَا إِذَا كَانَتْ الْجَدَّاتُ سَوَاءً وَرِثَ ثَلَاثُ جَدَّاتٍ جَدَّتَا أَبِيهِ أُمُّ أُمِّهِ وَأُمُّ أَبِيهِ وَجَدَّةُ أُمِّهِ فَإِنْ كَانَتْ إِحَدَاهُنَّ أَقْرَبَ فَالسَّهْمُ لِذَوِي الْقُرْبَى","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Asy'ats] dari [Asy Sya'bi] dari [Ali] dan [Zaid] keduanya berkata; Jika beberapa nenek memiliki kedudukan yang sama maka tiga orang nenek mendapat hak waris. Yaitu dua dari nenek ayah; Ibu dari ibunya ayah dan ibu dari ayahnya ayah dan nenek ibunya. Jika salah seorang dari mereka itu lebih dekat, maka bagian diberikan kepada yang terdekat."},"2456":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَسَنٌ عَنْ أَشْعَثَ عَنْ الشَّعْبِيِّ عَنْ عَلِيٍّ وَزَيْدٍ أَنَّهُمَا كَانَا لَا يُوَرِّثَانِ الْجَدَّةَ أُمَّ الْأَبِ مَعَ الْأَبِ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hasan] dari [Asy'ats] dari [Asy Sya'bi] dari [Ali] dan [Zaid] bahwa mereka berdua tidak memberikan hak waris kepada nenek, yakni ibu dari ayah, ketika bersama ayah."},"2457":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ الْمُغِيرَةِ عَنْ ابْنِ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ أَنَّ عُثْمَانَ كَانَ لَا يُوَرِّثُ الْجَدَّةَ وَابْنُهَا حَيٌّ","id":"Telah menceritakan kepada kami [Sa'id bin Al Mughirah] dari [Ibnu Al Mubarak] dari [Ma'mar] dari [Az Zuhri] bahwa [Utsman] tidak memberi hak waris kepada nenek jika anaknya masih hidup."},"2458":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْأَشْعَثُ عَنْ ابْنِ سِيرِينَ عَنْ ابْنِ مَسْعُودٍ قَالَ إِنَّ الْجَدَّاتِ لَيْسَ لَهُنَّ مِيرَاثٌ إِنَّمَا هِيَ طُعْمَةٌ أُطْعِمْنَهَا وَالْجَدَّاتُ أَقْرَبُهُنَّ وَأَبْعَدُهُنَّ سَوَاءٌ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Asy'ats] dari [Ibnu Sirin] dari [Ibnu Mas'ud] ia berkata; Sesungguhnya para nenek tidak memiliki hak waris, namun hanya ibarat makanan yang diberikan kepada mereka. Para nenek yang dekat dan yang jauh adalah sama."},"2459":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ الْمُغِيرَةِ عَنْ إِبْرَاهِيمَ قَالَ قَالَ عَبْدُ اللَّهِ تَرِثُ الْجَدَّةُ وَابْنُهَا حَيٌّ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah mengabarkan kepada kami [Abu 'Awanah] dari [Al Mughirah] dari [Ibrahim] ia berkata; [Abdullah] berkata; Nenek mendapat warisan jika anaknya masih hidup."},"2460":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْأَشْعَثُ عَنْ الشَّعْبِيِّ قَالَ جِئْنَ أَرْبَعُ جَدَّاتٍ يَتَسَاوَقْنَ إِلَى مَسْرُوقٍ فَأَلْقَى أَمَّ أَبِ الْأَبِ وَوَرَّثَ ثَلَاثًا جَدَّتَيْ أَبِيهِ أُمَّ أُمِّهِ وَأُمَّ أَبِيهِ وَجَدَّةَ أُمِّهِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Asy'ats] dari [Asy Sya'bi] ia berkata; Empat orang nenek berjalan sambil berdesak-desakan mendatangi [Masruq]. Maka ia (memutuskan) tidak memberikan hak waris kepada satu nenek (ibu dari ayahnya ayah), namun ia memberi hak waris kepada tiga nenek (yang lain); Dua nenek dari ayahnya, yaitu ibu dari ibunya dan ibu dari ayahnya, dan nenek dari ibunya."},"2461":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شَرِيكٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ اللَّهِ فِي ابْنَةٍ وَابْنَةِ ابْنٍ قَالَ النِّصْفُ وَالسُّدُسُ وَمَا بَقِيَ فَرَدٌّ عَلَى الْبِنْتِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Syarik] dari [Al A'masy] dari [Ibrahim] dari [Abdullah] tentang anak perempuan dan anak perempuan dari anak perempuan (cucu). Ia berkata; Setengah dan seperenam, sedangkan yang tersisa dikembalikan kepada anak perempuan."},"2462":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ أَنَّهُ أُتِيَ فِي إِخْوَةٍ لِأُمٍّ وَأُمٍّ فَأَعْطَى الْإِخْوَةَ مِنْ الْأُمِّ الثُّلُثَ وَالْأُمَّ سَائِرَ الْمَالِ وَقَالَ الْأُمُّ عَصَبَةُ مَنْ لَا عَصَبَةَ لَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] bahwa ia pernah ditanya tentang saudara laki-laki seibu dan ibu. Maka ia memberikan bagian saudara laki-laki seibu sepertiga dan ibu mendapat (sisa) seluruh harta warisan. Ia berkata lagi; Ibu adalah ashabah orang yang tidak memiliki ashabah."},"2463":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَسَنٌ عَنْ أَبِيهِ قَالَ سَأَلْتُ الشَّعْبِيَّ عَنْ رَجُلٍ مَاتَ وَتَرَكَ ابْنَتَهُ لَا يُعْلَمُ لَهُ وَارِثٌ غَيْرُهَا قَالَ لَهَا الْمَالُ كُلُّهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hasan] dari [ayahnya] ia berkata; Aku bertanya kepada [Asy Sya'bi] tentang seorang laki-laki yang meninggal dunia dan meninggalkan anak perempuan. Tidak diketahui ada ahli waris lain selain anak perempuan tersebut. Asy Sya'bi berkata; Seluruh harta tersebut untuknya."},"2464":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ سَالِمٍ عَنْ الشَّعْبِيِّ أَنَّ ابْنَ مَسْعُودٍ كَانَ لَا يَرُدُّ عَلَى أَخٍ لِأُمٍّ مَعَ أُمٍّ وَلَا عَلَى جَدَّةٍ إِذَا كَانَ مَعَهَا غَيْرُهَا مَنْ لَهُ فَرِيضَةٌ وَلَا عَلَى ابْنَةِ ابْنٍ مَعَ ابْنَةِ الصُّلْبِ وَلَا عَلَى امْرَأَةٍ وَزَوْجٍ وَكَانَ عَلِيٌّ يَرُدُّ عَلَى كُلِّ ذِي سَهْمٍ إِلَّا الْمَرْأَةَ وَالزَّوْجَ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Salim] dari [Asy Sya'bi] bahwa [Ibnu Mas'ud] tidak mengembalikan sisa harta warisan kepada saudara laki-laki seibu yang ada bersama-sama dengan ibu, tidak mengembalikannya kepada nenek jika bersama ahli waris lain yang memiliki bagian yang sudah ditetapkan, tidak membagikan kepada anak perempuan dari anak laki-laki jika bersama anak perempuan kandung dan tidak membagikan kepada isteri dan suami. Sedangkan [Ali] mengembalikan harta (sisa harta yang telah dibagikan) kepada seluruh orang yang memiliki bagian kecuali isteri dan suami."},"2465":{"ar":" أَخْبَرَنَا مُحَمَّدٌ حَدَّثَنَا سُفْيَانُ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ سَالِمٍ عَنْ خَارِجَةَ بْنِ زَيْدٍ عَنْ زَيْدِ بْنِ ثَابِتٍ أَنَّهُ أُتِيَ فِي ابْنَةٍ أَوْ أُخْتٍ فَأَعْطَاهَا النِّصْفَ وَجَعَلَ مَا بَقِيَ فِي بَيْتِ الْمَالِ و قَالَ يَزِيدُ بْنُ هَارُونَ عَنْ مُحَمَّدِ بْنِ سَالِمٍ عَنْ الشَّعْبِيِّ عَنْ خَارِجَةَ","id":"Telah mengabarkan kepada kami [Muhammad] telah menceritakan kepada kami [Sufyan] ia berkata; telah mengabarkan kepadaku [Muhammad bin Salim] dari [Kharijah bin Zaid] dari [Zaid bin Tsabit] bahwa ia pernah ditanya tentang anak perempuan atau saudara perempuan. Maka ia memberikan setengah kepadanya dan memasukkan warisan yang tersisa ke dalam Baitul Mal. [Yazid bin Harun] berkata; Dari [Muhammad bin Salim] dari [Asy Sya'bi] dari [Kharijah]."},"2466":{"ar":" أَخْبَرَنَا مُعَاذُ بْنُ هَانِئٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ طَهْمَانَ قَالَ سَمِعْتُ رَجُلًا سَأَلَ عَطَاءَ بْنَ أَبِي رَبَاحٍ عَنْ وَلَدِ الْمُتَلَاعِنَيْنِ لِمَنْ مِيرَاثُهُ قَالَ لِأُمِّهِ وَأَهْلِهَا","id":"Telah mengabarkan kepada kami [Mu'adz bin Hani] telah menceritakan kepada kami [Ibrahim bin Thahman] ia berkata; Aku mendengar [seseorang] bertanya kepada ['Atha` bin Abu Rabah] tentang anak dari suami isteri yang melakukan li'an untuk siapa warisannya? Ia menjawab; Untuk ibunya dan keluarga ibu."},"2467":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَسَنٌ عَنْ أَبِي سَهْلٍ عَنْ الشَّعْبِيِّ قَالَ قَالَ عَلِيٌّ فِي ابْنِ الْمُلَاعَنَةِ تَرَكَ أَخَاهُ لِأُمِّهِ وَأُمَّهُ لِأَخِيهِ السُّدُسُ وَلِأُمِّهِ الثُّلُثُ ثُمَّ يُرَدُّ عَلَيْهِمْ فَيَصِيرُ لِلْأَخِ الثُّلُثُ وَلِلْأُمِّ الثُّلُثَانِ و قَالَ ابْنُ مَسْعُودٍ لِأَخِيهِ السُّدُسُ وَمَا بَقِيَ فَلِلْأُمِّ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hasan] dari [Abu Sahl] dari [Asy Sya'bi] ia berkata; [Ali] berkata tentang anak dari seorang wanita yang terkena li'an, ia meninggalkan saudara laki-laki seibu dan ibu. Saudara laki-laki mendapat seperenam dan ibu mendapat sepertiga. Kemudian sisa harta warisan dibagikan lagi kepada mereka berdua (saudara laki-laki seibu dan ibu), maka saudara lai-laki mendapat sepertiga dan ibu mendapat dua pertiga (dari sisa harta warisan yang dibagikan kembali). Dalam riwayat lain [Ibnu Mas'ud] berkata; Saudara laki-laki mendapat seperenam dan warisan yang tersisa untuk ibu."},"2468":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا سَالِمُ بْنُ نُوحٍ عَنْ عُمَرَ بْنِ عَامِرٍ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ زَيْدِ بْنِ ثَابِتٍ فِي مِيرَاثِ ابْنِ الْمُلَاعَنَةِ لِأُمِّهِ الثُّلُثُ وَالثُّلُثَانِ لِبَيْتِ الْمَالِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Salim bin Nuh] dari [Umar bin Amir] dari [Qatadah] dari [Sa'id bin Al Musayyab] dari [Zaid bin Tsabit] tentang warisan anak laki-laki dari seorang wanita yang terkena li'an; Untuk ibu sepertiga dan dua pertiga untuk Baitul Mal."},"2469":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا سَالِمُ بْنُ نُوحٍ عَنْ عُمَرَ بْنِ عَامِرٍ عَنْ حَمَّادٍ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ اللَّهِ قَالَ مِيرَاثُهُ لِأُمِّهِ تَعْقِلُ عَنْهُ عَصَبَةُ أُمِّهِ و قَالَ قَتَادَةُ عَنْ الْحَسَنِ لِأُمِّهِ الثُّلُثُ وَبَقِيَّةُ الْمَالِ لِعَصَبَةِ أُمِّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Salim bin Nuh] dari [Umar bin Amir] dari [Hammad] dari [Ibrahim] dari [Abdullah] ia berkata; Warisannya diberikan untuk ibu, sebab yang membayar diyat adalah ashabah ibunya. Dalam riwayat lain [Qatadah] berkata; dari [Al Hasan]; Untuk ibunya sepertiga dan sisa harta untuk ashabah ibu."},"2470":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا قَتَادَةُ أَنَّ عَلِيًّا وَابْنَ مَسْعُودٍ قَالَا فِي وَلَدِ مُلَاعَنَةٍ تَرَكَ جَدَّتَهُ وَإِخْوَتَهُ لِأُمِّهِ قَالَ لِلْجَدَّةِ الثُّلُثُ وَلِلْإِخْوَةِ الثُّلُثَانِ و قَالَ زَيْدُ بْنُ ثَابِتٍ لِلْجَدَّةِ السُّدُسُ وَلِلْإِخْوَةِ لِلْأُمِّ الثُّلُثُ وَمَا بَقِيَ فَلِبَيْتِ الْمَالِ","id":"Telah mengabarkan kepada kami [Hajjaj bin Al Minhal] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Qatadah] bahwa [Ali] dan [Ibnu Mas'ud] keduanya berkata tentang anak dari seorang wanita yang terkena li'an, ia meninggalkan nenek dan beberapa saudara laki-laki seibu; Ia berkata; Untuk nenek sepertiga dan untuk para saudara laki-laki seibu dua pertiga. Dalam riwayat lain [Zaid bin Tsabit] berkata; Nenek mendapatkan seperenam, para saudara laki-laki seibu mendapat sepertiga dan harta warisan yang tersisa untuk Baitul Mal."},"2471":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا حَجَّاجٌ أَنَّ النَّخَعِيَّ وَالشَّعْبِيَّ قَالَا تَرِثُهُ أُمُّهُ","id":"Telah mengabarkan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad] telah menceritakan kepada kami [Hajjaj] bahwa [An Nakha'i] dan [Asy Sya'bi] keduanya berkata; Ibunya berhak mendapat warisannya."},"2472":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ قَالَ كَتَبْتُ إِلَى أَخٍ لِي مِنْ بَنِي زُرَيْقٍ أَسْأَلُهُ لِمَنْ قَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ابْنِ الْمُلَاعَنَةِ فَكَتَبَ إِلَيَّ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِهِ لِأُمِّهِ هِيَ بِمَنْزِلَةِ أُمِّهِ وَأَبِيهِ و قَالَ سُفْيَانُ الْمَالُ كُلُّهُ لِلْأُمِّ هِيَ بِمَنْزِلَةِ أَبِيهِ وَأُمِّهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Daud bin Abu Hind] dari [Abdullah bin Ubaid bin Umair] ia berkata; Aku pernah menulis surat kepada [saudara laki-lakiku] dari banu Zuraiq untuk menanyakan keputusan Nabi shallallahu 'alaihi wasallam dalam masalah anak seorang wanita yang terkena li'an, untuk siapa harta itu? (Maka ia membalas suratku); Sesungguhnya Rasulullah shallallahu 'alaihi wasallam memutuskan warisannya diberikan kepada ibunya, ibu itu menempati posisi ibu dan ayahnya. Sufyan berkata; Seluruh harta untuk ibu karena ia menempati posisi ayah dan ibunya."},"2473":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ ابْنِ أَبِي لَيْلَى عَنْ عَامِرٍ عَنْ عَلِيٍّ وَعَبْدِ اللَّهِ فِي ابْنِ الْمُلَاعَنَةِ قَالَا عَصَبَتُهُ عَصَبَةُ أُمِّهِ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Ibnu Abu Laila] dari [Amir] dari [Ali] dan [Abdullah] tentang anak seorang wanita yang terkena li'an, keduanya berkata; Ashabahnya adalah ashabah ibunya."},"2474":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ الْحَلَبِيُّ مُوسَى بْنُ خَالِدٍ حَدَّثَنَا مُعْتَمِرٌ عَنْ يُونُسَ عَنْ الْحَسَنِ أَنَّهُ كَانَ يَقُولُ مِيرَاثُ وَلَدِ الْمُلَاعَنَةِ لِأُمِّهِ قُلْتُ فَإِنْ كَانَ لَهُ أَخٌ مِنْ أُمِّهِ قَالَ لَهُ السُّدُسُ","id":"Telah menceritakan kepada kami [Abu Al Walid Al Halabi Musa bin Khalid] telah menceritakan kepada kami [Mu'tamir] dari [Yunus] dari [Al Hasan] bahwa ia berkata; Warisan anak seorang wanita yang terkena li'an untuk ibunya. Aku bertanya; Jika ia memiliki saudara laki-laki dari ibunya? Ia menjawab; Ia (saudara laki-laki) mendapat seperenam."},"2475":{"ar":" حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا الزُّهْرِيُّ قَالَ وَلَدُ الْمُلَاعَنَةِ لِأُمِّهِ تَرِثُ فَرِيضَتَهَا مِنْهُ وَسَائِرُ ذَلِكَ فِي بَيْتِ الْمَالِ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepada kami [Az Zuhri] ia berkata; Harta warisan anak seorang wanita yang melakukan li'an berhak diwarisi ibunya. Ibunya memperoleh warisan sesuai dengan bagian yang telah ditetapkan untuknya, sedangkan sisanya dimasukkan ke dalam Baitul Mal."},"2476":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ عَبْدِ الْأَعْلَى أَنَّهُ سَمِعَ مُحَمَّدَ بْنَ عَلِيٍّ يُحَدِّثُ عَنْ عَلِيٍّ فِي الرَّجُلِ يَكُونُ لَهُ مَا لِلرَّجُلِ وَمَا لِلْمَرْأَةِ مِنْ أَيِّهِمَا يُوَرَّثُ فَقَالَ مِنْ أَيِّهِمَا بَالَ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Isra`il] dari [Abdul A'la] bahwa ia mendengar [Muhammad bin Ali] menceritakan dari [Ali] tentang seorang laki-laki yang memiliki alat kelamin laki-laki dan alat kelamin perempuan, sebagai apa statusnya ia mewarisi (laki-laki atau perempuan)? Ia menjawab; Dilihat dari alat kelaminnya yang mengeluarkan kencing (dari situlah ditetapkan statusnya)."},"2477":{"ar":" حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هُشَيْمٌ عَنْ مُغِيرَةَ عَنْ شِبَاكٍ عَنْ الشَّعْبِيِّ عَنْ عَلِيٍّ فِي الْخُنْثَى قَالَ يُوَرَّثُ مِنْ قِبَلِ مَبَالِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Husyaim] dari [Mughirah] dari [Syibak] dari [Asy Sya'bi] dari [Ali] tentang khuntsa, ia berkata; Ia diberi warisan berdasarkan tempat keluarnya air kencing. "},"2478":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا أَبُو هَانِئٍ قَالَ سُئِلَ عَامِرٌ عَنْ مَوْلُودٍ وُلِدَ وَلَيْسَ بِذَكَرٍ وَلَا أُنْثَى لَيْسَ لَهُ مَا لِلذَّكَرِ وَلَيْسَ لَهُ مَا لِلْأُنْثَى يُخْرِجُ مِنْ سُرَّتِهِ كَهَيْئَةِ الْبَوْلِ وَالْغَائِطِ سُئِلَ عَنْ مِيرَاثِهِ فَقَالَ نِصْفُ حَظِّ الذَّكَرِ وَنِصْفُ حَظِّ الْأُنْثَى","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Abu Hani`] ia berkata; [Amir] pernah ditanya tentang warisan seorang anak yang melahirkan tanpa alat kelamin laki-laki dan alat kelamin perempuan, sementara dari pusarnya keluar sesuatu seperti air kencing dan kotoran. Maka ia menjawab; (Bagian warisannya adalah) setengah dari bagian laki-laki dan setengah dari bagian perempuan."},"2479":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا عَاصِمٌ عَنْ الشَّعْبِيِّ قَالَ سُئِلَ أَبُو بَكْرٍ عَنْ الْكَلَالَةِ فَقَالَ إِنِّي سَأَقُولُ فِيهَا بِرَأْيِي فَإِنْ كَانَ صَوَابًا فَمِنْ اللَّهِ وَإِنْ كَانَ خَطَأً فَمِنِّي وَمِنْ الشَّيْطَانِ أُرَاهُ مَا خَلَا الْوَالِدَ وَالْوَلَدَ فَلَمَّا اسْتُخْلِفَ عُمَرُ قَالَ إِنِّي لَأَسْتَحْيِي اللَّهَ أَنْ أَرُدَّ شَيْئًا قَالَهُ أَبُو بَكْرٍ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami ['Ashim] dari [Asy Sya'bi] ia berkata; [Abu Bakr] pernah ditanya tentang Al Kalalah. Maka ia menjawab; Sesungguhnya aku akan menjawab tentangnya berdasarkan pendapatku. Jika benar maka itu dari Allah dan jika salah maka itu dariku dan setan. Menurutku Al Kalalah adalah orang yang tidak memiliki ayah dan anak. Ketika [Umar] menjadi khalifah, ia berkata; Sesungguhnya aku malu kepada Allah jika aku menolak sesuatu yang telah dikatakan Abu Bakr. "},"2480":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا سَعِيدٌ هُوَ ابْنُ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ مَرْثَدِ بْنِ عَبْدِ اللَّهِ الْيَزَنِيِّ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ أَنَّهُ قَالَ مَا أَعْضَلَ بِأَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْءٌ مَا أَعْضَلَتْ بِهِمْ الْكَلَالَةُ","id":"Telah menceritakan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Sa'id] ia adalah Ibnu Abu Ayyub, ia berkata; Telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Martsad bin Abdullah Al Yazani] dari [Uqbah bin Amir Al Juhani] bahwa ia berkata; Tidak ada suatu pun yang menyulitkan bagi para sahabat Rasulullah shallallahu 'alaihi wasallam seperti kesulitan mereka dalam masalah Al Kalalah."},"2481":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ الْحَسَنِ بْنِ مُحَمَّدٍ عَنْ ابْنِ عَبَّاسٍ قَالَ الْكَلَالَةُ مَا خَلَا الْوَالِدَ وَالْوَلَدَ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Amr bin Dinar] dari [Al Hasan bin Muhammad] dari [Ibnu Abbas] ia berkata; Al Kalalah adalah orang yang tidak memiliki ayah dan anak."},"2482":{"ar":" أَخْبَرَنَا مُحَمَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ الْقَاسِمِ بْنِ عَبْدِ اللَّهِ عَنْ سَعْدٍ أَنَّهُ كَانَ يَقْرَأُ هَذِهِ الْآيَةَ { وَإِنْ كَانَ رَجُلٌ يُورَثُ كَلَالَةً أَوْ امْرَأَةٌ وَلَهُ أَخٌ أَوْ أُخْتٌ } لِأُمٍّ","id":"Telah mengabarkan kepada kami [Muhammad] telah menceritakan kepada kami [Sufyan] dari [Ya'la bin 'Atha`] dari [Al Qasim bin Abdullah] dari [Sa'd] bahwa ia membaca ayat ini: (Jika seseorang mati, baik laki-laki maupun perempuan yang tidak meninggalkan ayah dan tidak meninggalkan anak, tetapi mempunyai seorang saudara laki-laki atau seorang saudara perempuan), yakni seibu."},"2483":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا حَيْوَةُ حَدَّثَنَا أَبُو الْأَسْوَدِ مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ أَنَّ عَاصِمَ بْنَ عُمَرَ بْنِ قَتَادَةَ الْأَنْصَارِيَّ أَخْبَرَهُ أَنَّ عُمَرَ بْنَ الْخَطَّابِ الْتَمَسَ مَنْ يَرِثُ ابْنَ الدَّحْدَاحَةِ فَلَمْ يَجِدْ وَارِثًا فَدَفَعَ مَالَ ابْنِ الدَّحْدَاحَةِ إِلَى أَخْوَالِ ابْنِ الدَّحْدَاحَةِ","id":"Telah mengabarkan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Haiwah] telah menceritakan kepada kami [Abu Al Aswad Muhammad bin Abdurrahman bin Naufal] bahwa ['Ashim bin Umar bin Qatadah Al Anshari] mengabarkan kepadanya bahwa [Umar bin Al Khaththab] mencari orang yang berhak mewarisi Ibnu Ad Dahdahah, namun ia tidak menemukan satu pun ahli waris. Maka ia menyerahkan harta Ibnu Ad Dahdahah kepada para paman Ibnu Ad Dahdahah dari pihak ibu."},"2484":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَمْرِو بْنِ مُسْلِمٍ عَنْ طَاوُسٍ عَنْ عَائِشَةَ قَالَتْ اللَّهُ وَرَسُولُهُ مَوْلَى مَنْ لَا مَوْلَى لَهُ وَالْخَالُ وَارِثُ مَنْ لَا وَارِثَ لَهُ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Amru bin Muslim] dari [Thawus] dari [A`isyah] ia berkata; Allah dan RasulNya adalah wali bagi orang yang tidak memiliki wali dan paman dari pihak ibu adalah ahli waris bagi orang yang tidak memiliki ahli waris."},"2485":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ فِرَاسٍ عَنْ الشَّعْبِيِّ عَنْ زِيَادٍ قَالَ أُتِيَ عُمَرُ فِي عَمٍّ لِأُمٍّ وَخَالَةٍ فَأَعْطَى الْعَمَّ لِلْأُمِّ الثُّلُثَيْنِ وَأَعْطَى الْخَالَةَ الثُّلُثَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Firas] dari [Asy Sya'bi] dari [Ziyad] ia berkata; [Umar] pernah ditanya tentang paman seibu dari pihak ayah dan bibi dari pihak ibu. Maka ia memberikan paman seibu dari pihak ayah dua pertiga dan memberikan bibi dari pihak ibu sepertiga dari harta warisan."},"2486":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ يُونُسَ عَنْ الْحَسَنِ أَنَّ عُمَرَ بْنَ الْخَطَّابِ أَعْطَى الْخَالَةَ الثُّلُثَ وَالْعَمَّةَ الثُّلُثَيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Yunus] dari [Al Hasan] bahwa [Umar bin Al Khaththab] memberikan bibi dari pihak ibu sepertiga dan bibi dari pihak ayah dua pertiga dari harta warisan."},"2487":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الْحَسَنِ بْنِ عَمْرٍو عَنْ غَالِبِ بْنِ عَبَّادٍ عَنْ قَيْسِ بْنِ حَبْتَرٍ النَّهْشَلِيِّ قَالَ أُتِيَ عَبْدُ الْمَلِكِ بْنُ مَرْوَانَ فِي خَالَةٍ وَعَمَّةٍ فَقَامَ شَيْخٌ فَقَالَ شَهِدْتُ عُمَرَ بْنَ الْخَطَّابِ أَعْطَى الْخَالَةَ الثُّلُثَ وَالْعَمَّةَ الثُّلُثَيْنِ قَالَ فَهَمَّ أَنْ يَكْتُبَ بِهِ ثُمَّ قَالَ أَيْنَ زَيْدٌ عَنْ هَذَا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Al Hasan bin Amr] dari [Ghalib bin 'Abbad] dari [Qais bin Habtar An Nahsyali] ia berkata; Abdul Malik bin Marwan pernah ditanya tentang bibi dari pihak ibu dan bibi dari pihak ayah. Maka ada seseorang [syaikh] berdiri seraya berkata; Aku menyaksikan [Umar bin Al Khaththab] memberikan bagian kepada bibi dari pihak ibu sepertiga dan bibi dari pihak ayah dua pertiga. Ia berkata lagi; Ia berniat menulis keputusannya ini, namun ia berkata; Bagaimana pendapat Zaid tentang hal ini? "},"2488":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ سَالِمٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَ الْخَالَةُ بِمَنْزِلَةِ الْأُمِّ وَالْعَمَّةُ بِمَنْزِلَةِ الْأَبِ وَبِنْتُ الْأَخِ بِمَنْزِلَةِ الْأَخِ وَكُلُّ رَحِمٍ بِمَنْزِلَةِ رَحِمِهِ الَّتِي يُدْلِي بِهَا إِذَا لَمْ يَكُنْ وَارِثٌ ذُو قَرَابَةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Salim] dari [Asy Sya'bi] dari [Masruq] dari [Abdullah] ia berkata; Kedudukan bibi dari pihak ibu sama dengan kedudukan ibu, bibi dari pihak ayah sama dengan ayah, anak perempuan dari saudara laki-laki sama dengan saudara laki-laki dan seluruh dzawul arham sama dengan dzawul arham lainnya yang ditentukan olehnya, mereka memiliki hubungan dengan mayit jika tidak ada ahli waris yang memiliki hubungan kerabat dekat. "},"2489":{"ar":"أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هِشَامٌ عَنْ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ عُتْبَةَ قَالَ حَدَّثَنِي الضَّحَّاكُ بْنُ قَيْسٍ أَنَّ عُمَرَ قَضَى فِي أَهْلِ طَاعُونِ عَمَوَاسَ أَنَّهُمْ كَانُوا إِذَا كَانُوا مِنْ قِبَلِ الْأَبِ سَوَاءً فَبَنُو الْأُمِّ أَحَقُّ وَإِذَا كَانَ بَعْضُهُمْ أَقْرَبَ مِنْ بَعْضٍ بِأَبٍ فَهُمْ أَحَقُّ بِالْمَالِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hisyam] dari [Muhammad] dari [Abdullah bin Utbah] ia berkata; telah menceritakan kepadaku [Adl Dlahhak bin Qais] bahwa [Umar] telah memutuskan para orang-orang yang terkena tha'un (lepra) Amawas. Jika mereka yang berasal dari pihak ayah kedudukannya sama, maka para anak laki-laki dari ibu lebih berhak. Jika sebagian mereka lebih dekat dari sebagian yang lain kepada ayah maka mereka lebih berhak mendapat harta warisan."},"2490":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو شِهَابٍ حَدَّثَنِي أَبُو إِسْحَقَ الشَّيْبَانِيُّ عَنْ عُبَيْدِ بْنِ أَبِي الْجَعْدِ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادِ بْنِ الْهَادِ قَالَ أُصِيبَ سَالِمٌ مَوْلَى أَبِي حُذَيْفَةَ يَوْمَ الْيَمَامَةِ فَبَلَغَ مِيرَاثُهُ مِائَتَيْ دِرْهَمٍ فَقَالَ عُمَرُ احْبِسُوهَا عَلَى أُمِّهِ حَتَّى تَأْتِيَ عَلَى آخِرِهَا","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Syihab] telah menceritakan kepadaku [Abu Ishaq Asy Syaibani] dari [Ubaid bin Abu Al Ja'd] dari [Abdullah bin Syaddad bin Al Had] ia berkata; Salim mantan budak Abu Hudzaifah meninggal (terbunuh) dalam perang Yamamah. Harta warisan yang ditinggalkan berjumlah dua ratus dirham. Maka [Umar] berkata; Simpan harta itu untuk ibunya, hingga akhirnya ia (ibu) datang."},"2491":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْإِخْوَةُ مِنْ الْأُمِّ يَتَوَارَثُونَ دُونَ بَنِي الْعَلَّاتِ يَرِثُ الرَّجُلُ أَخَاهُ لِأَبِيهِ وَأُمِّهِ دُونَ أَخِيهِ لِأَبِيهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari [Al Harits] dari [Ali] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Para saudara laki-laki seibu dapat saling mewarisi, tidak bagi saudara laki-laki seayah. Seseorang dapat mewarisi saudara laki-laki seayah dan seibu kecuali saudara laki-laki seayah.\""},"2492":{"ar":" حَدَّثَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ عَنْ النُّعْمَانِ بْنِ سَالِمٍ قَالَ قُلْتُ لِابْنِ عُمَرَ أَرَأَيْتَ رَجُلًا تَرَكَ ابْنَ ابْنَتِهِ أَيَرِثُهُ قَالَ لَا","id":"Telah menceritakan kepada kami [Sahal bin Hammad] telah menceritakan kepada kami [Syu'bah] dari [An Nu'man bin Salim] ia berkata; Aku pernah bertanya kepada [Ibnu Umar]; Apa pendapatmu tentang seseorang yang meninggal dunia dan meninggalkan seorang anak laki-laki dari anak perempuan, apakah ia mendapat warisan? Ia menjawab; Tidak."},"2493":{"ar":" حَدَّثَنَا يَعْلَى حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ قَالَ قَالَ عَبْدُ اللَّهِ الْأُمُّ عَصَبَةُ مَنْ لَا عَصَبَةَ لَهُ وَالْأُخْتُ عَصَبَةُ مَنْ لَا عَصَبَةَ لَهُ","id":"Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] ia berkata; [Abdullah] pernah berkata; Ibu adalah ashabah bagi orang yang tidak memiliki ashabah. Saudara perempuan juga ashabah bagi orang yang tidak memiliki ashabah."},"2494":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلْحِقُوا الْفَرَائِضَ بِأَهْلِهَا فَمَا بَقِيَ فَهُوَ لِأَوْلَى رَجُلٍ ذَكَرٍ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu Thawus] dari [ayahnya] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Berikan bagian yang sudah ditetapkan kepada orang yang berhak mendapatkannya. Sedangkan harta yang tersisa dibagikan kepada pihak laki-laki yang paling dekat dengan mayit.\""},"2495":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا يَحْيَى أَنَّ سُلَيْمَانَ بْنَ يَسَارٍ أَخْبَرَهُ عَنْ مُحَمَّدِ بْنِ الْأَشْعَثِ أَنَّ عَمَّةً لَهُ تُوُفِّيَتْ يَهُودِيَّةً بِالْيَمَنِ فَذَكَرَ ذَلِكَ لِعُمَرَ بْنِ الْخَطَّابِ فَقَالَ يَرِثُهَا أَقْرَبُ النَّاسِ إِلَيْهَا مِنْ أَهْلِ دِينِهَا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Yahya] bahwa [Sulaiman bin Yasar] mengabarkan kepadanya dari [Muhammad bin Al Asy'ats] bahwa seorang bibinya meninggal dunia di Yaman dalam keadaan (beragama) yahudi. Lalu ia menceritakan hal itu kepada [Umar bin Al Khaththab], maka ia berkata; Orang yang terdekat dan seagama dengannya adalah yang berhak mewarisinya."},"2496":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ حَمَّادٍ عَنْ إِبْرَاهِيمَ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِ أَهْلُ الشِّرْكِ لَا نَرِثُهُمْ وَلَا يَرِثُونَا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Hammad] dari [Ibrahim] ia berkata; [Umar bin Al Khaththab] pernah berkata; Kita tidak berhak mewarisi warisan orang musyrik dan mereka tidak berhak mewarisi kita."},"2497":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَسَنٌ عَنْ عِيسَى الْحَنَّاطِ عَنْ الشَّعْبِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ قَالُوا لَا يَتَوَارَثُ أَهْلُ دِينَيْنِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hasan] dari [Isa Al Hannath] dari [Asy Sya'bi] bahwa Rasulullah shallallahu 'alaihi wasallam, Abu Bakr dan Umar mengatakan; (Antara) dua pemeluk agama (yang berbeda) tidak bisa saling mewarisi."},"2498":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ مُطَرِّفٍ عَنْ عَامِرٍ عَنْ عُمَرَ قَالَ لَا يَتَوَارَثُ أَهْلُ مِلَّتَيْنِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zuhair] dari [Mutharrif] dari [Amir] dari [Umar] ia berkata; Dua pemeluk agama tidak bisa saling mewarisi."},"2499":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا شَرِيكٌ عَنْ الْأَشْعَثِ عَنْ الْحَسَنِ عَنْ جَابِرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَرِثُ أَهْلَ الْكِتَابِ وَلَا يَرِثُونَا إِلَّا الرَّجُلُ يَرِثُ عَبْدَهُ أَوْ أَمَتَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Syarik] dari [Al Asy'ats] dari [Al Hasan] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kita tidak berhak mewarisi ahli kitab dan mereka tidak berhak mewarisi kita kecuali seseorang yang mewarisi budak laki-laki atau budak perempuan miliknya.\""},"2500":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ كَانَ مُعَاوِيَةُ يُوَرِّثُ الْمُسْلِمَ مِنْ الْكَافِرِ وَلَا يُوَرِّثُ الْكَافِرَ مِنْ الْمُسْلِمِ قَالَ قَالَ مَسْرُوقٌ وَمَا حَدَثَ فِي الْإِسْلَامِ قَضَاءٌ أَحَبُّ إِلَيَّ مِنْهُ قِيلَ لِأَبِي مُحَمَّدٍ تَقُولُ بِهَذَا قَالَ لَا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Dawud] dari [Asy Sya'bi] dari [Masruq] ia berkata; [Mu'awiyah] membolehkan orang muslim mewarisi orang kafir namun tidak membolehkan orang kafir mewarisi orang muslim. Ia melanjutkan; Masruq berkata; Tidak ada satu keputusan dalam Islam yang lebih aku sukai dari pada keputusan ini. Ada yang bertanya kepada Abu Muhammad; Apakah engkau juga mengatakan seperti ini? Ia menjawab; Tidak."}};
